def normalize_proxy_status_value(value):
    if value is None:
        return None
    normalized = str(value).strip().lower()
    if not normalized:
        return None
    aliases = {
        'утерян': 'lost',
        'lost': 'lost',
        'сдан в hr': 'returned_to_hr',
        'сдан hr': 'returned_to_hr',
        'returned_to_hr': 'returned_to_hr',
        'returned': 'returned_to_hr',
        'не получал': 'not_received',
        'не получил': 'not_received',
        'not_received': 'not_received',
        'not received': 'not_received',
        'на руках': 'on_hand',
        'on_hand': 'on_hand',
        'on hand': 'on_hand',
    }
    normalized = aliases.get(normalized, normalized)
    if normalized not in PROXY_STATUS_VALUES:
        raise ValueError("Invalid proxy_status")
    return normalized


def _invalidate_shift_auction_runtime_caches(include_participants=False):
    with SHIFT_AUCTION_SNAPSHOT_COMMON_CACHE_LOCK:
        SHIFT_AUCTION_SNAPSHOT_COMMON_CACHE["key"] = None
        SHIFT_AUCTION_SNAPSHOT_COMMON_CACHE["expires_at"] = 0.0
        SHIFT_AUCTION_SNAPSHOT_COMMON_CACHE["value"] = None
    if include_participants:
        with SHIFT_AUCTION_PARTICIPANT_CACHE_LOCK:
            SHIFT_AUCTION_PARTICIPANT_CACHE["expires_at"] = 0.0
            SHIFT_AUCTION_PARTICIPANT_CACHE["ids"] = frozenset()

