    def update_telegram_id(self, user_id, telegram_id):
        with self._get_cursor() as cursor:
            cursor.execute("""
                UPDATE users 
                SET telegram_id = %s
                WHERE id = %s
                RETURNING telegram_id
            """, (telegram_id, user_id))
            result = cursor.fetchone()
            if result:
                return result[0]
            return None

    def get_admin_feedback_telegram_report_setting(self, user_id: int) -> Optional[bool]:
        try:
            user_id_int = int(user_id)
        except (TypeError, ValueError):
            return None

        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT COALESCE(ap.feedback_telegram_report_enabled,
                               u.feedback_telegram_report_enabled, FALSE)
                FROM users u
                LEFT JOIN admin_profiles ap ON ap.user_id = u.id
                WHERE u.id = %s
                  AND LOWER(COALESCE(u.role, '')) IN ('admin', 'super_admin')
                LIMIT 1
            """, (user_id_int,))
            row = cursor.fetchone()
            if not row:
                return None
            return bool(row[0])

    def set_admin_feedback_telegram_report_setting(self, user_id: int, enabled: bool) -> Optional[bool]:
        try:
            user_id_int = int(user_id)
        except (TypeError, ValueError):
            return None

        with self._get_cursor() as cursor:
            cursor.execute("""
                UPDATE users
                SET feedback_telegram_report_enabled = %s
                WHERE id = %s
                  AND LOWER(COALESCE(role, '')) IN ('admin', 'super_admin')
                RETURNING COALESCE(feedback_telegram_report_enabled, FALSE)
            """, (bool(enabled), user_id_int))
            row = cursor.fetchone()
            if not row:
                return None
            # Sync to admin_profiles
            cursor.execute("""
                INSERT INTO admin_profiles (user_id, feedback_telegram_report_enabled)
                VALUES (%s, %s)
                ON CONFLICT (user_id) DO UPDATE SET feedback_telegram_report_enabled = EXCLUDED.feedback_telegram_report_enabled
            """, (user_id_int, bool(enabled)))
            return bool(row[0])

    def get_admins_with_feedback_telegram_reports_enabled(self) -> List[Dict[str, Any]]:
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT u.id, u.name, u.telegram_id
                FROM users u
                LEFT JOIN admin_profiles ap ON ap.user_id = u.id
                WHERE LOWER(COALESCE(u.role, '')) IN ('admin', 'super_admin')
                  AND u.telegram_id IS NOT NULL
                  AND COALESCE(ap.feedback_telegram_report_enabled,
                               u.feedback_telegram_report_enabled, FALSE) = TRUE
                ORDER BY u.name
            """)
            rows = cursor.fetchall()

        result = []
        for row in rows:
            result.append({
                "id": int(row[0]),
                "name": row[1] or "",
                "telegram_id": int(row[2]) if row[2] is not None else None
            })
        return result

    def get_call_evaluation_notify_setting(self, user_id: int) -> Optional[Dict[str, Any]]:
        try:
            user_id_int = int(user_id)
        except (TypeError, ValueError):
            return None

        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT
                    COALESCE(ap.call_evaluation_notify_enabled, FALSE) AS enabled,
                    ap.call_evaluation_notify_department_id,
                    d.name AS department_name
                FROM users u
                LEFT JOIN admin_profiles ap ON ap.user_id = u.id
                LEFT JOIN departments d ON d.id = ap.call_evaluation_notify_department_id
                WHERE u.id = %s
                LIMIT 1
            """, (user_id_int,))
            row = cursor.fetchone()

        if not row:
            return None
        return {
            "enabled": bool(row[0]),
            "department_id": int(row[1]) if row[1] is not None else None,
            "department_name": row[2] or None,
        }

    def set_call_evaluation_notify_setting(self, user_id: int, enabled: bool, department_id=None) -> Optional[Dict[str, Any]]:
        try:
            user_id_int = int(user_id)
        except (TypeError, ValueError):
            return None

        department_id_int = None
        if department_id not in (None, ''):
            try:
                department_id_int = int(department_id)
            except (TypeError, ValueError):
                return None

        with self._get_cursor() as cursor:
            cursor.execute("""
                INSERT INTO admin_profiles (
                    user_id,
                    call_evaluation_notify_enabled,
                    call_evaluation_notify_department_id
                )
                SELECT u.id, %s, %s
                FROM users u
                WHERE u.id = %s
                ON CONFLICT (user_id) DO UPDATE SET
                    call_evaluation_notify_enabled = EXCLUDED.call_evaluation_notify_enabled,
                    call_evaluation_notify_department_id = EXCLUDED.call_evaluation_notify_department_id
                RETURNING call_evaluation_notify_enabled, call_evaluation_notify_department_id
            """, (bool(enabled), department_id_int, user_id_int))
            row = cursor.fetchone()

        if not row:
            return None
        return {
            "enabled": bool(row[0]),
            "department_id": int(row[1]) if row[1] is not None else None,
        }

    def get_call_evaluation_notify_recipients(self, operator_id: int) -> List[Dict[str, Any]]:
        try:
            operator_id_int = int(operator_id)
        except (TypeError, ValueError):
            return []

        with self._get_cursor() as cursor:
            cursor.execute("SELECT department_id FROM users WHERE id = %s", (operator_id_int,))
            operator_row = cursor.fetchone()
            if not operator_row or operator_row[0] is None:
                return []

            department_id = int(operator_row[0])
            cursor.execute("""
                SELECT
                    u.id,
                    u.name,
                    u.telegram_id,
                    d.id AS department_id,
                    d.name AS department_name
                FROM admin_profiles ap
                JOIN users u ON u.id = ap.user_id
                JOIN departments d ON d.id = ap.call_evaluation_notify_department_id
                WHERE COALESCE(ap.call_evaluation_notify_enabled, FALSE) = TRUE
                  AND ap.call_evaluation_notify_department_id = %s
                  AND u.telegram_id IS NOT NULL
                  AND (
                    LOWER(COALESCE(u.role, '')) IN ('admin', 'super_admin')
                    OR d.head_user_id = u.id
                  )
                ORDER BY u.name
            """, (department_id,))
            rows = cursor.fetchall() or []

        result = []
        for row in rows:
            if row[2] is None:
                continue
            result.append({
                "id": int(row[0]),
                "name": row[1] or "",
                "telegram_id": int(row[2]),
                "department_id": int(row[3]) if row[3] is not None else None,
                "department_name": row[4] or "",
            })
        return result

    # ---- Telegram-отчёт о сменах ставок операторов ----

    def get_rate_change_report_setting(self, user_id) -> Optional[bool]:
        """Текущее значение переключателя отчёта о сменах ставок. None если юзер не найден."""
        try:
            uid = int(user_id)
        except (TypeError, ValueError):
            return None
        with self._get_cursor() as cursor:
            cursor.execute(
                "SELECT COALESCE(rate_change_report_enabled, FALSE) FROM users WHERE id = %s",
                (uid,)
            )
            row = cursor.fetchone()
            return bool(row[0]) if row else None

    def set_rate_change_report_setting(self, user_id, enabled: bool) -> Optional[bool]:
        try:
            uid = int(user_id)
        except (TypeError, ValueError):
            return None
        with self._get_cursor() as cursor:
            cursor.execute(
                """
                UPDATE users SET rate_change_report_enabled = %s
                WHERE id = %s
                RETURNING COALESCE(rate_change_report_enabled, FALSE)
                """,
                (bool(enabled), uid)
            )
            row = cursor.fetchone()
            return bool(row[0]) if row else None

    def get_rate_change_report_recipients(self) -> List[Dict[str, Any]]:
        """Получатели отчёта о сменах ставок.

        - Админы с включённым переключателем -> глобальный отчёт (department_id=None).
        - Главы отделов с включённым переключателем -> отчёт по своему отделу.
        Если пользователь и админ, и глава отдела — оставляем только глобальный.
        """
        recipients = []
        seen_user_ids = set()
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT id, name, telegram_id
                FROM users
                WHERE LOWER(COALESCE(role, '')) IN ('admin', 'super_admin')
                  AND telegram_id IS NOT NULL
                  AND COALESCE(rate_change_report_enabled, FALSE) = TRUE
                ORDER BY name
            """)
            for row in cursor.fetchall():
                recipients.append({
                    "id": int(row[0]), "name": row[1] or "",
                    "telegram_id": int(row[2]),
                    "department_id": None, "department_name": None,
                })
                seen_user_ids.add(int(row[0]))

            cursor.execute("""
                SELECT h.id, h.name, h.telegram_id, d.id, d.name
                FROM departments d
                JOIN users h ON h.id = d.head_user_id
                WHERE h.telegram_id IS NOT NULL
                  AND COALESCE(h.rate_change_report_enabled, FALSE) = TRUE
                ORDER BY d.name
            """)
            for row in cursor.fetchall():
                if int(row[0]) in seen_user_ids:
                    continue
                recipients.append({
                    "id": int(row[0]), "name": row[1] or "",
                    "telegram_id": int(row[2]),
                    "department_id": int(row[3]), "department_name": row[4] or "",
                })
        return recipients

    def get_rate_change_report_data(self, window_start, window_end, department_id=None) -> Dict[str, Any]:
        """Данные для отчёта о сменах ставок за окно [window_start, window_end).

        window_start/window_end — naive-datetime в локальном времени Алматы
        (так же хранится user_history.changed_at). Для каждого оператора берём
        итоговый переход за окно (с какой ставки на какую), пропуская net-zero.
        """
        allowed_rates = (1.0, 0.75, 0.5)

        def _snap(raw):
            try:
                v = float(raw)
            except (TypeError, ValueError):
                return None
            return min(allowed_rates, key=lambda a: abs(a - v))

        params = [window_start, window_end]
        dept_clause = ""
        if department_id is not None:
            dept_clause = " AND u.department_id = %s"
            params.append(int(department_id))

        with self._get_cursor() as cursor:
            cursor.execute(f"""
                SELECT uh.user_id, u.name, dep.name, dir.name, sv.name,
                       uh.old_value, uh.new_value, uh.changed_at,
                       uh.changed_by, cb.name
                FROM user_history uh
                JOIN users u ON u.id = uh.user_id
                LEFT JOIN departments dep ON dep.id = u.department_id
                LEFT JOIN directions dir ON dir.id = u.direction_id
                LEFT JOIN users sv ON sv.id = u.supervisor_id
                LEFT JOIN users cb ON cb.id = uh.changed_by
                WHERE uh.field_changed = 'rate'
                  AND uh.changed_at >= %s AND uh.changed_at < %s
                  AND LOWER(COALESCE(u.role, '')) = 'operator'
                  {dept_clause}
                ORDER BY uh.user_id, uh.changed_at, uh.id
            """, params)
            rows = cursor.fetchall()

        by_op = {}
        order = []
        for uid, name, dept, direction, sv, old_v, new_v, changed_at, changed_by, cb_name in rows:
            if uid not in by_op:
                by_op[uid] = {
                    "operator_id": int(uid), "operator_name": name or "",
                    "department_name": dept or "", "direction_name": direction or "",
                    "supervisor_name": sv or "",
                    "first_old": _snap(old_v),
                    "change_count": 0,
                    "last_changed_at": changed_at,
                    "last_changed_by_id": changed_by,
                    "last_changed_by_name": cb_name or "",
                    "self_involved": False,
                }
                order.append(uid)
            rec = by_op[uid]
            rec["last_new"] = _snap(new_v)
            rec["change_count"] += 1
            rec["last_changed_at"] = changed_at
            rec["last_changed_by_id"] = changed_by
            rec["last_changed_by_name"] = cb_name or ""
            if changed_by is not None and int(changed_by) == int(uid):
                rec["self_involved"] = True

        changes = []
        new_rate_dist = {1.0: 0, 0.75: 0, 0.5: 0}
        self_count = 0
        for uid in order:
            rec = by_op[uid]
            old_r = rec.get("first_old")
            new_r = rec.get("last_new")
            if old_r is None or new_r is None or abs(old_r - new_r) < 1e-9:
                continue  # нет реального перехода
            rec["old_rate"] = old_r
            rec["new_rate"] = new_r
            rec["by_self"] = (
                rec["last_changed_by_id"] is not None
                and int(rec["last_changed_by_id"]) == int(uid)
            )
            changes.append(rec)
            if new_r in new_rate_dist:
                new_rate_dist[new_r] += 1
            if rec["self_involved"]:
                self_count += 1

        cur_params = []
        cur_dept = ""
        if department_id is not None:
            cur_dept = " AND department_id = %s"
            cur_params.append(int(department_id))
        current_dist = {1.0: 0, 0.75: 0, 0.5: 0}
        with self._get_cursor() as cursor:
            cursor.execute(f"""
                SELECT rate, COUNT(*) FROM users
                WHERE LOWER(COALESCE(role, '')) = 'operator'{cur_dept}
                GROUP BY rate
            """, cur_params)
            for rate, cnt in cursor.fetchall():
                r = _snap(rate)
                if r in current_dist:
                    current_dist[r] += int(cnt)

        return {
            "changes": changes,
            "summary": {
                "changed_count": len(changes),
                "total_change_events": sum(r["change_count"] for r in changes),
                "self_count": self_count,
                "by_other_count": len(changes) - self_count,
                "new_rate_distribution": new_rate_dist,
            },
            "current_distribution": current_dist,
        }

    def get_directions(self, department_id=None):
        """Получить активные направления. Если задан department_id — только этого отдела."""
        with self._get_cursor() as cursor:
            if department_id is not None:
                cursor.execute("""
                    SELECT id, name, has_file_upload, criteria, is_active, calculation_model_code, department_id
                    FROM directions
                    WHERE is_active = TRUE AND department_id = %s
                    ORDER BY name
                """, (department_id,))
            else:
                cursor.execute("""
                    SELECT id, name, has_file_upload, criteria, is_active, calculation_model_code, department_id
                    FROM directions
                    WHERE is_active = TRUE  -- Added filter for performance
                    ORDER BY name
                """)
            return [
                {
                    "id": row[0],
                    "name": row[1],
                    "hasFileUpload": row[2],
                    "criteria": row[3],
                    "isActive": row[4],
                    "calculationModelCode": normalize_calculation_model_code(row[5], row[1]),
                    "calculation_model_code": normalize_calculation_model_code(row[5], row[1]),
                    "departmentId": row[6],
                    "department_id": row[6]
                } for row in cursor.fetchall()
            ]

    def _parse_resource_schedule_date_value(self, value, field_name="date"):
        if isinstance(value, datetime):
            return value.date()
        if isinstance(value, date):
            return value
        text = str(value or '').strip()
        if not text:
            raise ValueError(f"{field_name.upper()}_REQUIRED")
        try:
            return datetime.strptime(text[:10], "%Y-%m-%d").date()
        except Exception as exc:
            raise ValueError("INVALID_RESOURCE_SCHEDULE_DATE") from exc

    def _format_resource_schedule_clock(self, minutes):
        try:
            minute_value = int(round(float(minutes or 0)))
        except Exception:
            minute_value = 0
        normalized = minute_value % (24 * 60)
        return f"{normalized // 60:02d}:{normalized % 60:02d}"

    def _coerce_resource_schedule_direction_ids(self, value):
        if value is None:
            return []
        if isinstance(value, str):
            try:
                value = json.loads(value)
            except Exception:
                value = [value]
        if not isinstance(value, (list, tuple, set)):
            value = [value]
        result = []
        seen = set()
        for item in value:
            try:
                direction_id = int(item)
            except Exception:
                continue
            if direction_id <= 0 or direction_id in seen:
                continue
            seen.add(direction_id)
            result.append(direction_id)
        return result

    def _resolve_resource_schedule_direction_context_tx(self, cursor, payload):
        safe_payload = payload or {}
        capacity = safe_payload.get("capacity") if isinstance(safe_payload.get("capacity"), dict) else {}
        meta = safe_payload.get("meta") if isinstance(safe_payload.get("meta"), dict) else {}
        explicit_name = (
            meta.get("directionName")
            or meta.get("direction_name")
            or safe_payload.get("directionName")
            or safe_payload.get("direction_name")
        )
        direction_ids = (
            capacity.get("selectedDirectionIds")
            or capacity.get("selected_direction_ids")
            or meta.get("selectedDirectionIds")
            or meta.get("selected_direction_ids")
            or safe_payload.get("selectedDirectionIds")
            or safe_payload.get("selected_direction_ids")
        )
        direction_ids = self._coerce_resource_schedule_direction_ids(direction_ids)
        if not direction_ids:
            cursor.execute("SELECT selected_direction_ids FROM resource_settings WHERE id = 1")
            settings_row = cursor.fetchone()
            direction_ids = self._coerce_resource_schedule_direction_ids(settings_row[0] if settings_row else [])

        directions = []
        if direction_ids:
            cursor.execute("""
                SELECT id, name
                FROM directions
                WHERE id = ANY(%s)
                ORDER BY array_position(%s::int[], id), name
            """, (direction_ids, direction_ids))
            directions = [
                {"id": int(row[0]), "name": row[1] or ""}
                for row in (cursor.fetchall() or [])
            ]

        direction_name = str(explicit_name or '').strip()
        if not direction_name and directions:
            direction_name = directions[0]["name"]
        direction_rules = self._get_work_schedule_break_rules_for_direction_tx(cursor, direction_name) if direction_name else []
        if not explicit_name and directions and not direction_rules:
            for item in directions[1:]:
                candidate_name = item.get("name") or ""
                candidate_rules = self._get_work_schedule_break_rules_for_direction_tx(cursor, candidate_name)
                if candidate_rules:
                    direction_name = candidate_name
                    direction_rules = candidate_rules
                    break
        return {
            "direction_id": directions[0]["id"] if directions else None,
            "direction_name": direction_name,
            "selected_direction_ids": direction_ids,
            "selected_directions": directions,
            "break_rules": direction_rules,
        }

    def _normalize_resource_saved_schedule_shifts(self, days, direction_name=None, direction_rules=None):
        rows = []
        for day_index, day in enumerate(days or []):
            if not isinstance(day, dict):
                continue
            try:
                shift_date = self._parse_resource_schedule_date_value(day.get("date"), "shift_date")
            except ValueError:
                continue
            for shift_index, shift in enumerate(day.get("shifts") or []):
                if not isinstance(shift, dict):
                    continue
                try:
                    start_minute = int(round(float(shift.get("startMinute", 0) or 0)))
                    end_minute = int(round(float(shift.get("endMinute", start_minute + 60) or (start_minute + 60))))
                except Exception:
                    continue
                start_minute = max(0, min(start_minute, (24 * 60) - 1))
                end_minute = max(start_minute + 1, min(end_minute, 32 * 60))
                duration_minutes = max(1, end_minute - start_minute)
                incoming_breaks = shift.get("breaks") if isinstance(shift.get("breaks"), list) else []
                computed_breaks = self._compute_auto_shift_breaks_minutes(
                    start_minute,
                    end_minute,
                    direction_name=direction_name,
                    direction_rules=direction_rules
                )
                meta = {
                    key: value for key, value in shift.items()
                    if key not in {
                        "id", "templateId", "rate", "label", "start", "end",
                        "startMinute", "endMinute", "durationMinutes", "overnight",
                        "source", "tone", "breaks"
                    }
                }
                if incoming_breaks:
                    meta["clientBreaks"] = incoming_breaks
                meta["breakSource"] = "work_schedule_break_rules"
                if direction_name:
                    meta["breakDirectionName"] = direction_name
                rows.append({
                    "client_shift_id": str(shift.get("id") or f"saved-{day_index}-{shift_index}")[:180],
                    "shift_date": shift_date,
                    "start_minute": start_minute,
                    "end_minute": end_minute,
                    "start_time": self._format_resource_schedule_clock(start_minute),
                    "end_time": self._format_resource_schedule_clock(end_minute),
                    "duration_minutes": duration_minutes,
                    "rate_min": float(shift.get("rate") or shift.get("rate_min") or 0),
                    "label": str(shift.get("label") or "")[:255],
                    "template_id": str(shift.get("templateId") or shift.get("template_id") or "")[:180],
                    "source": str(shift.get("source") or "")[:80],
                    "tone": str(shift.get("tone") or "")[:40],
                    "overnight": bool(shift.get("overnight") or end_minute >= 24 * 60),
                    "breaks": computed_breaks,
                    "meta": meta,
                })
        rows.sort(key=lambda item: (item["shift_date"], item["start_minute"], item["end_minute"], item["client_shift_id"]))
        return rows

    def _serialize_resource_saved_schedule_shift_row(self, row):
        shift_meta = row[14] if isinstance(row[14], dict) else {}
        payload = {
            **shift_meta,
            "id": row[1] or f"saved-{row[0]}",
            "savedShiftId": row[0],
            "templateId": row[10] or "",
            "rate": float(row[8]) if row[8] is not None else 0,
            "label": row[9] or "",
            "start": row[5].strftime('%H:%M') if row[5] else None,
            "end": row[6].strftime('%H:%M') if row[6] else None,
            "startMinute": int(row[3] or 0),
            "endMinute": int(row[4] or 0),
            "durationMinutes": int(row[7] or 0),
            "overnight": bool(row[13]),
            "source": row[11] or "",
            "tone": row[12] or "",
            "breaks": row[15] if isinstance(row[15], list) else [],
        }
        return payload

    def _serialize_resource_saved_schedule_plan(self, plan_row, shift_rows):
        if not plan_row:
            return None
        meta = plan_row[9] if isinstance(plan_row[9], dict) else {}
        shifts_by_date = defaultdict(list)
        for row in shift_rows or []:
            date_key = row[2].strftime('%Y-%m-%d') if row[2] else None
            if date_key:
                shifts_by_date[date_key].append(self._serialize_resource_saved_schedule_shift_row(row))

        stored_days = meta.get("days") if isinstance(meta.get("days"), list) else []
        days = []
        if stored_days:
            for day in stored_days:
                if not isinstance(day, dict):
                    continue
                date_key = str(day.get("date") or "")
                days.append({
                    **day,
                    "shifts": shifts_by_date.pop(date_key, []),
                })
        for date_key in sorted(shifts_by_date.keys()):
            days.append({
                "date": date_key,
                "short": date_key[5:],
                "label": date_key,
                "coverage": [],
                "stats": {},
                "shifts": shifts_by_date[date_key],
            })

        return {
            "id": plan_row[0],
            "date_from": plan_row[1].strftime('%Y-%m-%d') if plan_row[1] else None,
            "date_to": plan_row[2].strftime('%Y-%m-%d') if plan_row[2] else None,
            "title": plan_row[3] or "",
            "selectedVariantKey": plan_row[4] or "",
            "includeIncidentUplift": bool(plan_row[5]),
            "summary": plan_row[6] or {},
            "capacity": plan_row[7] or {},
            "templates": plan_row[8] or [],
            "meta": {key: value for key, value in meta.items() if key != "days"},
            "days": days,
            "created_by": plan_row[10],
            "updated_by": plan_row[11],
            "created_at": plan_row[12].isoformat() if plan_row[12] else None,
            "updated_at": plan_row[13].isoformat() if plan_row[13] else None,
        }

    def get_resource_saved_schedule(self, date_from=None, date_to=None, plan_id=None):
        with self._get_cursor() as cursor:
            if plan_id:
                cursor.execute("""
                    SELECT id, date_from, date_to, title, selected_variant_key,
                           include_incident_uplift, summary, capacity, templates, meta,
                           created_by, updated_by, created_at, updated_at
                    FROM resource_saved_schedule_plans
                    WHERE id = %s AND archived_at IS NULL
                """, (int(plan_id),))
            else:
                start_date = self._parse_resource_schedule_date_value(date_from, "date_from")
                end_date = self._parse_resource_schedule_date_value(date_to or date_from, "date_to")
                cursor.execute("""
                    SELECT id, date_from, date_to, title, selected_variant_key,
                           include_incident_uplift, summary, capacity, templates, meta,
                           created_by, updated_by, created_at, updated_at
                    FROM resource_saved_schedule_plans
                    WHERE date_from = %s
                      AND date_to = %s
                      AND archived_at IS NULL
                    ORDER BY updated_at DESC, id DESC
                    LIMIT 1
                """, (start_date, end_date))
            plan_row = cursor.fetchone()
            if not plan_row:
                return None
            cursor.execute("""
                SELECT id, client_shift_id, shift_date, start_minute, end_minute,
                       start_time, end_time, duration_minutes, rate_min, label,
                       template_id, source, tone, overnight, meta, breaks
                FROM resource_saved_schedule_shifts
                WHERE plan_id = %s
                ORDER BY shift_date, start_minute, end_minute, id
            """, (plan_row[0],))
            shift_rows = cursor.fetchall() or []
            return self._serialize_resource_saved_schedule_plan(plan_row, shift_rows)

    def save_resource_saved_schedule(self, payload, updated_by=None):
        safe_payload = payload or {}
        days = safe_payload.get("days") if isinstance(safe_payload.get("days"), list) else []
        if not days:
            raise ValueError("RESOURCE_SCHEDULE_EMPTY")

        date_from = safe_payload.get("date_from") or days[0].get("date")
        date_to = safe_payload.get("date_to") or days[-1].get("date") or date_from
        start_date = self._parse_resource_schedule_date_value(date_from, "date_from")
        end_date = self._parse_resource_schedule_date_value(date_to, "date_to")
        if end_date < start_date:
            raise ValueError("INVALID_RESOURCE_SCHEDULE_PERIOD")

        summary = safe_payload.get("summary") if isinstance(safe_payload.get("summary"), dict) else {}
        capacity = safe_payload.get("capacity") if isinstance(safe_payload.get("capacity"), dict) else {}
        templates = safe_payload.get("templates") if isinstance(safe_payload.get("templates"), list) else []
        base_meta = safe_payload.get("meta") if isinstance(safe_payload.get("meta"), dict) else {}
        title = str(safe_payload.get("title") or "")[:500]
        variant_key = str(safe_payload.get("selected_variant_key") or safe_payload.get("selectedVariantKey") or "")[:120]
        include_incident_uplift = bool(safe_payload.get("include_incident_uplift") or safe_payload.get("includeIncidentUplift"))

        plan_id = None
        raw_plan_id = safe_payload.get("id") or safe_payload.get("plan_id") or safe_payload.get("planId")
        try:
            plan_id = int(raw_plan_id) if raw_plan_id else None
        except Exception:
            plan_id = None

        with self._get_cursor() as cursor:
            direction_context = self._resolve_resource_schedule_direction_context_tx(cursor, {
                **safe_payload,
                "capacity": capacity,
                "meta": base_meta,
            })
            shift_rows = self._normalize_resource_saved_schedule_shifts(
                days,
                direction_name=direction_context.get("direction_name"),
                direction_rules=direction_context.get("break_rules")
            )
            meta = {
                **base_meta,
                "days": days,
                "shiftCount": len(shift_rows),
                "savedAt": datetime.now().isoformat(),
                "breakDirectionId": direction_context.get("direction_id"),
                "breakDirectionName": direction_context.get("direction_name"),
                "selectedDirectionIds": direction_context.get("selected_direction_ids") or [],
                "selectedDirections": direction_context.get("selected_directions") or [],
                "breakRules": direction_context.get("break_rules") or [],
            }

            if plan_id:
                cursor.execute("""
                    SELECT id
                    FROM resource_saved_schedule_plans
                    WHERE id = %s AND archived_at IS NULL
                    FOR UPDATE
                """, (plan_id,))
                if not cursor.fetchone():
                    plan_id = None

            if not plan_id:
                cursor.execute("""
                    SELECT id
                    FROM resource_saved_schedule_plans
                    WHERE date_from = %s
                      AND date_to = %s
                      AND archived_at IS NULL
                    ORDER BY updated_at DESC, id DESC
                    LIMIT 1
                    FOR UPDATE
                """, (start_date, end_date))
                existing = cursor.fetchone()
                plan_id = int(existing[0]) if existing else None

            if plan_id:
                cursor.execute("""
                    UPDATE resource_saved_schedule_plans
                    SET date_from = %s,
                        date_to = %s,
                        title = %s,
                        selected_variant_key = %s,
                        include_incident_uplift = %s,
                        summary = %s,
                        capacity = %s,
                        templates = %s,
                        meta = %s,
                        updated_by = %s,
                        updated_at = CURRENT_TIMESTAMP
                    WHERE id = %s
                """, (
                    start_date,
                    end_date,
                    title,
                    variant_key,
                    include_incident_uplift,
                    Json(summary),
                    Json(capacity),
                    Json(templates),
                    Json(meta),
                    updated_by,
                    plan_id,
                ))
            else:
                cursor.execute("""
                    INSERT INTO resource_saved_schedule_plans (
                        date_from, date_to, title, selected_variant_key,
                        include_incident_uplift, summary, capacity, templates,
                        meta, created_by, updated_by
                    )
                    VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
                    RETURNING id
                """, (
                    start_date,
                    end_date,
                    title,
                    variant_key,
                    include_incident_uplift,
                    Json(summary),
                    Json(capacity),
                    Json(templates),
                    Json(meta),
                    updated_by,
                    updated_by,
                ))
                plan_id = int(cursor.fetchone()[0])

            cursor.execute("DELETE FROM resource_saved_schedule_shifts WHERE plan_id = %s", (plan_id,))
            if shift_rows:
                execute_values(
                    cursor,
                    """
                    INSERT INTO resource_saved_schedule_shifts (
                        plan_id, client_shift_id, shift_date, start_minute, end_minute,
                        start_time, end_time, duration_minutes, rate_min, label,
                        template_id, source, tone, overnight, breaks, meta
                    )
                    VALUES %s
                    """,
                    [
                        (
                            plan_id,
                            row["client_shift_id"],
                            row["shift_date"],
                            row["start_minute"],
                            row["end_minute"],
                            row["start_time"],
                            row["end_time"],
                            row["duration_minutes"],
                            row["rate_min"],
                            row["label"],
                            row["template_id"],
                            row["source"],
                            row["tone"],
                            row["overnight"],
                            Json(row["breaks"]),
                            Json(row["meta"]),
                        )
                        for row in shift_rows
                    ],
                )

            cursor.execute("""
                SELECT id, shift_date, start_time, end_time, rate_min, breaks
                FROM resource_saved_schedule_shifts
                WHERE plan_id = %s
                  AND COALESCE(meta->>'excludeFromAuction', 'false') <> 'true'
                ORDER BY shift_date, start_minute, end_minute, id
            """, (plan_id,))
            saved_shift_rows = cursor.fetchall() or []
            event = self._insert_shift_auction_test_event(cursor, "resource_schedule_saved", {
                "plan_id": plan_id,
                "count": len(saved_shift_rows),
                "date_from": start_date.strftime('%Y-%m-%d'),
                "date_to": end_date.strftime('%Y-%m-%d'),
                "updated_by": updated_by,
                "break_direction_name": direction_context.get("direction_name"),
            })

        return {
            "schedule": self.get_resource_saved_schedule(plan_id=plan_id),
            "auction_count": sum(1 for row in shift_rows if not bool((row.get("meta") or {}).get("excludeFromAuction"))),
            "event": event,
        }

    def _get_shift_auction_test_status(self, enabled, starts_at=None, ends_at=None, paused_at=None, finished_at=None):
        if not enabled:
            return "disabled"
        if finished_at:
            return "closed"
        if paused_at:
            return "paused"
        now = datetime.now()
        if starts_at and now < starts_at:
            return "scheduled"
        if ends_at and now >= ends_at:
            return "closed"
        return "open"

    def _serialize_shift_auction_lot_row(self, row):
        return {
            "id": row[0],
            "shift_date": row[1].strftime('%Y-%m-%d') if row[1] else None,
            "start_time": row[2].strftime('%H:%M') if row[2] else None,
            "end_time": row[3].strftime('%H:%M') if row[3] else None,
            "rate_min": float(row[4]) if row[4] is not None else 0,
            "status": row[5],
            "claimed_by": row[6],
            "claimed_by_name": row[7] or "",
            "claimed_at": row[8].isoformat() if row[8] else None,
            "breaks": row[9] if len(row) > 9 and isinstance(row[9], list) else [],
            "source_schedule_plan_id": row[10] if len(row) > 10 else None,
            "source_schedule_shift_id": row[11] if len(row) > 11 else None,
            "post_auction_claimed": bool(row[12]) if len(row) > 12 and row[12] is not None else False,
            "claimed_by_direction_id": row[13] if len(row) > 13 else None,
            "claimed_by_direction": (row[14] or "") if len(row) > 14 else "",
            "source_start_minute": int(row[15]) if len(row) > 15 and row[15] is not None else None,
            "source_end_minute": int(row[16]) if len(row) > 16 and row[16] is not None else None,
            "claim_start_time": row[17].strftime('%H:%M') if len(row) > 17 and row[17] else None,
            "claim_end_time": row[18].strftime('%H:%M') if len(row) > 18 and row[18] else None,
            "claim_segments": row[19] if len(row) > 19 and isinstance(row[19], list) else [],
        }

    def _get_shift_auction_operator_work_shifts_tx(self, cursor, operator_id, lot_dates=None):
        try:
            op_id = int(operator_id)
        except Exception:
            return []
        dates = sorted({
            item for item in (lot_dates or [])
            if item is not None
        })
        if not dates:
            return []

        cursor.execute("""
            SELECT id, shift_date, start_time, end_time
            FROM work_shifts
            WHERE operator_id = %s
              AND shift_date >= %s
              AND shift_date <= %s
            ORDER BY shift_date, start_time, end_time, id
        """, (op_id, dates[0], dates[-1]))

        return [
            {
                "id": row[0],
                "shift_date": row[1].strftime('%Y-%m-%d') if row[1] else None,
                "start_time": row[2].strftime('%H:%M') if row[2] else None,
                "end_time": row[3].strftime('%H:%M') if row[3] else None,
            }
            for row in (cursor.fetchall() or [])
        ]

    def _cache_shift_auction_participant_ids(self, participant_rows):
        if SHIFT_AUCTION_PARTICIPANT_CACHE_TTL_SECONDS <= 0:
            return
        ids = frozenset(
            int(row[0])
            for row in (participant_rows or [])
            if row and row[0] is not None
        )
        with SHIFT_AUCTION_PARTICIPANT_CACHE_LOCK:
            SHIFT_AUCTION_PARTICIPANT_CACHE["ids"] = ids
            SHIFT_AUCTION_PARTICIPANT_CACHE["expires_at"] = time.time() + SHIFT_AUCTION_PARTICIPANT_CACHE_TTL_SECONDS

    def _get_shift_auction_participant_ids_cached_tx(self, cursor):
        now = time.time()
        if SHIFT_AUCTION_PARTICIPANT_CACHE_TTL_SECONDS > 0:
            with SHIFT_AUCTION_PARTICIPANT_CACHE_LOCK:
                if SHIFT_AUCTION_PARTICIPANT_CACHE["expires_at"] > now:
                    return set(SHIFT_AUCTION_PARTICIPANT_CACHE["ids"])

        cursor.execute("""
            SELECT operator_id
            FROM shift_auction_test_participants
        """)
        participant_ids = {
            int(row[0])
            for row in (cursor.fetchall() or [])
            if row and row[0] is not None
        }
        if SHIFT_AUCTION_PARTICIPANT_CACHE_TTL_SECONDS > 0:
            with SHIFT_AUCTION_PARTICIPANT_CACHE_LOCK:
                SHIFT_AUCTION_PARTICIPANT_CACHE["ids"] = frozenset(participant_ids)
                SHIFT_AUCTION_PARTICIPANT_CACHE["expires_at"] = time.time() + SHIFT_AUCTION_PARTICIPANT_CACHE_TTL_SECONDS
        return participant_ids

    def _shift_auction_snapshot_common_cache_key(self, settings_row, include_admin_fields):
        if not settings_row:
            return None
        # settings_row tail layout: ... published_to_work_schedules_by_name,
        # topup_started_at, topup_started_by, topup_started_by_name, last_event_id.
        # Probe the last position since the same row shape feeds multiple callers.
        last_event_id = settings_row[-1] if isinstance(settings_row, (list, tuple)) and len(settings_row) >= 14 else 0
        return (
            bool(include_admin_fields),
            int(last_event_id or 0),
            int(settings_row[6]) if settings_row[6] is not None else None
        )

    def _build_shift_auction_snapshot_common_tx(self, cursor, settings_row, include_admin_fields=False):
        cursor.execute("""
            SELECT
                u.id,
                u.name,
                u.role,
                u.status,
                u.rate,
                u.direction_id,
                d.name AS direction_name,
                u.supervisor_id,
                s.name AS supervisor_name,
                p.created_at
            FROM shift_auction_test_participants p
            JOIN users u ON u.id = p.operator_id
            LEFT JOIN directions d ON d.id = u.direction_id
            LEFT JOIN users s ON s.id = u.supervisor_id
            ORDER BY u.name
        """)
        participant_rows = cursor.fetchall() or []
        self._cache_shift_auction_participant_ids(participant_rows)

        cursor.execute("""
            SELECT
                l.id,
                l.shift_date,
                l.start_time,
                l.end_time,
                l.rate_min,
                l.status,
                l.claimed_by,
                u.name AS claimed_by_name,
                l.claimed_at,
                l.breaks,
                l.source_schedule_plan_id,
                l.source_schedule_shift_id,
                COALESCE(l.post_auction_claimed, FALSE) AS post_auction_claimed,
                u.direction_id AS claimed_by_direction_id,
                claimed_dir.name AS claimed_by_direction,
                -- Remainder lots share the source shift id (for grouping) but cover
                -- only a gap of it; null the source minutes so the frontend uses the
                -- lot's own start/end (the gap), not the full original shift range.
                source_shift.start_minute AS source_start_minute,
                source_shift.end_minute AS source_end_minute,
                l.post_claim_start_time,
                l.post_claim_end_time,
                COALESCE((
                    SELECT jsonb_agg(jsonb_build_object(
                        'claimed_by', hc.claimed_by,
                        'claimed_by_name', cu.name,
                        'start_time', to_char(hc.claimed_start_time, 'HH24:MI'),
                        'end_time', to_char(hc.claimed_end_time, 'HH24:MI')
                    ) ORDER BY hc.claimed_start_time)
                    FROM shift_auction_historical_claims hc
                    LEFT JOIN users cu ON cu.id = hc.claimed_by
                    WHERE hc.plan_id = l.source_schedule_plan_id
                      AND hc.source_schedule_shift_id = l.source_schedule_shift_id
                      AND hc.claimed_start_time IS NOT NULL
                      AND hc.claimed_end_time IS NOT NULL
                ), '[]'::jsonb) AS claim_segments
            FROM shift_auction_test_lots l
            LEFT JOIN users u ON u.id = l.claimed_by
            LEFT JOIN directions claimed_dir ON claimed_dir.id = u.direction_id
            LEFT JOIN resource_saved_schedule_shifts source_shift ON source_shift.id = l.source_schedule_shift_id
            ORDER BY l.shift_date, l.start_time, l.id
        """)
        lot_rows = cursor.fetchall() or []
        lots = [self._serialize_shift_auction_lot_row(row) for row in lot_rows]
        lot_dates = sorted({row[1] for row in lot_rows if row and row[1]})

        selected_period_row = self._get_shift_auction_period_row_tx(cursor, settings_row[6])
        available_periods = self._get_shift_auction_available_periods_tx(cursor)
        claim_journal_rows = []
        participant_workloads = []
        if include_admin_fields:
            participant_workloads = self._get_shift_auction_participant_workloads_tx(
                cursor, participant_rows, lots, lot_dates
            )
            cursor.execute("""
                SELECT
                    e.id,
                    e.created_at,
                    NULLIF(e.payload->'lot'->>'shift_date', '') AS shift_date,
                    NULLIF(e.payload->'lot'->>'start_time', '') AS start_time,
                    NULLIF(e.payload->'lot'->>'end_time', '') AS end_time,
                    COALESCE(
                        NULLIF(e.payload->'lot'->>'claimed_by', ''),
                        NULLIF(e.payload->>'operator_id', '')
                    )::INTEGER AS claimed_by,
                    COALESCE(u.name, NULLIF(e.payload->>'operator_name', ''), '') AS claimed_by_name,
                    NULLIF(e.payload->'lot'->>'source_schedule_plan_id', '')::INTEGER AS source_schedule_plan_id,
                    p.date_from,
                    p.date_to
                FROM shift_auction_test_events e
                LEFT JOIN users u
                  ON u.id = COALESCE(
                      NULLIF(e.payload->'lot'->>'claimed_by', ''),
                      NULLIF(e.payload->>'operator_id', '')
                  )::INTEGER
                LEFT JOIN resource_saved_schedule_plans p
                  ON p.id = NULLIF(e.payload->'lot'->>'source_schedule_plan_id', '')::INTEGER
                WHERE e.event_type = 'lot_claimed'
                  AND NULLIF(e.payload->'lot'->>'source_schedule_plan_id', '')::INTEGER = %s
                ORDER BY e.id DESC
                LIMIT 50
            """, (settings_row[6],))
            claim_journal_rows = cursor.fetchall() or []

        return {
            "participant_rows": participant_rows,
            "lots": lots,
            "lot_dates": lot_dates,
            "selected_period_row": selected_period_row,
            "available_periods": available_periods,
            "claim_journal_rows": claim_journal_rows,
            "participant_workloads": participant_workloads
        }

    def _get_shift_auction_snapshot_common_tx(self, cursor, settings_row, include_admin_fields=False):
        cache_key = self._shift_auction_snapshot_common_cache_key(settings_row, include_admin_fields)
        if not cache_key or SHIFT_AUCTION_SNAPSHOT_CACHE_TTL_SECONDS <= 0:
            return self._build_shift_auction_snapshot_common_tx(cursor, settings_row, include_admin_fields)

        now = time.time()
        with SHIFT_AUCTION_SNAPSHOT_COMMON_CACHE_LOCK:
            if (
                SHIFT_AUCTION_SNAPSHOT_COMMON_CACHE["key"] == cache_key
                and SHIFT_AUCTION_SNAPSHOT_COMMON_CACHE["expires_at"] > now
                and SHIFT_AUCTION_SNAPSHOT_COMMON_CACHE["value"] is not None
            ):
                return SHIFT_AUCTION_SNAPSHOT_COMMON_CACHE["value"]

            value = self._build_shift_auction_snapshot_common_tx(cursor, settings_row, include_admin_fields)
            SHIFT_AUCTION_SNAPSHOT_COMMON_CACHE["key"] = cache_key
            SHIFT_AUCTION_SNAPSHOT_COMMON_CACHE["value"] = value
            SHIFT_AUCTION_SNAPSHOT_COMMON_CACHE["expires_at"] = time.time() + SHIFT_AUCTION_SNAPSHOT_CACHE_TTL_SECONDS
            return value

    def _insert_shift_auction_test_event(self, cursor, event_type, payload):
        cursor.execute("""
            INSERT INTO shift_auction_test_events (event_type, payload)
            VALUES (%s, %s)
            RETURNING id, created_at
        """, (str(event_type or '').strip()[:64], Json(payload or {})))
        row = cursor.fetchone()
        event_id = row[0] if row else None
        if event_id is not None:
            cursor.execute(
                "SELECT pg_notify(%s, %s)",
                (SHIFT_AUCTION_TEST_EVENT_NOTIFY_CHANNEL, str(event_id))
            )
            # Only invalidate the global snapshot cache when structural fields
            # change (auction settings, participant list, lot collection, etc.).
            # `lot_claimed` / `lot_released` / `day_off_*` events ride on SSE for
            # real-time UI updates, and the 1.5s TTL keeps fresh views close
            # enough. Aggressive invalidation here caused a thundering-herd
            # rebuild storm under load — every claim made all polling clients
            # miss the cache at once and stampede the DB pool.
            structural_events = {
                "settings_updated",
                "lots_seeded",
                "auction_published",
                "auction_paused",
                "auction_resumed",
                "auction_finished",
                "auction_restarted",
                "auction_topup_started",
                "auction_topup_stopped",
                "resource_schedule_saved",
            }
            participant_invalidating_events = {"settings_updated"}
            normalized_event_type = str(event_type or '').strip()
            if normalized_event_type in structural_events:
                _invalidate_shift_auction_runtime_caches(
                    include_participants=normalized_event_type in participant_invalidating_events
                )
        return {
            "id": event_id,
            "event_type": event_type,
            "payload": payload or {},
            "created_at": row[1].isoformat() if row and row[1] else None
        }

    def _lock_shift_auction_operator_tx(self, cursor, operator_id):
        # Serialize one operator's auction mutations so shared invariants are
        # checked against a stable per-operator view inside this transaction.
        cursor.execute(
            "SELECT pg_advisory_xact_lock(%s, %s)",
            (self.SHIFT_AUCTION_OPERATOR_LOCK_NAMESPACE, int(operator_id))
        )

    def _shift_auction_break_minutes(self, breaks):
        total = 0
        for item in (breaks or []):
            if not isinstance(item, dict):
                continue
            try:
                start_minute = int(float(item.get("start", 0) or 0))
                end_minute = int(float(item.get("end", 0) or 0))
            except Exception:
                continue
            if end_minute <= start_minute:
                end_minute += 24 * 60
            total += max(0, end_minute - start_minute)
        return max(0, int(total))

    def _shift_auction_lot_minutes(self, start_time_value, end_time_value, breaks=None):
        start_minute, end_minute = self._schedule_interval_minutes(start_time_value, end_time_value)
        duration_minutes = max(0, end_minute - start_minute)
        break_minutes = min(duration_minutes, self._shift_auction_break_minutes(breaks if isinstance(breaks, list) else []))
        return {
            "duration_minutes": duration_minutes,
            "break_minutes": break_minutes,
            "net_minutes": max(0, duration_minutes - break_minutes),
        }

    def _shift_auction_day_off_quota(self, total_days):
        try:
            total = int(total_days or 0)
        except Exception:
            total = 0
        return min(2, max(0, total))

    def _get_shift_auction_participant_workloads_tx(self, cursor, participant_rows, lots, lot_dates, day_offs_by_operator=None):
        # Per-operator workload (norm vs claimed) computed in one pass.
        # Only the day-off / blocked-period counters need the DB; lot stats are
        # derived from the already-loaded `lots` list.
        if not participant_rows:
            return []
        operator_ids = [int(row[0]) for row in participant_rows if row and row[0] is not None]
        if not operator_ids:
            return []
        lot_dates_list = [d for d in (lot_dates or []) if d]
        total_days = len(lot_dates_list)

        day_offs_count = {op_id: 0 for op_id in operator_ids}
        day_off_dates_by_op = {op_id: [] for op_id in operator_ids}
        if day_offs_by_operator is not None:
            for op_id in operator_ids:
                dates = sorted(day_offs_by_operator.get(op_id, set()) or [])
                day_offs_count[op_id] = len(dates)
                day_off_dates_by_op[op_id] = [
                    d.strftime('%Y-%m-%d') if hasattr(d, 'strftime') else str(d)
                    for d in dates
                ]
        else:
            cursor.execute(
                """
                SELECT operator_id, day_off_date
                FROM shift_auction_test_day_offs
                WHERE operator_id = ANY(%s)
                ORDER BY operator_id, day_off_date
                """,
                (operator_ids,)
            )
            for op_id, day_off_date in (cursor.fetchall() or []):
                if op_id is None or day_off_date is None:
                    continue
                key = int(op_id)
                day_off_dates_by_op.setdefault(key, []).append(
                    day_off_date.strftime('%Y-%m-%d') if hasattr(day_off_date, 'strftime') else str(day_off_date)
                )
            for op_id in operator_ids:
                day_offs_count[op_id] = len(day_off_dates_by_op.get(op_id, []))

        blocked_days_count = {op_id: 0 for op_id in operator_ids}
        if lot_dates_list:
            period_start = min(lot_dates_list)
            period_end = max(lot_dates_list)
            cursor.execute(
                """
                SELECT p.operator_id, COUNT(DISTINCT d.shift_date)::int
                FROM operator_schedule_status_periods p
                JOIN UNNEST(%s::date[]) AS d(shift_date)
                  ON d.shift_date >= p.start_date
                 AND d.shift_date <= COALESCE(p.end_date, %s::date)
                WHERE p.operator_id = ANY(%s)
                  AND p.start_date <= %s::date
                  AND COALESCE(p.end_date, %s::date) >= %s::date
                GROUP BY p.operator_id
                """,
                (lot_dates_list, period_end, operator_ids, period_end, period_end, period_start)
            )
            for op_id, count_value in (cursor.fetchall() or []):
                if op_id is None:
                    continue
                blocked_days_count[int(op_id)] = int(count_value or 0)

        # Fully-claimed lots are attributed to their single owner. Lots carrying
        # claim_segments (partial доборы — possibly several operators per shift) are
        # attributed per-segment instead, to avoid double counting.
        claimed_by_operator = {op_id: [] for op_id in operator_ids}
        segments_by_operator = {op_id: [] for op_id in operator_ids}
        for lot in (lots or []):
            if not isinstance(lot, dict):
                continue
            segs = lot.get('claim_segments')
            if isinstance(segs, list) and segs:
                lot_breaks = lot.get('breaks') if isinstance(lot.get('breaks'), list) else []
                for seg in segs:
                    try:
                        seg_op = int(seg.get('claimed_by')) if seg.get('claimed_by') is not None else None
                    except Exception:
                        seg_op = None
                    if seg_op is None or seg_op not in segments_by_operator:
                        continue
                    segments_by_operator[seg_op].append({
                        'start_time': seg.get('start_time'),
                        'end_time': seg.get('end_time'),
                        'breaks': lot_breaks,
                    })
                continue
            if str(lot.get('status') or '') != 'claimed':
                continue
            owner = lot.get('claimed_by')
            try:
                owner_id = int(owner) if owner is not None else None
            except Exception:
                owner_id = None
            if owner_id is None or owner_id not in claimed_by_operator:
                continue
            claimed_by_operator[owner_id].append(lot)

        workloads = []
        for row in participant_rows:
            if not row or row[0] is None:
                continue
            op_id = int(row[0])
            try:
                rate = float(row[4]) if row[4] is not None else 1.0
            except Exception:
                rate = 1.0
            if rate <= 0:
                rate = 1.0
            blocked = blocked_days_count.get(op_id, 0)
            workday_count = self._shift_auction_norm_workday_count(total_days, blocked_days=blocked)
            norm_minutes = int(round(workday_count * 8 * 60 * rate))
            claimed_lots = claimed_by_operator.get(op_id, [])
            op_segments = segments_by_operator.get(op_id, [])
            claimed_net = 0
            claimed_break = 0
            for lot in claimed_lots:
                minutes = self._shift_auction_lot_minutes(
                    lot.get('claim_start_time') or lot.get('post_claim_start_time') or lot.get('start_time'),
                    lot.get('claim_end_time') or lot.get('post_claim_end_time') or lot.get('end_time'),
                    lot.get('breaks') if isinstance(lot.get('breaks'), list) else []
                )
                claimed_net += int(minutes.get('net_minutes') or 0)
                claimed_break += int(minutes.get('break_minutes') or 0)
            for seg in op_segments:
                minutes = self._shift_auction_lot_minutes(seg['start_time'], seg['end_time'], seg['breaks'])
                claimed_net += int(minutes.get('net_minutes') or 0)
                claimed_break += int(minutes.get('break_minutes') or 0)
            workloads.append({
                "operator_id": op_id,
                "rate": rate,
                "norm_minutes": norm_minutes,
                "workday_count": int(workday_count),
                "claimed_net_minutes": int(claimed_net),
                "claimed_break_minutes": int(claimed_break),
                "remaining_minutes": max(0, norm_minutes - int(claimed_net)),
                "over_minutes": max(0, int(claimed_net) - norm_minutes),
                "blocked_days": int(blocked),
                "selected_day_offs": int(day_offs_count.get(op_id, 0)),
                "day_off_dates": list(day_off_dates_by_op.get(op_id, [])),
                "lots_claimed_count": len(claimed_lots) + len(op_segments),
                "is_complete": bool(norm_minutes > 0 and claimed_net >= norm_minutes - 1),
            })
        return workloads

    def _shift_auction_norm_workday_count(self, total_days, blocked_days=0):
        try:
            total = int(total_days or 0)
        except Exception:
            total = 0
        try:
            blocked = int(blocked_days or 0)
        except Exception:
            blocked = 0
        blocked = min(max(0, blocked), max(0, total))
        available_days = max(0, total - blocked)
        if available_days <= 0:
            return 0
        day_off_quota = self._shift_auction_day_off_quota(total)
        manual_day_off_quota = max(0, day_off_quota - blocked)
        return max(1, available_days - manual_day_off_quota)

    def _shift_auction_status_period_label(self, status_code, dismissal_reason=None, is_blacklist=False):
        code = str(status_code or '').strip().lower()
        if code in ('bs', 'unpaid_leave'):
            return 'Б/С'
        if code == 'sick_leave':
            return 'Больничный'
        if code == 'annual_leave':
            return 'Отпуск'
        if code == 'dismissal':
            reason = str(dismissal_reason or '').strip()
            if is_blacklist:
                return 'ЧС'
            return reason or 'Увольнение'
        return str(status_code or '').strip() or 'Период'

    def _get_shift_auction_lot_dates_tx(self, cursor):
        cursor.execute("""
            SELECT DISTINCT shift_date
            FROM shift_auction_test_lots
            WHERE shift_date IS NOT NULL
            ORDER BY shift_date
        """)
        return [row[0] for row in (cursor.fetchall() or []) if row and row[0]]

    def _serialize_shift_auction_period_row(self, row):
        if not row:
            return None
        date_from = row[1]
        date_to = row[2]
        shift_count = int(row[5] or 0) if len(row) > 5 else 0
        can_restart = bool(row[6]) if len(row) > 6 else bool(date_to and date_to >= date.today())
        return {
            "id": int(row[0]),
            "date_from": date_from.strftime('%Y-%m-%d') if date_from else None,
            "date_to": date_to.strftime('%Y-%m-%d') if date_to else None,
            "title": row[3] or "",
            "updated_at": row[4].isoformat() if row[4] else None,
            "shift_count": shift_count,
            "can_restart": can_restart,
        }

    def _get_shift_auction_period_row_tx(self, cursor, plan_id):
        try:
            plan_id = int(plan_id or 0)
        except Exception:
            plan_id = 0
        if plan_id <= 0:
            return None
        cursor.execute("""
            SELECT
                p.id,
                p.date_from,
                p.date_to,
                p.title,
                p.updated_at,
                COUNT(s.id) AS shift_count,
                p.date_to >= CURRENT_DATE AS can_restart
            FROM resource_saved_schedule_plans p
            LEFT JOIN resource_saved_schedule_shifts s
              ON s.plan_id = p.id
             AND COALESCE(s.meta->>'excludeFromAuction', 'false') <> 'true'
            WHERE p.id = %s
              AND p.archived_at IS NULL
            GROUP BY p.id, p.date_from, p.date_to, p.title, p.updated_at
        """, (plan_id,))
        return cursor.fetchone()

    def _get_shift_auction_available_periods_tx(self, cursor):
        cursor.execute("""
            SELECT
                p.id,
                p.date_from,
                p.date_to,
                p.title,
                p.updated_at,
                COUNT(s.id) AS shift_count,
                p.date_to >= CURRENT_DATE AS can_restart
            FROM resource_saved_schedule_plans p
            LEFT JOIN resource_saved_schedule_shifts s
              ON s.plan_id = p.id
             AND COALESCE(s.meta->>'excludeFromAuction', 'false') <> 'true'
            WHERE p.archived_at IS NULL
              AND p.date_to = p.date_from + 6
            GROUP BY p.id, p.date_from, p.date_to, p.title, p.updated_at
            HAVING COUNT(s.id) > 0
            ORDER BY p.date_from, p.updated_at DESC, p.id DESC
        """)
        return [self._serialize_shift_auction_period_row(row) for row in (cursor.fetchall() or [])]

    def _validate_shift_auction_period_tx(self, cursor, schedule_plan_id, require_restartable=False):
        row = self._get_shift_auction_period_row_tx(cursor, schedule_plan_id)
        if not row:
            raise ValueError("AUCTION_PERIOD_NOT_FOUND")
        date_from = row[1]
        date_to = row[2]
        if not date_from or not date_to or date_to != date_from + timedelta(days=6):
            raise ValueError("AUCTION_PERIOD_NOT_WEEK")
        if int(row[5] or 0) <= 0:
            raise ValueError("AUCTION_PERIOD_EMPTY")
        if require_restartable and not bool(row[6]):
            raise ValueError("AUCTION_PERIOD_PAST")
        return row

    def _get_shift_auction_operator_blocked_dates_tx(self, cursor, operator_id, lot_dates=None):
        try:
            operator_id = int(operator_id or 0)
        except Exception:
            operator_id = 0
        if operator_id <= 0:
            return []

        auction_dates = list(lot_dates) if lot_dates is not None else self._get_shift_auction_lot_dates_tx(cursor)
        auction_dates = [item for item in auction_dates if item]
        if not auction_dates:
            return []

        period_start = min(auction_dates)
        period_end = max(auction_dates)
        cursor.execute("""
            SELECT DISTINCT ON (d.shift_date)
                d.shift_date,
                p.id,
                p.status_code,
                p.start_date,
                p.end_date,
                p.dismissal_reason,
                p.is_blacklist,
                p.comment
            FROM UNNEST(%s::date[]) AS d(shift_date)
            JOIN operator_schedule_status_periods p
              ON p.operator_id = %s
             AND d.shift_date >= p.start_date
             AND d.shift_date <= COALESCE(p.end_date, %s::date)
            WHERE p.start_date <= %s::date
              AND COALESCE(p.end_date, %s::date) >= %s::date
            ORDER BY d.shift_date,
                     p.start_date DESC,
                     COALESCE(p.end_date, p.start_date) DESC,
                     p.id DESC
        """, (auction_dates, operator_id, period_end, period_end, period_end, period_start))

        results = []
        for shift_date, period_id, status_code, start_date, end_date, dismissal_reason, is_blacklist, comment in (cursor.fetchall() or []):
            if not shift_date:
                continue
            label = self._shift_auction_status_period_label(status_code, dismissal_reason, is_blacklist)
            results.append({
                "date": shift_date.strftime('%Y-%m-%d'),
                "period_id": period_id,
                "status_code": status_code,
                "label": label,
                "start_date": start_date.strftime('%Y-%m-%d') if start_date else None,
                "end_date": end_date.strftime('%Y-%m-%d') if end_date else None,
                "dismissal_reason": dismissal_reason or "",
                "is_blacklist": bool(is_blacklist),
                "comment": comment or ""
            })
        return results

    def _get_shift_auction_operator_blocked_date_map_tx(self, cursor, operator_id, lot_dates=None):
        return {
            item["date"]: item
            for item in self._get_shift_auction_operator_blocked_dates_tx(cursor, operator_id, lot_dates=lot_dates)
            if item.get("date")
        }

    def _get_shift_auction_operator_workload_tx(
        self, cursor, operator_id, operator_rate,
        lot_dates=None, blocked_dates=None, claimed_rows=None
    ):
        if lot_dates is None:
            lot_dates = self._get_shift_auction_lot_dates_tx(cursor)
        period_days = len(lot_dates)
        if blocked_dates is None:
            blocked_dates = self._get_shift_auction_operator_blocked_dates_tx(cursor, operator_id, lot_dates=lot_dates)
        workday_count = self._shift_auction_norm_workday_count(period_days, len(blocked_dates))
        norm_minutes = int(round(workday_count * 8 * 60 * max(0.0, float(operator_rate or 0))))

        if claimed_rows is None:
            cursor.execute("""
                SELECT COALESCE(post_claim_start_time, start_time), COALESCE(post_claim_end_time, end_time), breaks
                FROM shift_auction_test_lots
                WHERE claimed_by = %s
                  AND status = 'claimed'
            """, (operator_id,))
            claimed_rows = cursor.fetchall() or []
        claimed_net_minutes = 0
        claimed_break_minutes = 0
        for start_time_value, end_time_value, breaks in claimed_rows:
            minutes = self._shift_auction_lot_minutes(
                start_time_value,
                end_time_value,
                breaks if isinstance(breaks, list) else []
            )
            claimed_net_minutes += minutes["net_minutes"]
            claimed_break_minutes += minutes["break_minutes"]

        return {
            "period_days": period_days,
            "blocked_days": len(blocked_dates),
            "workday_count": workday_count,
            "norm_minutes": norm_minutes,
            "claimed_net_minutes": int(claimed_net_minutes),
            "claimed_break_minutes": int(claimed_break_minutes),
            "remaining_minutes": max(0, norm_minutes - int(claimed_net_minutes)),
        }

    def get_shift_auction_test_access(self, current_user_id=None):
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT
                    s.enabled,
                    s.launch_note,
                    s.starts_at,
                    s.ends_at,
                    s.paused_at,
                    s.finished_at,
                    COALESCE(
                        s.selected_schedule_plan_id,
                        (
                            SELECT source_schedule_plan_id
                            FROM shift_auction_test_lots
                            WHERE source_schedule_plan_id IS NOT NULL
                            ORDER BY id
                            LIMIT 1
                        )
                    ) AS selected_schedule_plan_id,
                    s.updated_by,
                    u.name AS updated_by_name,
                    s.updated_at,
                    s.published_to_work_schedules_at,
                    s.published_to_work_schedules_by,
                    publisher.name AS published_to_work_schedules_by_name,
                    s.topup_started_at,
                    s.topup_started_by,
                    topup_user.name AS topup_started_by_name
                FROM shift_auction_test_access s
                LEFT JOIN users u ON u.id = s.updated_by
                LEFT JOIN users publisher ON publisher.id = s.published_to_work_schedules_by
                LEFT JOIN users topup_user ON topup_user.id = s.topup_started_by
                WHERE s.id = 1
            """)
            settings_row = cursor.fetchone()
            if not settings_row:
                cursor.execute("""
                    INSERT INTO shift_auction_test_access (id)
                    VALUES (1)
                    ON CONFLICT (id) DO NOTHING
                """)
                settings_row = (False, '', None, None, None, None, None, None, None, None, None, None, None, None, None, None)

            cursor.execute("""
                SELECT
                    u.id,
                    u.name,
                    u.role,
                    u.status,
                    u.rate,
                    u.direction_id,
                    d.name AS direction_name,
                    u.supervisor_id,
                    s.name AS supervisor_name,
                    p.created_at
                FROM shift_auction_test_participants p
                JOIN users u ON u.id = p.operator_id
                LEFT JOIN directions d ON d.id = u.direction_id
                LEFT JOIN users s ON s.id = u.supervisor_id
                ORDER BY u.name
            """)
            participant_rows = cursor.fetchall() or []
            selected_period_row = self._get_shift_auction_period_row_tx(cursor, settings_row[6])

        selected_operator_ids = [int(row[0]) for row in participant_rows if row and row[0] is not None]
        current_id = None
        try:
            current_id = int(current_user_id) if current_user_id is not None else None
        except Exception:
            current_id = None

        return {
            "enabled": bool(settings_row[0]) if settings_row else False,
            "launch_note": settings_row[1] or "",
            "starts_at": settings_row[2].isoformat() if settings_row and settings_row[2] else None,
            "ends_at": settings_row[3].isoformat() if settings_row and settings_row[3] else None,
            "paused_at": settings_row[4].isoformat() if settings_row and settings_row[4] else None,
            "finished_at": settings_row[5].isoformat() if settings_row and settings_row[5] else None,
            "selected_schedule_plan_id": settings_row[6] if settings_row else None,
            "selected_period": self._serialize_shift_auction_period_row(selected_period_row),
            "status": self._get_shift_auction_test_status(
                bool(settings_row[0]) if settings_row else False,
                settings_row[2] if settings_row else None,
                settings_row[3] if settings_row else None,
                settings_row[4] if settings_row else None,
                settings_row[5] if settings_row else None
            ),
            "updated_by": settings_row[7] if settings_row else None,
            "updated_by_name": settings_row[8] or "",
            "updated_at": settings_row[9].isoformat() if settings_row and settings_row[9] else None,
            "published_to_work_schedules_at": settings_row[10].isoformat() if settings_row and settings_row[10] else None,
            "published_to_work_schedules_by": settings_row[11] if settings_row else None,
            "published_to_work_schedules_by_name": settings_row[12] or "",
            "topup_started_at": settings_row[13].isoformat() if settings_row and len(settings_row) > 13 and settings_row[13] else None,
            "topup_started_by": settings_row[14] if settings_row and len(settings_row) > 14 else None,
            "topup_started_by_name": (settings_row[15] or "") if settings_row and len(settings_row) > 15 else "",
            "selected_operator_ids": selected_operator_ids,
            "selected_operators": [
                {
                    "id": row[0],
                    "name": row[1],
                    "role": normalize_role_value(row[2]),
                    "status": row[3],
                    "rate": float(row[4]) if row[4] is not None else 1.0,
                    "direction_id": row[5],
                    "direction": row[6] or "",
                    "supervisor_id": row[7],
                    "supervisor_name": row[8] or "",
                    "selected_at": row[9].isoformat() if row[9] else None
                }
                for row in participant_rows
            ],
            "is_current_user_tester": current_id in set(selected_operator_ids) if current_id is not None else False
        }

    def is_shift_auction_test_participant(self, operator_id):
        try:
            operator_id = int(operator_id)
        except Exception:
            return False
        if operator_id <= 0:
            return False

        with self._get_cursor() as cursor:
            return operator_id in self._get_shift_auction_participant_ids_cached_tx(cursor)

    def update_shift_auction_test_access(
        self,
        enabled=False,
        operator_ids=None,
        launch_note='',
        updated_by=None,
        starts_at=None,
        ends_at=None,
        schedule_plan_id=None,
    ):
        if starts_at and ends_at and ends_at <= starts_at:
            raise ValueError("AUCTION_END_BEFORE_START")
        normalized_ids = []
        seen = set()
        for raw_id in (operator_ids or []):
            try:
                operator_id = int(raw_id)
            except Exception:
                continue
            if operator_id > 0 and operator_id not in seen:
                seen.add(operator_id)
                normalized_ids.append(operator_id)

        selected_period_row = None
        selected_plan_id = None
        if schedule_plan_id not in (None, ''):
            try:
                raw_plan_id = int(schedule_plan_id or 0)
            except Exception:
                raw_plan_id = 0
            if raw_plan_id <= 0:
                raise ValueError("AUCTION_PERIOD_NOT_FOUND")

        with self._get_cursor() as cursor:
            saved_shift_rows = []
            if schedule_plan_id not in (None, ''):
                selected_period_row = self._validate_shift_auction_period_tx(
                    cursor,
                    schedule_plan_id,
                    require_restartable=True
                )
                selected_plan_id = int(selected_period_row[0])
                cursor.execute("""
                    SELECT id, shift_date, start_time, end_time, rate_min, breaks
                    FROM resource_saved_schedule_shifts
                    WHERE plan_id = %s
                      AND COALESCE(meta->>'excludeFromAuction', 'false') <> 'true'
                    ORDER BY shift_date, start_minute, end_minute, id
                """, (selected_plan_id,))
                saved_shift_rows = cursor.fetchall() or []

            cursor.execute("""
                SELECT selected_schedule_plan_id
                FROM shift_auction_test_access
                WHERE id = 1
                FOR UPDATE
            """)
            current_settings_row = cursor.fetchone()
            current_selected_plan_id = current_settings_row[0] if current_settings_row else None

            valid_ids = []
            if normalized_ids:
                cursor.execute("""
                    SELECT id
                    FROM users
                    WHERE id = ANY(%s)
                      AND LOWER(COALESCE(role, '')) = 'operator'
                      AND COALESCE(status, '') NOT IN ('fired', 'dismissal')
                """, (normalized_ids,))
                valid_ids = [int(row[0]) for row in (cursor.fetchall() or [])]

            should_refresh_lots = False
            if selected_plan_id is not None:
                cursor.execute("""
                    SELECT
                        COUNT(*)::int AS total_lots,
                        COUNT(*) FILTER (WHERE source_schedule_plan_id = %s)::int AS selected_plan_lots
                    FROM shift_auction_test_lots
                """, (selected_plan_id,))
                lot_counts = cursor.fetchone() or (0, 0)
                total_lots = int(lot_counts[0] or 0)
                selected_plan_lots = int(lot_counts[1] or 0)
                should_refresh_lots = (
                    current_selected_plan_id != selected_plan_id
                    or total_lots == 0
                    or selected_plan_lots != total_lots
                )

            next_selected_plan_id = selected_plan_id if selected_plan_id is not None else current_selected_plan_id
            cursor.execute("""
                UPDATE shift_auction_test_access
                SET enabled = %s,
                    launch_note = %s,
                    starts_at = %s,
                    ends_at = %s,
                    selected_schedule_plan_id = %s,
                    paused_at = CASE WHEN %s THEN NULL ELSE paused_at END,
                    finished_at = CASE WHEN %s THEN NULL ELSE finished_at END,
                    published_to_work_schedules_at = CASE WHEN %s THEN NULL ELSE published_to_work_schedules_at END,
                    published_to_work_schedules_by = CASE WHEN %s THEN NULL ELSE published_to_work_schedules_by END,
                    updated_by = %s,
                    updated_at = CURRENT_TIMESTAMP
                WHERE id = 1
            """, (
                bool(enabled),
                str(launch_note or '').strip()[:1000],
                starts_at,
                ends_at,
                next_selected_plan_id,
                should_refresh_lots,
                should_refresh_lots,
                should_refresh_lots,
                should_refresh_lots,
                updated_by,
            ))

            if should_refresh_lots:
                cursor.execute("""
                    DELETE FROM shift_auction_test_events
                    WHERE event_type = 'lot_claimed'
                      AND NULLIF(payload->'lot'->>'source_schedule_plan_id', '')::INTEGER = %s
                """, (selected_plan_id,))
                cursor.execute("DELETE FROM shift_auction_test_day_offs")
                cursor.execute("DELETE FROM shift_auction_test_lots")
                if saved_shift_rows:
                    execute_values(
                        cursor,
                        """
                        INSERT INTO shift_auction_test_lots (
                            shift_date, start_time, end_time, rate_min,
                            breaks, source_schedule_plan_id, source_schedule_shift_id
                        )
                        VALUES %s
                        """,
                        [
                            (
                                row[1],
                                row[2],
                                row[3],
                                row[4],
                                Json(row[5] if isinstance(row[5], list) else []),
                                selected_plan_id,
                                row[0],
                            )
                            for row in saved_shift_rows
                        ],
                    )

            cursor.execute("DELETE FROM shift_auction_test_participants")
            if valid_ids:
                rows = [(operator_id, updated_by) for operator_id in valid_ids]
                execute_values(
                    cursor,
                    """
                    INSERT INTO shift_auction_test_participants (operator_id, added_by)
                    VALUES %s
                    ON CONFLICT (operator_id) DO NOTHING
                    """,
                    rows
                )
            self._insert_shift_auction_test_event(cursor, "settings_updated", {
                "enabled": bool(enabled),
                "starts_at": starts_at.isoformat() if starts_at else None,
                "ends_at": ends_at.isoformat() if ends_at else None,
                "selected_operator_ids": valid_ids,
                "selected_schedule_plan_id": next_selected_plan_id,
                "lots_refreshed": should_refresh_lots,
                "date_from": selected_period_row[1].strftime('%Y-%m-%d') if selected_period_row and selected_period_row[1] else None,
                "date_to": selected_period_row[2].strftime('%Y-%m-%d') if selected_period_row and selected_period_row[2] else None,
            })

        _invalidate_shift_auction_runtime_caches(include_participants=True)
        return self.get_shift_auction_test_access(current_user_id=updated_by)

    def control_shift_auction_test(self, action, updated_by=None):
        action_norm = str(action or '').strip().lower()
        if action_norm not in {'pause', 'resume', 'finish'}:
            raise ValueError("INVALID_AUCTION_CONTROL_ACTION")

        now = datetime.now()
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT enabled, starts_at, ends_at, paused_at, finished_at
                FROM shift_auction_test_access
                WHERE id = 1
                FOR UPDATE
            """)
            row = cursor.fetchone()
            if not row:
                raise ValueError("AUCTION_NOT_AVAILABLE")

            enabled, starts_at, ends_at, paused_at, finished_at = row
            current_status = self._get_shift_auction_test_status(
                enabled,
                starts_at,
                ends_at,
                paused_at,
                finished_at
            )

            if action_norm == 'pause':
                if current_status != 'open':
                    raise ValueError("AUCTION_CANNOT_PAUSE")
                cursor.execute("""
                    UPDATE shift_auction_test_access
                    SET paused_at = %s,
                        updated_by = %s,
                        updated_at = CURRENT_TIMESTAMP
                    WHERE id = 1
                """, (now, updated_by))
                event = self._insert_shift_auction_test_event(cursor, "auction_paused", {
                    "paused_at": now.isoformat(),
                    "updated_by": updated_by,
                })
            elif action_norm == 'resume':
                if current_status != 'paused' or paused_at is None:
                    raise ValueError("AUCTION_NOT_PAUSED")
                pause_delta = now - paused_at
                next_ends_at = ends_at + pause_delta if ends_at else None
                cursor.execute("""
                    UPDATE shift_auction_test_access
                    SET paused_at = NULL,
                        ends_at = %s,
                        updated_by = %s,
                        updated_at = CURRENT_TIMESTAMP
                    WHERE id = 1
                """, (next_ends_at, updated_by))
                event = self._insert_shift_auction_test_event(cursor, "auction_resumed", {
                    "resumed_at": now.isoformat(),
                    "paused_seconds": max(0, int(pause_delta.total_seconds())),
                    "ends_at": next_ends_at.isoformat() if next_ends_at else None,
                    "updated_by": updated_by,
                })
            else:
                if current_status in {'disabled', 'closed'}:
                    raise ValueError("AUCTION_ALREADY_CLOSED")
                cursor.execute("""
                    UPDATE shift_auction_test_access
                    SET paused_at = NULL,
                        finished_at = %s,
                        updated_by = %s,
                        updated_at = CURRENT_TIMESTAMP
                    WHERE id = 1
                """, (now, updated_by))
                event = self._insert_shift_auction_test_event(cursor, "auction_finished", {
                    "finished_at": now.isoformat(),
                    "updated_by": updated_by,
                })

        return {
            "event": event,
            "snapshot": self.get_shift_auction_test_snapshot(
                current_user_id=updated_by,
                include_admin_fields=True
            ),
        }

    def set_shift_auction_test_topup(self, enabled, updated_by=None):
        # Toggle the "top-up" claim mode: when enabled, operators may claim
        # additional shifts that do not time-overlap with their existing claims
        # even if the total exceeds their norm. Only the admin can flip it.
        enable = bool(enabled)
        now = datetime.now()
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT enabled, starts_at, ends_at, paused_at, finished_at, topup_started_at
                FROM shift_auction_test_access
                WHERE id = 1
                FOR UPDATE
            """)
            row = cursor.fetchone()
            if not row:
                raise ValueError("AUCTION_NOT_AVAILABLE")
            current_status = self._get_shift_auction_test_status(row[0], row[1], row[2], row[3], row[4])
            current_topup_started_at = row[5]

            if enable:
                if current_status != 'open':
                    raise ValueError("AUCTION_NOT_OPEN")
                if current_topup_started_at is not None:
                    raise ValueError("TOPUP_ALREADY_ACTIVE")
                cursor.execute("""
                    UPDATE shift_auction_test_access
                    SET topup_started_at = %s,
                        topup_started_by = %s,
                        updated_by = %s,
                        updated_at = CURRENT_TIMESTAMP
                    WHERE id = 1
                    RETURNING topup_started_at
                """, (now, updated_by, updated_by))
                started_at_row = cursor.fetchone()
                topup_started_at = started_at_row[0] if started_at_row else now
                event = self._insert_shift_auction_test_event(cursor, "auction_topup_started", {
                    "topup_started_at": topup_started_at.isoformat() if topup_started_at else None,
                    "updated_by": updated_by,
                })
            else:
                if current_topup_started_at is None:
                    raise ValueError("TOPUP_NOT_ACTIVE")
                cursor.execute("""
                    UPDATE shift_auction_test_access
                    SET topup_started_at = NULL,
                        topup_started_by = NULL,
                        updated_by = %s,
                        updated_at = CURRENT_TIMESTAMP
                    WHERE id = 1
                """, (updated_by,))
                event = self._insert_shift_auction_test_event(cursor, "auction_topup_stopped", {
                    "stopped_at": now.isoformat(),
                    "updated_by": updated_by,
                })

        return {
            "event": event,
            "snapshot": self.get_shift_auction_test_snapshot(
                current_user_id=updated_by,
                include_admin_fields=True
            ),
        }

    def _merge_shift_auction_claimed_shifts_for_publish(self, shifts):
        ranges = []
        for shift in shifts or []:
            if not isinstance(shift, dict):
                continue
            start_time_value = shift.get("start_time")
            end_time_value = shift.get("end_time")
            if start_time_value is None or end_time_value is None:
                continue
            start_min, end_min = self._schedule_interval_minutes(start_time_value, end_time_value)
            if end_min <= start_min:
                continue
            ranges.append({"start": start_min, "end": end_min})

        if not ranges:
            return []

        ranges.sort(key=lambda item: (item["start"], item["end"]))
        merged = []
        for item in ranges:
            if not merged or item["start"] > merged[-1]["end"]:
                merged.append(dict(item))
                continue
            merged[-1]["end"] = max(merged[-1]["end"], item["end"])

        result = []
        for item in merged:
            result.append({
                "start_time": self._normalize_schedule_time(_minutes_to_time(item["start"]), "start_time"),
                "end_time": self._normalize_schedule_time(_minutes_to_time(item["end"]), "end_time"),
            })
        return result

    def _resolve_post_auction_merged_shift_range(self, existing_shifts, new_start_min, new_end_min):
        merged_start_min = int(new_start_min)
        merged_end_min = int(new_end_min)
        merge_ids = []
        remaining = []

        for sh_id, ex_start, ex_end in existing_shifts or []:
            ex_start_min, ex_end_min = self._schedule_interval_minutes(ex_start, ex_end)
            remaining.append({
                "id": int(sh_id),
                "start": ex_start_min,
                "end": ex_end_min,
            })

        changed = True
        while changed:
            changed = False
            next_remaining = []
            for item in remaining:
                if merged_start_min < item["end"] and item["start"] < merged_end_min:
                    raise ValueError("SHIFT_OVERLAPS_EXISTING")
                if item["end"] == merged_start_min or merged_end_min == item["start"]:
                    merge_ids.append(item["id"])
                    merged_start_min = min(merged_start_min, item["start"])
                    merged_end_min = max(merged_end_min, item["end"])
                    changed = True
                else:
                    next_remaining.append(item)
            remaining = next_remaining

        return merged_start_min, merged_end_min, merge_ids

    def _split_post_auction_shift_slice_tx(self, cursor, operator_id, shift_date,
                                           slice_start_time, slice_end_time):
        """
        Корректное «разъединение» при отмене добора — операция, обратная слиянию в
        _resolve_post_auction_merged_shift_range. Находит смену графика, которая
        содержит отменяемый отрезок (при взятии добор мог слиться с соседней сменой
        в один блок), удаляет её и заново создаёт оставшиеся части (0, 1 или 2).

        Для каждой оставшейся части перерывы пересчитываются по ТЕКУЩИМ правилам
        направления (_save_shift_tx с breaks=None) — чтобы на укоротившейся смене не
        остался перерыв от объединённого блока и у операторов не было проблем позже.

        Работает в минутах с учётом смен через полночь: отрезок выравнивается в
        систему координат смены сдвигом на сутки. Возвращает True, если содержащая
        смена найдена и обработана, иначе False (вызывающий код делает запасное
        точное удаление).
        """
        if not (shift_date and slice_start_time and slice_end_time):
            return False

        def _slice_minute(value):
            if isinstance(value, dt_time):
                return value.hour * 60 + value.minute
            return _time_to_minutes(str(value))

        DAY = 24 * 60
        raw_start = _slice_minute(slice_start_time)
        raw_end = _slice_minute(slice_end_time)

        cursor.execute("""
            SELECT id, start_time, end_time
            FROM work_shifts
            WHERE operator_id = %s AND shift_date = %s
            ORDER BY start_time
        """, (operator_id, shift_date))
        shifts = cursor.fetchall() or []

        for sh_id, ws_start, ws_end in shifts:
            ws_start_min, ws_end_min = self._schedule_interval_minutes(ws_start, ws_end)
            s_start = raw_start
            while s_start < ws_start_min:
                s_start += DAY
            s_end = raw_end
            while s_end <= s_start:
                s_end += DAY
            # Отрезок добора должен целиком лежать внутри этой смены.
            if s_start < ws_start_min or s_end > ws_end_min:
                continue

            cursor.execute("DELETE FROM work_shifts WHERE id = %s", (sh_id,))
            remaining = []
            if s_start > ws_start_min:
                remaining.append((ws_start_min, s_start))
            if s_end < ws_end_min:
                remaining.append((s_end, ws_end_min))
            for part_start, part_end in remaining:
                start_obj = self._normalize_schedule_time(_minutes_to_time(part_start % DAY), 'start')
                end_obj = self._normalize_schedule_time(_minutes_to_time(part_end), 'end')
                self._save_shift_tx(
                    cursor=cursor,
                    operator_id=operator_id,
                    shift_date=shift_date,
                    start_time=start_obj,
                    end_time=end_obj,
                    breaks=None,
                    shift_type=None,
                )
            return True
        return False

    def _normalize_post_auction_claim_range(self, source_start_time, source_end_time, claim_start_time=None, claim_end_time=None):
        source_start_min, source_end_min = self._schedule_interval_minutes(source_start_time, source_end_time)
        start_obj = self._normalize_schedule_time(
            claim_start_time if claim_start_time not in (None, '') else source_start_time,
            'claim_start_time'
        )
        end_obj = self._normalize_schedule_time(
            claim_end_time if claim_end_time not in (None, '') else source_end_time,
            'claim_end_time'
        )

        claim_start_min = _time_to_minutes(start_obj.strftime('%H:%M'))
        claim_end_min = _time_to_minutes(end_obj.strftime('%H:%M'))
        if source_end_min > 24 * 60 and claim_start_min < source_start_min:
            claim_start_min += 24 * 60
        if claim_end_min <= claim_start_min:
            claim_end_min += 24 * 60

        if claim_end_min <= claim_start_min:
            raise ValueError("INVALID_PARTIAL_SHIFT_RANGE")
        if claim_start_min < source_start_min or claim_end_min > source_end_min:
            raise ValueError("PARTIAL_SHIFT_OUT_OF_RANGE")

        return {
            "start_time": start_obj,
            "end_time": end_obj,
            "start_minute": int(claim_start_min),
            "end_minute": int(claim_end_min),
            "is_partial": bool(claim_start_min != source_start_min or claim_end_min != source_end_min),
        }

    # Minimal length (minutes) of a leftover segment that is worth re-offering to
    # other operators. Matches the frontend's >=15-min availability filter.
    POST_AUCTION_MIN_REMAINDER_MINUTES = 15

    @staticmethod
    def _break_overlaps_minute_range(brk, range_start_min, range_end_min):
        """True if a break {start,end} (in minutes, night-wrap aware) overlaps a range."""
        if not isinstance(brk, dict):
            return False
        try:
            b_start = int(brk.get('start'))
            b_end = int(brk.get('end'))
        except Exception:
            return False
        if b_end <= b_start:
            b_end += 24 * 60
        if range_end_min > 24 * 60 and b_start < range_start_min:
            b_start += 24 * 60
            b_end += 24 * 60
        return b_start < range_end_min and range_start_min < b_end

    def _create_post_auction_remainder_lots(self, cursor, parent_lot_id, shift_date,
                                            full_start_time, full_end_time,
                                            claim_start_min, claim_end_min,
                                            rate_min, breaks, source_plan_id, source_shift_id=None):
        """
        После частичного добора вернуть незабранный остаток смены в аукцион:
        для каждого свободного промежутка слева/справа от взятого куска создаём
        новый доступный лот (status='available'), доступный другим операторам.

        Остаточные лоты несут тот же source_schedule_shift_id, что и исходная смена —
        так в мониторинге они группируются с ней (видно «кто какую часть взял»), а
        повторный claim не конфликтует благодаря PK (plan, shift, claimed_by). В
        снапшоте source_*_minute для них обнуляются (remainder_of_lot_id IS NOT NULL),
        поэтому фронт считает диапазон по их собственным start/end (по промежутку).
        Связь с родителем хранится в remainder_of_lot_id для свода в admin_unclaim.
        """
        full_start_min, full_end_min = self._schedule_interval_minutes(full_start_time, full_end_time)
        candidate_gaps = []
        if claim_start_min > full_start_min:
            candidate_gaps.append((full_start_min, claim_start_min))
        if full_end_min > claim_end_min:
            candidate_gaps.append((claim_end_min, full_end_min))
        # Re-offer only gaps that are long enough AND stay within a single calendar day.
        # A gap that extends past midnight (gap_end_min > 1440) cannot be unambiguously
        # stored on the original shift_date, so that sliver is left unallocated.
        gaps = [
            (gap_start, gap_end) for (gap_start, gap_end) in candidate_gaps
            if gap_end - gap_start >= self.POST_AUCTION_MIN_REMAINDER_MINUTES
            and gap_end <= 24 * 60
        ]
        if not gaps:
            return []

        break_list = breaks if isinstance(breaks, list) else []
        created_ids = []
        for gap_start_min, gap_end_min in gaps:
            gap_start_obj = self._normalize_schedule_time(
                _minutes_to_time(gap_start_min % (24 * 60)), 'start'
            )
            gap_end_obj = self._normalize_schedule_time(
                _minutes_to_time(gap_end_min % (24 * 60)), 'end'
            )
            gap_breaks = [
                brk for brk in break_list
                if self._break_overlaps_minute_range(brk, gap_start_min, gap_end_min)
            ]
            cursor.execute("""
                INSERT INTO shift_auction_test_lots (
                    shift_date, start_time, end_time, rate_min, breaks,
                    source_schedule_plan_id, source_schedule_shift_id,
                    status, remainder_of_lot_id
                )
                VALUES (%s, %s, %s, %s, %s, %s, %s, 'available', %s)
                RETURNING id
            """, (shift_date, gap_start_obj, gap_end_obj, rate_min, Json(gap_breaks),
                  source_plan_id, source_shift_id, parent_lot_id))
            new_row = cursor.fetchone()
            if new_row:
                created_ids.append(int(new_row[0]))
        return created_ids

    def _consolidate_post_auction_lots(self, cursor):
        """
        Привести лоты к единой модели «один лот на смену»: удалить отдельные остаточные
        лоты (наследие прежней логики) и СНОВА ОТКРЫТЬ частично-взятые лоты — их взятые
        части лежат в shift_auction_historical_claims, а сам лот показывает свободную
        часть. Полностью взятые остаются 'claimed'. Идемпотентно; запускается на старте.
        """
        try:
            cursor.execute("DELETE FROM shift_auction_test_lots WHERE remainder_of_lot_id IS NOT NULL")
        except Exception:
            pass
        try:
            cursor.execute("""
                SELECT l.id, l.start_time, l.end_time, l.source_schedule_plan_id, l.source_schedule_shift_id
                FROM shift_auction_test_lots l
                WHERE COALESCE(l.post_auction_claimed, FALSE) = TRUE
                  AND l.source_schedule_shift_id IS NOT NULL
            """)
            rows = cursor.fetchall() or []
        except Exception:
            return
        for lot_id, start_time, end_time, plan_id, shift_id in rows:
            try:
                cursor.execute("""
                    SELECT claimed_start_time, claimed_end_time
                    FROM shift_auction_historical_claims
                    WHERE plan_id = %s AND source_schedule_shift_id = %s
                      AND claimed_start_time IS NOT NULL AND claimed_end_time IS NOT NULL
                """, (plan_id, shift_id))
                claims = cursor.fetchall() or []
                full_start_min, full_end_min = self._schedule_interval_minutes(start_time, end_time)
                claimed_ranges = []
                for cs, ce in claims:
                    rng = self._normalize_post_auction_claim_range(
                        start_time, end_time, cs.strftime('%H:%M'), ce.strftime('%H:%M')
                    )
                    claimed_ranges.append((rng["start_minute"], rng["end_minute"]))
                free_gaps = [g for g in self._subtract_ranges(full_start_min, full_end_min, claimed_ranges) if g[1] - g[0] > 0]
                # Only re-open if we actually know the taken parts AND something is free.
                if claimed_ranges and free_gaps:
                    cursor.execute("""
                        UPDATE shift_auction_test_lots
                        SET status = 'available', claimed_by = NULL, claimed_at = NULL,
                            post_auction_claimed = FALSE, post_claim_start_time = NULL,
                            post_claim_end_time = NULL, updated_at = CURRENT_TIMESTAMP
                        WHERE id = %s
                    """, (lot_id,))
            except Exception:
                continue

    @staticmethod
    def _subtract_ranges(start_min, end_min, busy_ranges):
        """Free sub-ranges of [start_min, end_min] after removing the busy ranges."""
        free = [(int(start_min), int(end_min))]
        for raw_start, raw_end in sorted(busy_ranges):
            b_start = max(int(start_min), int(raw_start))
            b_end = min(int(end_min), int(raw_end))
            if b_end <= b_start:
                continue
            next_free = []
            for f_start, f_end in free:
                if b_end <= f_start or b_start >= f_end:
                    next_free.append((f_start, f_end))
                    continue
                if b_start > f_start:
                    next_free.append((f_start, b_start))
                if b_end < f_end:
                    next_free.append((b_end, f_end))
            free = next_free
        return free

    def _build_preview_shift_lots(self, base_lot, claims, operator_info):
        """
        Expand one previewed saved-shift lot into per-operator claimed slices plus
        available remainder lots for the still-free gaps, so other operators can
        добор the leftover part of a partially-claimed shift in a published period.
        """
        full_start = base_lot.get("source_start_minute")
        full_end = base_lot.get("source_end_minute")
        if not (isinstance(full_start, int) and isinstance(full_end, int) and full_end > full_start):
            # No reliable minute range — fall back to the legacy single claimed lot.
            first = claims[0] if claims else None
            if first:
                info = operator_info.get(int(first["claimed_by"])) if first.get("claimed_by") else None
                cs = first.get("claim_start")
                ce = first.get("claim_end")
                base_lot.update({
                    "status": "claimed",
                    "claimed_by": first.get("claimed_by"),
                    "claimed_at": first["claimed_at"].isoformat() if first.get("claimed_at") else base_lot.get("claimed_at"),
                    "post_auction_claimed": True,
                    "claim_start_time": cs.strftime('%H:%M') if cs else base_lot.get("claim_start_time"),
                    "claim_end_time": ce.strftime('%H:%M') if ce else base_lot.get("claim_end_time"),
                    "claimed_by_name": (info or {}).get("name") or "",
                    "claimed_by_direction_id": (info or {}).get("direction_id"),
                    "claimed_by_direction": (info or {}).get("direction") or "",
                })
            return [base_lot]

        result = []
        claimed_ranges = []
        full_block = False
        for idx, claim in enumerate(claims):
            cs = claim.get("claim_start")
            ce = claim.get("claim_end")
            claimed_by = claim.get("claimed_by")
            info = operator_info.get(int(claimed_by)) if claimed_by else None
            slice_lot = dict(base_lot)
            slice_lot.update({
                "id": f"{base_lot['id']}-c{claimed_by if claimed_by is not None else idx}",
                "status": "claimed",
                "claimed_by": claimed_by,
                "claimed_at": claim["claimed_at"].isoformat() if claim.get("claimed_at") else base_lot.get("claimed_at"),
                "post_auction_claimed": True,
                "claim_start_time": cs.strftime('%H:%M') if cs else None,
                "claim_end_time": ce.strftime('%H:%M') if ce else None,
                "claimed_by_name": (info or {}).get("name") or "",
                "claimed_by_direction_id": (info or {}).get("direction_id"),
                "claimed_by_direction": (info or {}).get("direction") or "",
            })
            result.append(slice_lot)
            if cs is None or ce is None:
                full_block = True
                continue
            cs_min = _time_to_minutes(cs.strftime('%H:%M'))
            ce_min = _time_to_minutes(ce.strftime('%H:%M'))
            if full_end > 24 * 60 and cs_min < full_start:
                cs_min += 24 * 60
            if ce_min <= cs_min:
                ce_min += 24 * 60
            claimed_ranges.append((cs_min, ce_min))

        if not full_block:
            for gi, (gap_start, gap_end) in enumerate(self._subtract_ranges(full_start, full_end, claimed_ranges)):
                if gap_end - gap_start < self.POST_AUCTION_MIN_REMAINDER_MINUTES or gap_end > 24 * 60:
                    continue
                gap_lot = dict(base_lot)
                gap_lot.update({
                    "id": f"{base_lot['id']}-r{gi}",
                    "status": "available",
                    "claimed_by": None,
                    "claimed_by_name": "",
                    "claimed_at": None,
                    "post_auction_claimed": False,
                    "claim_start_time": None,
                    "claim_end_time": None,
                    "claimed_by_direction_id": None,
                    "claimed_by_direction": "",
                    "start_time": _minutes_to_time(gap_start % (24 * 60)),
                    "end_time": _minutes_to_time(gap_end % (24 * 60)),
                    "source_start_minute": gap_start,
                    "source_end_minute": gap_end,
                })
                result.append(gap_lot)
        return result

    def publish_shift_auction_test_to_work_schedules(self, updated_by=None):
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT enabled, starts_at, ends_at, paused_at, finished_at, selected_schedule_plan_id
                FROM shift_auction_test_access
                WHERE id = 1
                FOR UPDATE
            """)
            settings_row = cursor.fetchone()
            if not settings_row:
                raise ValueError("AUCTION_NOT_AVAILABLE")
            if self._get_shift_auction_test_status(*settings_row[:5]) != "closed":
                raise ValueError("AUCTION_NOT_CLOSED")
            selected_schedule_plan_id = int(settings_row[5]) if settings_row[5] is not None else None

            lot_dates = self._get_shift_auction_lot_dates_tx(cursor)
            if not lot_dates:
                raise ValueError("AUCTION_NO_LOTS")

            cursor.execute("""
                SELECT operator_id
                FROM shift_auction_test_participants
                ORDER BY operator_id
            """)
            operator_ids = [int(row[0]) for row in (cursor.fetchall() or []) if row and row[0] is not None]
            if not operator_ids:
                raise ValueError("AUCTION_NO_PARTICIPANTS")

            cursor.execute("""
                SELECT claimed_by, shift_date, start_time, end_time
                FROM shift_auction_test_lots
                WHERE status = 'claimed'
                  AND claimed_by = ANY(%s)
                ORDER BY claimed_by, shift_date, claimed_at, id
            """, (operator_ids,))
            claimed_by_operator_date = {}
            for claimed_by, shift_date_value, start_time_value, end_time_value in (cursor.fetchall() or []):
                if claimed_by is None or shift_date_value is None:
                    continue
                claimed_by_operator_date.setdefault((int(claimed_by), shift_date_value), []).append({
                    "start_time": start_time_value,
                    "end_time": end_time_value,
                })

            cursor.execute("""
                SELECT operator_id, day_off_date
                FROM shift_auction_test_day_offs
                WHERE operator_id = ANY(%s)
                ORDER BY operator_id, day_off_date
            """, (operator_ids,))
            day_off_dates = {
                (int(operator_id), day_off_date)
                for operator_id, day_off_date in (cursor.fetchall() or [])
                if operator_id is not None and day_off_date is not None
            }

            summary = {
                "operators_total": len(operator_ids),
                "days_total": len(lot_dates),
                "cleared_days": 0,
                "shifts_saved": 0,
                "days_off_saved": 0,
                "blocked_days": 0,
            }

            first_date = min(lot_dates)
            last_date = max(lot_dates)
            cursor.execute(
                """
                SELECT u.id, d.name
                FROM users u
                LEFT JOIN directions d ON d.id = u.direction_id
                WHERE u.id = ANY(%s)
                """,
                (operator_ids,)
            )
            operator_direction_map = {
                int(op_id): direction_name
                for op_id, direction_name in (cursor.fetchall() or [])
                if op_id is not None
            }
            direction_rules_cache = {}

            def _direction_rules_for_sort(direction_name):
                direction_key = self._normalize_direction_key(direction_name)
                if direction_key not in direction_rules_cache:
                    direction_rules_cache[direction_key] = self._get_work_schedule_break_rules_for_direction_tx(
                        cursor,
                        direction_name
                    )
                return direction_rules_cache[direction_key]

            def _publish_shift_sort_key(item):
                start_min, end_min = self._schedule_interval_minutes(item["start_time"], item["end_time"])
                duration = max(0, end_min - start_min)
                direction_name = item.get("direction")
                break_durations = self._pick_break_durations_for_shift(
                    duration,
                    direction_name=direction_name,
                    direction_rules=_direction_rules_for_sort(direction_name)
                )
                edge_margin, min_gap = self._break_layout_spacing(start_min, end_min, break_durations)
                required_minutes = (
                    sum(max(0, int(x)) for x in (break_durations or []))
                    + (2 * int(edge_margin))
                    + (int(min_gap) * max(0, len(break_durations or []) - 1))
                )
                flexibility = duration - required_minutes
                return (
                    item["shift_date"],
                    self._normalize_direction_key(direction_name),
                    flexibility,
                    start_min,
                    end_min,
                    int(item["operator_id"])
                )

            shifts_to_save = []
            for operator_id in operator_ids:
                blocked_date_map = self._get_shift_auction_operator_blocked_date_map_tx(
                    cursor,
                    operator_id,
                    lot_dates=lot_dates
                )
                for lot_date in lot_dates:
                    self._clear_day_schedule_tx(cursor, operator_id, lot_date)
                    summary["cleared_days"] += 1
                    lot_date_key = lot_date.strftime('%Y-%m-%d')
                    if lot_date_key in blocked_date_map:
                        summary["blocked_days"] += 1
                        continue

                    if (operator_id, lot_date) in day_off_dates:
                        self._set_day_off_tx(cursor, operator_id, lot_date)
                        summary["days_off_saved"] += 1
                        continue

                    claimed_shifts = claimed_by_operator_date.get((operator_id, lot_date), [])
                    if not claimed_shifts:
                        continue
                    for claimed in self._merge_shift_auction_claimed_shifts_for_publish(claimed_shifts):
                        shifts_to_save.append({
                            "operator_id": operator_id,
                            "shift_date": lot_date,
                            "start_time": claimed["start_time"],
                            "end_time": claimed["end_time"],
                            "direction": operator_direction_map.get(operator_id)
                        })

            for item in sorted(shifts_to_save, key=_publish_shift_sort_key):
                self._save_shift_tx(
                    cursor=cursor,
                    operator_id=item["operator_id"],
                    shift_date=item["shift_date"],
                    start_time=item["start_time"],
                    end_time=item["end_time"],
                    breaks=None,
                )
                summary["shifts_saved"] += 1

            for operator_id in operator_ids:
                self._recalculate_auto_daily_hours_tx(
                    cursor=cursor,
                    operator_ids=[operator_id],
                    start_date=first_date,
                    end_date=last_date
                )

            cursor.execute("""
                UPDATE shift_auction_test_access
                SET published_to_work_schedules_at = CURRENT_TIMESTAMP,
                    published_to_work_schedules_by = %s,
                    updated_by = %s,
                    updated_at = CURRENT_TIMESTAMP
                WHERE id = 1
                RETURNING published_to_work_schedules_at
            """, (updated_by, updated_by))
            published_at_row = cursor.fetchone()
            published_at = published_at_row[0] if published_at_row else None

            if selected_schedule_plan_id and first_date and last_date:
                cursor.execute("""
                    INSERT INTO shift_auction_published_periods
                        (plan_id, date_from, date_to, published_at, published_by, participant_ids, updated_at)
                    VALUES (%s, %s, %s, COALESCE(%s, CURRENT_TIMESTAMP), %s, %s, CURRENT_TIMESTAMP)
                    ON CONFLICT (plan_id) DO UPDATE
                      SET date_from = EXCLUDED.date_from,
                          date_to = EXCLUDED.date_to,
                          published_at = EXCLUDED.published_at,
                          published_by = EXCLUDED.published_by,
                          participant_ids = EXCLUDED.participant_ids,
                          updated_at = CURRENT_TIMESTAMP
                """, (
                    selected_schedule_plan_id,
                    first_date,
                    last_date,
                    published_at,
                    updated_by,
                    operator_ids,
                ))
                cursor.execute("""
                    INSERT INTO shift_auction_historical_claims
                        (plan_id, source_schedule_shift_id, claimed_by, claimed_at)
                    SELECT source_schedule_plan_id, source_schedule_shift_id, claimed_by,
                           COALESCE(claimed_at, CURRENT_TIMESTAMP)
                    FROM shift_auction_test_lots
                    WHERE status = 'claimed'
                      AND source_schedule_plan_id = %s
                      AND source_schedule_shift_id IS NOT NULL
                      AND claimed_by IS NOT NULL
                    ON CONFLICT (plan_id, source_schedule_shift_id, claimed_by) DO NOTHING
                """, (selected_schedule_plan_id,))

            event = self._insert_shift_auction_test_event(cursor, "auction_published", {
                **summary,
                "published_at": published_at.isoformat() if published_at else None,
                "published_by": updated_by,
                "selected_schedule_plan_id": selected_schedule_plan_id,
                "date_from": first_date.strftime('%Y-%m-%d') if first_date else None,
                "date_to": last_date.strftime('%Y-%m-%d') if last_date else None,
            })

        return {
            "summary": summary,
            "event": event,
            "snapshot": self.get_shift_auction_test_snapshot(
                current_user_id=updated_by,
                include_admin_fields=True
            ),
        }

    def get_shift_auction_entries_for_simulation(self):
        """
        Возвращает claimed лоты текущего аукциона в формате entries для Python-симуляции перерывов.
        Включает direction оператора из users → directions.
        Результат: [{operator_id, date (str 'YYYY-MM-DD'), direction (str|None),
                     shifts: [{'start': 'HH:MM', 'end': 'HH:MM'}]}]
        Отсортировано по operator_id, shift_date — детерминированный порядок,
        совпадающий с порядком обработки в publish_shift_auction_test_to_work_schedules.
        """
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT operator_id
                FROM shift_auction_test_participants
                ORDER BY operator_id
            """)
            operator_ids = [int(row[0]) for row in (cursor.fetchall() or []) if row and row[0] is not None]
            if not operator_ids:
                return []

            cursor.execute("""
                SELECT l.claimed_by,
                       l.shift_date,
                       l.start_time,
                       l.end_time,
                       d.name AS direction_name
                FROM shift_auction_test_lots l
                JOIN shift_auction_test_participants p ON p.operator_id = l.claimed_by
                LEFT JOIN users u ON u.id = l.claimed_by
                LEFT JOIN directions d ON d.id = u.direction_id
                WHERE l.status = 'claimed'
                  AND l.claimed_by = ANY(%s)
                ORDER BY l.claimed_by, l.shift_date, l.claimed_at, l.id
            """, (operator_ids,))

            entry_map = {}
            for claimed_by, shift_date_value, start_time_value, end_time_value, direction_name in (cursor.fetchall() or []):
                if claimed_by is None or shift_date_value is None:
                    continue
                op_id = int(claimed_by)
                date_str = shift_date_value.strftime('%Y-%m-%d')
                key = (op_id, date_str)
                if key not in entry_map:
                    entry_map[key] = {
                        'operator_id': op_id,
                        'date': date_str,
                        'direction': direction_name,
                        'shifts': []
                    }
                entry_map[key]['shifts'].append({
                    'start': start_time_value.strftime('%H:%M'),
                    'end': end_time_value.strftime('%H:%M')
                })

            return [entry_map[k] for k in sorted(entry_map.keys())]

    def get_shift_auction_test_export_data(self):
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT enabled, starts_at, ends_at, paused_at, finished_at, selected_schedule_plan_id
                FROM shift_auction_test_access
                WHERE id = 1
            """)
            settings_row = cursor.fetchone()
            if not settings_row:
                raise ValueError("AUCTION_NOT_AVAILABLE")

            selected_period_row = self._get_shift_auction_period_row_tx(cursor, settings_row[5])
            selected_period = self._serialize_shift_auction_period_row(selected_period_row)

            cursor.execute("""
                SELECT
                    l.id,
                    l.shift_date,
                    l.start_time,
                    l.end_time,
                    l.rate_min,
                    l.status,
                    l.claimed_by,
                    u.name AS claimed_by_name,
                    l.claimed_at,
                    l.breaks,
                    l.source_schedule_plan_id,
                    l.source_schedule_shift_id,
                    COALESCE(l.post_auction_claimed, FALSE) AS post_auction_claimed,
                    u.direction_id AS claimed_by_direction_id,
                    claimed_dir.name AS claimed_by_direction,
                    source_shift.start_minute AS source_start_minute,
                    source_shift.end_minute AS source_end_minute,
                    l.post_claim_start_time,
                    l.post_claim_end_time
                FROM shift_auction_test_lots l
                LEFT JOIN users u ON u.id = l.claimed_by
                LEFT JOIN directions claimed_dir ON claimed_dir.id = u.direction_id
                LEFT JOIN resource_saved_schedule_shifts source_shift ON source_shift.id = l.source_schedule_shift_id
                ORDER BY l.shift_date, l.start_time, l.id
            """)
            lot_rows = cursor.fetchall() or []
            if not lot_rows:
                raise ValueError("AUCTION_NO_LOTS")

            lots = [self._serialize_shift_auction_lot_row(row) for row in lot_rows]
            lot_dates = sorted({row[1] for row in lot_rows if row and row[1]})

            cursor.execute("""
                WITH report_operators AS (
                    SELECT operator_id AS id
                    FROM shift_auction_test_participants
                    UNION
                    SELECT claimed_by AS id
                    FROM shift_auction_test_lots
                    WHERE claimed_by IS NOT NULL
                )
                SELECT
                    u.id,
                    u.name,
                    u.rate,
                    u.status,
                    d.name AS direction_name,
                    u.supervisor_id,
                    s.name AS supervisor_name
                FROM report_operators ro
                JOIN users u ON u.id = ro.id
                LEFT JOIN directions d ON d.id = u.direction_id
                LEFT JOIN users s ON s.id = u.supervisor_id
                ORDER BY LOWER(COALESCE(u.name, '')), u.id
            """)
            operator_rows = cursor.fetchall() or []
            operators = [
                {
                    "id": int(row[0]),
                    "name": row[1] or f"Operator #{row[0]}",
                    "rate": float(row[2]) if row[2] is not None else None,
                    "status": row[3] or "",
                    "direction": row[4] or "",
                    "supervisor_id": row[5],
                    "supervisor_name": row[6] or "",
                }
                for row in operator_rows
                if row and row[0] is not None
            ]

            cursor.execute("""
                SELECT operator_id, day_off_date
                FROM shift_auction_test_day_offs
                ORDER BY operator_id, day_off_date
            """)
            day_offs = [
                {
                    "operator_id": int(row[0]),
                    "date": row[1].strftime('%Y-%m-%d') if row[1] else None,
                }
                for row in (cursor.fetchall() or [])
                if row and row[0] is not None and row[1] is not None
            ]

            return {
                "settings": {
                    "enabled": bool(settings_row[0]),
                    "starts_at": settings_row[1].isoformat() if settings_row[1] else None,
                    "ends_at": settings_row[2].isoformat() if settings_row[2] else None,
                    "paused_at": settings_row[3].isoformat() if settings_row[3] else None,
                    "finished_at": settings_row[4].isoformat() if settings_row[4] else None,
                    "selected_schedule_plan_id": settings_row[5],
                    "status": self._get_shift_auction_test_status(
                        settings_row[0],
                        settings_row[1],
                        settings_row[2],
                        settings_row[3],
                        settings_row[4]
                    ),
                },
                "selected_period": selected_period,
                "lot_dates": [item.strftime('%Y-%m-%d') for item in lot_dates],
                "operators": operators,
                "lots": lots,
                "day_offs": day_offs,
            }

    @staticmethod
    def _parse_shift_auction_export_date(value):
        if isinstance(value, datetime):
            return value.date()
        if isinstance(value, date):
            return value
        text = str(value or '').strip()
        if not text:
            return None
        try:
            return datetime.strptime(text[:10], '%Y-%m-%d').date()
        except Exception:
            return None

    @staticmethod
    def _format_shift_auction_excel_time(value):
        if hasattr(value, 'strftime'):
            text = value.strftime('%H:%M')
        else:
            text = str(value or '').strip()
        try:
            hh, mm = text.split(':', 1)
            h = int(hh)
            m = int(str(mm)[:2])
        except Exception:
            return text
        if m == 0:
            return f"{h:02d}"
        return f"{h:02d}/{m:02d}"

    def _format_shift_auction_report_shift(self, lot):
        start = self._format_shift_auction_excel_time(lot.get('start_time') or lot.get('start'))
        end = self._format_shift_auction_excel_time(lot.get('end_time') or lot.get('end'))
        return f"{start}*{end}" if start or end else ""

    def generate_shift_auction_test_excel_report(self):
        report = self.get_shift_auction_test_export_data()
        selected_period = report.get('selected_period') or {}
        lot_dates = [
            self._parse_shift_auction_export_date(value)
            for value in (report.get('lot_dates') or [])
        ]
        lot_dates = sorted({value for value in lot_dates if value})
        start_date_obj = self._parse_shift_auction_export_date(selected_period.get('date_from'))
        end_date_obj = self._parse_shift_auction_export_date(selected_period.get('date_to'))
        if not start_date_obj and lot_dates:
            start_date_obj = min(lot_dates)
        if not end_date_obj and lot_dates:
            end_date_obj = max(lot_dates)
        if not start_date_obj or not end_date_obj or end_date_obj < start_date_obj:
            raise ValueError("AUCTION_NO_LOTS")

        date_list = []
        current_date = start_date_obj
        while current_date <= end_date_obj:
            date_list.append(current_date)
            current_date += timedelta(days=1)

        operators = report.get('operators') or []
        lots = report.get('lots') or []
        settings = report.get('settings') or {}

        claimed_by_operator_date = {}
        unclaimed_lots = []
        for lot in lots:
            status = str(lot.get('status') or '').strip().lower()
            if status == 'claimed' and lot.get('claimed_by') is not None:
                key = (int(lot.get('claimed_by')), str(lot.get('shift_date') or ''))
                claimed_by_operator_date.setdefault(key, []).append(lot)
            elif status != 'claimed':
                unclaimed_lots.append(lot)

        day_off_dates = {
            (int(item.get('operator_id')), str(item.get('date') or ''))
            for item in (report.get('day_offs') or [])
            if item.get('operator_id') is not None and item.get('date')
        }

        wb = Workbook()
        ws = wb.active
        ws.title = 'Итоги аукциона'

        total_columns = max(2 + len(date_list), 6)

        thin_side = Side(style='thin', color='CBD5E1')
        border = Border(left=thin_side, right=thin_side, top=thin_side, bottom=thin_side)
        title_fill = PatternFill(fill_type='solid', fgColor='0F172A')
        subtitle_fill = PatternFill(fill_type='solid', fgColor='E0F2FE')
        matrix_header_fill = PatternFill(fill_type='solid', fgColor='1E3A8A')
        unclaimed_header_fill = PatternFill(fill_type='solid', fgColor='92400E')
        claimed_fill = PatternFill(fill_type='solid', fgColor='DCFCE7')
        day_off_fill = PatternFill(fill_type='solid', fgColor='F1F5F9')
        zebra_fill = PatternFill(fill_type='solid', fgColor='F8FAFC')
        empty_fill = PatternFill(fill_type='solid', fgColor='FFFFFF')

        title_font = Font(bold=True, color='FFFFFF', size=14)
        subtitle_font = Font(color='0F172A', size=10)
        header_font = Font(bold=True, color='FFFFFF')
        section_font = Font(bold=True, color='FFFFFF', size=12)
        base_alignment = Alignment(horizontal='center', vertical='center', wrap_text=True)
        left_alignment = Alignment(horizontal='left', vertical='center', wrap_text=True)

        ws.merge_cells(start_row=1, start_column=1, end_row=1, end_column=total_columns)
        title_cell = ws.cell(row=1, column=1, value='Отчет по аукциону смен')
        title_cell.fill = title_fill
        title_cell.font = title_font
        title_cell.alignment = left_alignment

        period_label = f"{start_date_obj.strftime('%d.%m.%Y')} - {end_date_obj.strftime('%d.%m.%Y')}"
        generated_label = datetime.now().strftime('%d.%m.%Y %H:%M')
        status_label = {
            'disabled': 'выключен',
            'scheduled': 'запланирован',
            'open': 'открыт',
            'paused': 'приостановлен',
            'closed': 'завершен',
        }.get(str(settings.get('status') or '').lower(), str(settings.get('status') or ''))
        ws.merge_cells(start_row=2, start_column=1, end_row=2, end_column=total_columns)
        subtitle_cell = ws.cell(
            row=2,
            column=1,
            value=f"Период: {period_label} | Статус: {status_label or '-'} | Сформировано: {generated_label}"
        )
        subtitle_cell.fill = subtitle_fill
        subtitle_cell.font = subtitle_font
        subtitle_cell.alignment = left_alignment

        matrix_header_row = 4
        ws.cell(row=matrix_header_row, column=1, value='ФИО')
        ws.cell(row=matrix_header_row, column=2, value='Ставка')
        for idx, day_obj in enumerate(date_list, start=3):
            cell = ws.cell(row=matrix_header_row, column=idx, value=day_obj)
            cell.number_format = 'DD.MM.YYYY'

        for col_idx in range(1, total_columns + 1):
            cell = ws.cell(row=matrix_header_row, column=col_idx)
            cell.fill = matrix_header_fill
            cell.font = header_font
            cell.border = border
            cell.alignment = base_alignment

        matrix_first_data_row = matrix_header_row + 1
        if operators:
            for row_idx, operator in enumerate(operators, start=matrix_first_data_row):
                operator_id = int(operator.get('id'))
                ws.cell(row=row_idx, column=1, value=operator.get('name') or '')
                rate_cell = ws.cell(row=row_idx, column=2, value=operator.get('rate') if operator.get('rate') is not None else '')
                if isinstance(rate_cell.value, (int, float)):
                    rate_cell.number_format = '0.00'

                for col_idx, day_obj in enumerate(date_list, start=3):
                    date_key = day_obj.strftime('%Y-%m-%d')
                    shifts = claimed_by_operator_date.get((operator_id, date_key), [])
                    cell = ws.cell(row=row_idx, column=col_idx)
                    if shifts:
                        cell.value = ', '.join(filter(None, (self._format_shift_auction_report_shift(lot) for lot in shifts)))
                        cell.fill = claimed_fill
                    elif (operator_id, date_key) in day_off_dates:
                        cell.value = 'Выходной'
                        cell.fill = day_off_fill
                    else:
                        cell.value = ''
                        cell.fill = zebra_fill if ((row_idx - matrix_first_data_row) % 2) else empty_fill

                for col_idx in range(1, total_columns + 1):
                    cell = ws.cell(row=row_idx, column=col_idx)
                    cell.border = border
                    cell.alignment = left_alignment if col_idx == 1 else base_alignment
                    if col_idx <= 2 and ((row_idx - matrix_first_data_row) % 2):
                        cell.fill = zebra_fill
            matrix_last_row = matrix_first_data_row + len(operators) - 1
        else:
            matrix_last_row = matrix_first_data_row
            ws.merge_cells(start_row=matrix_first_data_row, start_column=1, end_row=matrix_first_data_row, end_column=total_columns)
            cell = ws.cell(row=matrix_first_data_row, column=1, value='Нет выбранных операторов для отчета')
            cell.alignment = left_alignment
            cell.fill = zebra_fill
            for col_idx in range(1, total_columns + 1):
                ws.cell(row=matrix_first_data_row, column=col_idx).border = border

        ws.freeze_panes = 'C5'
        ws.auto_filter.ref = f"A{matrix_header_row}:{get_column_letter(2 + len(date_list))}{max(matrix_last_row, matrix_header_row)}"

        unclaimed_title_row = matrix_last_row + 3
        ws.merge_cells(start_row=unclaimed_title_row, start_column=1, end_row=unclaimed_title_row, end_column=total_columns)
        section_cell = ws.cell(row=unclaimed_title_row, column=1, value='Неразобранные смены')
        section_cell.fill = unclaimed_header_fill
        section_cell.font = section_font
        section_cell.alignment = left_alignment

        def _unclaimed_start_key(lot):
            text = str(lot.get('start_time') or '')
            try:
                hh, mm = text.split(':')[:2]
                return (int(hh), int(mm))
            except Exception:
                return (24, 0)

        unclaimed_by_date = {}
        for lot in unclaimed_lots:
            shift_date = self._parse_shift_auction_export_date(lot.get('shift_date'))
            if not shift_date:
                continue
            unclaimed_by_date.setdefault(shift_date, []).append(lot)
        for shifts in unclaimed_by_date.values():
            shifts.sort(key=_unclaimed_start_key)

        unclaimed_header_row = unclaimed_title_row + 1
        for col_idx in (1, 2):
            cell = ws.cell(row=unclaimed_header_row, column=col_idx)
            cell.fill = unclaimed_header_fill
            cell.border = border
        for idx, day_obj in enumerate(date_list, start=3):
            cell = ws.cell(row=unclaimed_header_row, column=idx, value=day_obj)
            cell.number_format = 'DD.MM.YYYY'
            cell.fill = unclaimed_header_fill
            cell.font = header_font
            cell.border = border
            cell.alignment = base_alignment

        max_shifts_per_day = max((len(shifts) for shifts in unclaimed_by_date.values()), default=0)

        if max_shifts_per_day == 0:
            info_row = unclaimed_header_row + 1
            ws.merge_cells(start_row=info_row, start_column=1, end_row=info_row, end_column=total_columns)
            cell = ws.cell(row=info_row, column=1, value='Все смены разобраны')
            cell.alignment = left_alignment
            cell.fill = claimed_fill
            for col_idx in range(1, total_columns + 1):
                ws.cell(row=info_row, column=col_idx).border = border
        else:
            free_fill = PatternFill(fill_type='solid', fgColor='FEF3C7')
            cancelled_fill = PatternFill(fill_type='solid', fgColor='FECACA')
            for row_offset in range(max_shifts_per_day):
                row_idx = unclaimed_header_row + 1 + row_offset
                base_fill = zebra_fill if (row_offset % 2) else empty_fill
                for col_idx in (1, 2):
                    cell = ws.cell(row=row_idx, column=col_idx)
                    cell.border = border
                    cell.fill = base_fill
                for col_idx, day_obj in enumerate(date_list, start=3):
                    cell = ws.cell(row=row_idx, column=col_idx)
                    cell.border = border
                    cell.alignment = base_alignment
                    day_shifts = unclaimed_by_date.get(day_obj, [])
                    if row_offset < len(day_shifts):
                        lot = day_shifts[row_offset]
                        cell.value = self._format_shift_auction_report_shift(lot)
                        status = str(lot.get('status') or '').strip().lower()
                        cell.fill = cancelled_fill if status == 'cancelled' else free_fill
                    else:
                        cell.fill = base_fill

        ws.row_dimensions[1].height = 26
        ws.row_dimensions[2].height = 22
        ws.row_dimensions[matrix_header_row].height = 24
        ws.row_dimensions[unclaimed_header_row].height = 24
        ws.column_dimensions['A'].width = 34
        ws.column_dimensions['B'].width = 10
        for idx in range(len(date_list)):
            ws.column_dimensions[get_column_letter(3 + idx)].width = 15

        output = BytesIO()
        wb.save(output)
        output.seek(0)
        return output, start_date_obj, end_date_obj

    def get_shift_auction_test_snapshot(self, current_user_id=None, include_admin_fields=False):
        current_id = None
        try:
            current_id = int(current_user_id) if current_user_id is not None else None
        except Exception:
            current_id = None

        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT
                    s.enabled,
                    s.launch_note,
                    s.starts_at,
                    s.ends_at,
                    s.paused_at,
                    s.finished_at,
                    COALESCE(
                        s.selected_schedule_plan_id,
                        (
                            SELECT source_schedule_plan_id
                            FROM shift_auction_test_lots
                            WHERE source_schedule_plan_id IS NOT NULL
                            ORDER BY id
                            LIMIT 1
                        )
                    ) AS selected_schedule_plan_id,
                    s.updated_by,
                    u.name AS updated_by_name,
                    s.updated_at,
                    s.published_to_work_schedules_at,
                    s.published_to_work_schedules_by,
                    publisher.name AS published_to_work_schedules_by_name,
                    s.topup_started_at,
                    s.topup_started_by,
                    topup_user.name AS topup_started_by_name,
                    (SELECT COALESCE(MAX(id), 0) FROM shift_auction_test_events) AS last_event_id
                FROM shift_auction_test_access s
                LEFT JOIN users u ON u.id = s.updated_by
                LEFT JOIN users publisher ON publisher.id = s.published_to_work_schedules_by
                LEFT JOIN users topup_user ON topup_user.id = s.topup_started_by
                WHERE s.id = 1
            """)
            settings_row = cursor.fetchone()
            if not settings_row:
                cursor.execute("""
                    INSERT INTO shift_auction_test_access (id)
                    VALUES (1)
                    ON CONFLICT (id) DO NOTHING
                """)
                settings_row = (False, '', None, None, None, None, None, None, None, None, None, None, None, None, None, None, 0)

            common_snapshot = self._get_shift_auction_snapshot_common_tx(
                cursor,
                settings_row,
                include_admin_fields=include_admin_fields
            )
            participant_rows = common_snapshot["participant_rows"]
            lots = common_snapshot["lots"]
            lot_dates = common_snapshot["lot_dates"]
            selected_period_row = common_snapshot["selected_period_row"]
            available_periods = common_snapshot["available_periods"]
            claim_journal_rows = common_snapshot["claim_journal_rows"]
            participant_workloads = common_snapshot.get("participant_workloads") or []

            my_day_offs = []
            if current_id:
                cursor.execute("""
                    SELECT day_off_date
                    FROM shift_auction_test_day_offs
                    WHERE operator_id = %s
                    ORDER BY day_off_date
                """, (current_id,))
                my_day_offs = [
                    row[0].strftime('%Y-%m-%d')
                    for row in (cursor.fetchall() or [])
                    if row and row[0]
                ]

            my_blocked_dates = (
                self._get_shift_auction_operator_blocked_dates_tx(cursor, current_id, lot_dates=lot_dates)
                if current_id else []
            )
            my_work_shifts = (
                self._get_shift_auction_operator_work_shifts_tx(cursor, current_id, lot_dates)
                if current_id else []
            )

        selected_operator_ids = [int(row[0]) for row in participant_rows if row and row[0] is not None]
        post_auction_active = bool(
            settings_row and settings_row[10]
            and current_id is not None
            and current_id in set(selected_operator_ids)
        )
        notify_post_claim_enabled = (
            self.get_admin_post_claim_notify_setting(current_id)
            if include_admin_fields and current_id is not None else False
        )
        return {
            "enabled": bool(settings_row[0]) if settings_row else False,
            "launch_note": settings_row[1] or "",
            "starts_at": settings_row[2].isoformat() if settings_row and settings_row[2] else None,
            "ends_at": settings_row[3].isoformat() if settings_row and settings_row[3] else None,
            "paused_at": settings_row[4].isoformat() if settings_row and settings_row[4] else None,
            "finished_at": settings_row[5].isoformat() if settings_row and settings_row[5] else None,
            "selected_schedule_plan_id": settings_row[6] if settings_row else None,
            "selected_period": self._serialize_shift_auction_period_row(selected_period_row),
            "status": self._get_shift_auction_test_status(
                bool(settings_row[0]) if settings_row else False,
                settings_row[2] if settings_row else None,
                settings_row[3] if settings_row else None,
                settings_row[4] if settings_row else None,
                settings_row[5] if settings_row else None
            ),
            "updated_by": settings_row[7] if settings_row else None,
            "updated_by_name": settings_row[8] or "",
            "updated_at": settings_row[9].isoformat() if settings_row and settings_row[9] else None,
            "published_to_work_schedules_at": settings_row[10].isoformat() if settings_row and settings_row[10] else None,
            "published_to_work_schedules_by": settings_row[11] if settings_row else None,
            "published_to_work_schedules_by_name": settings_row[12] or "",
            "topup_started_at": settings_row[13].isoformat() if settings_row and len(settings_row) > 13 and settings_row[13] else None,
            "topup_started_by": settings_row[14] if settings_row and len(settings_row) > 14 else None,
            "topup_started_by_name": (settings_row[15] or "") if settings_row and len(settings_row) > 15 else "",
            "selected_operator_ids": selected_operator_ids,
            "selected_operators": [
                {
                    "id": row[0],
                    "name": row[1],
                    "role": normalize_role_value(row[2]),
                    "status": row[3],
                    "rate": float(row[4]) if row[4] is not None else 1.0,
                    "direction_id": row[5],
                    "direction": row[6] or "",
                    "supervisor_id": row[7],
                    "supervisor_name": row[8] or "",
                    "selected_at": row[9].isoformat() if row[9] else None
                }
                for row in participant_rows
            ],
            "is_current_user_tester": current_id in set(selected_operator_ids) if current_id is not None else False,
            "lots": lots,
            "my_day_offs": my_day_offs,
            "my_blocked_dates": my_blocked_dates,
            "my_work_shifts": my_work_shifts,
            "available_periods": available_periods,
            "participant_workloads": participant_workloads,
            "claim_journal": [
                {
                    "id": row[0],
                    "claimed_at": row[1].isoformat() if row[1] else None,
                    "shift_date": row[2],
                    "start_time": row[3],
                    "end_time": row[4],
                    "claimed_by": row[5],
                    "claimed_by_name": row[6] or "",
                    "source_schedule_plan_id": row[7],
                    "period_start": row[8].strftime('%Y-%m-%d') if row[8] else None,
                    "period_end": row[9].strftime('%Y-%m-%d') if row[9] else None,
                }
                for row in claim_journal_rows
            ],
            "last_event_id": int(settings_row[16] or 0) if settings_row and len(settings_row) > 16 else 0,
            "post_auction_active": post_auction_active,
            "notify_post_claim_enabled": notify_post_claim_enabled,
        }

    def get_shift_auction_period_preview(self, schedule_plan_id, current_user_id=None):
        current_id = None
        try:
            current_id = int(current_user_id) if current_user_id is not None else None
        except Exception:
            current_id = None

        with self._get_cursor() as cursor:
            period_row = self._validate_shift_auction_period_tx(
                cursor,
                schedule_plan_id,
                require_restartable=False
            )
            plan_id = int(period_row[0])
            period_start = period_row[1]
            period_end = period_row[2]
            cursor.execute("""
                SELECT id, shift_date, start_time, end_time, rate_min, breaks, start_minute, end_minute
                FROM resource_saved_schedule_shifts
                WHERE plan_id = %s
                  AND COALESCE(meta->>'excludeFromAuction', 'false') <> 'true'
                ORDER BY shift_date, start_minute, end_minute, id
            """, (plan_id,))
            shift_rows = cursor.fetchall() or []
            lot_dates = sorted({row[1] for row in shift_rows if row and row[1]})
            my_blocked_dates = (
                self._get_shift_auction_operator_blocked_dates_tx(cursor, current_id, lot_dates=lot_dates)
                if current_id else []
            )
            my_work_shifts = (
                self._get_shift_auction_operator_work_shifts_tx(cursor, current_id, lot_dates)
                if current_id else []
            )

            cursor.execute("""
                SELECT e.id, e.event_type, e.payload, e.created_at
                FROM shift_auction_test_events e
                WHERE (
                    e.event_type IN ('lot_claimed', 'lot_released', 'lot_post_auction_claimed')
                    AND NULLIF(e.payload->'lot'->>'source_schedule_plan_id', '')::INTEGER = %s
                )
                OR (
                    e.event_type IN ('day_off_selected', 'day_off_removed')
                    AND NULLIF(e.payload->>'date', '')::DATE >= %s
                    AND NULLIF(e.payload->>'date', '')::DATE <= %s
                )
                OR (
                    e.event_type = 'settings_updated'
                    AND (
                        NULLIF(e.payload->>'selected_schedule_plan_id', '')::INTEGER = %s
                        OR (
                            e.payload->>'date_from' = %s
                            AND e.payload->>'date_to' = %s
                        )
                    )
                )
                ORDER BY e.id
            """, (
                plan_id,
                period_start,
                period_end,
                plan_id,
                period_start.strftime('%Y-%m-%d') if period_start else None,
                period_end.strftime('%Y-%m-%d') if period_end else None,
            ))
            event_rows = cursor.fetchall() or []

            lots_by_shift_id = {}
            lots_by_time_key = {}
            lots = []
            for row in shift_rows:
                shift_date_text = row[1].strftime('%Y-%m-%d') if row[1] else None
                start_text = row[2].strftime('%H:%M') if row[2] else None
                end_text = row[3].strftime('%H:%M') if row[3] else None
                lot = {
                    "id": f"preview-{row[0]}",
                    "shift_date": shift_date_text,
                    "start_time": start_text,
                    "end_time": end_text,
                    "rate_min": float(row[4]) if row[4] is not None else 0,
                    "status": "available",
                    "claimed_by": None,
                    "claimed_by_name": "",
                    "claimed_at": None,
                    "breaks": row[5] if len(row) > 5 and isinstance(row[5], list) else [],
                    "source_schedule_plan_id": plan_id,
                    "source_schedule_shift_id": row[0],
                    "post_auction_claimed": False,
                    "claimed_by_direction_id": None,
                    "claimed_by_direction": "",
                    "source_start_minute": int(row[6]) if len(row) > 6 and row[6] is not None else None,
                    "source_end_minute": int(row[7]) if len(row) > 7 and row[7] is not None else None,
                    "claim_start_time": None,
                    "claim_end_time": None,
                    "preview_only": True,
                }
                lots.append(lot)
                lots_by_shift_id[int(row[0])] = lot
                lots_by_time_key[(shift_date_text, start_text, end_text)] = lot

            selected_operator_ids = []
            day_offs_by_operator = {}
            claim_journal_items = []
            claimed_operator_ids = set()

            def _event_int(value):
                try:
                    result = int(value)
                except Exception:
                    return None
                return result if result > 0 else None

            def _event_lot_target(lot_payload):
                shift_id = _event_int((lot_payload or {}).get("source_schedule_shift_id"))
                if shift_id and shift_id in lots_by_shift_id:
                    return lots_by_shift_id[shift_id]
                key = (
                    str((lot_payload or {}).get("shift_date") or ""),
                    str((lot_payload or {}).get("start_time") or "")[:5],
                    str((lot_payload or {}).get("end_time") or "")[:5],
                )
                return lots_by_time_key.get(key)

            def _date_in_period(date_text):
                if not date_text:
                    return False
                try:
                    value = datetime.strptime(str(date_text), "%Y-%m-%d").date()
                except Exception:
                    return False
                return bool(period_start and period_end and period_start <= value <= period_end)

            for event_id, event_type, payload, created_at in event_rows:
                event_payload = payload or {}
                event_type_text = str(event_type or '')
                if event_type_text == "settings_updated":
                    raw_ids = event_payload.get("selected_operator_ids")
                    if isinstance(raw_ids, list):
                        selected_operator_ids = [
                            op_id for op_id in (_event_int(item) for item in raw_ids)
                            if op_id
                        ]
                    continue

                if event_type_text in ("day_off_selected", "day_off_removed"):
                    op_id = _event_int(event_payload.get("operator_id"))
                    if not op_id:
                        continue
                    current_dates = day_offs_by_operator.setdefault(op_id, set())
                    raw_day_offs = event_payload.get("my_day_offs")
                    if isinstance(raw_day_offs, list):
                        day_offs_by_operator[op_id] = {
                            str(item)
                            for item in raw_day_offs
                            if _date_in_period(item)
                        }
                    else:
                        date_text = str(event_payload.get("date") or "")
                        if not _date_in_period(date_text):
                            continue
                        if event_type_text == "day_off_selected":
                            current_dates.add(date_text)
                        else:
                            current_dates.discard(date_text)
                    continue

                if event_type_text not in ("lot_claimed", "lot_released", "lot_post_auction_claimed"):
                    continue
                lot_payload = event_payload.get("lot") if isinstance(event_payload, dict) else {}
                if not isinstance(lot_payload, dict):
                    continue
                target_lot = _event_lot_target(lot_payload)
                if not target_lot:
                    continue
                if event_type_text == "lot_released":
                    target_lot.update({
                        "status": "available",
                        "claimed_by": None,
                        "claimed_by_name": "",
                        "claimed_at": None,
                        "post_auction_claimed": False,
                        "claimed_by_direction_id": None,
                        "claimed_by_direction": "",
                    })
                    continue
                claimed_by = _event_int(lot_payload.get("claimed_by"))
                if not claimed_by and event_type_text == "lot_post_auction_claimed":
                    claimed_by = _event_int(event_payload.get("operator_id"))
                if claimed_by:
                    claimed_operator_ids.add(claimed_by)
                target_lot.update({
                    "status": "claimed",
                    "claimed_by": claimed_by,
                    "claimed_at": lot_payload.get("claimed_at") or (created_at.isoformat() if created_at else None),
                    "post_auction_claimed": bool(lot_payload.get("post_auction_claimed")),
                    "claim_start_time": lot_payload.get("claim_start_time") or lot_payload.get("post_claim_start_time"),
                    "claim_end_time": lot_payload.get("claim_end_time") or lot_payload.get("post_claim_end_time"),
                })
                claim_journal_items.append({
                    "id": event_id,
                    "claimed_at": target_lot.get("claimed_at"),
                    "shift_date": target_lot.get("shift_date"),
                    "start_time": target_lot.get("claim_start_time") or target_lot.get("start_time"),
                    "end_time": target_lot.get("claim_end_time") or target_lot.get("end_time"),
                    "claimed_by": claimed_by,
                    "source_schedule_plan_id": plan_id,
                    "period_start": period_start.strftime('%Y-%m-%d') if period_start else None,
                    "period_end": period_end.strftime('%Y-%m-%d') if period_end else None,
                })

            # Historical claims are the source of truth for a published period and may
            # hold SEVERAL disjoint partial claims per shift (partial добор). Load them
            # up-front so each claiming operator is included in the participant lookup.
            cursor.execute("""
                SELECT source_schedule_shift_id, claimed_by, claimed_at, claimed_start_time, claimed_end_time
                FROM shift_auction_historical_claims
                WHERE plan_id = %s
                ORDER BY source_schedule_shift_id, claimed_start_time NULLS FIRST
            """, (plan_id,))
            claims_by_shift = {}
            for sid, cby, cat, cs, ce in (cursor.fetchall() or []):
                if sid is None:
                    continue
                claims_by_shift.setdefault(int(sid), []).append({
                    "claimed_by": int(cby) if cby is not None else None,
                    "claimed_at": cat,
                    "claim_start": cs,
                    "claim_end": ce,
                })
                if cby is not None:
                    claimed_operator_ids.add(int(cby))

            operator_ids = []
            seen_operator_ids = set()
            for op_id in [*selected_operator_ids, *sorted(claimed_operator_ids), *sorted(day_offs_by_operator.keys())]:
                if op_id and op_id not in seen_operator_ids:
                    seen_operator_ids.add(op_id)
                    operator_ids.append(op_id)

            participant_rows = []
            if operator_ids:
                cursor.execute("""
                    SELECT
                        u.id,
                        u.name,
                        u.role,
                        u.status,
                        u.rate,
                        u.direction_id,
                        d.name AS direction_name,
                        u.supervisor_id,
                        s.name AS supervisor_name,
                        NULL::timestamp AS selected_at
                    FROM users u
                    LEFT JOIN directions d ON d.id = u.direction_id
                    LEFT JOIN users s ON s.id = u.supervisor_id
                    WHERE u.id = ANY(%s)
                    ORDER BY u.name
                """, (operator_ids,))
                participant_rows = cursor.fetchall() or []

            operator_info = {
                int(row[0]): {
                    "id": row[0],
                    "name": row[1],
                    "role": normalize_role_value(row[2]),
                    "status": row[3],
                    "rate": float(row[4]) if row[4] is not None else 1.0,
                    "direction_id": row[5],
                    "direction": row[6] or "",
                    "supervisor_id": row[7],
                    "supervisor_name": row[8] or "",
                    "selected_at": row[9].isoformat() if row[9] else None,
                }
                for row in participant_rows
                if row and row[0] is not None
            }
            for lot in lots:
                claimed_by = _event_int(lot.get("claimed_by"))
                if not claimed_by:
                    continue
                info = operator_info.get(claimed_by) or {}
                lot["claimed_by_name"] = info.get("name") or ""
                lot["claimed_by_direction_id"] = info.get("direction_id")
                lot["claimed_by_direction"] = info.get("direction") or ""

            # SINGLE-LOT model: keep ONE lot per shift and attach claim_segments (the
            # taken parts). Fully-covered shifts → 'claimed' (grey); partially-taken →
            # stay 'available' and the frontend shows the free part with a marker.
            for lot in lots:
                shift_id = _event_int(lot.get("source_schedule_shift_id"))
                claims = claims_by_shift.get(shift_id) if shift_id else None
                if not claims:
                    lot["claim_segments"] = []
                    continue
                full_start = lot.get("source_start_minute")
                full_end = lot.get("source_end_minute")
                has_range = isinstance(full_start, int) and isinstance(full_end, int) and full_end > full_start
                segments = []
                claimed_ranges = []
                full_block = False
                for claim in claims:
                    cs = claim.get("claim_start")
                    ce = claim.get("claim_end")
                    info = operator_info.get(int(claim["claimed_by"])) if claim.get("claimed_by") else None
                    segments.append({
                        "claimed_by": claim.get("claimed_by"),
                        "claimed_by_name": (info or {}).get("name") or "",
                        "start_time": cs.strftime('%H:%M') if cs else lot.get("start_time"),
                        "end_time": ce.strftime('%H:%M') if ce else lot.get("end_time"),
                    })
                    if cs is None or ce is None:
                        full_block = True
                    elif has_range:
                        cs_min = _time_to_minutes(cs.strftime('%H:%M'))
                        ce_min = _time_to_minutes(ce.strftime('%H:%M'))
                        if full_end > 24 * 60 and cs_min < full_start:
                            cs_min += 24 * 60
                        if ce_min <= cs_min:
                            ce_min += 24 * 60
                        claimed_ranges.append((cs_min, ce_min))
                lot["claim_segments"] = segments
                free_gaps = (
                    [g for g in self._subtract_ranges(full_start, full_end, claimed_ranges) if g[1] - g[0] > 0]
                    if (has_range and not full_block) else []
                )
                if not free_gaps:
                    first = claims[0]
                    finfo = operator_info.get(int(first["claimed_by"])) if first.get("claimed_by") else None
                    lot.update({
                        "status": "claimed",
                        "post_auction_claimed": True,
                        "claimed_by": first.get("claimed_by"),
                        "claimed_by_name": (finfo or {}).get("name") or lot.get("claimed_by_name") or "",
                    })
                else:
                    lot.update({
                        "status": "available",
                        "post_auction_claimed": False,
                        "claimed_by": None,
                        "claimed_by_name": "",
                        "claim_start_time": None,
                        "claim_end_time": None,
                    })

            participant_workloads = self._get_shift_auction_participant_workloads_tx(
                cursor,
                participant_rows,
                lots,
                lot_dates,
                day_offs_by_operator=day_offs_by_operator,
            )
            my_day_offs = sorted(day_offs_by_operator.get(current_id, set()) or []) if current_id else []
            for item in claim_journal_items:
                item["claimed_by_name"] = (operator_info.get(int(item["claimed_by"] or 0)) or {}).get("name", "")
            cursor.execute(
                "SELECT 1 FROM shift_auction_published_periods WHERE plan_id = %s",
                (plan_id,)
            )
            post_auction_active = cursor.fetchone() is not None

        return {
            "period": self._serialize_shift_auction_period_row(period_row),
            "lots": lots,
            "my_blocked_dates": my_blocked_dates,
            "my_day_offs": my_day_offs,
            "my_work_shifts": my_work_shifts,
            "selected_operator_ids": operator_ids,
            "selected_operators": list(operator_info.values()),
            "participant_workloads": participant_workloads,
            "claim_journal": list(reversed(claim_journal_items[-50:])),
            "history_available": bool(event_rows),
            "post_auction_active": post_auction_active,
        }

    def has_shift_auction_history_access(self, operator_id):
        try:
            operator_id = int(operator_id)
        except Exception:
            return False
        if operator_id <= 0:
            return False
        with self._get_cursor() as cursor:
            if operator_id in self._get_shift_auction_participant_ids_cached_tx(cursor):
                return True
            cursor.execute("""
                SELECT 1
                FROM shift_auction_published_periods
                WHERE participant_ids @> ARRAY[%s]::INTEGER[]
                LIMIT 1
            """, (operator_id,))
            return cursor.fetchone() is not None

    def is_shift_auction_period_participant(self, operator_id, schedule_plan_id):
        try:
            operator_id = int(operator_id)
            plan_id = int(schedule_plan_id) if schedule_plan_id not in (None, '') else 0
        except Exception:
            return False
        if operator_id <= 0 or plan_id <= 0:
            return False
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT selected_schedule_plan_id
                FROM shift_auction_test_access
                WHERE id = 1
            """)
            settings_row = cursor.fetchone()
            current_plan_id = None
            try:
                current_plan_id = int(settings_row[0]) if settings_row and settings_row[0] is not None else None
            except Exception:
                current_plan_id = None
            if (
                current_plan_id == plan_id
                and operator_id in self._get_shift_auction_participant_ids_cached_tx(cursor)
            ):
                return True
            cursor.execute("""
                SELECT 1
                FROM shift_auction_published_periods
                WHERE plan_id = %s
                  AND participant_ids @> ARRAY[%s]::INTEGER[]
                LIMIT 1
            """, (plan_id, operator_id))
            return cursor.fetchone() is not None

    def get_shift_auction_lots_for_planner_date(self, target_date):
        """
        Возвращает «выбранные смены» (claimed лоты) для указанной даты, чтобы
        раздел «Графики работы → почасовая группировка → План» мог учитывать
        и активный аукцион, и уже опубликованные исторические периоды.

        Сначала проверяем shift_auction_test_lots (активный план). Если на эту
        дату там лотов нет — собираем «виртуальные» лоты из
        resource_saved_schedule_shifts + shift_auction_historical_claims по
        опубликованным периодам, в чьи даты попадает target_date.
        Формат лотов совместим со snapshot.lots.
        """
        if hasattr(target_date, 'strftime'):
            date_obj = target_date
        else:
            try:
                date_obj = datetime.strptime(str(target_date), '%Y-%m-%d').date()
            except Exception:
                return {"lots": [], "selected_operators": []}

        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT
                    l.id, l.shift_date, l.start_time, l.end_time, l.rate_min,
                    l.status, l.claimed_by, l.claimed_at, l.breaks,
                    l.source_schedule_plan_id, l.source_schedule_shift_id,
                    COALESCE(l.post_auction_claimed, FALSE) AS post_auction_claimed,
                    u.name AS claimed_by_name,
                    u.direction_id AS claimed_by_direction_id,
                    cdir.name AS claimed_by_direction,
                    s.start_minute, s.end_minute,
                    l.post_claim_start_time,
                    l.post_claim_end_time
                FROM shift_auction_test_lots l
                LEFT JOIN users u ON u.id = l.claimed_by
                LEFT JOIN directions cdir ON cdir.id = u.direction_id
                LEFT JOIN resource_saved_schedule_shifts s
                    ON s.id = l.source_schedule_shift_id
                WHERE l.shift_date BETWEEN %s::date - INTERVAL '1 day' AND %s::date
                ORDER BY l.shift_date, l.start_time, l.end_time, l.id
            """, (date_obj, date_obj))
            active_rows = cursor.fetchall() or []

            lots = []
            for row in active_rows:
                lots.append({
                    "id": row[0],
                    "shift_date": row[1].strftime('%Y-%m-%d') if row[1] else None,
                    "start_time": row[2].strftime('%H:%M') if row[2] else None,
                    "end_time": row[3].strftime('%H:%M') if row[3] else None,
                    "rate_min": float(row[4]) if row[4] is not None else 0,
                    "status": row[5],
                    "claimed_by": row[6],
                    "claimed_at": row[7].isoformat() if row[7] else None,
                    "breaks": row[8] if isinstance(row[8], list) else [],
                    "source_schedule_plan_id": row[9],
                    "source_schedule_shift_id": row[10],
                    "post_auction_claimed": bool(row[11]),
                    "claimed_by_name": row[12] or "",
                    "claimed_by_direction_id": row[13],
                    "claimed_by_direction": row[14] or "",
                    "source_start_minute": int(row[15]) if row[15] is not None else None,
                    "source_end_minute": int(row[16]) if row[16] is not None else None,
                    "claim_start_time": row[17].strftime('%H:%M') if row[17] else None,
                    "claim_end_time": row[18].strftime('%H:%M') if row[18] else None,
                })

            if lots:
                participant_plan_ids = sorted({lot.get("source_schedule_plan_id") for lot in lots if lot.get("source_schedule_plan_id")})
                cursor.execute("""
                    SELECT DISTINCT u.id, u.name, u.role, u.status, u.rate, u.direction_id, d.name AS direction_name
                    FROM shift_auction_test_participants p
                    JOIN users u ON u.id = p.operator_id
                    LEFT JOIN directions d ON d.id = u.direction_id
                """)
                participants = cursor.fetchall() or []
                selected_operators = [
                    {
                        "id": r[0], "name": r[1],
                        "role": normalize_role_value(r[2]) if r[2] else None,
                        "status": r[3], "rate": float(r[4]) if r[4] is not None else 1.0,
                        "direction_id": r[5], "direction": r[6] or "",
                    } for r in participants
                ]
                return {"lots": lots, "selected_operators": selected_operators}

            cursor.execute("""
                SELECT plan_id, participant_ids
                FROM shift_auction_published_periods
                WHERE date_from <= %s AND date_to >= %s
                ORDER BY published_at DESC
            """, (date_obj, date_obj))
            historical_periods = cursor.fetchall() or []
            if not historical_periods:
                return {"lots": [], "selected_operators": []}

            plan_ids = [int(row[0]) for row in historical_periods if row and row[0] is not None]
            participant_ids_union = set()
            for row in historical_periods:
                for op_id in (row[1] or []):
                    try:
                        op_int = int(op_id)
                    except Exception:
                        continue
                    if op_int > 0:
                        participant_ids_union.add(op_int)

            cursor.execute("""
                SELECT
                    s.id, s.plan_id, s.shift_date, s.start_time, s.end_time,
                    s.rate_min, s.breaks, s.start_minute, s.end_minute,
                    hc.claimed_by, hc.claimed_at,
                    hc.claimed_start_time, hc.claimed_end_time,
                    u.name AS claimed_by_name,
                    u.direction_id AS claimed_by_direction_id,
                    cdir.name AS claimed_by_direction
                FROM resource_saved_schedule_shifts s
                LEFT JOIN shift_auction_historical_claims hc
                  ON hc.plan_id = s.plan_id AND hc.source_schedule_shift_id = s.id
                LEFT JOIN users u ON u.id = hc.claimed_by
                LEFT JOIN directions cdir ON cdir.id = u.direction_id
                WHERE s.plan_id = ANY(%s)
                  AND s.shift_date BETWEEN %s::date - INTERVAL '1 day' AND %s::date
                  AND COALESCE(s.meta->>'excludeFromAuction', 'false') <> 'true'
                ORDER BY s.shift_date, s.start_time, s.end_time, s.id
            """, (plan_ids, date_obj, date_obj))
            historical_rows = cursor.fetchall() or []
            for row in historical_rows:
                shift_id = int(row[0])
                plan_id = int(row[1])
                # A shift may now have several disjoint claims → several rows here.
                # Keep ids unique per operator so claimed slices don't collide.
                lot_id = f"preview-{shift_id}-c{int(row[9])}" if row[9] else f"preview-{shift_id}"
                lots.append({
                    "id": lot_id,
                    "shift_date": row[2].strftime('%Y-%m-%d') if row[2] else None,
                    "start_time": row[3].strftime('%H:%M') if row[3] else None,
                    "end_time": row[4].strftime('%H:%M') if row[4] else None,
                    "rate_min": float(row[5]) if row[5] is not None else 0,
                    "status": "claimed" if row[9] else "available",
                    "claimed_by": row[9],
                    "claimed_at": row[10].isoformat() if row[10] else None,
                    "breaks": row[6] if isinstance(row[6], list) else [],
                    "source_schedule_plan_id": plan_id,
                    "source_schedule_shift_id": shift_id,
                    "source_start_minute": int(row[7]) if row[7] is not None else None,
                    "source_end_minute": int(row[8]) if row[8] is not None else None,
                    "post_auction_claimed": bool(row[9]),
                    "claim_start_time": row[11].strftime('%H:%M') if row[11] else None,
                    "claim_end_time": row[12].strftime('%H:%M') if row[12] else None,
                    "claimed_by_name": row[13] or "",
                    "claimed_by_direction_id": row[14],
                    "claimed_by_direction": row[15] or "",
                    "preview_only": True,
                })

            selected_operators = []
            if participant_ids_union:
                cursor.execute("""
                    SELECT u.id, u.name, u.role, u.status, u.rate, u.direction_id, d.name AS direction_name
                    FROM users u
                    LEFT JOIN directions d ON d.id = u.direction_id
                    WHERE u.id = ANY(%s)
                """, (sorted(participant_ids_union),))
                selected_operators = [
                    {
                        "id": r[0], "name": r[1],
                        "role": normalize_role_value(r[2]) if r[2] else None,
                        "status": r[3], "rate": float(r[4]) if r[4] is not None else 1.0,
                        "direction_id": r[5], "direction": r[6] or "",
                    } for r in (cursor.fetchall() or [])
                ]

            return {"lots": lots, "selected_operators": selected_operators}

    def _shift_auction_period_has_published_history_tx(self, cursor, plan_id, period_start=None, period_end=None):
        try:
            plan_id = int(plan_id or 0)
        except Exception:
            plan_id = 0
        if plan_id <= 0:
            return False
        cursor.execute(
            "SELECT 1 FROM shift_auction_published_periods WHERE plan_id = %s",
            (plan_id,)
        )
        return cursor.fetchone() is not None

    def restart_shift_auction_test(self, schedule_plan_id, updated_by=None):
        with self._get_cursor() as cursor:
            period_row = self._validate_shift_auction_period_tx(
                cursor,
                schedule_plan_id,
                require_restartable=True
            )
            cursor.execute("""
                SELECT id, shift_date, start_time, end_time, rate_min, breaks
                FROM resource_saved_schedule_shifts
                WHERE plan_id = %s
                  AND COALESCE(meta->>'excludeFromAuction', 'false') <> 'true'
                ORDER BY shift_date, start_minute, end_minute, id
            """, (int(period_row[0]),))
            saved_shift_rows = cursor.fetchall() or []
            cursor.execute("""
                UPDATE shift_auction_test_access
                SET selected_schedule_plan_id = %s,
                    paused_at = NULL,
                    finished_at = NULL,
                    published_to_work_schedules_at = NULL,
                    published_to_work_schedules_by = NULL,
                    updated_by = %s,
                    updated_at = CURRENT_TIMESTAMP
                WHERE id = 1
            """, (int(period_row[0]), updated_by))
            cursor.execute("""
                DELETE FROM shift_auction_test_events
                WHERE event_type = 'lot_claimed'
                  AND NULLIF(payload->'lot'->>'source_schedule_plan_id', '')::INTEGER = %s
            """, (int(period_row[0]),))
            cursor.execute("DELETE FROM shift_auction_test_day_offs")
            cursor.execute("DELETE FROM shift_auction_test_lots")
            execute_values(
                cursor,
                """
                INSERT INTO shift_auction_test_lots (
                    shift_date, start_time, end_time, rate_min,
                    breaks, source_schedule_plan_id, source_schedule_shift_id
                )
                VALUES %s
                """,
                [
                    (
                        row[1],
                        row[2],
                        row[3],
                        row[4],
                        Json(row[5] if isinstance(row[5], list) else []),
                        int(period_row[0]),
                        row[0],
                    )
                    for row in saved_shift_rows
                ],
            )
            event = self._insert_shift_auction_test_event(cursor, "auction_restarted", {
                "plan_id": int(period_row[0]),
                "count": len(saved_shift_rows),
                "date_from": period_row[1].strftime('%Y-%m-%d'),
                "date_to": period_row[2].strftime('%Y-%m-%d'),
                "updated_by": updated_by,
            })
        return {
            "count": len(saved_shift_rows),
            "period": self._serialize_shift_auction_period_row(period_row),
            "event": event,
            "snapshot": self.get_shift_auction_test_snapshot(
                current_user_id=updated_by,
                include_admin_fields=True
            ),
        }

    def seed_shift_auction_test_lots(self, updated_by=None, start_date=None):
        base_date = start_date or (date.today() + timedelta(days=1))
        template_labels = [
            (1.0, ["7*16", "8*17", "9*18", "10*19", "11*20", "13*22", "15*00", "17*02"]),
            (0.75, ["7*13/30", "8*14/30", "9*15/30", "10*16/30", "11*17/30", "12*18/30", "13*19/30", "14*20", "15*21/30", "15/30*22", "16/30*23", "17/30*00", "19/30*02"]),
            (0.5, ["7*11", "8*12", "9*13", "10*14", "11*15", "12*16", "13*17", "14*18", "15*19", "16*20", "17*21", "18*22", "19*23", "20*00", "22*02"]),
            (1.0, ["20*08"]),
        ]

        def parse_template_time(part):
            raw = str(part or '').strip()
            if '/' in raw:
                hour_raw, minute_raw = raw.split('/', 1)
                minute = int(minute_raw or 0)
            else:
                hour_raw, minute = raw, 0
            hour = int(hour_raw or 0) % 24
            return f"{hour:02d}:{minute:02d}"

        templates = []
        for rate_min, labels in template_labels:
            for label in labels:
                start_raw, end_raw = str(label).split('*', 1)
                templates.append((parse_template_time(start_raw), parse_template_time(end_raw), rate_min))

        rows = []
        for day_offset in range(7):
            lot_date = base_date + timedelta(days=day_offset)
            for start_time, end_time, rate_min in templates:
                rows.append((lot_date, start_time, end_time, rate_min))

        with self._get_cursor() as cursor:
            cursor.execute("DELETE FROM shift_auction_test_day_offs")
            cursor.execute("DELETE FROM shift_auction_test_lots")
            if rows:
                execute_values(
                    cursor,
                    """
                    INSERT INTO shift_auction_test_lots (shift_date, start_time, end_time, rate_min)
                    VALUES %s
                    """,
                    rows
                )
            event = self._insert_shift_auction_test_event(cursor, "lots_seeded", {
                "count": len(rows),
                "start_date": base_date.strftime('%Y-%m-%d'),
                "updated_by": updated_by
            })
        return {
            "count": len(rows),
            "event": event,
            "snapshot": self.get_shift_auction_test_snapshot(
                current_user_id=updated_by,
                include_admin_fields=True
            )
        }

    def get_shift_auction_test_journal(self, page=1, per_page=50):
        # Paginated claim journal for the currently-selected auction period.
        # Returns rows ordered newest-first plus a total count for UI paging.
        try:
            page = max(1, int(page or 1))
        except Exception:
            page = 1
        try:
            per_page = max(1, min(200, int(per_page or 50)))
        except Exception:
            per_page = 50
        offset = (page - 1) * per_page
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT selected_schedule_plan_id FROM shift_auction_test_access WHERE id = 1
            """)
            settings_row = cursor.fetchone()
            plan_id = settings_row[0] if settings_row else None
            if plan_id is None:
                return {"entries": [], "total": 0, "page": page, "per_page": per_page, "has_more": False}

            cursor.execute("""
                SELECT COUNT(*)::int
                FROM shift_auction_test_events e
                WHERE e.event_type IN ('lot_claimed', 'lot_post_auction_claimed')
                  AND NULLIF(e.payload->'lot'->>'source_schedule_plan_id', '')::INTEGER = %s
            """, (plan_id,))
            total_row = cursor.fetchone()
            total = int(total_row[0] or 0) if total_row else 0

            cursor.execute("""
                SELECT
                    e.id,
                    e.created_at,
                    NULLIF(e.payload->'lot'->>'shift_date', '') AS shift_date,
                    NULLIF(e.payload->'lot'->>'start_time', '') AS start_time,
                    NULLIF(e.payload->'lot'->>'end_time', '') AS end_time,
                    COALESCE(
                        NULLIF(e.payload->'lot'->>'claimed_by', ''),
                        NULLIF(e.payload->>'operator_id', '')
                    )::INTEGER AS claimed_by,
                    COALESCE(u.name, NULLIF(e.payload->>'operator_name', ''), '') AS claimed_by_name,
                    NULLIF(e.payload->'lot'->>'source_schedule_plan_id', '')::INTEGER AS source_schedule_plan_id,
                    p.date_from,
                    p.date_to,
                    e.event_type,
                    NULLIF(e.payload->'lot'->>'claim_start_time', '') AS claim_start_time,
                    NULLIF(e.payload->'lot'->>'claim_end_time', '') AS claim_end_time
                FROM shift_auction_test_events e
                LEFT JOIN users u
                  ON u.id = COALESCE(
                      NULLIF(e.payload->'lot'->>'claimed_by', ''),
                      NULLIF(e.payload->>'operator_id', '')
                  )::INTEGER
                LEFT JOIN resource_saved_schedule_plans p
                  ON p.id = NULLIF(e.payload->'lot'->>'source_schedule_plan_id', '')::INTEGER
                WHERE e.event_type IN ('lot_claimed', 'lot_post_auction_claimed')
                  AND NULLIF(e.payload->'lot'->>'source_schedule_plan_id', '')::INTEGER = %s
                ORDER BY e.id DESC
                LIMIT %s OFFSET %s
            """, (plan_id, per_page, offset))
            rows = cursor.fetchall() or []

        entries = []
        for row in rows:
            is_post_auction = (row[10] == 'lot_post_auction_claimed')
            claim_start_time = row[11]
            claim_end_time = row[12]
            # Partial добор: a piece of the original shift window was taken.
            is_partial = bool(
                is_post_auction
                and claim_start_time and claim_end_time
                and (claim_start_time != row[3] or claim_end_time != row[4])
            )
            entries.append({
                "id": row[0],
                "claimed_at": row[1].isoformat() if row[1] else None,
                "shift_date": row[2],
                "start_time": row[3],
                "end_time": row[4],
                "claimed_by": row[5],
                "claimed_by_name": row[6] or "",
                "source_schedule_plan_id": row[7],
                "period_start": row[8].strftime('%Y-%m-%d') if row[8] else None,
                "period_end": row[9].strftime('%Y-%m-%d') if row[9] else None,
                "is_post_auction": is_post_auction,
                "claim_start_time": claim_start_time,
                "claim_end_time": claim_end_time,
                "is_partial": is_partial,
            })
        return {
            "entries": entries,
            "total": total,
            "page": page,
            "per_page": per_page,
            "has_more": (page * per_page) < total,
        }

    def get_shift_auction_test_events_after(self, after_id=0, limit=100):
        try:
            after_id = int(after_id or 0)
        except Exception:
            after_id = 0
        limit = max(1, min(int(limit or 100), 500))
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT id, event_type, payload, created_at
                FROM shift_auction_test_events
                WHERE id > %s
                ORDER BY id
                LIMIT %s
            """, (after_id, limit))
            return [
                {
                    "id": row[0],
                    "event_type": row[1],
                    "payload": row[2] or {},
                    "created_at": row[3].isoformat() if row[3] else None
                }
                for row in (cursor.fetchall() or [])
            ]

    def claim_shift_auction_test_lot(self, operator_id, lot_id):
        operator_id = int(operator_id)
        lot_id = int(lot_id)
        timings = {}
        lock_started_at = time.perf_counter()
        with self._get_cursor() as cursor:
            self._lock_shift_auction_operator_tx(cursor, operator_id)
            timings["lock"] = (time.perf_counter() - lock_started_at) * 1000
            started_at = time.perf_counter()
            cursor.execute("""
                SELECT
                    s.enabled,
                    s.starts_at,
                    s.ends_at,
                    s.paused_at,
                    s.finished_at,
                    EXISTS(SELECT 1 FROM shift_auction_test_participants WHERE operator_id = %s) AS is_participant,
                    (
                        SELECT COALESCE(rate, 1)
                        FROM users
                        WHERE id = %s
                          AND LOWER(COALESCE(role, '')) = 'operator'
                          AND COALESCE(status, '') NOT IN ('fired', 'dismissal')
                    ) AS operator_rate,
                    s.topup_started_at
                FROM shift_auction_test_access s
                WHERE s.id = 1
            """, (operator_id, operator_id))
            header = cursor.fetchone()
            timings["header"] = (time.perf_counter() - started_at) * 1000
            if not header or self._get_shift_auction_test_status(header[0], header[1], header[2], header[3], header[4]) != "open":
                raise ValueError("AUCTION_NOT_OPEN")
            if not header[5]:
                raise ValueError("NOT_TEST_PARTICIPANT")
            if header[6] is None:
                raise ValueError("OPERATOR_NOT_FOUND")
            operator_rate = float(header[6] or 1)
            is_topup_mode = bool(header[7]) and not header[4]  # topup_started_at set, auction not finished

            started_at = time.perf_counter()
            cursor.execute("""
                SELECT id, shift_date, start_time, end_time, rate_min, status, claimed_by, claimed_at, breaks,
                       source_schedule_plan_id, source_schedule_shift_id
                FROM shift_auction_test_lots
                WHERE id = %s
            """, (lot_id,))
            lot = cursor.fetchone()
            timings["lot"] = (time.perf_counter() - started_at) * 1000
            if not lot:
                raise ValueError("LOT_NOT_FOUND")
            if lot[5] != 'available':
                raise ValueError("LOT_ALREADY_CLAIMED")

            lot_date = lot[1]
            started_at = time.perf_counter()
            cursor.execute("""
                SELECT
                    EXISTS(
                        SELECT 1 FROM shift_auction_test_day_offs
                        WHERE operator_id = %s AND day_off_date = %s
                    ) AS has_day_off,
                    EXISTS(
                        SELECT 1 FROM shift_auction_test_lots
                        WHERE claimed_by = %s AND shift_date = %s AND status = 'claimed'
                    ) AS has_shift_on_date,
                    COALESCE((
                        SELECT array_agg(DISTINCT shift_date ORDER BY shift_date)
                        FROM shift_auction_test_lots
                        WHERE shift_date IS NOT NULL
                    ), ARRAY[]::date[]) AS lot_dates,
                    COALESCE((
                        SELECT json_agg(json_build_object(
                            'shift_date', to_char(shift_date, 'YYYY-MM-DD'),
                            'start_time', to_char(start_time, 'HH24:MI'),
                            'end_time', to_char(end_time, 'HH24:MI'),
                            'breaks', breaks
                        ))
                        FROM shift_auction_test_lots
                        WHERE claimed_by = %s AND status = 'claimed'
                    ), '[]'::json) AS claimed_rows
            """, (operator_id, lot_date, operator_id, lot_date, operator_id))
            checks = cursor.fetchone()
            timings["checks"] = (time.perf_counter() - started_at) * 1000
            has_day_off, has_shift_on_date, lot_dates, claimed_rows_json = checks

            started_at = time.perf_counter()
            blocked_dates = self._get_shift_auction_operator_blocked_dates_tx(
                cursor, operator_id, lot_dates=list(lot_dates or [])
            )
            timings["blocked"] = (time.perf_counter() - started_at) * 1000
            blocked_date_map = {item["date"]: item for item in blocked_dates if item.get("date")}
            lot_date_key = lot_date.strftime('%Y-%m-%d') if lot_date else ''
            if lot_date_key and lot_date_key in blocked_date_map:
                raise ValueError("SHIFT_AUCTION_STATUS_PERIOD_BLOCKED")
            if has_day_off:
                raise ValueError("DAY_OFF_SELECTED")

            if is_topup_mode:
                # Top-up mode allows more than one shift per day as long as the
                # candidate does not overlap with the operator's existing
                # claims on the same date. The hard daily limit is replaced by
                # a precise time-interval overlap check.
                candidate_range = self._schedule_interval_minutes(lot[2], lot[3])
                conflicts = False
                for claimed in (claimed_rows_json or []):
                    if str(claimed.get('shift_date') or '') != lot_date_key:
                        continue
                    other_range = self._schedule_interval_minutes(
                        claimed.get('start_time'),
                        claimed.get('end_time')
                    )
                    if (
                        candidate_range[0] < other_range[1]
                        and other_range[0] < candidate_range[1]
                    ):
                        conflicts = True
                        break
                if conflicts:
                    raise ValueError("SHIFT_OVERLAPS_EXISTING")
            else:
                if has_shift_on_date:
                    raise ValueError("DAY_ALREADY_HAS_SHIFT")

            claimed_rows = [
                (row.get('start_time'), row.get('end_time'), row.get('breaks'))
                for row in (claimed_rows_json or [])
            ]
            workload = self._get_shift_auction_operator_workload_tx(
                cursor, operator_id, operator_rate,
                lot_dates=list(lot_dates or []),
                blocked_dates=blocked_dates,
                claimed_rows=claimed_rows
            )
            candidate_minutes = self._shift_auction_lot_minutes(
                lot[2],
                lot[3],
                lot[8] if isinstance(lot[8], list) else []
            )
            if (
                not is_topup_mode
                and workload["norm_minutes"] > 0
                and workload["claimed_net_minutes"] + candidate_minutes["net_minutes"] > workload["norm_minutes"] + 1
            ):
                raise ValueError("SHIFT_NORM_EXCEEDED")

            cas_started_at = time.perf_counter()
            cursor.execute("""
                UPDATE shift_auction_test_lots
                SET status = 'claimed',
                    claimed_by = %s,
                    claimed_at = CURRENT_TIMESTAMP,
                    updated_at = CURRENT_TIMESTAMP
                WHERE id = %s AND status = 'available'
                RETURNING id, shift_date, start_time, end_time, rate_min, status, claimed_by, claimed_at,
                          breaks, source_schedule_plan_id, source_schedule_shift_id
            """, (operator_id, lot_id))
            updated = cursor.fetchone()
            timings["cas_update"] = (time.perf_counter() - cas_started_at) * 1000
            if not updated:
                raise ValueError("LOT_ALREADY_CLAIMED")
            event_started_at = time.perf_counter()
            lot_payload = {
                "id": updated[0],
                "shift_date": updated[1].strftime('%Y-%m-%d') if updated[1] else None,
                "start_time": updated[2].strftime('%H:%M') if updated[2] else None,
                "end_time": updated[3].strftime('%H:%M') if updated[3] else None,
                "rate_min": float(updated[4] or 0),
                "status": updated[5],
                "claimed_by": updated[6],
                "claimed_at": updated[7].isoformat() if updated[7] else None,
                "breaks": updated[8] if isinstance(updated[8], list) else [],
                "source_schedule_plan_id": updated[9],
                "source_schedule_shift_id": updated[10],
            }
            event = self._insert_shift_auction_test_event(cursor, "lot_claimed", {"lot": lot_payload})
            timings["event"] = (time.perf_counter() - event_started_at) * 1000
            timings["write"] = timings["cas_update"] + timings["event"]
        return {"lot": lot_payload, "event": event, "_timings": timings}

    def release_shift_auction_test_lot(self, operator_id, lot_id):
        operator_id = int(operator_id)
        lot_id = int(lot_id)
        with self._get_cursor() as cursor:
            self._lock_shift_auction_operator_tx(cursor, operator_id)
            cursor.execute("""
                SELECT
                    s.enabled,
                    s.starts_at,
                    s.ends_at,
                    s.paused_at,
                    s.finished_at,
                    EXISTS(SELECT 1 FROM shift_auction_test_participants WHERE operator_id = %s) AS is_participant
                FROM shift_auction_test_access s
                WHERE s.id = 1
            """, (operator_id,))
            header = cursor.fetchone()
            if not header or self._get_shift_auction_test_status(header[0], header[1], header[2], header[3], header[4]) != "open":
                raise ValueError("AUCTION_NOT_OPEN")
            if not header[5]:
                raise ValueError("NOT_TEST_PARTICIPANT")

            cursor.execute("""
                SELECT id, shift_date, start_time, end_time, rate_min, status,
                       claimed_by, claimed_at, breaks, source_schedule_plan_id, source_schedule_shift_id,
                       COALESCE(post_auction_claimed, FALSE)
                FROM shift_auction_test_lots
                WHERE id = %s
                FOR UPDATE
            """, (lot_id,))
            lot = cursor.fetchone()
            if lot is None:
                raise ValueError("LOT_NOT_FOUND")
            if lot[5] != 'claimed':
                raise ValueError("LOT_NOT_CLAIMED")
            if lot[6] is None or int(lot[6]) != operator_id:
                raise ValueError("LOT_NOT_OWNED")
            if bool(lot[11]):
                raise ValueError("POST_AUCTION_LOT_NOT_RELEASABLE")

            cursor.execute("""
                UPDATE shift_auction_test_lots
                SET status = 'available',
                    claimed_by = NULL,
                    claimed_at = NULL,
                    updated_at = CURRENT_TIMESTAMP
                WHERE id = %s
                RETURNING id, shift_date, start_time, end_time, rate_min, status, claimed_by, claimed_at,
                          breaks, source_schedule_plan_id, source_schedule_shift_id
            """, (lot_id,))
            updated = cursor.fetchone()
            lot_payload = {
                "id": updated[0],
                "shift_date": updated[1].strftime('%Y-%m-%d') if updated[1] else None,
                "start_time": updated[2].strftime('%H:%M') if updated[2] else None,
                "end_time": updated[3].strftime('%H:%M') if updated[3] else None,
                "rate_min": float(updated[4] or 0),
                "status": updated[5],
                "claimed_by": updated[6],
                "claimed_at": updated[7].isoformat() if updated[7] else None,
                "breaks": updated[8] if isinstance(updated[8], list) else [],
                "source_schedule_plan_id": updated[9],
                "source_schedule_shift_id": updated[10],
            }
            event = self._insert_shift_auction_test_event(cursor, "lot_released", {
                "lot": lot_payload,
                "operator_id": operator_id
            })
        return {"lot": lot_payload, "event": event}

    def post_auction_claim_lot(self, operator_id, lot_id, claim_start_time=None, claim_end_time=None):
        """
        Забрать смену после окончания аукциона (после публикации в графики).
        Лот должен быть available или cancelled, смена ещё не началась,
        и не должен пересекаться (только TOUCH допустим) с реальными сменами оператора.
        Смена сразу сохраняется в work_shifts. Если стыкуется с соседней —
        соседние объединяются в одну, перерывы пересчитываются автоматически.
        """
        operator_id = int(operator_id)
        lot_id = int(lot_id)
        with self._get_cursor() as cursor:
            self._lock_shift_auction_operator_tx(cursor, operator_id)

            cursor.execute("""
                SELECT
                    s.published_to_work_schedules_at,
                    EXISTS(SELECT 1 FROM shift_auction_test_participants WHERE operator_id = %s) AS is_participant,
                    (
                        SELECT name FROM users WHERE id = %s
                    ) AS operator_name,
                    (
                        SELECT COALESCE(LOWER(role), '') FROM users WHERE id = %s
                    ) AS operator_role,
                    (
                        SELECT COALESCE(status, '') FROM users WHERE id = %s
                    ) AS operator_status
                FROM shift_auction_test_access s
                WHERE s.id = 1
            """, (operator_id, operator_id, operator_id, operator_id))
            header = cursor.fetchone()
            if not header:
                raise ValueError("AUCTION_NOT_AVAILABLE")
            if not header[0]:
                raise ValueError("POST_AUCTION_NOT_ACTIVE")
            if not header[1]:
                raise ValueError("NOT_TEST_PARTICIPANT")
            if header[3] != 'operator' or header[4] in ('fired', 'dismissal'):
                raise ValueError("OPERATOR_NOT_FOUND")
            operator_name = header[2] or f"Operator #{operator_id}"

            cursor.execute("""
                SELECT id, shift_date, start_time, end_time, rate_min, status,
                       claimed_by, claimed_at, breaks, source_schedule_plan_id, source_schedule_shift_id,
                       COALESCE(post_auction_claimed, FALSE)
                FROM shift_auction_test_lots
                WHERE id = %s
                FOR UPDATE
            """, (lot_id,))
            lot = cursor.fetchone()
            if not lot:
                raise ValueError("LOT_NOT_FOUND")
            if bool(lot[11]):
                raise ValueError("LOT_ALREADY_CLAIMED")
            if lot[5] not in ('available', 'cancelled'):
                raise ValueError("LOT_NOT_OPEN_FOR_POST_CLAIM")

            shift_date = lot[1]
            start_time = lot[2]
            end_time = lot[3]
            if shift_date is None or start_time is None or end_time is None:
                raise ValueError("LOT_INVALID")

            source_plan_id = int(lot[9]) if lot[9] is not None else None
            source_shift_id = int(lot[10]) if lot[10] is not None else None
            if source_shift_id:
                cursor.execute(
                    "SELECT pg_advisory_xact_lock(%s, %s)",
                    (self.SHIFT_AUCTION_SAVED_SHIFT_LOCK_NAMESPACE, source_shift_id)
                )

            claim_range = self._normalize_post_auction_claim_range(
                start_time,
                end_time,
                claim_start_time=claim_start_time,
                claim_end_time=claim_end_time
            )
            selected_start_time = claim_range["start_time"]
            selected_end_time = claim_range["end_time"]

            shift_start_date = shift_date + timedelta(days=1 if claim_range["start_minute"] >= 24 * 60 else 0)
            shift_start_dt = datetime.combine(shift_start_date, selected_start_time)
            if shift_start_dt <= datetime.now():
                raise ValueError("SHIFT_ALREADY_STARTED")

            blocked_dates = self._get_shift_auction_operator_blocked_dates_tx(
                cursor, operator_id, lot_dates=[shift_date]
            )
            lot_date_key = shift_date.strftime('%Y-%m-%d')
            if any((item.get("date") or '') == lot_date_key for item in blocked_dates):
                raise ValueError("SHIFT_AUCTION_STATUS_PERIOD_BLOCKED")

            cursor.execute(
                "SELECT 1 FROM days_off WHERE operator_id = %s AND day_off_date = %s",
                (operator_id, shift_date)
            )
            day_off_row = cursor.fetchone()

            new_start_min = claim_range["start_minute"]
            new_end_min = claim_range["end_minute"]

            cursor.execute("""
                SELECT id, start_time, end_time
                FROM work_shifts
                WHERE operator_id = %s AND shift_date = %s
                ORDER BY start_time
            """, (operator_id, shift_date))
            existing_shifts = cursor.fetchall() or []

            merged_start_min, merged_end_min, merge_ids = self._resolve_post_auction_merged_shift_range(
                existing_shifts,
                new_start_min,
                new_end_min
            )

            # SINGLE-LOT model for partial доборы: the shift stays ONE lot. Each taken
            # piece is recorded in shift_auction_historical_claims (several operators may
            # take disjoint parts). The lot only becomes fully 'claimed' once every minute
            # is covered; otherwise it stays 'available' and shows the free part.
            existing_claims = []
            if source_plan_id and source_shift_id:
                cursor.execute("""
                    SELECT claimed_by, claimed_start_time, claimed_end_time
                    FROM shift_auction_historical_claims
                    WHERE plan_id = %s AND source_schedule_shift_id = %s
                    FOR UPDATE
                """, (source_plan_id, source_shift_id))
                existing_claims = cursor.fetchall() or []
                for ex_by, ex_start, ex_end in existing_claims:
                    if ex_by is not None and int(ex_by) == operator_id:
                        raise ValueError("LOT_ALREADY_CLAIMED")
                    if ex_start is None or ex_end is None:
                        raise ValueError("LOT_ALREADY_CLAIMED")
                    ex_range = self._normalize_post_auction_claim_range(
                        start_time, end_time, ex_start.strftime('%H:%M'), ex_end.strftime('%H:%M')
                    )
                    if new_start_min < ex_range["end_minute"] and ex_range["start_minute"] < new_end_min:
                        raise ValueError("SHIFT_OVERLAPS_EXISTING")
                cursor.execute("""
                    INSERT INTO shift_auction_historical_claims
                        (plan_id, source_schedule_shift_id, claimed_by, claimed_at, claimed_start_time, claimed_end_time)
                    VALUES (%s, %s, %s, CURRENT_TIMESTAMP, %s, %s)
                    ON CONFLICT (plan_id, source_schedule_shift_id, claimed_by) DO NOTHING
                """, (source_plan_id, source_shift_id, operator_id, selected_start_time, selected_end_time))

            # Does this claim complete the shift? (no source shift = single-claim lot)
            full_start_min, full_end_min = self._schedule_interval_minutes(start_time, end_time)
            claimed_ranges = [(new_start_min, new_end_min)]
            for ex_by, ex_start, ex_end in existing_claims:
                if ex_start is None or ex_end is None:
                    continue
                ex_range = self._normalize_post_auction_claim_range(
                    start_time, end_time, ex_start.strftime('%H:%M'), ex_end.strftime('%H:%M')
                )
                claimed_ranges.append((ex_range["start_minute"], ex_range["end_minute"]))
            free_gaps = [g for g in self._subtract_ranges(full_start_min, full_end_min, claimed_ranges) if g[1] - g[0] > 0]
            fully_covered = (not source_shift_id) or (not free_gaps)

            if fully_covered:
                cursor.execute("""
                    UPDATE shift_auction_test_lots
                    SET status = 'claimed',
                        claimed_by = %s,
                        claimed_at = CURRENT_TIMESTAMP,
                        post_auction_claimed = TRUE,
                        post_claim_start_time = %s,
                        post_claim_end_time = %s,
                        updated_at = CURRENT_TIMESTAMP
                    WHERE id = %s AND status IN ('available', 'cancelled')
                    RETURNING id, shift_date, start_time, end_time, rate_min, status, claimed_by, claimed_at,
                              breaks, source_schedule_plan_id, source_schedule_shift_id,
                              COALESCE(post_auction_claimed, FALSE), post_claim_start_time, post_claim_end_time
                """, (operator_id, selected_start_time, selected_end_time, lot_id))
            else:
                # Partial: keep the lot available so others can take the rest.
                cursor.execute("""
                    UPDATE shift_auction_test_lots
                    SET updated_at = CURRENT_TIMESTAMP
                    WHERE id = %s AND status IN ('available', 'cancelled')
                    RETURNING id, shift_date, start_time, end_time, rate_min, status, claimed_by, claimed_at,
                              breaks, source_schedule_plan_id, source_schedule_shift_id,
                              COALESCE(post_auction_claimed, FALSE), post_claim_start_time, post_claim_end_time
                """, (lot_id,))
            updated = cursor.fetchone()
            if not updated:
                raise ValueError("LOT_ALREADY_CLAIMED")

            if day_off_row:
                cursor.execute(
                    "DELETE FROM days_off WHERE operator_id = %s AND day_off_date = %s",
                    (operator_id, shift_date)
                )

            if merge_ids:
                cursor.execute("DELETE FROM work_shifts WHERE id = ANY(%s)", (merge_ids,))
                merged_start_obj = self._normalize_schedule_time(
                    _minutes_to_time(merged_start_min % (24 * 60)), 'start'
                )
                merged_end_obj = self._normalize_schedule_time(
                    _minutes_to_time(merged_end_min),
                    'end'
                )
                self._save_shift_tx(
                    cursor=cursor,
                    operator_id=operator_id,
                    shift_date=shift_date,
                    start_time=merged_start_obj,
                    end_time=merged_end_obj,
                    breaks=None,
                    shift_type=None,
                )
            else:
                self._save_shift_tx(
                    cursor=cursor,
                    operator_id=operator_id,
                    shift_date=shift_date,
                    start_time=selected_start_time,
                    end_time=selected_end_time,
                    breaks=None,
                    shift_type=None,
                )

            self._recalculate_auto_daily_hours_tx(
                cursor=cursor,
                operator_ids=[operator_id],
                start_date=shift_date,
                end_date=shift_date
            )

            lot_payload = {
                "id": updated[0],
                "shift_date": updated[1].strftime('%Y-%m-%d') if updated[1] else None,
                "start_time": updated[2].strftime('%H:%M') if updated[2] else None,
                "end_time": updated[3].strftime('%H:%M') if updated[3] else None,
                "rate_min": float(updated[4] or 0),
                "status": updated[5],
                "claimed_by": updated[6],
                "claimed_at": updated[7].isoformat() if updated[7] else None,
                "breaks": updated[8] if isinstance(updated[8], list) else [],
                "source_schedule_plan_id": updated[9],
                "source_schedule_shift_id": updated[10],
                "post_auction_claimed": bool(updated[11]),
                # The journal / Telegram / monitoring need the part this operator took,
                # even for a partial claim where the lot stays available (post_claim NULL).
                "claim_start_time": (updated[12].strftime('%H:%M') if updated[12] else (selected_start_time.strftime('%H:%M') if selected_start_time else None)),
                "claim_end_time": (updated[13].strftime('%H:%M') if updated[13] else (selected_end_time.strftime('%H:%M') if selected_end_time else None)),
            }
            event = self._insert_shift_auction_test_event(cursor, "lot_post_auction_claimed", {
                "lot": lot_payload,
                "operator_id": operator_id,
                "operator_name": operator_name,
                "merged_with_existing": bool(merge_ids),
            })

        return {
            "lot": lot_payload,
            "event": event,
            "operator": {"id": operator_id, "name": operator_name},
            "merged_with_existing": bool(merge_ids),
        }

    def post_auction_claim_saved_shift(self, operator_id, schedule_plan_id, source_schedule_shift_id, claim_start_time=None, claim_end_time=None):
        """
        Забор смены из УЖЕ ОПУБЛИКОВАННОГО прошлого периода (исторический добор).
        Источник правды о занятости — таблица shift_auction_historical_claims
        с уникальным ключом (plan_id, source_schedule_shift_id): двойной claim
        отлавливается атомарно на уровне БД, без сканирования журнала событий.
        """
        operator_id = int(operator_id)
        schedule_plan_id = int(schedule_plan_id)
        source_schedule_shift_id = int(source_schedule_shift_id)
        if schedule_plan_id <= 0 or source_schedule_shift_id <= 0:
            raise ValueError("LOT_NOT_FOUND")

        with self._get_cursor() as cursor:
            self._lock_shift_auction_operator_tx(cursor, operator_id)
            cursor.execute(
                "SELECT pg_advisory_xact_lock(%s, %s)",
                (self.SHIFT_AUCTION_SAVED_SHIFT_LOCK_NAMESPACE, source_schedule_shift_id)
            )

            cursor.execute("""
                SELECT plan_id, date_from, date_to, participant_ids
                FROM shift_auction_published_periods
                WHERE plan_id = %s
            """, (schedule_plan_id,))
            period_row = cursor.fetchone()
            if not period_row:
                raise ValueError("POST_AUCTION_NOT_ACTIVE")
            plan_id = int(period_row[0])
            participant_ids = set(int(x) for x in (period_row[3] or []) if x is not None)

            cursor.execute("""
                SELECT selected_schedule_plan_id
                FROM shift_auction_test_access
                WHERE id = 1
            """)
            settings_row = cursor.fetchone()
            current_plan_id = None
            try:
                current_plan_id = int(settings_row[0]) if settings_row and settings_row[0] is not None else None
            except Exception:
                current_plan_id = None
            if current_plan_id == plan_id:
                participant_ids.update(self._get_shift_auction_participant_ids_cached_tx(cursor))
            if operator_id not in participant_ids:
                raise ValueError("NOT_TEST_PARTICIPANT")

            cursor.execute("""
                SELECT u.name, u.role, COALESCE(u.status, ''), u.direction_id, d.name AS direction_name
                FROM users u
                LEFT JOIN directions d ON d.id = u.direction_id
                WHERE u.id = %s
            """, (operator_id,))
            operator_row = cursor.fetchone()
            if (
                not operator_row
                or normalize_role_value(operator_row[1]) != 'operator'
                or str(operator_row[2] or '').strip().lower() in ('fired', 'dismissal')
            ):
                raise ValueError("OPERATOR_NOT_FOUND")
            operator_name = operator_row[0] or f"Operator #{operator_id}"

            cursor.execute("""
                SELECT id, shift_date, start_time, end_time, rate_min, breaks, start_minute, end_minute
                FROM resource_saved_schedule_shifts
                WHERE id = %s
                  AND plan_id = %s
                  AND COALESCE(meta->>'excludeFromAuction', 'false') <> 'true'
                FOR UPDATE
            """, (source_schedule_shift_id, plan_id))
            saved_shift = cursor.fetchone()
            if not saved_shift:
                raise ValueError("LOT_NOT_FOUND")

            shift_date = saved_shift[1]
            start_time = saved_shift[2]
            end_time = saved_shift[3]
            if shift_date is None or start_time is None or end_time is None:
                raise ValueError("LOT_INVALID")

            claim_range = self._normalize_post_auction_claim_range(
                start_time,
                end_time,
                claim_start_time=claim_start_time,
                claim_end_time=claim_end_time
            )
            selected_start_time = claim_range["start_time"]
            selected_end_time = claim_range["end_time"]

            shift_start_date = shift_date + timedelta(days=1 if claim_range["start_minute"] >= 24 * 60 else 0)
            shift_start_dt = datetime.combine(shift_start_date, selected_start_time)
            if shift_start_dt <= datetime.now():
                raise ValueError("SHIFT_ALREADY_STARTED")

            blocked_dates = self._get_shift_auction_operator_blocked_dates_tx(
                cursor, operator_id, lot_dates=[shift_date]
            )
            lot_date_key = shift_date.strftime('%Y-%m-%d')
            if any((item.get("date") or '') == lot_date_key for item in blocked_dates):
                raise ValueError("SHIFT_AUCTION_STATUS_PERIOD_BLOCKED")

            # Disjoint partial доборы are allowed: several operators may each take a
            # non-overlapping slice of the same shift. Reject only if the requested
            # range overlaps an existing claim (or a full-shift claim already exists).
            cursor.execute("""
                SELECT claimed_by, claimed_start_time, claimed_end_time
                FROM shift_auction_historical_claims
                WHERE plan_id = %s AND source_schedule_shift_id = %s
                FOR UPDATE
            """, (plan_id, source_schedule_shift_id))
            existing_claims = cursor.fetchall() or []
            req_start_min = claim_range["start_minute"]
            req_end_min = claim_range["end_minute"]
            for ex_by, ex_start, ex_end in existing_claims:
                if ex_by is not None and int(ex_by) == operator_id:
                    raise ValueError("LOT_ALREADY_CLAIMED")
                if ex_start is None or ex_end is None:
                    raise ValueError("LOT_ALREADY_CLAIMED")
                ex_range = self._normalize_post_auction_claim_range(
                    start_time, end_time,
                    ex_start.strftime('%H:%M'), ex_end.strftime('%H:%M')
                )
                if req_start_min < ex_range["end_minute"] and ex_range["start_minute"] < req_end_min:
                    raise ValueError("LOT_ALREADY_CLAIMED")

            cursor.execute("""
                INSERT INTO shift_auction_historical_claims
                    (plan_id, source_schedule_shift_id, claimed_by, claimed_at, claimed_start_time, claimed_end_time)
                VALUES (%s, %s, %s, CURRENT_TIMESTAMP, %s, %s)
                ON CONFLICT (plan_id, source_schedule_shift_id, claimed_by) DO NOTHING
                RETURNING claimed_at
            """, (plan_id, source_schedule_shift_id, operator_id, selected_start_time, selected_end_time))
            claim_row = cursor.fetchone()
            if not claim_row:
                raise ValueError("LOT_ALREADY_CLAIMED")
            claimed_at = claim_row[0]

            cursor.execute(
                "SELECT 1 FROM days_off WHERE operator_id = %s AND day_off_date = %s",
                (operator_id, shift_date)
            )
            day_off_row = cursor.fetchone()

            new_start_min = claim_range["start_minute"]
            new_end_min = claim_range["end_minute"]

            cursor.execute("""
                SELECT id, start_time, end_time
                FROM work_shifts
                WHERE operator_id = %s AND shift_date = %s
                ORDER BY start_time
            """, (operator_id, shift_date))
            existing_shifts = cursor.fetchall() or []

            merged_start_min, merged_end_min, merge_ids = self._resolve_post_auction_merged_shift_range(
                existing_shifts,
                new_start_min,
                new_end_min
            )

            if day_off_row:
                cursor.execute(
                    "DELETE FROM days_off WHERE operator_id = %s AND day_off_date = %s",
                    (operator_id, shift_date)
                )

            if merge_ids:
                cursor.execute("DELETE FROM work_shifts WHERE id = ANY(%s)", (merge_ids,))
                merged_start_obj = self._normalize_schedule_time(
                    _minutes_to_time(merged_start_min % (24 * 60)), 'start'
                )
                merged_end_obj = self._normalize_schedule_time(
                    _minutes_to_time(merged_end_min),
                    'end'
                )
                self._save_shift_tx(
                    cursor=cursor,
                    operator_id=operator_id,
                    shift_date=shift_date,
                    start_time=merged_start_obj,
                    end_time=merged_end_obj,
                    breaks=None,
                    shift_type=None,
                )
            else:
                self._save_shift_tx(
                    cursor=cursor,
                    operator_id=operator_id,
                    shift_date=shift_date,
                    start_time=selected_start_time,
                    end_time=selected_end_time,
                    breaks=None,
                    shift_type=None,
                )

            self._recalculate_auto_daily_hours_tx(
                cursor=cursor,
                operator_ids=[operator_id],
                start_date=shift_date,
                end_date=shift_date
            )

            breaks = saved_shift[5] if isinstance(saved_shift[5], list) else []
            lot_payload = {
                "id": f"preview-{int(saved_shift[0])}",
                "shift_date": shift_date.strftime('%Y-%m-%d') if shift_date else None,
                "start_time": start_time.strftime('%H:%M') if start_time else None,
                "end_time": end_time.strftime('%H:%M') if end_time else None,
                "rate_min": float(saved_shift[4] or 0),
                "status": "claimed",
                "claimed_by": operator_id,
                "claimed_by_name": operator_name,
                "claimed_at": claimed_at.isoformat() if claimed_at else None,
                "breaks": breaks,
                "source_schedule_plan_id": plan_id,
                "source_schedule_shift_id": int(saved_shift[0]),
                "post_auction_claimed": True,
                "claim_start_time": selected_start_time.strftime('%H:%M') if selected_start_time else None,
                "claim_end_time": selected_end_time.strftime('%H:%M') if selected_end_time else None,
                "claimed_by_direction_id": operator_row[3],
                "claimed_by_direction": operator_row[4] or "",
                "source_start_minute": int(saved_shift[6]) if saved_shift[6] is not None else None,
                "source_end_minute": int(saved_shift[7]) if saved_shift[7] is not None else None,
                "preview_only": True,
            }
            event = self._insert_shift_auction_test_event(cursor, "lot_post_auction_claimed", {
                "lot": lot_payload,
                "operator_id": operator_id,
                "operator_name": operator_name,
                "merged_with_existing": bool(merge_ids),
                "historical_period_claim": True,
            })

        return {
            "lot": lot_payload,
            "event": event,
            "operator": {"id": operator_id, "name": operator_name},
            "merged_with_existing": bool(merge_ids),
        }

    def admin_unclaim_shift(self, admin_id, lot_id=None, plan_id=None, source_schedule_shift_id=None, claimed_by=None):
        """
        Снять claim с лота админом — для таблицы смен.
        Принимает либо lot_id (активный план), либо (plan_id, source_schedule_shift_id)
        (исторический добор). claimed_by адресует КОНКРЕТНЫЙ частичный claim, если на
        смене их несколько. Удаляет work_shifts если есть.
        """
        try:
            admin_id = int(admin_id) if admin_id is not None else None
        except Exception:
            admin_id = None
        try:
            lot_id_int = int(lot_id) if lot_id not in (None, '') else None
        except Exception:
            lot_id_int = None
        try:
            plan_id_int = int(plan_id) if plan_id not in (None, '') else None
        except Exception:
            plan_id_int = None
        try:
            shift_id_int = int(source_schedule_shift_id) if source_schedule_shift_id not in (None, '') else None
        except Exception:
            shift_id_int = None
        try:
            target_claimed_by = int(claimed_by) if claimed_by not in (None, '') else None
        except Exception:
            target_claimed_by = None

        with self._get_cursor() as cursor:
            shift_date = None
            start_time = None
            end_time = None
            operator_id = None
            resolved_plan_id = plan_id_int
            resolved_shift_id = shift_id_int

            if lot_id_int:
                cursor.execute("""
                    SELECT id, shift_date, start_time, end_time, claimed_by,
                           source_schedule_plan_id, source_schedule_shift_id, status,
                           post_claim_start_time, post_claim_end_time
                    FROM shift_auction_test_lots
                    WHERE id = %s
                    FOR UPDATE
                """, (lot_id_int,))
                lot = cursor.fetchone()
                if not lot:
                    raise ValueError("LOT_NOT_FOUND")
                if lot[7] != 'claimed' or lot[4] is None:
                    raise ValueError("LOT_NOT_CLAIMED")
                shift_date = lot[1]
                start_time = lot[8] or lot[2]
                end_time = lot[9] or lot[3]
                operator_id = int(lot[4])
                resolved_plan_id = int(lot[5]) if lot[5] is not None else resolved_plan_id
                resolved_shift_id = int(lot[6]) if lot[6] is not None else resolved_shift_id

                if resolved_shift_id:
                    cursor.execute(
                        "SELECT pg_advisory_xact_lock(%s, %s)",
                        (self.SHIFT_AUCTION_SAVED_SHIFT_LOCK_NAMESPACE, resolved_shift_id)
                    )
                self._lock_shift_auction_operator_tx(cursor, operator_id)

                cursor.execute("""
                    UPDATE shift_auction_test_lots
                    SET status = 'available',
                        claimed_by = NULL,
                        claimed_at = NULL,
                        post_auction_claimed = FALSE,
                        post_claim_start_time = NULL,
                        post_claim_end_time = NULL,
                        updated_at = CURRENT_TIMESTAMP
                    WHERE id = %s
                """, (lot_id_int,))

                # Reconcile any remainder lots that were split off from this lot during
                # a partial добор (see _create_post_auction_remainder_lots).
                cursor.execute("""
                    SELECT COUNT(*) FROM shift_auction_test_lots
                    WHERE remainder_of_lot_id = %s AND status = 'claimed'
                """, (lot_id_int,))
                claimed_remainders = (cursor.fetchone() or [0])[0]
                if claimed_remainders:
                    # Another operator already took part of the leftover — keep their lots
                    # and shrink this restored lot back to the slice it actually occupied,
                    # so the full window is not offered on top of an active claim.
                    if lot[8] and lot[9]:
                        cursor.execute("""
                            UPDATE shift_auction_test_lots
                            SET start_time = %s,
                                end_time = %s,
                                source_schedule_shift_id = NULL,
                                updated_at = CURRENT_TIMESTAMP
                            WHERE id = %s
                        """, (lot[8], lot[9], lot_id_int))
                else:
                    # Nobody picked up the leftover — fold the free remainder lots back
                    # into the original lot, which again covers the full window.
                    cursor.execute("""
                        DELETE FROM shift_auction_test_lots
                        WHERE remainder_of_lot_id = %s AND status = 'available'
                    """, (lot_id_int,))
            else:
                if not (resolved_plan_id and resolved_shift_id):
                    raise ValueError("MISSING_TARGET")
                cursor.execute(
                    "SELECT pg_advisory_xact_lock(%s, %s)",
                    (self.SHIFT_AUCTION_SAVED_SHIFT_LOCK_NAMESPACE, resolved_shift_id)
                )
                cursor.execute("""
                    SELECT shift_date, start_time, end_time
                    FROM resource_saved_schedule_shifts
                    WHERE id = %s AND plan_id = %s
                """, (resolved_shift_id, resolved_plan_id))
                saved = cursor.fetchone()
                if not saved:
                    raise ValueError("SHIFT_NOT_FOUND")
                shift_date, start_time, end_time = saved[0], saved[1], saved[2]
                if target_claimed_by:
                    cursor.execute("""
                        SELECT claimed_by, claimed_start_time, claimed_end_time FROM shift_auction_historical_claims
                        WHERE plan_id = %s AND source_schedule_shift_id = %s AND claimed_by = %s
                        FOR UPDATE
                    """, (resolved_plan_id, resolved_shift_id, target_claimed_by))
                else:
                    cursor.execute("""
                        SELECT claimed_by, claimed_start_time, claimed_end_time FROM shift_auction_historical_claims
                        WHERE plan_id = %s AND source_schedule_shift_id = %s
                        ORDER BY claimed_start_time NULLS FIRST
                        FOR UPDATE
                    """, (resolved_plan_id, resolved_shift_id))
                row = cursor.fetchone()
                if not row:
                    raise ValueError("LOT_NOT_CLAIMED")
                operator_id = int(row[0])
                start_time = row[1] or start_time
                end_time = row[2] or end_time
                self._lock_shift_auction_operator_tx(cursor, operator_id)
                cursor.execute("""
                    UPDATE shift_auction_test_lots
                    SET status = 'available',
                        claimed_by = NULL,
                        claimed_at = NULL,
                        post_auction_claimed = FALSE,
                        post_claim_start_time = NULL,
                        post_claim_end_time = NULL,
                        updated_at = CURRENT_TIMESTAMP
                    WHERE source_schedule_plan_id = %s
                      AND source_schedule_shift_id = %s
                      AND status = 'claimed'
                """, (resolved_plan_id, resolved_shift_id))

            if resolved_plan_id and resolved_shift_id:
                # Remove only THIS operator's claim so other operators' disjoint
                # partial доборы of the same shift stay intact.
                if operator_id:
                    cursor.execute("""
                        DELETE FROM shift_auction_historical_claims
                        WHERE plan_id = %s AND source_schedule_shift_id = %s AND claimed_by = %s
                    """, (resolved_plan_id, resolved_shift_id, operator_id))
                else:
                    cursor.execute("""
                        DELETE FROM shift_auction_historical_claims
                        WHERE plan_id = %s AND source_schedule_shift_id = %s
                    """, (resolved_plan_id, resolved_shift_id))

            if operator_id and shift_date and start_time and end_time:
                cursor.execute("""
                    DELETE FROM work_shifts
                    WHERE operator_id = %s
                      AND shift_date = %s
                      AND start_time = %s
                      AND end_time = %s
                """, (operator_id, shift_date, start_time, end_time))
                self._recalculate_auto_daily_hours_tx(
                    cursor=cursor,
                    operator_ids=[operator_id],
                    start_date=shift_date,
                    end_date=shift_date
                )

            event_payload = {
                "operator_id": operator_id,
                "lot_id": lot_id_int,
                "plan_id": resolved_plan_id,
                "source_schedule_shift_id": resolved_shift_id,
                "shift_date": shift_date.strftime('%Y-%m-%d') if hasattr(shift_date, 'strftime') else None,
                "start_time": start_time.strftime('%H:%M') if hasattr(start_time, 'strftime') else None,
                "end_time": end_time.strftime('%H:%M') if hasattr(end_time, 'strftime') else None,
                "admin_id": admin_id,
            }
            event = self._insert_shift_auction_test_event(cursor, "lot_admin_unclaimed", event_payload)

        return {
            "operator_id": operator_id,
            "lot_id": lot_id_int,
            "plan_id": resolved_plan_id,
            "source_schedule_shift_id": resolved_shift_id,
            "shift_date": event_payload["shift_date"],
            "start_time": event_payload["start_time"],
            "end_time": event_payload["end_time"],
            "event": event,
        }

    def get_operator_recent_post_auction_claims(self, operator_id, window_hours=24, limit=30, cancel_window_minutes=10):
        """
        Список НЕДАВНИХ доборов оператора (взятых доп. смен) за последние
        window_hours часов, новые сверху. Используется панелью «Мои доборы»:
        оператор видит, что он взял, и может отменить смену, если с момента
        взятия прошло не больше cancel_window_minutes (по умолчанию 10 минут).

        Объединяет два источника:
          • shift_auction_historical_claims — доборы с исходной сменой (как из
            активного периода, так и из опубликованных прошлых периодов);
          • shift_auction_test_lots — синтетические лоты без исходной смены.

        cancel_seconds_left считается на часах БД (CURRENT_TIMESTAMP) — один
        источник времени, чтобы отсчёт на клиенте не зависел от рассинхронизации
        часов браузера.
        """
        try:
            operator_id = int(operator_id)
        except Exception:
            return []
        window_hours = int(window_hours) if window_hours else 24
        limit = max(1, int(limit) if limit else 30)
        cancel_window_minutes = int(cancel_window_minutes) if cancel_window_minutes else 10

        def _fmt_time(value):
            return value.strftime('%H:%M') if hasattr(value, 'strftime') else None

        entries = []
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT hc.plan_id, hc.source_schedule_shift_id, hc.claimed_at,
                       hc.claimed_start_time, hc.claimed_end_time,
                       s.shift_date, s.start_time, s.end_time, s.rate_min,
                       l.id AS lot_id,
                       GREATEST(0, EXTRACT(EPOCH FROM (
                           hc.claimed_at + (%s * INTERVAL '1 minute') - CURRENT_TIMESTAMP
                       )))::int AS cancel_seconds_left
                FROM shift_auction_historical_claims hc
                JOIN resource_saved_schedule_shifts s
                  ON s.id = hc.source_schedule_shift_id AND s.plan_id = hc.plan_id
                LEFT JOIN shift_auction_test_lots l
                  ON l.source_schedule_plan_id = hc.plan_id
                 AND l.source_schedule_shift_id = hc.source_schedule_shift_id
                WHERE hc.claimed_by = %s
                  AND hc.claimed_at >= CURRENT_TIMESTAMP - (%s * INTERVAL '1 hour')
                ORDER BY hc.claimed_at DESC
                LIMIT %s
            """, (cancel_window_minutes, operator_id, window_hours, limit))
            for row in (cursor.fetchall() or []):
                claimed_at = row[2]
                seconds_left = int(row[10] or 0)
                entries.append({
                    "_claimed_at": claimed_at,
                    "lot_id": int(row[9]) if row[9] is not None else None,
                    "plan_id": int(row[0]) if row[0] is not None else None,
                    "source_schedule_shift_id": int(row[1]) if row[1] is not None else None,
                    "shift_date": row[5].strftime('%Y-%m-%d') if row[5] else None,
                    "start_time": _fmt_time(row[3]) or _fmt_time(row[6]),
                    "end_time": _fmt_time(row[4]) or _fmt_time(row[7]),
                    "rate_min": float(row[8]) if row[8] is not None else 0.0,
                    "claimed_at": claimed_at.isoformat() if claimed_at else None,
                    "cancel_seconds_left": seconds_left,
                    "can_cancel": seconds_left > 0,
                })

            cursor.execute("""
                SELECT l.id, l.shift_date, l.start_time, l.end_time, l.rate_min,
                       l.claimed_at, l.post_claim_start_time, l.post_claim_end_time,
                       GREATEST(0, EXTRACT(EPOCH FROM (
                           l.claimed_at + (%s * INTERVAL '1 minute') - CURRENT_TIMESTAMP
                       )))::int AS cancel_seconds_left
                FROM shift_auction_test_lots l
                WHERE l.claimed_by = %s
                  AND COALESCE(l.post_auction_claimed, FALSE) = TRUE
                  AND l.source_schedule_shift_id IS NULL
                  AND l.claimed_at IS NOT NULL
                  AND l.claimed_at >= CURRENT_TIMESTAMP - (%s * INTERVAL '1 hour')
                ORDER BY l.claimed_at DESC
                LIMIT %s
            """, (cancel_window_minutes, operator_id, window_hours, limit))
            for row in (cursor.fetchall() or []):
                claimed_at = row[5]
                seconds_left = int(row[8] or 0)
                entries.append({
                    "_claimed_at": claimed_at,
                    "lot_id": int(row[0]) if row[0] is not None else None,
                    "plan_id": None,
                    "source_schedule_shift_id": None,
                    "shift_date": row[1].strftime('%Y-%m-%d') if row[1] else None,
                    "start_time": _fmt_time(row[6]) or _fmt_time(row[2]),
                    "end_time": _fmt_time(row[7]) or _fmt_time(row[3]),
                    "rate_min": float(row[4]) if row[4] is not None else 0.0,
                    "claimed_at": claimed_at.isoformat() if claimed_at else None,
                    "cancel_seconds_left": seconds_left,
                    "can_cancel": seconds_left > 0,
                })

        entries.sort(key=lambda item: item["_claimed_at"] or datetime.min, reverse=True)
        entries = entries[:limit]
        for item in entries:
            item.pop("_claimed_at", None)
        return entries

    def operator_cancel_post_auction_claim(self, operator_id, lot_id=None, plan_id=None,
                                           source_schedule_shift_id=None, cancel_window_minutes=10):
        """
        Оператор сам отменяет недавно взятую дополнительную смену (добор), если с
        момента взятия прошло не больше cancel_window_minutes (по умолчанию 10).
        Смена возвращается в доступные и убирается из графика. Это «зеркало»
        admin_unclaim_shift, но строго для СВОЕГО claim'а и с лимитом по времени.
        Окно проверяется по часам БД (CURRENT_TIMESTAMP), а не по часам клиента.

        Смена убирается из графика «разъединением» (_split_post_auction_shift_slice_tx):
        если добор был слит с соседней сменой, отрезок добора вычитается, а оставшиеся
        части пересоздаются с пересчётом перерывов по текущим правилам направления.
        """
        operator_id = int(operator_id)
        try:
            lot_id_int = int(lot_id) if lot_id not in (None, '') else None
        except Exception:
            lot_id_int = None
        try:
            plan_id_int = int(plan_id) if plan_id not in (None, '') else None
        except Exception:
            plan_id_int = None
        try:
            shift_id_int = int(source_schedule_shift_id) if source_schedule_shift_id not in (None, '') else None
        except Exception:
            shift_id_int = None
        cancel_window_minutes = int(cancel_window_minutes) if cancel_window_minutes else 10

        with self._get_cursor() as cursor:
            self._lock_shift_auction_operator_tx(cursor, operator_id)

            shift_date = None
            start_time = None
            end_time = None
            claimed_at = None
            resolved_plan_id = plan_id_int
            resolved_shift_id = shift_id_int
            used_lot_id = None

            if resolved_plan_id and resolved_shift_id:
                # Добор с исходной сменой — источник правды shift_auction_historical_claims.
                cursor.execute(
                    "SELECT pg_advisory_xact_lock(%s, %s)",
                    (self.SHIFT_AUCTION_SAVED_SHIFT_LOCK_NAMESPACE, resolved_shift_id)
                )
                cursor.execute("""
                    SELECT claimed_at, claimed_start_time, claimed_end_time
                    FROM shift_auction_historical_claims
                    WHERE plan_id = %s AND source_schedule_shift_id = %s AND claimed_by = %s
                    FOR UPDATE
                """, (resolved_plan_id, resolved_shift_id, operator_id))
                claim_row = cursor.fetchone()
                if not claim_row:
                    raise ValueError("CLAIM_NOT_FOUND")
                claimed_at = claim_row[0]
                cursor.execute("""
                    SELECT shift_date, start_time, end_time
                    FROM resource_saved_schedule_shifts
                    WHERE id = %s AND plan_id = %s
                """, (resolved_shift_id, resolved_plan_id))
                saved = cursor.fetchone()
                if not saved:
                    raise ValueError("SHIFT_NOT_FOUND")
                shift_date = saved[0]
                start_time = claim_row[1] or saved[1]
                end_time = claim_row[2] or saved[2]
            elif lot_id_int:
                # Синтетический лот активного плана без исходной смены.
                cursor.execute("""
                    SELECT shift_date, start_time, end_time, claimed_by, claimed_at, status,
                           source_schedule_plan_id, source_schedule_shift_id,
                           post_claim_start_time, post_claim_end_time,
                           COALESCE(post_auction_claimed, FALSE)
                    FROM shift_auction_test_lots
                    WHERE id = %s
                    FOR UPDATE
                """, (lot_id_int,))
                lot = cursor.fetchone()
                if not lot:
                    raise ValueError("LOT_NOT_FOUND")
                if lot[5] != 'claimed' or lot[3] is None:
                    raise ValueError("LOT_NOT_CLAIMED")
                if int(lot[3]) != operator_id:
                    raise ValueError("LOT_NOT_OWNED")
                if not bool(lot[10]):
                    # Отменять так можно только пост-аукционные доборы; обычный
                    # claim во время аукциона возвращается через release.
                    raise ValueError("POST_AUCTION_LOT_NOT_RELEASABLE")
                used_lot_id = lot_id_int
                shift_date = lot[0]
                start_time = lot[8] or lot[1]
                end_time = lot[9] or lot[2]
                claimed_at = lot[4]
                resolved_plan_id = int(lot[6]) if lot[6] is not None else None
                resolved_shift_id = int(lot[7]) if lot[7] is not None else None
                if resolved_shift_id:
                    cursor.execute(
                        "SELECT pg_advisory_xact_lock(%s, %s)",
                        (self.SHIFT_AUCTION_SAVED_SHIFT_LOCK_NAMESPACE, resolved_shift_id)
                    )
            else:
                raise ValueError("MISSING_TARGET")

            if claimed_at is None:
                raise ValueError("CLAIM_NOT_FOUND")

            # Окно отмены — авторитетно по часам БД.
            cursor.execute(
                "SELECT (%s + (%s * INTERVAL '1 minute')) < CURRENT_TIMESTAMP",
                (claimed_at, cancel_window_minutes)
            )
            window_expired = bool((cursor.fetchone() or [True])[0])
            if window_expired:
                raise ValueError("CANCEL_WINDOW_EXPIRED")

            # Возвращаем лот(ы) в доступные.
            if used_lot_id and not (resolved_plan_id and resolved_shift_id):
                cursor.execute("""
                    UPDATE shift_auction_test_lots
                    SET status = 'available', claimed_by = NULL, claimed_at = NULL,
                        post_auction_claimed = FALSE, post_claim_start_time = NULL,
                        post_claim_end_time = NULL, updated_at = CURRENT_TIMESTAMP
                    WHERE id = %s
                """, (used_lot_id,))

            if resolved_plan_id and resolved_shift_id:
                cursor.execute("""
                    UPDATE shift_auction_test_lots
                    SET status = 'available', claimed_by = NULL, claimed_at = NULL,
                        post_auction_claimed = FALSE, post_claim_start_time = NULL,
                        post_claim_end_time = NULL, updated_at = CURRENT_TIMESTAMP
                    WHERE source_schedule_plan_id = %s
                      AND source_schedule_shift_id = %s
                      AND status = 'claimed'
                      AND claimed_by = %s
                """, (resolved_plan_id, resolved_shift_id, operator_id))
                # Снимаем ТОЛЬКО claim этого оператора — частичные доборы других
                # операторов на той же смене остаются нетронутыми.
                cursor.execute("""
                    DELETE FROM shift_auction_historical_claims
                    WHERE plan_id = %s AND source_schedule_shift_id = %s AND claimed_by = %s
                """, (resolved_plan_id, resolved_shift_id, operator_id))

            if shift_date and start_time and end_time:
                # Корректное разъединение: вычитаем отрезок добора, оставшиеся части
                # пересоздаём с пересчётом перерывов по текущим правилам. Если смена,
                # содержащая отрезок, не найдена — запасное точное удаление.
                split_done = self._split_post_auction_shift_slice_tx(
                    cursor, operator_id, shift_date, start_time, end_time
                )
                if not split_done:
                    cursor.execute("""
                        DELETE FROM work_shifts
                        WHERE operator_id = %s AND shift_date = %s
                          AND start_time = %s AND end_time = %s
                    """, (operator_id, shift_date, start_time, end_time))
                self._recalculate_auto_daily_hours_tx(
                    cursor=cursor,
                    operator_ids=[operator_id],
                    start_date=shift_date,
                    end_date=shift_date
                )

            event_payload = {
                "operator_id": operator_id,
                "lot_id": used_lot_id,
                "plan_id": resolved_plan_id,
                "source_schedule_shift_id": resolved_shift_id,
                "shift_date": shift_date.strftime('%Y-%m-%d') if hasattr(shift_date, 'strftime') else None,
                "start_time": start_time.strftime('%H:%M') if hasattr(start_time, 'strftime') else None,
                "end_time": end_time.strftime('%H:%M') if hasattr(end_time, 'strftime') else None,
                "self_cancelled": True,
            }
            event = self._insert_shift_auction_test_event(cursor, "lot_post_auction_cancelled", event_payload)

        return {
            "operator_id": operator_id,
            "lot_id": used_lot_id,
            "plan_id": resolved_plan_id,
            "source_schedule_shift_id": resolved_shift_id,
            "shift_date": event_payload["shift_date"],
            "start_time": event_payload["start_time"],
            "end_time": event_payload["end_time"],
            "event": event,
        }

    def admin_claim_shift_for_operator(self, admin_id, operator_id, lot_id=None, plan_id=None, source_schedule_shift_id=None,
                                       claim_start_time=None, claim_end_time=None):
        """
        Назначить лот/часть смены оператору админом. Аналог post_auction_claim_lot/_saved_shift,
        но без проверки is_participant — админ имеет право. Если переданы claim_start_time/
        claim_end_time — назначается ЧАСТЬ смены (свободный кусок), с проверкой пересечения
        с уже взятыми частями. Иначе — вся смена. Проверяет непересечение со сменами оператора.
        """
        try:
            admin_id = int(admin_id) if admin_id is not None else None
        except Exception:
            admin_id = None
        try:
            operator_id_int = int(operator_id)
        except Exception:
            raise ValueError("OPERATOR_NOT_FOUND")
        try:
            lot_id_int = int(lot_id) if lot_id not in (None, '') else None
        except Exception:
            lot_id_int = None
        try:
            plan_id_int = int(plan_id) if plan_id not in (None, '') else None
        except Exception:
            plan_id_int = None
        try:
            shift_id_int = int(source_schedule_shift_id) if source_schedule_shift_id not in (None, '') else None
        except Exception:
            shift_id_int = None

        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT u.name, u.role, COALESCE(u.status, '')
                FROM users u WHERE u.id = %s
            """, (operator_id_int,))
            op_row = cursor.fetchone()
            if not op_row or normalize_role_value(op_row[1]) != 'operator' or str(op_row[2] or '').strip().lower() in ('fired', 'dismissal'):
                raise ValueError("OPERATOR_NOT_FOUND")
            operator_name = op_row[0] or f"Operator #{operator_id_int}"

            if lot_id_int:
                cursor.execute("""
                    SELECT id, shift_date, start_time, end_time, status, claimed_by,
                           source_schedule_plan_id, source_schedule_shift_id, rate_min, breaks
                    FROM shift_auction_test_lots
                    WHERE id = %s
                    FOR UPDATE
                """, (lot_id_int,))
                lot = cursor.fetchone()
                if not lot:
                    raise ValueError("LOT_NOT_FOUND")
                if lot[4] == 'claimed':
                    raise ValueError("LOT_ALREADY_CLAIMED")
                shift_date, start_time, end_time = lot[1], lot[2], lot[3]
                resolved_plan_id = int(lot[6]) if lot[6] is not None else plan_id_int
                resolved_shift_id = int(lot[7]) if lot[7] is not None else shift_id_int
            else:
                if not (plan_id_int and shift_id_int):
                    raise ValueError("MISSING_TARGET")
                resolved_plan_id = plan_id_int
                resolved_shift_id = shift_id_int
                cursor.execute("""
                    SELECT shift_date, start_time, end_time
                    FROM resource_saved_schedule_shifts
                    WHERE id = %s AND plan_id = %s
                      AND COALESCE(meta->>'excludeFromAuction', 'false') <> 'true'
                """, (resolved_shift_id, resolved_plan_id))
                saved = cursor.fetchone()
                if not saved:
                    raise ValueError("SHIFT_NOT_FOUND")
                shift_date, start_time, end_time = saved[0], saved[1], saved[2]

            if resolved_shift_id:
                cursor.execute(
                    "SELECT pg_advisory_xact_lock(%s, %s)",
                    (self.SHIFT_AUCTION_SAVED_SHIFT_LOCK_NAMESPACE, resolved_shift_id)
                )
            self._lock_shift_auction_operator_tx(cursor, operator_id_int)

            # When claim times are given, the admin assigns only a PART of the shift.
            is_partial_assign = bool(claim_start_time and claim_end_time)
            if is_partial_assign:
                claim_range = self._normalize_post_auction_claim_range(start_time, end_time, claim_start_time, claim_end_time)
                eff_start_time = claim_range["start_time"]
                eff_end_time = claim_range["end_time"]
                new_start_min = claim_range["start_minute"]
                new_end_min = claim_range["end_minute"]
            else:
                eff_start_time, eff_end_time = start_time, end_time
                new_start_min, new_end_min = self._schedule_interval_minutes(start_time, end_time)

            if lot_id_int is None and resolved_plan_id and resolved_shift_id:
                # A full assign is refused if any claim exists; a partial assign only if
                # it overlaps one (disjoint parts are allowed).
                cursor.execute("""
                    SELECT claimed_by, claimed_start_time, claimed_end_time
                    FROM shift_auction_historical_claims
                    WHERE plan_id = %s AND source_schedule_shift_id = %s
                    FOR UPDATE
                """, (resolved_plan_id, resolved_shift_id))
                for ex_by, ex_s, ex_e in (cursor.fetchall() or []):
                    if ex_by is not None and int(ex_by) == operator_id_int:
                        raise ValueError("LOT_ALREADY_CLAIMED")
                    if not is_partial_assign or ex_s is None or ex_e is None:
                        raise ValueError("LOT_ALREADY_CLAIMED")
                    ex_rng = self._normalize_post_auction_claim_range(start_time, end_time, ex_s.strftime('%H:%M'), ex_e.strftime('%H:%M'))
                    if new_start_min < ex_rng["end_minute"] and ex_rng["start_minute"] < new_end_min:
                        raise ValueError("SHIFT_OVERLAPS_EXISTING")

            cursor.execute("""
                SELECT id, start_time, end_time
                FROM work_shifts
                WHERE operator_id = %s AND shift_date = %s
                ORDER BY start_time
            """, (operator_id_int, shift_date))
            existing_shifts = cursor.fetchall() or []
            for _ws_id, ws_start, ws_end in existing_shifts:
                ws_s, ws_e = self._schedule_interval_minutes(ws_start, ws_end)
                if ws_s < new_end_min and new_start_min < ws_e:
                    raise ValueError("SHIFT_OVERLAP")

            if lot_id_int:
                cursor.execute("""
                    UPDATE shift_auction_test_lots
                    SET status = 'claimed', claimed_by = %s, claimed_at = CURRENT_TIMESTAMP,
                        post_auction_claimed = TRUE, updated_at = CURRENT_TIMESTAMP
                    WHERE id = %s AND status <> 'claimed'
                    RETURNING claimed_at
                """, (operator_id_int, lot_id_int))
                updated_row = cursor.fetchone()
                if not updated_row:
                    raise ValueError("LOT_ALREADY_CLAIMED")
                claimed_at = updated_row[0]
            else:
                claimed_at = None

            if resolved_plan_id and resolved_shift_id:
                cursor.execute("""
                    INSERT INTO shift_auction_historical_claims
                        (plan_id, source_schedule_shift_id, claimed_by, claimed_at, claimed_start_time, claimed_end_time)
                    VALUES (%s, %s, %s, COALESCE(%s, CURRENT_TIMESTAMP), %s, %s)
                    ON CONFLICT (plan_id, source_schedule_shift_id, claimed_by) DO NOTHING
                    RETURNING claimed_at
                """, (resolved_plan_id, resolved_shift_id, operator_id_int, claimed_at,
                      eff_start_time if is_partial_assign else None,
                      eff_end_time if is_partial_assign else None))
                row = cursor.fetchone()
                if not row and lot_id_int is None:
                    raise ValueError("LOT_ALREADY_CLAIMED")
                if row:
                    claimed_at = row[0]

            self._save_shift_tx(
                cursor=cursor,
                operator_id=operator_id_int,
                shift_date=shift_date,
                start_time=eff_start_time,
                end_time=eff_end_time,
                breaks=None,
                shift_type=None,
            )
            self._recalculate_auto_daily_hours_tx(
                cursor=cursor,
                operator_ids=[operator_id_int],
                start_date=shift_date,
                end_date=shift_date
            )

            # Partial assign on a single lot: if every minute is now taken, close it.
            if is_partial_assign and lot_id_int is None and resolved_plan_id and resolved_shift_id:
                cursor.execute("""
                    SELECT claimed_start_time, claimed_end_time FROM shift_auction_historical_claims
                    WHERE plan_id = %s AND source_schedule_shift_id = %s AND claimed_start_time IS NOT NULL
                """, (resolved_plan_id, resolved_shift_id))
                fs, fe = self._schedule_interval_minutes(start_time, end_time)
                cov = []
                for cs, ce in (cursor.fetchall() or []):
                    rng = self._normalize_post_auction_claim_range(start_time, end_time, cs.strftime('%H:%M'), ce.strftime('%H:%M'))
                    cov.append((rng["start_minute"], rng["end_minute"]))
                if not [g for g in self._subtract_ranges(fs, fe, cov) if g[1] - g[0] > 0]:
                    cursor.execute("""
                        UPDATE shift_auction_test_lots
                        SET status = 'claimed', post_auction_claimed = TRUE, updated_at = CURRENT_TIMESTAMP
                        WHERE source_schedule_plan_id = %s AND source_schedule_shift_id = %s AND status IN ('available', 'cancelled')
                    """, (resolved_plan_id, resolved_shift_id))

            event_payload = {
                "operator_id": operator_id_int,
                "operator_name": operator_name,
                "lot_id": lot_id_int,
                "plan_id": resolved_plan_id,
                "source_schedule_shift_id": resolved_shift_id,
                "shift_date": shift_date.strftime('%Y-%m-%d') if hasattr(shift_date, 'strftime') else None,
                "start_time": eff_start_time.strftime('%H:%M') if hasattr(eff_start_time, 'strftime') else None,
                "end_time": eff_end_time.strftime('%H:%M') if hasattr(eff_end_time, 'strftime') else None,
                "admin_id": admin_id,
            }
            event = self._insert_shift_auction_test_event(cursor, "lot_admin_claimed", event_payload)

        return {
            **event_payload,
            "claimed_at": claimed_at.isoformat() if claimed_at else None,
            "event": event,
        }

    def get_admin_post_claim_notify_recipients(self):
        """Список admin'ов с включённым тумблером уведомлений (id, name, telegram_id)."""
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT u.id, u.name, u.telegram_id
                FROM admin_profiles ap
                JOIN users u ON u.id = ap.user_id
                WHERE COALESCE(ap.auction_post_claim_notify_enabled, FALSE) = TRUE
                  AND u.telegram_id IS NOT NULL
                  AND LOWER(COALESCE(u.role, '')) IN ('admin', 'super_admin')
            """)
            rows = cursor.fetchall() or []
            return [
                {"id": int(row[0]), "name": row[1] or '', "telegram_id": int(row[2])}
                for row in rows
                if row and row[0] is not None and row[2] is not None
            ]

    def get_admin_post_claim_notify_setting(self, user_id):
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT COALESCE(auction_post_claim_notify_enabled, FALSE)
                FROM admin_profiles
                WHERE user_id = %s
            """, (int(user_id),))
            row = cursor.fetchone()
            return bool(row[0]) if row else False

    def set_admin_post_claim_notify_setting(self, user_id, enabled):
        enabled_value = bool(enabled)
        with self._get_cursor() as cursor:
            cursor.execute("""
                INSERT INTO admin_profiles (user_id, auction_post_claim_notify_enabled)
                VALUES (%s, %s)
                ON CONFLICT (user_id) DO UPDATE
                SET auction_post_claim_notify_enabled = EXCLUDED.auction_post_claim_notify_enabled
            """, (int(user_id), enabled_value))
            return enabled_value

    def set_shift_auction_test_day_off(self, operator_id, day_off_date, selected=True):
        operator_id = int(operator_id)
        if isinstance(day_off_date, str):
            day_value = datetime.strptime(day_off_date, "%Y-%m-%d").date()
        else:
            day_value = day_off_date

        with self._get_cursor() as cursor:
            self._lock_shift_auction_operator_tx(cursor, operator_id)
            cursor.execute("""
                SELECT enabled, starts_at, ends_at, paused_at, finished_at
                FROM shift_auction_test_access
                WHERE id = 1
            """)
            settings = cursor.fetchone()
            if not settings or self._get_shift_auction_test_status(settings[0], settings[1], settings[2], settings[3], settings[4]) not in ("scheduled", "open"):
                raise ValueError("AUCTION_NOT_AVAILABLE")

            cursor.execute("SELECT 1 FROM shift_auction_test_participants WHERE operator_id = %s", (operator_id,))
            if not cursor.fetchone():
                raise ValueError("NOT_TEST_PARTICIPANT")

            cursor.execute("SELECT 1 FROM shift_auction_test_lots WHERE shift_date = %s LIMIT 1", (day_value,))
            if not cursor.fetchone():
                raise ValueError("LOT_NOT_FOUND")

            lot_dates = self._get_shift_auction_lot_dates_tx(cursor)
            blocked_date_map = self._get_shift_auction_operator_blocked_date_map_tx(cursor, operator_id, lot_dates=lot_dates)
            day_key = day_value.strftime('%Y-%m-%d') if day_value else ''
            if selected and day_key and day_key in blocked_date_map:
                raise ValueError("SHIFT_AUCTION_STATUS_PERIOD_BLOCKED")

            if selected:
                cursor.execute("""
                    SELECT 1
                    FROM shift_auction_test_lots
                    WHERE claimed_by = %s
                      AND shift_date = %s
                      AND status = 'claimed'
                    LIMIT 1
                """, (operator_id, day_value))
                if cursor.fetchone():
                    raise ValueError("DAY_HAS_CLAIMED_SHIFT")

                cursor.execute("""
                    SELECT day_off_date
                    FROM shift_auction_test_day_offs
                    WHERE operator_id = %s
                    ORDER BY day_off_date
                """, (operator_id,))
                selected_day_offs = [
                    row[0].strftime('%Y-%m-%d')
                    for row in (cursor.fetchall() or [])
                    if row and row[0]
                ]
                day_off_quota = self._shift_auction_day_off_quota(len(lot_dates))
                blocked_quota_count = min(day_off_quota, len(blocked_date_map))
                count = len([item for item in selected_day_offs if item not in blocked_date_map])
                already_selected = day_key in selected_day_offs
                if count + blocked_quota_count >= day_off_quota and not already_selected:
                    raise ValueError("DAY_OFF_LIMIT")
                cursor.execute("""
                    INSERT INTO shift_auction_test_day_offs (operator_id, day_off_date)
                    VALUES (%s, %s)
                    ON CONFLICT (operator_id, day_off_date) DO NOTHING
                """, (operator_id, day_value))
                event_type = "day_off_selected"
            else:
                cursor.execute("""
                    DELETE FROM shift_auction_test_day_offs
                    WHERE operator_id = %s AND day_off_date = %s
                """, (operator_id, day_value))
                event_type = "day_off_removed"

            cursor.execute("""
                SELECT day_off_date
                FROM shift_auction_test_day_offs
                WHERE operator_id = %s
                ORDER BY day_off_date
            """, (operator_id,))
            my_day_offs = [row[0].strftime('%Y-%m-%d') for row in (cursor.fetchall() or [])]
            event = self._insert_shift_auction_test_event(cursor, event_type, {
                "operator_id": operator_id,
                "date": day_value.strftime('%Y-%m-%d'),
                "my_day_offs": my_day_offs
            })
        return {"my_day_offs": my_day_offs, "event": event}

    # ── Department CRUD ──────────────────────────────────────────────

    @staticmethod
    def _department_row_to_dict(r):
        return {
            "id": r[0], "code": r[1], "slug": r[2], "name": r[3],
            "description": r[4], "is_active": r[5],
            "head_user_id": r[6], "head_name": r[7],
            "operator_field_schema": r[8] if r[8] is not None else [],
        }

    def get_departments(self):
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT d.id, d.code, d.slug, d.name, d.description, d.is_active,
                       d.head_user_id, h.name, d.operator_field_schema
                FROM departments d
                LEFT JOIN users h ON h.id = d.head_user_id
                ORDER BY d.name
            """)
            return [self._department_row_to_dict(r) for r in cursor.fetchall()]

    def get_department_by_id(self, department_id):
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT d.id, d.code, d.slug, d.name, d.description, d.is_active,
                       d.head_user_id, h.name, d.operator_field_schema
                FROM departments d
                LEFT JOIN users h ON h.id = d.head_user_id
                WHERE d.id = %s
            """, (department_id,))
            r = cursor.fetchone()
            if not r:
                return None
            return self._department_row_to_dict(r)

    def create_department(self, code, name, description=None, slug=None):
        if not slug:
            slug = code
        with self._get_cursor() as cursor:
            cursor.execute("""
                INSERT INTO departments (code, slug, name, description)
                VALUES (%s, %s, %s, %s)
                RETURNING id, code, slug, name, description, is_active, head_user_id, operator_field_schema
            """, (code, slug, name, description))
            r = cursor.fetchone()
            return {
                "id": r[0], "code": r[1], "slug": r[2], "name": r[3],
                "description": r[4], "is_active": r[5],
                "head_user_id": r[6], "head_name": None,
                "operator_field_schema": r[7] if r[7] is not None else [],
            }

    def update_department(self, department_id, **kwargs):
        allowed = {'code', 'slug', 'name', 'description', 'is_active', 'operator_field_schema'}
        updates = {k: v for k, v in kwargs.items() if k in allowed}
        if not updates:
            return self.get_department_by_id(department_id)
        from psycopg2 import sql as _sql
        from psycopg2.extras import Json as _Json
        set_clause = _sql.SQL(', ').join(
            _sql.SQL("{} = %s").format(_sql.Identifier(k)) for k in updates
        )
        params = [
            _Json(v) if k == 'operator_field_schema' else v
            for k, v in updates.items()
        ]
        with self._get_cursor() as cursor:
            cursor.execute(
                _sql.SQL("UPDATE departments SET {} WHERE id = %s RETURNING id").format(set_clause),
                params + [department_id]
            )
            if cursor.fetchone() is None:
                return None
        return self.get_department_by_id(department_id)

    def set_department_head(self, department_id, user_id, changed_by=None):
        """Назначить/снять главу отдела с записью в журнал истории.

        user_id=None снимает текущего главу. Денормализованный «текущий глава»
        хранится в departments.head_user_id, полная история — в
        department_head_assignments. Возвращает обновлённый отдел или None.
        """
        new_head = int(user_id) if user_id not in (None, '') else None
        with self._get_cursor() as cursor:
            cursor.execute("SELECT head_user_id FROM departments WHERE id = %s", (department_id,))
            row = cursor.fetchone()
            if not row:
                return None
            current_head = row[0]
            if current_head != new_head:
                cursor.execute(
                    "UPDATE departments SET head_user_id = %s WHERE id = %s",
                    (new_head, department_id)
                )
                if current_head is not None:
                    cursor.execute("""
                        INSERT INTO department_head_assignments (department_id, user_id, action, changed_by)
                        VALUES (%s, %s, 'unassigned', %s)
                    """, (department_id, current_head, changed_by))
                if new_head is not None:
                    cursor.execute("""
                        INSERT INTO department_head_assignments (department_id, user_id, action, changed_by)
                        VALUES (%s, %s, 'assigned', %s)
                    """, (department_id, new_head, changed_by))
        return self.get_department_by_id(department_id)

    def get_department_head_history(self, department_id):
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT a.id, a.user_id, u.name, a.action, a.changed_by, cb.name, a.created_at
                FROM department_head_assignments a
                LEFT JOIN users u ON u.id = a.user_id
                LEFT JOIN users cb ON cb.id = a.changed_by
                WHERE a.department_id = %s
                ORDER BY a.created_at DESC, a.id DESC
            """, (department_id,))
            return [
                {
                    "id": r[0],
                    "user_id": r[1],
                    "user_name": r[2],
                    "action": r[3],
                    "changed_by": r[4],
                    "changed_by_name": r[5],
                    "created_at": r[6].isoformat() if r[6] else None,
                }
                for r in cursor.fetchall()
            ]

    def headed_department_id_for_user(self, user_id):
        """Вернуть id отдела, главой которого является пользователь, иначе None."""
        if not user_id:
            return None
        with self._get_cursor() as cursor:
            cursor.execute("SELECT id FROM departments WHERE head_user_id = %s LIMIT 1", (user_id,))
            r = cursor.fetchone()
            return r[0] if r else None

    def get_user_department_id(self, user_id):
        """Лёгкий доступ к users.department_id без позиционного кортежа get_user."""
        if not user_id:
            return None
        with self._get_cursor() as cursor:
            cursor.execute("SELECT department_id FROM users WHERE id = %s", (user_id,))
            r = cursor.fetchone()
            return r[0] if r else None

    def get_user_department(self, user_id):
        """Вернуть (department_id, department_code) пользователя одним запросом."""
        if not user_id:
            return (None, None)
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT u.department_id, d.code
                FROM users u
                LEFT JOIN departments d ON d.id = u.department_id
                WHERE u.id = %s
            """, (user_id,))
            r = cursor.fetchone()
            return (r[0], r[1]) if r else (None, None)

    def get_department_member_ids(self, department_id):
        """Множество id пользователей, принадлежащих отделу (для скоупа главы)."""
        if not department_id:
            return set()
        with self._get_cursor() as cursor:
            cursor.execute("SELECT id FROM users WHERE department_id = %s", (department_id,))
            return {r[0] for r in cursor.fetchall()}

    def get_direction_department_id(self, direction_id):
        """Вернуть department_id направления (для проверки принадлежности отделу)."""
        if not direction_id:
            return None
        with self._get_cursor() as cursor:
            cursor.execute("SELECT department_id FROM directions WHERE id = %s", (direction_id,))
            r = cursor.fetchone()
            return r[0] if r else None

    def assign_user_department(self, user_id, department_id):
        with self._get_cursor() as cursor:
            cursor.execute("UPDATE users SET department_id = %s WHERE id = %s RETURNING id", (department_id, user_id))
            return cursor.fetchone() is not None

    def insert_or_update_daily_hours(self, operator_id, day, work_time=0.0, break_time=0.0,
                                    talk_time=0.0, calls=0, efficiency=0.0,
                                    fine_amount=0.0, fine_reason=None, fine_comment=None,
                                    fines: List[Dict[str, Any]] = None,
                                    bonuses: List[Dict[str, Any]] = None,
                                    group_id=None):
        """
        Вставляет/обновляет запись daily_hours (operator_id + day).
        efficiency и fine_amount ожидаются в часах/суммах соответственно.

        group_id — группа, к которой относится этот день оператора. Уникальность
        остаётся по (operator_id, day): правило «один оператор = одна группа в день»
        делает её совместимой, group_id просто меняется по дням. Если group_id не
        передан, существующее значение сохраняется (COALESCE), а при отсутствии —
        проставляется активная группа оператора на эту дату.
        """
        if isinstance(day, str):
            day = datetime.strptime(day, "%Y-%m-%d").date()
        with self._get_cursor() as cursor:
            # Если group_id не задан явно — резолвим активную группу оператора на дату.
            if group_id is None:
                group_id = self._get_operator_group_id_tx(cursor, operator_id, day)
            # Insert or update daily_hours and return its id for managing daily_fines
            cursor.execute("""
                INSERT INTO daily_hours (
                    operator_id, day, work_time, break_time, talk_time, calls, efficiency,
                    fine_amount, fine_reason, fine_comment, group_id
                )
                VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
                ON CONFLICT (operator_id, day)
                DO UPDATE SET
                    work_time = EXCLUDED.work_time,
                    break_time = EXCLUDED.break_time,
                    talk_time = EXCLUDED.talk_time,
                    calls = EXCLUDED.calls,
                    efficiency = EXCLUDED.efficiency,
                    fine_amount = EXCLUDED.fine_amount,
                    fine_reason = EXCLUDED.fine_reason,
                    fine_comment = EXCLUDED.fine_comment,
                    group_id = COALESCE(EXCLUDED.group_id, daily_hours.group_id),
                    created_at = CURRENT_TIMESTAMP
                RETURNING id
            """, (operator_id, day, work_time, break_time, talk_time, calls, efficiency,
                float(fine_amount) if fine_amount is not None else 0.0,
                fine_reason, fine_comment, group_id))
            res = cursor.fetchone()
            daily_id = res[0] if res else None

            # If fines provided, replace existing fines for this daily_hours record
            if daily_id and isinstance(fines, list):
                # remove previous fines for this daily row
                cursor.execute("DELETE FROM daily_fines WHERE daily_hours_id = %s", (daily_id,))
                insert_vals = []
                total_amount = 0.0
                first_reason = None
                comments = []
                for f in fines:
                    amt = float(f.get('amount') or 0)
                    reason = f.get('reason')
                    comment = f.get('comment')
                    insert_vals.append((daily_id, operator_id, day, amt, reason, comment))
                    total_amount += amt
                    if not first_reason and reason:
                        first_reason = reason
                    if comment:
                        comments.append(str(comment))

                if insert_vals:
                    cursor.executemany(
                        "INSERT INTO daily_fines (daily_hours_id, operator_id, day, amount, reason, comment) VALUES (%s, %s, %s, %s, %s, %s)",
                        insert_vals
                    )

                # update aggregated fields in daily_hours for backward compatibility
                agg_comment = '; '.join(comments) if comments else None
                cursor.execute("""
                    UPDATE daily_hours SET fine_amount = %s, fine_reason = %s, fine_comment = %s
                    WHERE id = %s
                """, (float(total_amount), first_reason, agg_comment, daily_id))

            if daily_id and isinstance(bonuses, list):
                cursor.execute("DELETE FROM daily_bonuses WHERE daily_hours_id = %s", (daily_id,))
                insert_bonus_vals = []

                for b in bonuses:
                    if not isinstance(b, dict):
                        continue

                    bonus_type = str(b.get('type') or b.get('bonus_type') or '').strip()
                    if not bonus_type:
                        continue

                    quantity_raw = b.get('quantity')
                    try:
                        quantity = max(int(float(quantity_raw)), 1) if quantity_raw not in (None, '') else 1
                    except Exception:
                        quantity = 1

                    training_hours_raw = b.get('training_hours')
                    if training_hours_raw in (None, ''):
                        training_hours_raw = b.get('hours')
                    try:
                        training_hours = float(training_hours_raw) if training_hours_raw not in (None, '') else 0.0
                    except Exception:
                        training_hours = 0.0
                    if training_hours < 0:
                        training_hours = 0.0

                    if bonus_type == 'Обучение':
                        quantity = 1

                    amount_raw = b.get('amount')
                    if bonus_type == 'Обучение':
                        amount = float(training_hours * 500.0)
                    elif bonus_type in ('Приведи друга', 'Съемки'):
                        amount = float(quantity * 5000.0)
                    elif amount_raw in (None, ''):
                        amount = 0.0
                    else:
                        try:
                            amount = float(amount_raw)
                        except Exception:
                            amount = 0.0

                    friend_names = str(b.get('friend_names') or '').strip() or None
                    video_links = str(b.get('video_links') or '').strip() or None
                    comment = str(b.get('comment') or '').strip() or None

                    insert_bonus_vals.append((
                        daily_id,
                        operator_id,
                        day,
                        bonus_type,
                        int(quantity),
                        float(training_hours) if bonus_type == 'Обучение' else None,
                        float(amount),
                        friend_names,
                        video_links,
                        comment
                    ))

                if insert_bonus_vals:
                    cursor.executemany(
                        """
                        INSERT INTO daily_bonuses (
                            daily_hours_id, operator_id, day, bonus_type, quantity, training_hours, amount, friend_names, video_links, comment
                        ) VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
                        """,
                        insert_bonus_vals
                    )

    def _load_technical_issues_by_operator_day_tx(self, cursor, operator_ids, start_date, end_date, group_id=None):
        """
        Возвращает:
        - map: {operator_id: {day_num_str: [issues...]}}
        - totals: {operator_id: total_hours}
        """
        op_ids = sorted({int(v) for v in (operator_ids or []) if v is not None})
        result = {op_id: {} for op_id in op_ids}
        totals = {op_id: 0.0 for op_id in op_ids}
        if not op_ids:
            return result, totals

        group_filter_sql = ""
        params = [op_ids, start_date, end_date]
        if group_id is not None:
            group_filter_sql = """
              AND EXISTS (
                  SELECT 1
                  FROM group_operator_memberships gom
                  WHERE gom.operator_id = ti.operator_id
                    AND gom.group_id = %s
                    AND gom.start_date <= ti.issue_date
                    AND (gom.end_date IS NULL OR gom.end_date >= ti.issue_date)
              )
            """
            params.append(int(group_id))

        cursor.execute(
            f"""
            SELECT
                ti.id,
                ti.operator_id,
                ti.issue_date,
                ti.start_time,
                ti.end_time,
                ti.reason,
                ti.comment,
                ti.workplace_number,
                ti.for_supervisor,
                cb.name,
                ti.created_at
            FROM operator_technical_issues ti
            LEFT JOIN users cb ON cb.id = ti.created_by
            WHERE ti.operator_id = ANY(%s)
              AND ti.issue_date >= %s
              AND ti.issue_date <= %s
              {group_filter_sql}
            ORDER BY ti.operator_id, ti.issue_date, ti.start_time, ti.end_time, ti.id
            """,
            params,
        )
        for issue_id, op_id, issue_date, start_time, end_time, reason, comment, workplace_number, for_supervisor, created_by_name, created_at in cursor.fetchall() or []:
            try:
                op_id_int = int(op_id)
            except Exception:
                continue
            if op_id_int not in result or issue_date is None:
                continue

            start_text = start_time.strftime('%H:%M') if start_time else None
            end_text = end_time.strftime('%H:%M') if end_time else None
            duration_minutes = 0
            try:
                if start_time and end_time:
                    start_min, end_min = self._schedule_interval_minutes(start_time, end_time)
                    duration_minutes = max(0, int(end_min - start_min))
            except Exception:
                duration_minutes = 0
            duration_hours = round(float(duration_minutes) / 60.0, 2)

            day_key = str(int(issue_date.day))
            result.setdefault(op_id_int, {}).setdefault(day_key, []).append({
                "id": int(issue_id),
                "date": issue_date.strftime('%Y-%m-%d'),
                "start_time": start_text,
                "end_time": end_text,
                "time_range": f"{start_text} - {end_text}" if start_text and end_text else None,
                "reason": reason,
                "comment": comment,
                "workplace_number": int(workplace_number) if workplace_number is not None else None,
                "for_supervisor": bool(for_supervisor) if for_supervisor is not None else False,
                "created_by_name": created_by_name,
                "created_at": created_at.strftime('%Y-%m-%d %H:%M:%S') if created_at else None,
                "duration_minutes": int(duration_minutes),
                "duration_hours": float(duration_hours),
            })
            totals[op_id_int] = round(float(totals.get(op_id_int, 0.0)) + float(duration_hours), 2)

        return result, totals

    def _phone_shift_training_status_keys(self):
        return sorted({
            self._normalize_import_status_key(item)
            for item in (
                set(CHAT_MANAGER_TRAINING_STATUS_KEYS)
                | {SCHEDULE_AUTO_TRAINING_STATUS_KEY, 'training', 'study'}
            )
            if self._normalize_import_status_key(item)
        })

    def _time_label_from_seconds(self, seconds_value, round_end=False):
        seconds_int = max(0, int(seconds_value or 0))
        if round_end:
            minutes = int((seconds_int + 59) // 60)
        else:
            minutes = int(seconds_int // 60)
        return _minutes_to_time(minutes)

    def _load_phone_shift_training_offline_intervals_by_operator_day_tx(
        self,
        cursor,
        operator_ids,
        start_date,
        end_date,
        group_id=None
    ):
        op_ids = sorted({int(v) for v in (operator_ids or []) if v is not None})
        result = {op_id: {} for op_id in op_ids}
        totals = {op_id: 0.0 for op_id in op_ids}
        if not op_ids:
            return result, totals

        start_date_obj = self._normalize_schedule_date(start_date)
        end_date_obj = self._normalize_schedule_date(end_date)
        if end_date_obj < start_date_obj:
            start_date_obj, end_date_obj = end_date_obj, start_date_obj

        shift_source_start = start_date_obj - timedelta(days=1)
        shift_source_end = end_date_obj
        cursor.execute(
            """
            SELECT id, operator_id, shift_date, start_time, end_time
            FROM work_shifts
            WHERE operator_id = ANY(%s)
              AND COALESCE(shift_type, 'regular') = %s
              AND shift_date >= %s
              AND shift_date <= %s
            ORDER BY operator_id, shift_date, start_time, end_time, id
            """,
            (op_ids, WORK_SHIFT_TYPE_PHONE_SHIFT, shift_source_start, shift_source_end)
        )

        phone_shift_intervals_by_day = {}
        for shift_id, op_id, shift_date_value, start_time_value, end_time_value in cursor.fetchall() or []:
            op_id_int = int(op_id)
            if op_id_int not in result or shift_date_value is None:
                continue
            start_min, end_min = self._schedule_interval_minutes(start_time_value, end_time_value)
            day_chunks = self._split_absolute_minutes_intervals_by_day(
                [{'start': int(start_min), 'end': int(end_min)}],
                shift_date_value
            )
            for chunk in day_chunks:
                chunk_date = chunk.get('date')
                if not chunk_date:
                    continue
                if chunk_date < start_date_obj or chunk_date > end_date_obj:
                    continue
                start_sec = int(chunk.get('start_min') or 0) * 60
                end_sec = int(chunk.get('end_min') or 0) * 60
                if end_sec <= start_sec:
                    continue
                phone_shift_intervals_by_day.setdefault((op_id_int, chunk_date), []).append({
                    'start': start_sec,
                    'end': end_sec,
                    'shift_id': int(shift_id)
                })

        if not phone_shift_intervals_by_day:
            return result, totals

        group_filter_sql = ""
        params = [op_ids, self._phone_shift_training_status_keys(), start_date_obj, end_date_obj]
        if group_id is not None:
            group_filter_sql = """
              AND EXISTS (
                  SELECT 1
                  FROM group_operator_memberships gom
                  WHERE gom.operator_id = oss.operator_id
                    AND gom.group_id = %s
                    AND gom.start_date <= oss.status_date
                    AND (gom.end_date IS NULL OR gom.end_date >= oss.status_date)
              )
            """
            params.append(int(group_id))

        cursor.execute(
            f"""
            SELECT
                oss.id,
                oss.operator_id,
                oss.status_date,
                oss.start_at,
                oss.end_at,
                oss.status_key
            FROM operator_status_segments oss
            WHERE oss.operator_id = ANY(%s)
              AND LOWER(BTRIM(oss.status_key)) = ANY(%s)
              AND oss.status_date >= %s
              AND oss.status_date <= %s
              {group_filter_sql}
            ORDER BY oss.operator_id, oss.status_date, oss.start_at, oss.end_at, oss.id
            """,
            params
        )

        raw_intersections = {op_id: {} for op_id in op_ids}
        for status_id, op_id, status_date_value, start_at_value, end_at_value, status_key in cursor.fetchall() or []:
            op_id_int = int(op_id)
            if op_id_int not in result:
                continue
            for chunk in self._schedule_auto_split_status_segment_by_day(status_date_value, start_at_value, end_at_value):
                chunk_day = chunk.get('day')
                if not isinstance(chunk_day, date):
                    continue
                if chunk_day < start_date_obj or chunk_day > end_date_obj:
                    continue
                phone_intervals = phone_shift_intervals_by_day.get((op_id_int, chunk_day)) or []
                if not phone_intervals:
                    continue
                status_interval = {
                    'start': int(chunk.get('start', 0)),
                    'end': int(chunk.get('end', 0))
                }
                intersections = self._schedule_auto_intersect_interval_with_list(
                    status_interval,
                    phone_intervals
                )
                if not intersections:
                    continue
                day_key = chunk_day.strftime('%Y-%m-%d')
                for interval in intersections:
                    start_sec = int(interval.get('start', 0))
                    end_sec = int(interval.get('end', 0))
                    if end_sec <= start_sec:
                        continue
                    raw_intersections.setdefault(op_id_int, {}).setdefault(day_key, []).append({
                        'start': start_sec,
                        'end': end_sec,
                        'status_id': int(status_id),
                        'status_key': self._normalize_import_status_key(status_key)
                    })

        for op_id_int, days_map in raw_intersections.items():
            for day_key, intervals in (days_map or {}).items():
                merged = self._merge_break_intervals(intervals or [])
                for idx, interval in enumerate(merged):
                    start_sec = int(interval.get('start', 0))
                    end_sec = int(interval.get('end', 0))
                    duration_seconds = max(0, end_sec - start_sec)
                    if duration_seconds <= 0:
                        continue
                    result.setdefault(op_id_int, {}).setdefault(day_key, []).append({
                        'id': f"phone-shift-training-{op_id_int}-{day_key}-{idx}-{start_sec}-{end_sec}",
                        'date': day_key,
                        'start_seconds': start_sec,
                        'end_seconds': end_sec,
                        'duration_seconds': duration_seconds,
                        'start_time': self._time_label_from_seconds(start_sec),
                        'end_time': self._time_label_from_seconds(end_sec, round_end=True),
                        'comment': WORK_SHIFT_PHONE_SHIFT_OFFLINE_COMMENT,
                        'source': 'work_shift_training_status',
                        'shift_type': WORK_SHIFT_TYPE_PHONE_SHIFT,
                        'read_only': True,
                        'is_phone_shift_training': True
                    })
                    totals[op_id_int] = round(
                        float(totals.get(op_id_int, 0.0)) + (float(duration_seconds) / 3600.0),
                        4
                    )

        return result, totals

    def _load_phone_shift_manual_training_offline_intervals_by_operator_day_tx(
        self,
        cursor,
        operator_ids,
        start_date,
        end_date,
        group_id=None,
        counted_only=False
    ):
        op_ids = sorted({int(v) for v in (operator_ids or []) if v is not None})
        result = {op_id: {} for op_id in op_ids}
        totals = {op_id: 0.0 for op_id in op_ids}
        if not op_ids:
            return result, totals

        start_date_obj = self._normalize_schedule_date(start_date)
        end_date_obj = self._normalize_schedule_date(end_date)
        if end_date_obj < start_date_obj:
            start_date_obj, end_date_obj = end_date_obj, start_date_obj

        shift_source_start = start_date_obj - timedelta(days=1)
        shift_source_end = end_date_obj
        cursor.execute(
            """
            SELECT id, operator_id, shift_date, start_time, end_time
            FROM work_shifts
            WHERE operator_id = ANY(%s)
              AND COALESCE(shift_type, 'regular') = %s
              AND shift_date >= %s
              AND shift_date <= %s
            ORDER BY operator_id, shift_date, start_time, end_time, id
            """,
            (op_ids, WORK_SHIFT_TYPE_PHONE_SHIFT, shift_source_start, shift_source_end)
        )

        phone_shift_intervals_by_day = {}
        for shift_id, op_id, shift_date_value, start_time_value, end_time_value in cursor.fetchall() or []:
            op_id_int = int(op_id)
            if op_id_int not in result or shift_date_value is None:
                continue
            start_min, end_min = self._schedule_interval_minutes(start_time_value, end_time_value)
            day_chunks = self._split_absolute_minutes_intervals_by_day(
                [{'start': int(start_min), 'end': int(end_min)}],
                shift_date_value
            )
            for chunk in day_chunks:
                chunk_date = chunk.get('date')
                if not chunk_date:
                    continue
                if chunk_date < start_date_obj or chunk_date > end_date_obj:
                    continue
                start_sec = int(chunk.get('start_min') or 0) * 60
                end_sec = int(chunk.get('end_min') or 0) * 60
                if end_sec <= start_sec:
                    continue
                phone_shift_intervals_by_day.setdefault((op_id_int, chunk_date), []).append({
                    'start': start_sec,
                    'end': end_sec,
                    'shift_id': int(shift_id)
                })

        if not phone_shift_intervals_by_day:
            return result, totals

        group_filter_sql = ""
        counted_filter_sql = "AND t.count_in_hours = TRUE" if counted_only else ""
        params = [op_ids, start_date_obj - timedelta(days=1), end_date_obj]
        if group_id is not None:
            group_filter_sql = """
              AND EXISTS (
                  SELECT 1
                  FROM group_operator_memberships gom
                  WHERE gom.operator_id = t.operator_id
                    AND gom.group_id = %s
                    AND gom.start_date <= t.training_date
                    AND (gom.end_date IS NULL OR gom.end_date >= t.training_date)
              )
            """
            params.append(int(group_id))

        cursor.execute(
            f"""
            SELECT
                t.id,
                t.operator_id,
                t.training_date,
                t.start_time,
                t.end_time,
                t.count_in_hours
            FROM trainings t
            WHERE t.operator_id = ANY(%s)
              AND t.training_date >= %s
              AND t.training_date <= %s
              {counted_filter_sql}
              {group_filter_sql}
            ORDER BY t.operator_id, t.training_date, t.start_time, t.end_time, t.id
            """,
            params
        )

        raw_intersections = {op_id: {} for op_id in op_ids}
        for training_id, op_id, training_date_value, start_time_value, end_time_value, count_in_hours in cursor.fetchall() or []:
            op_id_int = int(op_id)
            if op_id_int not in result or training_date_value is None:
                continue
            start_min, end_min = self._schedule_interval_minutes(start_time_value, end_time_value)
            day_chunks = self._split_absolute_minutes_intervals_by_day(
                [{'start': int(start_min), 'end': int(end_min)}],
                training_date_value
            )
            for chunk in day_chunks:
                chunk_day = chunk.get('date')
                if not isinstance(chunk_day, date):
                    continue
                if chunk_day < start_date_obj or chunk_day > end_date_obj:
                    continue
                phone_intervals = phone_shift_intervals_by_day.get((op_id_int, chunk_day)) or []
                if not phone_intervals:
                    continue
                training_interval = {
                    'start': int(chunk.get('start_min') or 0) * 60,
                    'end': int(chunk.get('end_min') or 0) * 60
                }
                intersections = self._schedule_auto_intersect_interval_with_list(
                    training_interval,
                    phone_intervals
                )
                if not intersections:
                    continue
                day_key = chunk_day.strftime('%Y-%m-%d')
                for interval in intersections:
                    start_sec = int(interval.get('start', 0))
                    end_sec = int(interval.get('end', 0))
                    if end_sec <= start_sec:
                        continue
                    raw_intersections.setdefault(op_id_int, {}).setdefault(day_key, []).append({
                        'start': start_sec,
                        'end': end_sec,
                        'training_id': int(training_id),
                        'count_in_hours': bool(count_in_hours)
                    })

        for op_id_int, days_map in raw_intersections.items():
            for day_key, intervals in (days_map or {}).items():
                merged = self._merge_break_intervals(intervals or [])
                for idx, interval in enumerate(merged):
                    start_sec = int(interval.get('start', 0))
                    end_sec = int(interval.get('end', 0))
                    duration_seconds = max(0, end_sec - start_sec)
                    if duration_seconds <= 0:
                        continue
                    result.setdefault(op_id_int, {}).setdefault(day_key, []).append({
                        'id': f"phone-shift-manual-training-{op_id_int}-{day_key}-{idx}-{start_sec}-{end_sec}",
                        'date': day_key,
                        'start_seconds': start_sec,
                        'end_seconds': end_sec,
                        'duration_seconds': duration_seconds,
                        'start_time': self._time_label_from_seconds(start_sec),
                        'end_time': self._time_label_from_seconds(end_sec, round_end=True),
                        'comment': WORK_SHIFT_PHONE_SHIFT_OFFLINE_COMMENT,
                        'source': 'training_phone_shift',
                        'shift_type': WORK_SHIFT_TYPE_PHONE_SHIFT,
                        'read_only': True,
                        'is_phone_shift_training': True
                    })
                    totals[op_id_int] = round(
                        float(totals.get(op_id_int, 0.0)) + (float(duration_seconds) / 3600.0),
                        4
                    )

        return result, totals

    def _sum_phone_shift_offline_interval_maps(self, operator_ids, *interval_maps):
        op_ids = sorted({int(v) for v in (operator_ids or []) if v is not None})
        intervals_by_operator_day = {op_id: {} for op_id in op_ids}
        for interval_map in interval_maps:
            for op_id_raw, days_map in (interval_map or {}).items():
                try:
                    op_id_int = int(op_id_raw)
                except Exception:
                    continue
                if op_id_int not in intervals_by_operator_day:
                    continue
                for day_key, items in (days_map or {}).items():
                    for item in (items or []):
                        start_sec = int(item.get('start_seconds') or 0)
                        end_sec = int(item.get('end_seconds') or 0)
                        if end_sec <= start_sec:
                            continue
                        day_key_text = str(item.get('date') or day_key)
                        intervals_by_operator_day[op_id_int].setdefault(day_key_text, []).append({
                            'start': start_sec,
                            'end': end_sec
                        })

        totals = {op_id: 0.0 for op_id in op_ids}
        for op_id, days_map in intervals_by_operator_day.items():
            total_seconds = 0
            for intervals in (days_map or {}).values():
                for interval in self._merge_break_intervals(intervals or []):
                    total_seconds += max(0, int(interval.get('end', 0)) - int(interval.get('start', 0)))
            totals[op_id] = round(float(total_seconds) / 3600.0, 4)
        return totals

    def _load_offline_activities_by_operator_day_tx(self, cursor, operator_ids, start_date, end_date, group_id=None):
        """
        Возвращает:
        - map: {operator_id: {day_num_str: [activities...]}}
        - totals: {operator_id: total_hours}
        """
        op_ids = sorted({int(v) for v in (operator_ids or []) if v is not None})
        result = {op_id: {} for op_id in op_ids}
        totals = {op_id: 0.0 for op_id in op_ids}
        if not op_ids:
            return result, totals

        group_filter_sql = ""
        params = [op_ids, start_date, end_date]
        if group_id is not None:
            group_filter_sql = """
              AND EXISTS (
                  SELECT 1
                  FROM group_operator_memberships gom
                  WHERE gom.operator_id = oa.operator_id
                    AND gom.group_id = %s
                    AND gom.start_date <= oa.activity_date
                    AND (gom.end_date IS NULL OR gom.end_date >= oa.activity_date)
              )
            """
            params.append(int(group_id))

        cursor.execute(
            f"""
            SELECT
                oa.id,
                oa.operator_id,
                oa.activity_date,
                oa.start_time,
                oa.end_time,
                oa.comment,
                cb.name,
                oa.created_at
            FROM operator_offline_activities oa
            LEFT JOIN users cb ON cb.id = oa.created_by
            WHERE oa.operator_id = ANY(%s)
              AND oa.activity_date >= %s
              AND oa.activity_date <= %s
              {group_filter_sql}
            ORDER BY oa.operator_id, oa.activity_date, oa.start_time, oa.end_time, oa.id
            """,
            params,
        )
        for activity_id, op_id, activity_date, start_time, end_time, comment, created_by_name, created_at in cursor.fetchall() or []:
            try:
                op_id_int = int(op_id)
            except Exception:
                continue
            if op_id_int not in result or activity_date is None:
                continue

            start_text = start_time.strftime('%H:%M') if start_time else None
            end_text = end_time.strftime('%H:%M') if end_time else None
            duration_minutes = 0
            try:
                if start_time and end_time:
                    start_min, end_min = self._schedule_interval_minutes(start_time, end_time)
                    duration_minutes = max(0, int(end_min - start_min))
            except Exception:
                duration_minutes = 0
            duration_hours = round(float(duration_minutes) / 60.0, 2)

            day_key = str(int(activity_date.day))
            comment_text = str(comment or '').strip()
            result.setdefault(op_id_int, {}).setdefault(day_key, []).append({
                "id": int(activity_id),
                "date": activity_date.strftime('%Y-%m-%d'),
                "start_time": start_text,
                "end_time": end_text,
                "time_range": f"{start_text} - {end_text}" if start_text and end_text else None,
                "comment": comment_text,
                "created_by_name": created_by_name,
                "created_at": created_at.strftime('%Y-%m-%d %H:%M:%S') if created_at else None,
                "duration_minutes": int(duration_minutes),
                "duration_hours": float(duration_hours),
            })
            totals[op_id_int] = round(float(totals.get(op_id_int, 0.0)) + float(duration_hours), 2)

        shift_group_filter_sql = ""
        shift_params = [op_ids, start_date, end_date]
        if group_id is not None:
            shift_group_filter_sql = """
              AND EXISTS (
                  SELECT 1
                  FROM group_operator_memberships gom
                  WHERE gom.operator_id = ws.operator_id
                    AND gom.group_id = %s
                    AND gom.start_date <= ws.shift_date
                    AND (gom.end_date IS NULL OR gom.end_date >= ws.shift_date)
              )
            """
            shift_params.append(int(group_id))

        cursor.execute(
            f"""
            SELECT
                ws.id,
                ws.operator_id,
                ws.shift_date,
                ws.start_time,
                ws.end_time
            FROM work_shifts ws
            WHERE ws.operator_id = ANY(%s)
              AND COALESCE(ws.shift_type, 'regular') = 'office_practice'
              AND ws.shift_date >= %s
              AND ws.shift_date <= %s
              {shift_group_filter_sql}
            ORDER BY ws.operator_id, ws.shift_date, ws.start_time, ws.end_time, ws.id
            """,
            shift_params,
        )
        for shift_id, op_id, shift_date, start_time, end_time in cursor.fetchall() or []:
            try:
                op_id_int = int(op_id)
            except Exception:
                continue
            if op_id_int not in result or shift_date is None:
                continue

            start_text = start_time.strftime('%H:%M') if start_time else None
            end_text = end_time.strftime('%H:%M') if end_time else None
            duration_minutes = 0
            try:
                if start_time and end_time:
                    start_min, end_min = self._schedule_interval_minutes(start_time, end_time)
                    duration_minutes = max(0, int(end_min - start_min))
            except Exception:
                duration_minutes = 0
            duration_hours = round(float(duration_minutes) / 60.0, 2)

            day_key = str(int(shift_date.day))
            result.setdefault(op_id_int, {}).setdefault(day_key, []).append({
                "id": f"practice-shift-{int(shift_id)}",
                "operator_id": op_id_int,
                "date": shift_date.strftime('%Y-%m-%d'),
                "start_time": start_text,
                "end_time": end_text,
                "time_range": f"{start_text} - {end_text}" if start_text and end_text else None,
                "comment": WORK_SHIFT_OFFICE_PRACTICE_OFFLINE_COMMENT,
                "created_by_name": "Планировщик",
                "created_at": None,
                "duration_minutes": int(duration_minutes),
                "duration_hours": float(duration_hours),
                "source": "work_shift",
                "shift_type": WORK_SHIFT_TYPE_OFFICE_PRACTICE,
                "is_practice_shift": True,
                "read_only": True,
            })
            totals[op_id_int] = round(float(totals.get(op_id_int, 0.0)) + float(duration_hours), 2)

        manual_phone_training_map, _manual_phone_training_totals = self._load_phone_shift_manual_training_offline_intervals_by_operator_day_tx(
            cursor=cursor,
            operator_ids=op_ids,
            start_date=start_date,
            end_date=end_date,
            group_id=group_id
        )
        status_phone_training_map, _status_phone_training_totals = self._load_phone_shift_training_offline_intervals_by_operator_day_tx(
            cursor=cursor,
            operator_ids=op_ids,
            start_date=start_date,
            end_date=end_date,
            group_id=group_id
        )
        phone_training_seen = {op_id: set() for op_id in op_ids}
        for phone_training_map in (manual_phone_training_map, status_phone_training_map):
            for op_id_int, days_map in (phone_training_map or {}).items():
                try:
                    op_id_int = int(op_id_int)
                except Exception:
                    continue
                if op_id_int not in result:
                    continue
                for day_key, items in (days_map or {}).items():
                    for item in (items or []):
                        start_sec = max(0, int(item.get('start_seconds') or 0))
                        end_sec = max(0, int(item.get('end_seconds') or 0))
                        if end_sec <= start_sec:
                            continue
                        signature = (str(item.get('date') or day_key), start_sec, end_sec)
                        if signature in phone_training_seen.setdefault(op_id_int, set()):
                            continue
                        phone_training_seen[op_id_int].add(signature)
                        duration_seconds = end_sec - start_sec
                        duration_minutes = self._schedule_auto_seconds_to_display_minutes(duration_seconds)
                        duration_hours = round(float(duration_seconds) / 3600.0, 2)
                        start_text = item.get('start_time')
                        end_text = item.get('end_time')
                        result.setdefault(op_id_int, {}).setdefault(str(day_key), []).append({
                            "id": item.get('id'),
                            "operator_id": op_id_int,
                            "date": item.get('date') or str(day_key),
                            "start_time": start_text,
                            "end_time": end_text,
                            "time_range": f"{start_text} - {end_text}" if start_text and end_text else None,
                            "comment": WORK_SHIFT_PHONE_SHIFT_OFFLINE_COMMENT,
                            "created_by_name": "Планировщик",
                            "created_at": None,
                            "duration_minutes": int(duration_minutes),
                            "duration_seconds": int(duration_seconds),
                            "duration_hours": float(duration_hours),
                            "source": item.get('source') or "work_shift_training_status",
                            "shift_type": WORK_SHIFT_TYPE_PHONE_SHIFT,
                            "is_phone_shift_training": True,
                            "read_only": True,
                        })
        phone_training_totals = self._sum_phone_shift_offline_interval_maps(
            op_ids,
            manual_phone_training_map,
            status_phone_training_map
        )
        for op_id_int in op_ids:
            totals[op_id_int] = round(
                float(totals.get(op_id_int, 0.0)) + float(phone_training_totals.get(op_id_int, 0.0) or 0.0),
                2
            )

        return result, totals

    def _load_chat_manager_metrics_by_operator_day_tx(self, cursor, operator_ids, start_date, end_date, group_id=None):
        op_ids = sorted({int(v) for v in (operator_ids or []) if v is not None})
        result = {op_id: {} for op_id in op_ids}
        totals = {
            op_id: {
                'chats_count': 0,
                'whatsapp_chats_count': 0,
                'name_requests_chats_count': 0,
                'transfer_chat_count': 0,
                'avg_score': None,
                'avg_response_time_seconds': None
            }
            for op_id in op_ids
        }
        if not op_ids:
            return result, totals

        group_filter_sql = ""
        params = [op_ids, start_date, end_date]
        if group_id is not None:
            group_filter_sql = """
              AND EXISTS (
                  SELECT 1
                  FROM group_operator_memberships gom
                  WHERE gom.operator_id = chat_manager_daily_metrics.operator_id
                    AND gom.group_id = %s
                    AND gom.start_date <= chat_manager_daily_metrics.day
                    AND (gom.end_date IS NULL OR gom.end_date >= chat_manager_daily_metrics.day)
              )
            """
            params.append(int(group_id))

        cursor.execute(
            f"""
            SELECT
                operator_id,
                day,
                COALESCE(chats_count, 0),
                avg_score,
                avg_response_time_seconds,
                COALESCE(transfer_chat_count, 0),
                score_sum,
                score_count,
                COALESCE(whatsapp_chats_count, 0),
                COALESCE(name_requests_chats_count, 0)
            FROM chat_manager_daily_metrics
            WHERE operator_id = ANY(%s)
              AND day >= %s
              AND day <= %s
              {group_filter_sql}
            ORDER BY operator_id, day
            """,
            params
        )

        # Средняя оценка считается ВЗВЕШЕННО: суммируем score_sum и score_count по дням.
        # Для дней без счётчика (ручной ввод в модалке — только avg_score) берём avg_score с весом 1.
        score_acc = {op_id: {'sum': 0.0, 'count': 0} for op_id in op_ids}
        # Время ответа храним как готовое дневное среднее — период считаем как среднее дневных.
        response_acc = {op_id: {'sum': 0.0, 'count': 0} for op_id in op_ids}
        for op_id, day_obj, chats_count, avg_score, avg_response_time_seconds, transfer_chat_count, score_sum, score_count, whatsapp_chats_count, name_requests_chats_count in cursor.fetchall() or []:
            op_id_int = int(op_id)
            if op_id_int not in result or day_obj is None:
                continue
            chats_int = max(0, int(chats_count or 0))
            whatsapp_chats_int = max(0, int(whatsapp_chats_count or 0))
            name_requests_chats_int = max(0, int(name_requests_chats_count or 0))
            transfer_int = max(0, int(transfer_chat_count or 0))
            s_sum = float(score_sum) if score_sum is not None else None
            s_cnt = int(score_count) if score_count is not None else None
            # Дневная средняя оценка: взвешенная (sum/count), иначе сохранённое avg_score.
            if s_cnt and s_cnt > 0 and s_sum is not None:
                day_avg_score = round(s_sum / s_cnt, 2)
            elif avg_score is not None:
                day_avg_score = float(avg_score)
            else:
                day_avg_score = None
            payload = {
                "date": day_obj.strftime('%Y-%m-%d'),
                "chats_count": chats_int,
                "whatsapp_chats_count": whatsapp_chats_int,
                "name_requests_chats_count": name_requests_chats_int,
                "avg_score": day_avg_score,
                "score_sum": s_sum,
                "score_count": s_cnt,
                "avg_response_time_seconds": float(avg_response_time_seconds) if avg_response_time_seconds is not None else None,
                "avg_response_time_minutes": round(float(avg_response_time_seconds) / 60.0, 2) if avg_response_time_seconds is not None else None,
                "transfer_chat_count": transfer_int
            }
            day_key = str(int(day_obj.day))
            result.setdefault(op_id_int, {})[day_key] = payload
            totals[op_id_int]['chats_count'] += chats_int
            totals[op_id_int]['whatsapp_chats_count'] += whatsapp_chats_int
            totals[op_id_int]['name_requests_chats_count'] += name_requests_chats_int
            totals[op_id_int]['transfer_chat_count'] += transfer_int
            if s_cnt and s_cnt > 0 and s_sum is not None:
                score_acc[op_id_int]['sum'] += s_sum
                score_acc[op_id_int]['count'] += s_cnt
            elif avg_score is not None:
                score_acc[op_id_int]['sum'] += float(avg_score)
                score_acc[op_id_int]['count'] += 1
            if avg_response_time_seconds is not None:
                response_acc[op_id_int]['sum'] += float(avg_response_time_seconds)
                response_acc[op_id_int]['count'] += 1

        for op_id in op_ids:
            score_count = score_acc[op_id]['count']
            response_count = response_acc[op_id]['count']
            if score_count > 0:
                totals[op_id]['avg_score'] = round(score_acc[op_id]['sum'] / score_count, 2)
            if response_count > 0:
                totals[op_id]['avg_response_time_seconds'] = round(response_acc[op_id]['sum'] / response_count, 2)

        return result, totals

    @staticmethod
    def _normalize_low_rating_review_status(value):
        text = str(value or '').strip().lower()
        if not text:
            return None
        if text in {'valid', 'justified', 'substantiated', 'true', '1', 'yes', 'обоснованно', 'обоснованная'}:
            return 'valid'
        if text in {'invalid', 'unjustified', 'not_valid', 'false', '0', 'no', 'необоснованно', 'необоснованная'}:
            return 'invalid'
        raise ValueError("review status must be valid, invalid or empty")

    @staticmethod
    def _resolve_low_rating_final_status(arai_status, zhanna_status, head_status):
        arai = Database._normalize_low_rating_review_status(arai_status)
        zhanna = Database._normalize_low_rating_review_status(zhanna_status)
        head = Database._normalize_low_rating_review_status(head_status)
        if arai and zhanna and arai == zhanna:
            return arai, 'consensus'
        if head:
            return head, 'head'
        return None, None

    @staticmethod
    def _parse_low_rating_datetime(value):
        if value in (None, ''):
            return None
        if isinstance(value, datetime):
            return value.replace(tzinfo=None)
        if isinstance(value, date):
            return datetime.combine(value, dt_time.min)
        text = str(value or '').strip()
        if not text:
            return None
        try:
            parsed = datetime.fromisoformat(text.replace('Z', '+00:00'))
            if getattr(parsed, 'tzinfo', None) is not None:
                parsed = parsed.astimezone().replace(tzinfo=None)
            return parsed
        except Exception:
            pass
        for fmt in ('%Y-%m-%d %H:%M:%S', '%Y-%m-%d %H:%M', '%Y-%m-%d'):
            try:
                return datetime.strptime(text, fmt)
            except Exception:
                continue
        return None

    @staticmethod
    def _normalize_low_rating_phone(value):
        return re.sub(r'\D+', '', str(value or ''))

    @staticmethod
    def _low_rating_review_state(row):
        arai = row.get('arai_status')
        zhanna = row.get('zhanna_status')
        final_status = row.get('final_status')
        if final_status:
            return 'resolved'
        if arai and zhanna and arai != zhanna:
            return 'conflict'
        return 'pending'

    @staticmethod
    def _low_rating_row_to_dict(row):
        keys = [
            'id', 'source', 'source_key', 'operator_id', 'operator_name', 'phone_number',
            'phone_normalized', 'taxi_park', 'rated_at', 'day', 'score', 'raw_payload',
            'imported_by', 'source_batch_id', 'arai_status', 'arai_comment',
            'arai_updated_by', 'arai_updated_by_name', 'arai_updated_at',
            'zhanna_status', 'zhanna_comment', 'zhanna_updated_by',
            'zhanna_updated_by_name', 'zhanna_updated_at', 'head_status',
            'head_comment', 'head_updated_by', 'head_updated_by_name',
            'head_updated_at', 'final_status', 'final_source', 'final_comment',
            'final_decided_by', 'final_decided_by_name', 'final_decided_at',
            'created_at', 'updated_at', 'direction_name', 'department_id', 'department_name'
        ]
        item = dict(zip(keys, row))
        for key in ('id', 'source_batch_id'):
            if item.get(key) is not None:
                item[key] = str(item[key])
        for key in (
            'rated_at', 'day', 'arai_updated_at', 'zhanna_updated_at',
            'head_updated_at', 'final_decided_at', 'created_at', 'updated_at'
        ):
            value = item.get(key)
            if isinstance(value, datetime):
                item[key] = value.isoformat()
            elif isinstance(value, date):
                item[key] = value.strftime('%Y-%m-%d')
            elif value is None:
                item[key] = None
        item['score'] = float(item.get('score') or 0)
        item['review_state'] = Database._low_rating_review_state(item)
        item['needs_head_decision'] = bool(item['review_state'] == 'conflict')
        return item

    @staticmethod
    def _low_rating_extract_source_details(item):
        raw = item.get('raw_payload') if isinstance(item.get('raw_payload'), dict) else {}
        return {
            'client_comment': str(raw.get('client_comment') or '').strip(),
            'rating_text': str(raw.get('rating_text') or raw.get('rating_name') or '').strip(),
            'request_id': raw.get('request_id'),
            'rating_id': raw.get('rating_id'),
            'valuation_request_id': raw.get('valuation_request_id'),
            'channel_name': raw.get('channel_name'),
        }

    @staticmethod
    def _low_rating_public_item(item, viewer_id=None, can_finalize=False):
        public_item = {
            'id': item.get('id'),
            'operator_id': item.get('operator_id'),
            'operator_name': item.get('operator_name') or '',
            'phone_number': item.get('phone_number') or '',
            'phone_normalized': item.get('phone_normalized') or '',
            'taxi_park': item.get('taxi_park') or '',
            'rated_at': item.get('rated_at'),
            'day': item.get('day'),
            'score': item.get('score'),
            'direction_name': item.get('direction_name') or '',
            'department_id': item.get('department_id'),
            'department_name': item.get('department_name') or '',
            'final_status': item.get('final_status'),
            'final_source': item.get('final_source'),
            'final_comment': item.get('final_comment') or '',
            'final_decided_by_name': item.get('final_decided_by_name') or '',
            'final_decided_at': item.get('final_decided_at'),
            'review_count': int(item.get('review_count') or 0),
            'review_state': item.get('review_state') or 'pending',
            'has_review_conflict': bool(item.get('has_review_conflict')),
            'needs_head_decision': bool(item.get('needs_head_decision')),
            'can_finalize': bool(can_finalize and item.get('has_review_conflict')),
            'review_entries': item.get('review_entries') or [],
            'my_review_status': item.get('my_review_status'),
            'my_review_comment': item.get('my_review_comment') or '',
            'my_review_updated_at': item.get('my_review_updated_at'),
        }
        public_item.update(Database._low_rating_extract_source_details(item))
        return public_item

    def _attach_low_rating_review_entries_tx(self, cursor, items, viewer_id=None):
        if not items:
            return items
        review_ids = [str(item.get('id')) for item in items if item.get('id')]
        if not review_ids:
            return items

        cursor.execute(
            """
            SELECT review_id::text, status, COUNT(*)
            FROM chat_manager_low_rating_review_entries
            WHERE review_id::text = ANY(%s)
              AND status IS NOT NULL
            GROUP BY review_id, status
            """,
            (review_ids,)
        )
        by_review = {}
        for review_id, status, count in cursor.fetchall() or []:
            bucket = by_review.setdefault(str(review_id), {'review_count': 0, 'status_counts': {}})
            normalized = self._normalize_low_rating_review_status(status)
            bucket['status_counts'][normalized] = int(count or 0)
            bucket['review_count'] += int(count or 0)

        review_entries = {}
        cursor.execute(
            """
            SELECT e.review_id::text, e.reviewer_id, COALESCE(NULLIF(u.name, ''), ''), e.status, e.comment, e.updated_at
            FROM chat_manager_low_rating_review_entries e
            LEFT JOIN users u ON u.id = e.reviewer_id
            WHERE e.review_id::text = ANY(%s)
              AND e.status IS NOT NULL
            ORDER BY e.updated_at ASC NULLS LAST, e.created_at ASC NULLS LAST
            """,
            (review_ids,)
        )
        for review_id, reviewer_id, reviewer_name, status, comment, updated_at in cursor.fetchall() or []:
            normalized = self._normalize_low_rating_review_status(status)
            if not normalized:
                continue
            review_entries.setdefault(str(review_id), []).append({
                'reviewer_id': int(reviewer_id) if reviewer_id is not None else None,
                'reviewer_name': reviewer_name or '',
                'status': normalized,
                'comment': comment or '',
                'updated_at': updated_at.isoformat() if isinstance(updated_at, datetime) else None,
                'is_mine': bool(viewer_id is not None and reviewer_id is not None and int(reviewer_id) == int(viewer_id)),
            })

        my_entries = {}
        if viewer_id is not None:
            cursor.execute(
                """
                SELECT review_id::text, status, comment, updated_at
                FROM chat_manager_low_rating_review_entries
                WHERE review_id::text = ANY(%s)
                  AND reviewer_id = %s
                """,
                (review_ids, int(viewer_id))
            )
            for review_id, status, comment, updated_at in cursor.fetchall() or []:
                my_entries[str(review_id)] = {
                    'my_review_status': self._normalize_low_rating_review_status(status),
                    'my_review_comment': comment or '',
                    'my_review_updated_at': updated_at.isoformat() if isinstance(updated_at, datetime) else None,
                }

        for item in items:
            review_id = str(item.get('id'))
            counts = by_review.get(review_id, {'review_count': 0, 'status_counts': {}})
            status_counts = counts.get('status_counts') or {}
            review_count = int(counts.get('review_count') or 0)
            has_review_conflict = bool(
                review_count >= 2
                and int(status_counts.get('valid') or 0) > 0
                and int(status_counts.get('invalid') or 0) > 0
            )
            item['review_count'] = int(counts.get('review_count') or 0)
            item['review_status_counts'] = status_counts
            item.update(my_entries.get(review_id, {
                'my_review_status': None,
                'my_review_comment': '',
                'my_review_updated_at': None,
            }))
            item['has_review_conflict'] = has_review_conflict
            item['review_entries'] = review_entries.get(review_id, [])
            if item.get('final_status'):
                item['review_state'] = 'resolved'
            elif has_review_conflict:
                item['review_state'] = 'conflict'
            else:
                item['review_state'] = 'pending'
            item['needs_head_decision'] = bool(has_review_conflict and not item.get('final_status'))
        return items

    def _resolve_low_rating_final_status_from_entries_tx(self, cursor, review_id, manager_status=None):
        cursor.execute(
            """
            SELECT status, COUNT(*)
            FROM chat_manager_low_rating_review_entries
            WHERE review_id = %s
              AND status IS NOT NULL
            GROUP BY status
            """,
            (review_id,)
        )
        counts = {}
        for status, count in cursor.fetchall() or []:
            normalized = self._normalize_low_rating_review_status(status)
            if normalized:
                counts[normalized] = counts.get(normalized, 0) + int(count or 0)
        review_count = sum(counts.values())
        has_review_conflict = bool(
            review_count >= 2
            and counts.get('valid', 0) > 0
            and counts.get('invalid', 0) > 0
        )
        if review_count >= 2 and len(counts) == 1:
            return next(iter(counts.keys())), 'consensus'
        manager = self._normalize_low_rating_review_status(manager_status)
        if manager and has_review_conflict:
            return manager, 'manager'
        return None, None

    def _recalculate_chat_manager_score_adjustments_tx(self, cursor, operator_day_pairs):
        pairs = sorted({
            (
                int(op_id),
                day_obj.date() if isinstance(day_obj, datetime)
                else day_obj if isinstance(day_obj, date)
                else datetime.strptime(str(day_obj), '%Y-%m-%d').date()
            )
            for op_id, day_obj in (operator_day_pairs or [])
            if op_id is not None and day_obj is not None
        }, key=lambda item: (item[0], item[1]))
        if not pairs:
            return {'adjusted_days': 0, 'aggregations': {}}

        adjusted = []
        for operator_id, day_obj in pairs:
            cursor.execute(
                """
                SELECT raw_score_sum, raw_score_count
                FROM chat_manager_daily_metrics
                WHERE operator_id = %s AND day = %s
                FOR UPDATE
                """,
                (operator_id, day_obj)
            )
            metric_row = cursor.fetchone()
            if not metric_row:
                continue
            raw_sum, raw_count = metric_row
            if raw_sum is None or raw_count is None:
                continue
            try:
                base_sum = float(raw_sum)
                base_count = int(raw_count)
            except Exception:
                continue

            cursor.execute(
                """
                SELECT COALESCE(SUM(score), 0), COUNT(*)
                FROM chat_manager_low_rating_reviews
                WHERE operator_id = %s
                  AND day = %s
                  AND final_status = 'invalid'
                """,
                (operator_id, day_obj)
            )
            invalid_sum_raw, invalid_count_raw = cursor.fetchone() or (0, 0)
            invalid_sum = float(invalid_sum_raw or 0.0)
            invalid_count = int(invalid_count_raw or 0)
            effective_count = max(0, base_count - invalid_count)
            effective_sum = round(max(0.0, base_sum - invalid_sum), 4)
            effective_avg = round(effective_sum / effective_count, 4) if effective_count > 0 else None

            cursor.execute(
                """
                UPDATE chat_manager_daily_metrics
                SET score_sum = %s,
                    score_count = %s,
                    avg_score = %s,
                    updated_at = CURRENT_TIMESTAMP
                WHERE operator_id = %s AND day = %s
                """,
                (effective_sum, effective_count, effective_avg, operator_id, day_obj)
            )
            adjusted.append((operator_id, day_obj))

        aggregations = {}
        for operator_id, day_obj in adjusted:
            month_key = day_obj.strftime('%Y-%m')
            aggregations.setdefault(operator_id, {})[month_key] = self._aggregate_month_from_daily_tx(
                cursor,
                operator_id,
                month_key
            )
        return {'adjusted_days': len(adjusted), 'aggregations': aggregations}

    def save_chat_manager_low_ratings(self, low_ratings, imported_by=None, source_batch_id=None):
        if not isinstance(low_ratings, list):
            raise ValueError("low_ratings must be a list")

        rows = []
        affected_pairs = set()
        imported_by_id = int(imported_by) if imported_by is not None else None
        batch_id = str(source_batch_id) if source_batch_id else None

        for item in low_ratings:
            if not isinstance(item, dict):
                continue
            try:
                operator_id = int(item.get('operator_id'))
                score = float(str(item.get('score')).replace(',', '.'))
            except Exception:
                continue
            if score >= 4:
                continue

            rated_at = self._parse_low_rating_datetime(
                item.get('rated_at') or item.get('created_at') or item.get('date')
            )
            day_raw = item.get('day') or item.get('metric_day') or item.get('date')
            day_obj = None
            if isinstance(day_raw, datetime):
                day_obj = day_raw.date()
            elif isinstance(day_raw, date):
                day_obj = day_raw
            else:
                try:
                    day_obj = datetime.strptime(str(day_raw or '').strip()[:10], '%Y-%m-%d').date()
                except Exception:
                    day_obj = rated_at.date() if rated_at else None
            if day_obj is None:
                continue
            if rated_at is None:
                rated_at = datetime.combine(day_obj, dt_time.min)

            source = str(item.get('source') or 'chat2desk').strip()[:64] or 'chat2desk'
            phone_number = str(item.get('phone_number') or item.get('phone') or '').strip()[:64]
            phone_normalized = self._normalize_low_rating_phone(phone_number)[:32]
            taxi_park = str(item.get('taxi_park') or item.get('taxopark') or item.get('direction') or '').strip()[:255]
            operator_name = str(item.get('operator_name') or '').strip()[:255]
            raw_payload = item.get('raw_payload') if isinstance(item.get('raw_payload'), dict) else dict(item)

            source_key = str(item.get('source_key') or item.get('external_id') or '').strip()
            if not source_key:
                source_key_seed = json.dumps({
                    'source': source,
                    'operator_id': operator_id,
                    'rated_at': rated_at.isoformat() if rated_at else None,
                    'day': day_obj.strftime('%Y-%m-%d'),
                    'score': score,
                    'phone': phone_normalized,
                    'taxi_park': taxi_park,
                    'source_row': item.get('source_row'),
                    'raw': raw_payload,
                }, ensure_ascii=False, sort_keys=True, default=str)
                source_key = uuid.uuid5(uuid.NAMESPACE_URL, source_key_seed).hex
            source_key = source_key[:255]

            rows.append((
                source,
                source_key,
                operator_id,
                operator_name,
                phone_number,
                phone_normalized,
                taxi_park,
                rated_at,
                day_obj,
                score,
                Json(raw_payload),
                imported_by_id,
                batch_id,
            ))
            affected_pairs.add((operator_id, day_obj))

        if not rows:
            return {'processed': 0, 'adjusted_days': 0}

        with self._get_cursor() as cursor:
            execute_values(
                cursor,
                """
                INSERT INTO chat_manager_low_rating_reviews (
                    source, source_key, operator_id, operator_name, phone_number,
                    phone_normalized, taxi_park, rated_at, day, score, raw_payload,
                    imported_by, source_batch_id
                )
                VALUES %s
                ON CONFLICT (source, source_key)
                DO UPDATE SET
                    operator_id = EXCLUDED.operator_id,
                    operator_name = COALESCE(NULLIF(EXCLUDED.operator_name, ''), chat_manager_low_rating_reviews.operator_name),
                    phone_number = COALESCE(NULLIF(EXCLUDED.phone_number, ''), chat_manager_low_rating_reviews.phone_number),
                    phone_normalized = COALESCE(NULLIF(EXCLUDED.phone_normalized, ''), chat_manager_low_rating_reviews.phone_normalized),
                    taxi_park = COALESCE(NULLIF(EXCLUDED.taxi_park, ''), chat_manager_low_rating_reviews.taxi_park),
                    rated_at = EXCLUDED.rated_at,
                    day = EXCLUDED.day,
                    score = EXCLUDED.score,
                    raw_payload = EXCLUDED.raw_payload,
                    imported_by = EXCLUDED.imported_by,
                    source_batch_id = COALESCE(EXCLUDED.source_batch_id, chat_manager_low_rating_reviews.source_batch_id),
                    updated_at = CURRENT_TIMESTAMP
                """,
                rows,
                page_size=1000
            )
            adjustment = self._recalculate_chat_manager_score_adjustments_tx(cursor, affected_pairs)

        return {
            'processed': len(rows),
            'adjusted_days': int((adjustment or {}).get('adjusted_days') or 0),
            'aggregations': (adjustment or {}).get('aggregations') or {},
        }

    def list_chat_manager_low_rating_reviews(
        self,
        month,
        department_id=None,
        operator_id=None,
        status=None,
        limit=2000,
        page=1,
        per_page=12,
        viewer_id=None,
        can_finalize=False,
    ):
        try:
            year, mon = map(int, str(month or '').split('-'))
            start = date(year, mon, 1)
            end = date(year, mon, calendar.monthrange(year, mon)[1])
        except Exception as exc:
            raise ValueError("month must be in YYYY-MM format") from exc

        where = ["lr.day >= %s", "lr.day <= %s"]
        params = [start, end]
        if department_id not in (None, ''):
            where.append("u.department_id = %s")
            params.append(int(department_id))
        if operator_id not in (None, ''):
            where.append("lr.operator_id = %s")
            params.append(int(operator_id))

        safe_limit = max(1, min(10000, int(limit or 2000)))
        safe_page = max(1, int(page or 1))
        safe_per_page = max(1, min(50, int(per_page or 12)))
        with self._get_cursor() as cursor:
            cursor.execute(
                f"""
                SELECT
                    lr.id, lr.source, lr.source_key, lr.operator_id,
                    COALESCE(NULLIF(lr.operator_name, ''), u.name, '') AS operator_name,
                    lr.phone_number, lr.phone_normalized, lr.taxi_park,
                    lr.rated_at, lr.day, lr.score, lr.raw_payload,
                    lr.imported_by, lr.source_batch_id,
                    lr.arai_status, lr.arai_comment, lr.arai_updated_by, au.name, lr.arai_updated_at,
                    lr.zhanna_status, lr.zhanna_comment, lr.zhanna_updated_by, zu.name, lr.zhanna_updated_at,
                    lr.head_status, lr.head_comment, lr.head_updated_by, hu.name, lr.head_updated_at,
                    lr.final_status, lr.final_source, lr.final_comment, lr.final_decided_by, fu.name, lr.final_decided_at,
                    lr.created_at, lr.updated_at,
                    d.name AS direction_name,
                    dep.id AS department_id,
                    dep.name AS department_name
                FROM chat_manager_low_rating_reviews lr
                JOIN users u ON u.id = lr.operator_id
                LEFT JOIN directions d ON d.id = u.direction_id
                LEFT JOIN departments dep ON dep.id = u.department_id
                LEFT JOIN users au ON au.id = lr.arai_updated_by
                LEFT JOIN users zu ON zu.id = lr.zhanna_updated_by
                LEFT JOIN users hu ON hu.id = lr.head_updated_by
                LEFT JOIN users fu ON fu.id = lr.final_decided_by
                WHERE {' AND '.join(where)}
                ORDER BY lr.rated_at DESC NULLS LAST, lr.day DESC, lr.created_at DESC
                LIMIT %s
                """,
                params + [safe_limit]
            )
            all_rows = [self._low_rating_row_to_dict(row) for row in cursor.fetchall() or []]
            self._attach_low_rating_review_entries_tx(cursor, all_rows, viewer_id=viewer_id)

        summary = {
            'total': len(all_rows),
            'pending': 0,
            'conflict': 0,
            'valid': 0,
            'invalid': 0,
        }
        for item in all_rows:
            state = item.get('review_state')
            final_status = item.get('final_status')
            if final_status == 'valid':
                summary['valid'] += 1
            elif final_status == 'invalid':
                summary['invalid'] += 1
            elif state == 'conflict':
                summary['conflict'] += 1
            else:
                summary['pending'] += 1

        status_key = str(status or 'attention').strip().lower()
        if status_key in ('all', ''):
            rows = all_rows
        elif status_key == 'attention':
            rows = [item for item in all_rows if not item.get('final_status')]
        elif status_key == 'mine':
            rows = [item for item in all_rows if item.get('my_review_status')]
        elif status_key in ('pending', 'conflict'):
            rows = [item for item in all_rows if item.get('review_state') == status_key]
        elif status_key in ('valid', 'invalid'):
            rows = [item for item in all_rows if item.get('final_status') == status_key]
        else:
            rows = all_rows

        total_filtered = len(rows)
        total_pages = max(1, int(math.ceil(total_filtered / safe_per_page)))
        safe_page = min(safe_page, total_pages)
        start_idx = (safe_page - 1) * safe_per_page
        page_rows = rows[start_idx:start_idx + safe_per_page]

        return {
            'month': f"{year:04d}-{mon:02d}",
            'rows': [
                self._low_rating_public_item(item, viewer_id=viewer_id, can_finalize=can_finalize)
                for item in page_rows
            ],
            'summary': summary,
            'pagination': {
                'page': safe_page,
                'per_page': safe_per_page,
                'total': total_filtered,
                'total_pages': total_pages,
            },
        }

    def get_chat_manager_low_rating_review(self, review_id, viewer_id=None, public=False, can_finalize=False):
        with self._get_cursor() as cursor:
            cursor.execute(
                """
                SELECT
                    lr.id, lr.source, lr.source_key, lr.operator_id,
                    COALESCE(NULLIF(lr.operator_name, ''), u.name, '') AS operator_name,
                    lr.phone_number, lr.phone_normalized, lr.taxi_park,
                    lr.rated_at, lr.day, lr.score, lr.raw_payload,
                    lr.imported_by, lr.source_batch_id,
                    lr.arai_status, lr.arai_comment, lr.arai_updated_by, au.name, lr.arai_updated_at,
                    lr.zhanna_status, lr.zhanna_comment, lr.zhanna_updated_by, zu.name, lr.zhanna_updated_at,
                    lr.head_status, lr.head_comment, lr.head_updated_by, hu.name, lr.head_updated_at,
                    lr.final_status, lr.final_source, lr.final_comment, lr.final_decided_by, fu.name, lr.final_decided_at,
                    lr.created_at, lr.updated_at,
                    d.name AS direction_name,
                    dep.id AS department_id,
                    dep.name AS department_name
                FROM chat_manager_low_rating_reviews lr
                JOIN users u ON u.id = lr.operator_id
                LEFT JOIN directions d ON d.id = u.direction_id
                LEFT JOIN departments dep ON dep.id = u.department_id
                LEFT JOIN users au ON au.id = lr.arai_updated_by
                LEFT JOIN users zu ON zu.id = lr.zhanna_updated_by
                LEFT JOIN users hu ON hu.id = lr.head_updated_by
                LEFT JOIN users fu ON fu.id = lr.final_decided_by
                WHERE lr.id = %s
                """,
                (review_id,)
            )
            row = cursor.fetchone()
            item = self._low_rating_row_to_dict(row) if row else None
            if item is not None:
                self._attach_low_rating_review_entries_tx(cursor, [item], viewer_id=viewer_id)
        if not item:
            return None
        if public:
            return self._low_rating_public_item(item, viewer_id=viewer_id, can_finalize=can_finalize)
        return item

    def save_chat_manager_low_rating_personal_review(self, review_id, reviewer_id, status, comment=''):
        normalized_status = self._normalize_low_rating_review_status(status)
        clean_comment = str(comment or '').strip()[:4000]
        reviewer_id_int = int(reviewer_id)

        with self._get_cursor() as cursor:
            cursor.execute(
                """
                SELECT operator_id, day, head_status, head_comment
                FROM chat_manager_low_rating_reviews
                WHERE id = %s
                FOR UPDATE
                """,
                (review_id,)
            )
            current = cursor.fetchone()
            if not current:
                return None
            operator_id, day_obj, head_status, head_comment = current

            cursor.execute(
                """
                INSERT INTO chat_manager_low_rating_review_entries (
                    review_id, reviewer_id, status, comment, created_at, updated_at
                )
                VALUES (%s, %s, %s, %s, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP)
                ON CONFLICT (review_id, reviewer_id)
                DO UPDATE SET
                    status = EXCLUDED.status,
                    comment = EXCLUDED.comment,
                    updated_at = CURRENT_TIMESTAMP
                """,
                (review_id, reviewer_id_int, normalized_status, clean_comment)
            )
            final_status, final_source = self._resolve_low_rating_final_status_from_entries_tx(
                cursor,
                review_id,
                manager_status=head_status
            )
            final_comment = head_comment if final_source == 'manager' else ''
            cursor.execute(
                """
                UPDATE chat_manager_low_rating_reviews
                SET final_status = %s,
                    final_source = %s,
                    final_comment = %s,
                    final_decided_by = %s,
                    final_decided_at = CASE WHEN %s IS NULL THEN NULL ELSE CURRENT_TIMESTAMP END,
                    updated_at = CURRENT_TIMESTAMP
                WHERE id = %s
                """,
                (final_status, final_source, final_comment or '', reviewer_id_int if final_status else None, final_status, review_id)
            )
            adjustment = self._recalculate_chat_manager_score_adjustments_tx(cursor, [(operator_id, day_obj)])

        item = self.get_chat_manager_low_rating_review(review_id, viewer_id=reviewer_id_int)
        if item is not None:
            item['adjustment'] = adjustment
        return item

    def finalize_chat_manager_low_rating_review(self, review_id, status, comment='', updated_by=None):
        normalized_status = self._normalize_low_rating_review_status(status)
        if not normalized_status:
            raise ValueError("final status is required")
        clean_comment = str(comment or '').strip()[:4000]
        updated_by_id = int(updated_by) if updated_by is not None else None

        with self._get_cursor() as cursor:
            cursor.execute(
                """
                SELECT operator_id, day
                FROM chat_manager_low_rating_reviews
                WHERE id = %s
                FOR UPDATE
                """,
                (review_id,)
            )
            current = cursor.fetchone()
            if not current:
                return None
            operator_id, day_obj = current

            cursor.execute(
                """
                SELECT status, COUNT(*)
                FROM chat_manager_low_rating_review_entries
                WHERE review_id = %s
                  AND status IS NOT NULL
                GROUP BY status
                """,
                (review_id,)
            )
            counts = {}
            for status_value, count in cursor.fetchall() or []:
                normalized = self._normalize_low_rating_review_status(status_value)
                if normalized:
                    counts[normalized] = counts.get(normalized, 0) + int(count or 0)
            review_count = sum(counts.values())
            has_review_conflict = bool(
                review_count >= 2
                and counts.get('valid', 0) > 0
                and counts.get('invalid', 0) > 0
            )
            if not has_review_conflict:
                raise ValueError("Final decision is available only when two reviews disagree")

            final_status, final_source = self._resolve_low_rating_final_status_from_entries_tx(
                cursor,
                review_id,
                manager_status=normalized_status
            )
            final_comment = clean_comment if final_source == 'manager' else ''
            cursor.execute(
                """
                UPDATE chat_manager_low_rating_reviews
                SET head_status = %s,
                    head_comment = %s,
                    head_updated_by = %s,
                    head_updated_at = CURRENT_TIMESTAMP,
                    final_status = %s,
                    final_source = %s,
                    final_comment = %s,
                    final_decided_by = %s,
                    final_decided_at = CASE WHEN %s IS NULL THEN NULL ELSE CURRENT_TIMESTAMP END,
                    updated_at = CURRENT_TIMESTAMP
                WHERE id = %s
                """,
                (
                    normalized_status,
                    clean_comment,
                    updated_by_id,
                    final_status,
                    final_source,
                    final_comment,
                    updated_by_id if final_status else None,
                    final_status,
                    review_id,
                )
            )
            adjustment = self._recalculate_chat_manager_score_adjustments_tx(cursor, [(operator_id, day_obj)])

        item = self.get_chat_manager_low_rating_review(review_id, viewer_id=updated_by_id)
        if item is not None:
            item['adjustment'] = adjustment
        return item

    def update_chat_manager_low_rating_review(self, review_id, reviewer, status, comment='', updated_by=None):
        reviewer_key = str(reviewer or '').strip().lower()
        field_map = {
            'arai': ('arai_status', 'arai_comment', 'arai_updated_by', 'arai_updated_at'),
            'zhanna': ('zhanna_status', 'zhanna_comment', 'zhanna_updated_by', 'zhanna_updated_at'),
            'head': ('head_status', 'head_comment', 'head_updated_by', 'head_updated_at'),
        }
        if reviewer_key not in field_map:
            raise ValueError("reviewer must be arai, zhanna or head")
        normalized_status = self._normalize_low_rating_review_status(status)
        clean_comment = str(comment or '').strip()[:4000]
        updated_by_id = int(updated_by) if updated_by is not None else None
        status_col, comment_col, by_col, at_col = field_map[reviewer_key]

        with self._get_cursor() as cursor:
            cursor.execute(
                """
                SELECT operator_id, day, arai_status, zhanna_status, head_status
                FROM chat_manager_low_rating_reviews
                WHERE id = %s
                FOR UPDATE
                """,
                (review_id,)
            )
            current = cursor.fetchone()
            if not current:
                return None
            operator_id, day_obj, arai_status, zhanna_status, head_status = current

            cursor.execute(
                f"""
                UPDATE chat_manager_low_rating_reviews
                SET {status_col} = %s,
                    {comment_col} = %s,
                    {by_col} = %s,
                    {at_col} = CURRENT_TIMESTAMP,
                    updated_at = CURRENT_TIMESTAMP
                WHERE id = %s
                """,
                (normalized_status, clean_comment, updated_by_id, review_id)
            )

            next_statuses = {
                'arai': arai_status,
                'zhanna': zhanna_status,
                'head': head_status,
            }
            next_statuses[reviewer_key] = normalized_status
            final_status, final_source = self._resolve_low_rating_final_status(
                next_statuses.get('arai'),
                next_statuses.get('zhanna'),
                next_statuses.get('head')
            )
            cursor.execute(
                """
                UPDATE chat_manager_low_rating_reviews
                SET final_status = %s,
                    final_source = %s,
                    final_decided_by = %s,
                    final_decided_at = CASE WHEN %s IS NULL THEN NULL ELSE CURRENT_TIMESTAMP END,
                    updated_at = CURRENT_TIMESTAMP
                WHERE id = %s
                """,
                (final_status, final_source, updated_by_id if final_status else None, final_status, review_id)
            )
            adjustment = self._recalculate_chat_manager_score_adjustments_tx(cursor, [(operator_id, day_obj)])

        item = self.get_chat_manager_low_rating_review(review_id)
        if item is not None:
            item['adjustment'] = adjustment
        return item

    @staticmethod
    def _parse_chat_metric_surge_month(month):
        text = str(month or '').strip()
        if not re.fullmatch(r'\d{4}-\d{2}', text):
            raise ValueError("month must be in YYYY-MM format")
        try:
            return datetime.strptime(text, '%Y-%m').date().replace(day=1)
        except Exception:
            raise ValueError("month must be in YYYY-MM format")

    @staticmethod
    def _parse_chat_metric_surge_dt(value, field_name='datetime'):
        if isinstance(value, datetime):
            return value.replace(tzinfo=None)
        text = str(value or '').strip()
        if not text:
            raise ValueError(f"{field_name} is required")
        text = text.replace('Z', '')
        for fmt in ('%Y-%m-%dT%H:%M:%S', '%Y-%m-%dT%H:%M', '%Y-%m-%d %H:%M:%S', '%Y-%m-%d %H:%M'):
            try:
                return datetime.strptime(text, fmt)
            except Exception:
                pass
        try:
            return datetime.fromisoformat(text).replace(tzinfo=None)
        except Exception:
            raise ValueError(f"{field_name} must be a valid datetime")

    @staticmethod
    def _format_chat_metric_surge_dt(value):
        if isinstance(value, datetime):
            return value.strftime('%Y-%m-%dT%H:%M')
        return ''

    def get_chat_metric_surge_windows(self, month):
        month_start = self._parse_chat_metric_surge_month(month)
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT
                    id,
                    month,
                    start_at,
                    end_at,
                    description,
                    created_by,
                    updated_by,
                    created_at,
                    updated_at
                FROM chat_metric_surge_windows
                WHERE month = %s
                ORDER BY start_at ASC, end_at ASC, id ASC
            """, (month_start,))
            rows = cursor.fetchall() or []

        windows = []
        for row in rows:
            windows.append({
                'id': str(row[0]),
                'month': row[1].strftime('%Y-%m') if row[1] else month_start.strftime('%Y-%m'),
                'start': self._format_chat_metric_surge_dt(row[2]),
                'end': self._format_chat_metric_surge_dt(row[3]),
                'description': row[4] or '',
                'created_by': row[5],
                'updated_by': row[6],
                'created_at': row[7].isoformat() if row[7] else None,
                'updated_at': row[8].isoformat() if row[8] else None,
            })
        return {
            'month': month_start.strftime('%Y-%m'),
            'windows': windows,
        }

    def save_chat_metric_surge_windows(self, month, windows, updated_by=None):
        month_start = self._parse_chat_metric_surge_month(month)
        if not isinstance(windows, list):
            raise ValueError("windows must be a list")

        rows = []
        updated_by_id = int(updated_by) if updated_by is not None else None
        for item in windows:
            if not isinstance(item, dict):
                continue
            start_dt = self._parse_chat_metric_surge_dt(item.get('start'), 'start')
            end_dt = self._parse_chat_metric_surge_dt(item.get('end'), 'end')
            if end_dt < start_dt:
                start_dt, end_dt = end_dt, start_dt
            description = str(
                item.get('description')
                if item.get('description') is not None
                else item.get('comment') if item.get('comment') is not None else ''
            ).strip()[:2000]
            rows.append((month_start, start_dt, end_dt, description, updated_by_id, updated_by_id))

        with self._get_cursor() as cursor:
            cursor.execute("DELETE FROM chat_metric_surge_windows WHERE month = %s", (month_start,))
            if rows:
                execute_values(
                    cursor,
                    """
                    INSERT INTO chat_metric_surge_windows (
                        month,
                        start_at,
                        end_at,
                        description,
                        created_by,
                        updated_by
                    )
                    VALUES %s
                    """,
                    rows,
                    page_size=500
                )

        return self.get_chat_metric_surge_windows(month_start.strftime('%Y-%m'))

    def save_chat_manager_daily_metrics(self, metrics, imported_by=None, preserve_missing=False, update_fields=None):
        """Сохраняет дневные метрики чат-менеджеров (upsert по (operator_id, day)).

        update_fields: если задан (множество имён колонок из {chats_count,
        whatsapp_chats_count, name_requests_chats_count, avg_score,
        avg_response_time_seconds, transfer_chat_count, score_sum, score_count}) — на конфликте
        ПЕРЕЗАПИСЫВАЮТСЯ только эти колонки (остальные метрики дня сохраняются нетронутыми).
        Это нужно для пер-форматного импорта: отчёт по оценкам не должен обнулять чаты и т.п.
        Для двух отчётов количества чатов обновляется только своя составляющая, а chats_count
        пересчитывается как whatsapp_chats_count + name_requests_chats_count.
        Если None — прежнее поведение (обновляются все метрики; preserve_missing влияет на
        avg_score/avg_response_time_seconds; score_sum/score_count сохраняются при отсутствии)."""
        if not isinstance(metrics, list):
            raise ValueError("metrics must be a list")

        _ALLOWED_UPDATE_FIELDS = {
            'chats_count', 'avg_score', 'avg_response_time_seconds',
            'transfer_chat_count', 'score_sum', 'score_count',
            'whatsapp_chats_count', 'name_requests_chats_count',
        }
        _CHAT_COUNT_COMPONENT_FIELDS = {'whatsapp_chats_count', 'name_requests_chats_count'}
        _PRESERVE_WHEN_MISSING_FIELDS = {
            'avg_score', 'avg_response_time_seconds', 'score_sum', 'score_count',
            'whatsapp_chats_count', 'name_requests_chats_count',
        }
        update_set = None
        if update_fields is not None:
            update_set = {str(f) for f in update_fields if str(f) in _ALLOWED_UPDATE_FIELDS}
            if not update_set:
                raise ValueError("update_fields must contain at least one valid metric column")

        rows = []
        batch_id = uuid.uuid4()
        imported_by_id = int(imported_by) if imported_by is not None else None

        for item in metrics:
            if not isinstance(item, dict):
                continue
            try:
                operator_id = int(item.get('operator_id'))
            except Exception:
                continue

            day_raw = item.get('day') or item.get('date')
            if isinstance(day_raw, datetime):
                day_obj = day_raw.date()
            elif isinstance(day_raw, date):
                day_obj = day_raw
            else:
                try:
                    day_obj = datetime.strptime(str(day_raw or '').strip(), '%Y-%m-%d').date()
                except Exception:
                    continue

            def _optional_float(raw):
                if raw in (None, ''):
                    return None
                try:
                    value = float(str(raw).replace(',', '.'))
                except Exception:
                    return None
                return value if math.isfinite(value) else None

            def _optional_int(raw):
                if raw in (None, ''):
                    return 0
                try:
                    return max(0, int(round(float(str(raw).replace(',', '.')))))
                except Exception:
                    return 0

            def _optional_int_or_none(raw):
                if raw in (None, ''):
                    return None
                try:
                    return max(0, int(round(float(str(raw).replace(',', '.')))))
                except Exception:
                    return None

            avg_response_seconds = _optional_float(
                item.get('avg_response_time_seconds')
                if item.get('avg_response_time_seconds') not in (None, '')
                else item.get('response_time_seconds')
            )
            avg_response_minutes = _optional_float(
                item.get('avg_response_time_minutes')
                if item.get('avg_response_time_minutes') not in (None, '')
                else item.get('response_time_minutes')
            )
            if avg_response_seconds is None and avg_response_minutes is not None:
                avg_response_seconds = avg_response_minutes * 60.0

            score_sum_val = _optional_float(item.get('score_sum'))
            score_count_val = _optional_int_or_none(item.get('score_count'))
            avg_score_val = _optional_float(item.get('avg_score') if item.get('avg_score') not in (None, '') else item.get('score'))
            # Если оценка пришла как сумма+количество (импорт отчёта), avg = sum/count.
            if avg_score_val is None and score_sum_val is not None and score_count_val:
                avg_score_val = round(score_sum_val / score_count_val, 4)
            raw_score_sum_val = score_sum_val if 'score_sum' in item else None
            raw_score_count_val = score_count_val if 'score_count' in item else None

            whatsapp_chats_val = _optional_int(item.get('whatsapp_chats_count'))
            name_requests_chats_val = _optional_int(item.get('name_requests_chats_count'))

            rows.append((
                operator_id,
                day_obj,
                _optional_int(item.get('chats_count') if item.get('chats_count') not in (None, '') else item.get('chats')),
                avg_score_val,
                avg_response_seconds,
                _optional_int(item.get('transfer_chat_count') if item.get('transfer_chat_count') not in (None, '') else item.get('transfers')),
                imported_by_id,
                str(batch_id),
                Json(item),
                score_sum_val,
                score_count_val,
                whatsapp_chats_val,
                name_requests_chats_val,
                raw_score_sum_val,
                raw_score_count_val,
            ))

        if not rows:
            return {'batch_id': str(batch_id), 'processed': 0}

        if update_set is not None:
            # Пер-форматный импорт: перезаписываем ТОЛЬКО указанные колонки (replace),
            # остальные метрики дня остаются нетронутыми (другой отчёт их не обнуляет).
            component_updates = update_set & _CHAT_COUNT_COMPONENT_FIELDS

            def _update_expr(col):
                if col in _PRESERVE_WHEN_MISSING_FIELDS:
                    return (
                        f"CASE WHEN EXCLUDED.raw_payload ? '{col}' "
                        f"THEN EXCLUDED.{col} ELSE chat_manager_daily_metrics.{col} END"
                    )
                return f"EXCLUDED.{col}"

            set_clauses = [
                f"{col} = {_update_expr(col)}"
                for col in sorted(update_set)
                if col not in _CHAT_COUNT_COMPONENT_FIELDS and not (component_updates and col == 'chats_count')
            ]
            if 'score_sum' in update_set:
                set_clauses.append(
                    "raw_score_sum = CASE WHEN EXCLUDED.raw_payload ? 'score_sum' "
                    "THEN EXCLUDED.raw_score_sum ELSE chat_manager_daily_metrics.raw_score_sum END"
                )
            if 'score_count' in update_set:
                set_clauses.append(
                    "raw_score_count = CASE WHEN EXCLUDED.raw_payload ? 'score_count' "
                    "THEN EXCLUDED.raw_score_count ELSE chat_manager_daily_metrics.raw_score_count END"
                )
            set_clauses.extend([f"{col} = {_update_expr(col)}" for col in sorted(component_updates)])
            if component_updates:
                whatsapp_expr = (
                    _update_expr('whatsapp_chats_count')
                    if 'whatsapp_chats_count' in component_updates
                    else "chat_manager_daily_metrics.whatsapp_chats_count"
                )
                name_requests_expr = (
                    _update_expr('name_requests_chats_count')
                    if 'name_requests_chats_count' in component_updates
                    else "chat_manager_daily_metrics.name_requests_chats_count"
                )
                set_clauses.append(
                    f"chats_count = COALESCE({whatsapp_expr}, 0) + COALESCE({name_requests_expr}, 0)"
                )
        else:
            # Прежнее поведение: обновляем все метрики. preserve_missing защищает оценку/время
            # ответа от затирания NULL-ом; score_sum/score_count сохраняем при отсутствии (модалка
            # их не присылает), чтобы не терять взвешенную оценку из импорта.
            avg_score_expr = (
                "COALESCE(EXCLUDED.avg_score, chat_manager_daily_metrics.avg_score)"
                if preserve_missing else "EXCLUDED.avg_score"
            )
            avg_response_expr = (
                "COALESCE(EXCLUDED.avg_response_time_seconds, chat_manager_daily_metrics.avg_response_time_seconds)"
                if preserve_missing else "EXCLUDED.avg_response_time_seconds"
            )
            set_clauses = [
                "chats_count = EXCLUDED.chats_count",
                f"avg_score = {avg_score_expr}",
                f"avg_response_time_seconds = {avg_response_expr}",
                "transfer_chat_count = EXCLUDED.transfer_chat_count",
                "score_sum = COALESCE(EXCLUDED.score_sum, chat_manager_daily_metrics.score_sum)",
                "score_count = COALESCE(EXCLUDED.score_count, chat_manager_daily_metrics.score_count)",
                "raw_score_sum = COALESCE(EXCLUDED.raw_score_sum, chat_manager_daily_metrics.raw_score_sum)",
                "raw_score_count = COALESCE(EXCLUDED.raw_score_count, chat_manager_daily_metrics.raw_score_count)",
            ]
        set_clauses += [
            "imported_by = EXCLUDED.imported_by",
            "source_batch_id = EXCLUDED.source_batch_id",
            "raw_payload = EXCLUDED.raw_payload",
            "updated_at = CURRENT_TIMESTAMP",
        ]
        do_update_sql = ",\n                    ".join(set_clauses)

        with self._get_cursor() as cursor:
            execute_values(
                cursor,
                f"""
                INSERT INTO chat_manager_daily_metrics (
                    operator_id,
                    day,
                    chats_count,
                    avg_score,
                    avg_response_time_seconds,
                    transfer_chat_count,
                    imported_by,
                    source_batch_id,
                    raw_payload,
                    score_sum,
                    score_count,
                    whatsapp_chats_count,
                    name_requests_chats_count,
                    raw_score_sum,
                    raw_score_count
                )
                VALUES %s
                ON CONFLICT (operator_id, day)
                DO UPDATE SET
                    {do_update_sql}
                """,
                rows,
                page_size=2000
            )

            score_adjustment = self._recalculate_chat_manager_score_adjustments_tx(
                cursor,
                [(row[0], row[1]) for row in rows]
            )
            affected_months = sorted({(int(row[0]), row[1].strftime('%Y-%m')) for row in rows})
            aggregations = {}
            for operator_id, month_key in affected_months:
                aggregations.setdefault(operator_id, {})[month_key] = self._aggregate_month_from_daily_tx(
                    cursor,
                    operator_id,
                    month_key
                )

        return {
            'batch_id': str(batch_id),
            'processed': len(rows),
            'aggregations': aggregations,
            'score_adjustment': score_adjustment,
        }

    def get_daily_hours_for_operator_month(self, operator_id: int, month: str):
        """
        Возвращает daily_hours для одного оператора за месяц YYYY-MM,
        а также norm_hours, aggregates (из work_hours) и rate/name из users.

        Включает поля штрафов из daily_hours: fine_amount, fine_reason, fine_comment
        и агрегированное поле fines из work_hours.

        Результат:
        {
            "month": month,
            "days_in_month": <int>,
            "operator": { ... }
        }
        """
        import calendar as _py_calendar
        from datetime import date as _date

        # validate month format YYYY-MM and compute date range
        try:
            year, mon = map(int, month.split('-'))
            days_in_month = _py_calendar.monthrange(year, mon)[1]
            start = _date(year, mon, 1)
            end = _date(year, mon, days_in_month)
        except Exception as e:
            raise ValueError("Invalid month format, expected YYYY-MM") from e

        with self._get_cursor() as cursor:
            # 1) Получаем daily_hours (одним запросом), теперь с информацией о штрафах
            cursor.execute(
                """
                SELECT day, work_time, break_time, talk_time, calls, efficiency,
                    fine_amount, fine_reason, fine_comment,
                    COALESCE(no_phone_minutes, 0), COALESCE(no_phone_seconds, 0)
                FROM daily_hours
                WHERE operator_id = %s AND day >= %s AND day <= %s
                ORDER BY day
                """,
                (operator_id, start, end),
            )
            daily_rows = cursor.fetchall()

            # build daily map: { "1": {...}, "2": {...}, ... }
            daily_map = {}
            no_phone_hours = 0.0
            for row in daily_rows:
                # row: (day, work_time, break_time, talk_time, calls, efficiency, fine_amount, fine_reason, fine_comment)
                day_obj = row[0]
                day_key = str(int(day_obj.day))
                no_phone_minutes = int(row[9] or 0)
                no_phone_seconds = int(row[10] or 0)
                no_phone_day_hours = float(no_phone_seconds or 0) / 3600.0
                no_phone_hours += no_phone_day_hours
                daily_map[day_key] = {
                    "work_time": float(row[1]) if row[1] is not None else 0.0,
                    "break_time": float(row[2]) if row[2] is not None else 0.0,
                    "talk_time": float(row[3]) if row[3] is not None else 0.0,
                    "calls": int(row[4]) if row[4] is not None else 0,
                    "efficiency": float(row[5]) if row[5] is not None else 0.0,
                    "fine_amount": float(row[6]) if row[6] is not None else 0.0,
                    "fine_reason": row[7],
                    "fine_comment": row[8],
                    "no_phone_minutes": no_phone_minutes,
                    "no_phone_seconds": no_phone_seconds,
                    "no_phone_hours": round(float(no_phone_day_hours), 4),
                    "fines": [],  # will populate from daily_fines table if present
                    "bonuses": []  # will populate from daily_bonuses table if present
                }

            # fetch fines for this operator in the date range
            cursor.execute(
                """
                SELECT df.amount, df.reason, df.comment, dh.day
                FROM daily_fines df
                JOIN daily_hours dh ON df.daily_hours_id = dh.id
                WHERE dh.operator_id = %s AND dh.day >= %s AND dh.day <= %s
                ORDER BY dh.day, df.id
                """,
                (operator_id, start, end)
            )
            fines_rows = cursor.fetchall()
            for amt, reason, comment, day_obj in fines_rows:
                day_key = str(int(day_obj.day))
                entry = daily_map.get(day_key)
                fine_obj = {
                    "amount": float(amt) if amt is not None else 0.0,
                    "reason": reason,
                    "comment": comment
                }
                # include minutes for Опоздание for client convenience
                try:
                    if str(reason) == 'Опоздание':
                        fine_obj['minutes'] = int(round(float(amt) / 50)) if amt else 0
                except Exception:
                    pass
                if entry is not None:
                    entry.setdefault('fines', []).append(fine_obj)

            cursor.execute(
                """
                SELECT bonus_type, quantity, training_hours, amount, friend_names, video_links, comment, day
                FROM daily_bonuses
                WHERE operator_id = %s AND day >= %s AND day <= %s
                ORDER BY day, id
                """,
                (operator_id, start, end)
            )
            bonuses_rows = cursor.fetchall()
            for bonus_type, quantity, training_hours, amount, friend_names, video_links, comment, day_obj in bonuses_rows:
                day_key = str(int(day_obj.day))
                entry = daily_map.get(day_key)
                if entry is None:
                    continue
                entry.setdefault('bonuses', []).append({
                    "type": bonus_type,
                    "bonus_type": bonus_type,
                    "quantity": int(quantity) if quantity is not None else 1,
                    "training_hours": float(training_hours) if training_hours is not None else None,
                    "amount": float(amount) if amount is not None else 0.0,
                    "friend_names": friend_names,
                    "video_links": video_links,
                    "comment": comment
                })

            technical_map_by_operator, technical_totals_by_operator = self._load_technical_issues_by_operator_day_tx(
                cursor=cursor,
                operator_ids=[operator_id],
                start_date=start,
                end_date=end
            )
            offline_map_by_operator, offline_totals_by_operator = self._load_offline_activities_by_operator_day_tx(
                cursor=cursor,
                operator_ids=[operator_id],
                start_date=start,
                end_date=end
            )
            training_totals_by_operator = self._load_training_hours_by_operator_tx(
                cursor=cursor,
                operator_ids=[operator_id],
                start_date=start,
                end_date=end
            )
            chat_metrics_by_operator, chat_totals_by_operator = self._load_chat_manager_metrics_by_operator_day_tx(
                cursor=cursor,
                operator_ids=[operator_id],
                start_date=start,
                end_date=end
            )

            # 2) Получаем имя/ставку + данные work_hours одним LEFT JOIN запросом (включая fines)
            cursor.execute(
                """
                SELECT u.name,
                    COALESCE(
                        (SELECT wr.rate FROM work_hours wr
                         WHERE wr.operator_id = u.id AND wr.rate IS NOT NULL AND wr.month <= %s
                         ORDER BY wr.month DESC LIMIT 1),
                        u.rate
                    ) AS rate,
                    d.name as direction_name,
                    d.calculation_model_code,
                    COALESCE(w.norm_hours, 0) AS norm_hours,
                    COALESCE(w.regular_hours, 0) AS regular_hours,
                    COALESCE(w.total_break_time, 0) AS total_break_time,
                    COALESCE(w.total_talk_time, 0) AS total_talk_time,
                    COALESCE(w.total_calls, 0) AS total_calls,
                    COALESCE(w.total_efficiency_hours, 0) AS total_efficiency_hours,
                    COALESCE(w.calls_per_hour, 0) AS calls_per_hour,
                    COALESCE(w.fines, 0) AS fines
                FROM users u
                LEFT JOIN work_hours w
                ON w.operator_id = u.id AND w.month = %s
                LEFT JOIN directions d ON u.direction_id = d.id
                WHERE u.id = %s
                LIMIT 1
                """,
                (month, month, operator_id),
            )
            row = cursor.fetchone()

        technical_issues_by_day = technical_map_by_operator.get(int(operator_id), {}) if isinstance(technical_map_by_operator, dict) else {}
        technical_issue_hours = float(technical_totals_by_operator.get(int(operator_id), 0.0)) if isinstance(technical_totals_by_operator, dict) else 0.0
        offline_activities_by_day = offline_map_by_operator.get(int(operator_id), {}) if isinstance(offline_map_by_operator, dict) else {}
        offline_activity_hours = float(offline_totals_by_operator.get(int(operator_id), 0.0)) if isinstance(offline_totals_by_operator, dict) else 0.0
        training_hours = float(training_totals_by_operator.get(int(operator_id), 0.0)) if isinstance(training_totals_by_operator, dict) else 0.0
        chat_metrics_by_day = chat_metrics_by_operator.get(int(operator_id), {}) if isinstance(chat_metrics_by_operator, dict) else {}
        chat_metric_totals = chat_totals_by_operator.get(int(operator_id), {}) if isinstance(chat_totals_by_operator, dict) else {}

        # default values if user / work_hours not found
        if row:
            name, rate, direction_name, calculation_model_raw, norm_hours, regular_hours, total_break_time, total_talk_time, \
                total_calls, total_efficiency_hours, calls_per_hour, fines = row
            rate = float(rate) if rate is not None else 0.0
        else:
            name = None
            rate = 0.0
            direction_name = None
            calculation_model_raw = None
            norm_hours = regular_hours = total_break_time = total_talk_time = 0.0
            total_calls = 0
            total_efficiency_hours = calls_per_hour = fines = 0.0
        calculation_model_code = self._normalize_calculation_model_code(calculation_model_raw, direction_name)

        # Сегменты членства оператора за месяц — для уведомления «несколько направлений»
        # и селектора в «Мои часы». daily здесь НЕ разбиты по группам; сегменты дают
        # информативную раскладку по дням/направлениям (членства непересекающиеся).
        group_segments = []
        with self._get_cursor() as _seg_cursor:
            _seg_cursor.execute(
                """
                SELECT gom.group_id, gr.name, gr.direction_id, d.name,
                       gr.calculation_model_code, gom.start_date, gom.end_date
                FROM group_operator_memberships gom
                JOIN groups gr ON gr.id = gom.group_id
                LEFT JOIN directions d ON d.id = gr.direction_id
                WHERE gom.operator_id = %s
                  AND gom.start_date <= %s
                  AND (gom.end_date IS NULL OR gom.end_date >= %s)
                ORDER BY gom.start_date
                """,
                (operator_id, end, start),
            )
            for g_id, g_name, dir_id, dir_name, model_code, seg_start, seg_end in _seg_cursor.fetchall() or []:
                clipped_start = seg_start if (seg_start and seg_start > start) else start
                clipped_end = seg_end if (seg_end and seg_end < end) else end
                group_segments.append({
                    "group_id": int(g_id),
                    "group_name": g_name,
                    "direction_id": dir_id,
                    "direction_name": dir_name,
                    "calculation_model_code": normalize_calculation_model_code(model_code, dir_name),
                    "start_day": int(clipped_start.day),
                    "end_day": int(clipped_end.day),
                    "is_current": seg_end is None,
                })
        segment_model_codes = {
            str(seg.get("calculation_model_code") or "").strip()
            for seg in group_segments
            if seg.get("calculation_model_code")
        }
        effective_calculation_model_code = (
            next(iter(segment_model_codes))
            if len(segment_model_codes) == 1
            else calculation_model_code
        )

        if effective_calculation_model_code == CALCULATION_MODEL_CHAT_MANAGER:
            _chat_chats = int(chat_metric_totals.get("chats_count") or 0)
            total_calls = _chat_chats
            regular_hours_for_rate = max(0.0, float(regular_hours or 0.0))
            calls_per_hour = (float(total_calls) / regular_hours_for_rate) if regular_hours_for_rate > 0 else 0.0
            for day_key, metrics in (chat_metrics_by_day or {}).items():
                entry = daily_map.setdefault(str(day_key), {
                    "work_time": 0.0,
                    "break_time": 0.0,
                    "talk_time": 0.0,
                    "calls": 0,
                    "efficiency": 0.0,
                    "fine_amount": 0.0,
                    "fine_reason": None,
                    "fine_comment": None,
                    "fines": [],
                    "bonuses": []
                })
                entry["chat_metrics"] = metrics
                entry["calls"] = int(metrics.get("chats_count") or 0)

        accounted_hours = (
            float(regular_hours or 0.0)
            + float(training_hours or 0.0)
            + float(technical_issue_hours or 0.0)
            + float(offline_activity_hours or 0.0)
        )

        operator_obj = {
            "operator_id": operator_id,
            "name": name,
            "direction": direction_name,
            "calculation_model_code": effective_calculation_model_code,
            "calculationModelCode": effective_calculation_model_code,
            "rate": rate,
            "norm_hours": float(norm_hours),
            "fines": float(fines),
            "training_hours": round(float(training_hours), 2),
            "no_phone_hours": round(float(no_phone_hours), 2),
            "accounted_hours": round(float(accounted_hours), 2),
            "worked_hours_used": round(float(accounted_hours), 2),
            "daily": daily_map,
            "group_segments": group_segments,
            "chat_metrics_by_day": chat_metrics_by_day,
            "chat_metrics": chat_metric_totals,
            "technical_issues_by_day": technical_issues_by_day,
            "technical_issue_hours": round(float(technical_issue_hours), 2),
            "offline_activities_by_day": offline_activities_by_day,
            "offline_activity_hours": round(float(offline_activity_hours), 2),
            "aggregates": {
                "regular_hours": float(regular_hours),
                "total_break_time": float(total_break_time),
                "total_talk_time": float(total_talk_time),
                "total_calls": int(total_calls),
                "total_efficiency_hours": float(total_efficiency_hours),
                "calls_per_hour": float(calls_per_hour),
                "chat_avg_score": chat_metric_totals.get("avg_score"),
                "chat_avg_response_time_seconds": chat_metric_totals.get("avg_response_time_seconds"),
                "chat_transfer_count": int(chat_metric_totals.get("transfer_chat_count") or 0),
            },
        }

        return {"month": month, "days_in_month": days_in_month, "operator": operator_obj}

    def get_daily_hours_by_group_month(self, group_id, month):
        """Group-aware: часы операторов ГРУППЫ за месяц (членство пересекает месяц);
        модель и фильтр daily — по этой группе. Тонкая обёртка над
        get_daily_hours_by_supervisor_month."""
        return self.get_daily_hours_by_supervisor_month(None, month, group_id=group_id)

    def get_daily_hours_by_supervisor_month(self, supervisor_id, month, group_id=None):
        """
        Возвращает daily_hours и агрегаты work_hours для операторов за месяц YYYY-MM.
        Если задан group_id — операторы выбираются по членству в группе, пересекающему
        месяц; модель берётся из ГРУППЫ, а daily фильтруется по этой группе (поддержка
        раздельных дней при переводе посреди месяца). Иначе — legacy-выборка по
        users.supervisor_id (поведение сохранено 1:1).
        Включает также ставку (rate) из users, norm_hours и fines из work_hours.
        """
        import calendar as _py_calendar
        from datetime import date as _date

        # validate month format YYYY-MM
        try:
            year, mon = map(int, month.split('-'))
            days = _py_calendar.monthrange(year, mon)[1]
            start = _date(year, mon, 1)
            end = _date(year, mon, days)
        except Exception as e:
            raise ValueError("Invalid month format, expected YYYY-MM") from e

        with self._get_cursor() as cursor:
            # Ленивая заморозка: при первом обращении к ЗАКРЫТОМУ месяцу (после 10-го числа
            # следующего) создаём снимок, если его ещё нет. Защищено try/except — не ломает чтение.
            if group_id is not None and self._is_month_closed(month):
                try:
                    if not self._month_snapshot_exists_tx(cursor, month):
                        self._freeze_month_to_snapshots_tx(cursor, month)
                except Exception as _freeze_err:
                    logging.error("lazy snapshot freeze failed for %s: %s", month, _freeze_err, exc_info=True)
            # Получаем операторов + ставка + norm_hours + агрегаты work_hours (включая fines).
            # Колонка модели и источник операторов различаются: group-aware vs legacy,
            # но СПИСОК и ПОРЯДОК колонок идентичны (downstream-распаковка одна).
            _sel_prefix = """
                SELECT u.id, u.name,
                    COALESCE(
                        (SELECT wr.rate FROM work_hours wr
                         WHERE wr.operator_id = u.id AND wr.rate IS NOT NULL AND wr.month <= %s
                         ORDER BY wr.month DESC LIMIT 1),
                        u.rate
                    ) AS rate,
                    u.status, u.supervisor_id,
                    d.name as direction_name,
            """
            _sel_suffix = """
                    COALESCE(w.norm_hours, 0) as norm_hours,
                    COALESCE(w.regular_hours, 0) as regular_hours,
                    COALESCE(w.total_break_time, 0) as total_break_time,
                    COALESCE(w.total_talk_time, 0) as total_talk_time,
                    COALESCE(w.total_calls, 0) as total_calls,
                    COALESCE(w.total_efficiency_hours, 0) as total_efficiency_hours,
                    COALESCE(w.calls_per_hour, 0) as calls_per_hour,
                    COALESCE(w.fines, 0) as fines
            """
            if group_id is not None:
                cursor.execute(
                    _sel_prefix
                    + "                    g.calculation_model_code as calculation_model_code,\n"
                    + _sel_suffix
                    + """
                    FROM group_operator_memberships gom
                    JOIN groups g ON g.id = gom.group_id
                    -- Историческая видимость: состав месяца определяется ЧЛЕНСТВОМ в группе,
                    -- а не текущей ролью. Иначе оператор, ставший СВ/уволенный, пропадает из
                    -- прошлых месяцев. Роль/статус на конец месяца резолвятся отдельно (status_as_of).
                    JOIN users u ON u.id = gom.operator_id
                    LEFT JOIN work_hours w ON w.operator_id = u.id AND w.month = %s
                    LEFT JOIN directions d ON u.direction_id = d.id
                    WHERE gom.group_id = %s
                      AND gom.start_date <= %s
                      AND (gom.end_date IS NULL OR gom.end_date >= %s)
                    ORDER BY u.name
                    """,
                    (month, month, int(group_id), end, start),
                )
            else:
                cursor.execute(
                    _sel_prefix
                    + "                    d.calculation_model_code as calculation_model_code,\n"
                    + _sel_suffix
                    + """
                    FROM users u
                    LEFT JOIN work_hours w ON w.operator_id = u.id AND w.month = %s
                    LEFT JOIN directions d ON u.direction_id = d.id
                    WHERE u.role = 'operator' AND u.supervisor_id = %s
                    ORDER BY u.name
                    """,
                    (month, month, supervisor_id),
                )
            operator_rows = cursor.fetchall()  # list of tuples

            if not operator_rows:
                return {"month": month, "days_in_month": days, "operators": []}

            op_ids = [row[0] for row in operator_rows]

            # --- transfer-aware: членства всех операторов, пересекающие месяц ---
            # Только в group-aware режиме (group_id задан). В legacy сегменты пустые,
            # фронт остаётся в прежнем поведении 1:1. Важно отдавать модель сегмента:
            # при переводе между операторской и чат-моделью UI должен брать метрики
            # той модели, которая действовала в конкретные дни.
            segments_by_operator = {}
            if group_id is not None:
                segments_by_operator = self._load_segments_by_operator_tx(cursor, op_ids, start, end)
                for segs in segments_by_operator.values():
                    for seg in segs:
                        seg["is_current"] = int(seg.get("group_id") or 0) == int(group_id)

            # --- статус оператора на конец месяца (из user_history; fallback — текущий) ---
            # Прошлый месяц должен показывать статус, который был тогда, а не нынешний.
            status_as_of = {}
            cursor.execute(
                """
                SELECT user_id, old_value, new_value, changed_at
                FROM user_history
                WHERE field_changed = 'status' AND user_id = ANY(%s)
                ORDER BY user_id, changed_at
                """,
                (op_ids,),
            )
            _st_changes, _st_first_old = {}, {}
            for _uid, _oldv, _newv, _at in cursor.fetchall() or []:
                if _uid not in _st_changes:
                    _st_changes[_uid] = []
                    _st_first_old[_uid] = _oldv
                _st_changes[_uid].append((_at, _newv))
            _st_ref = datetime(year + 1, 1, 1) if mon == 12 else datetime(year, mon + 1, 1)
            for _uid, _changes in _st_changes.items():
                _eff = None
                for _at, _newv in _changes:
                    if _at is not None and _at < _st_ref:
                        _eff = _newv
                    else:
                        break
                if _eff is None:
                    _eff = _st_first_old.get(_uid)
                if _eff:
                    status_as_of[int(_uid)] = _eff

            # Получаем daily_hours для этих операторов за месяц (с информацией о штрафах).
            # В group-aware режиме фильтруем по группе: дни этого оператора, отнесённые
            # именно к этой группе (поддержка раздельных дней при переводе).
            _daily_sql = """
                SELECT d.operator_id, d.day, d.work_time, d.break_time, d.talk_time, d.calls, d.efficiency,
                    d.fine_amount, d.fine_reason, d.fine_comment,
                    COALESCE(d.no_phone_minutes, 0), COALESCE(d.no_phone_seconds, 0)
                FROM daily_hours d
                WHERE d.operator_id = ANY(%s)
                AND d.day >= %s AND d.day <= %s
                {group_filter}
                ORDER BY d.operator_id, d.day
            """
            if group_id is not None:
                cursor.execute(
                    _daily_sql.format(group_filter="AND d.group_id = %s"),
                    (op_ids, start, end, int(group_id)),
                )
            else:
                cursor.execute(
                    _daily_sql.format(group_filter=""),
                    (op_ids, start, end),
                )
            daily_rows = cursor.fetchall()

            # Готовим словарь daily: operator_id -> {day_number: {...}}
            daily_map = {}
            no_phone_totals_by_operator = {}
            for (op_id, day, work_time, break_time, talk_time, calls, eff,
                fine_amount, fine_reason, fine_comment, no_phone_minutes, no_phone_seconds) in daily_rows:
                day_num = str(int(day.day))
                no_phone_minutes = int(no_phone_minutes or 0)
                no_phone_seconds = int(no_phone_seconds or 0)
                no_phone_day_hours = float(no_phone_seconds or 0) / 3600.0
                no_phone_totals_by_operator[op_id] = no_phone_totals_by_operator.get(op_id, 0.0) + no_phone_day_hours
                d = {
                    "work_time": float(work_time) if work_time is not None else 0.0,
                    "break_time": float(break_time) if break_time is not None else 0.0,
                    "talk_time": float(talk_time) if talk_time is not None else 0.0,
                    "calls": int(calls) if calls is not None else 0,
                    "efficiency": float(eff) if eff is not None else 0.0,
                    "fine_amount": float(fine_amount) if fine_amount is not None else 0.0,
                    "fine_reason": fine_reason,
                    "fine_comment": fine_comment,
                    "no_phone_minutes": no_phone_minutes,
                    "no_phone_seconds": no_phone_seconds,
                    "no_phone_hours": round(float(no_phone_day_hours), 4),
                    "fines": [],
                    "bonuses": []
                }
                daily_map.setdefault(op_id, {})[day_num] = d

            # fetch fines for all operators in range
            cursor.execute("""
                SELECT df.operator_id, df.amount, df.reason, df.comment, df.day
                FROM daily_fines df
                WHERE df.operator_id = ANY(%s)
                AND df.day >= %s AND df.day <= %s
                ORDER BY df.operator_id, df.day, df.id
            """, (op_ids, start, end))
            fines_rows = cursor.fetchall()
            for op_id, amt, reason, comment, day_obj in fines_rows:
                day_num = str(int(day_obj.day))
                fine_obj = {"amount": float(amt) if amt is not None else 0.0, "reason": reason, "comment": comment}
                try:
                    if str(reason) == 'Опоздание':
                        fine_obj['minutes'] = int(round(float(amt) / 50)) if amt else 0
                except Exception:
                    pass
                if op_id in daily_map and day_num in daily_map[op_id]:
                    daily_map[op_id][day_num].setdefault('fines', []).append(fine_obj)

            cursor.execute("""
                SELECT db.operator_id, db.bonus_type, db.quantity, db.training_hours, db.amount, db.friend_names, db.video_links, db.comment, db.day
                FROM daily_bonuses db
                WHERE db.operator_id = ANY(%s)
                AND db.day >= %s AND db.day <= %s
                ORDER BY db.operator_id, db.day, db.id
            """, (op_ids, start, end))
            bonuses_rows = cursor.fetchall()
            for op_id, bonus_type, quantity, training_hours, amount, friend_names, video_links, comment, day_obj in bonuses_rows:
                day_num = str(int(day_obj.day))
                bonus_obj = {
                    "type": bonus_type,
                    "bonus_type": bonus_type,
                    "quantity": int(quantity) if quantity is not None else 1,
                    "training_hours": float(training_hours) if training_hours is not None else None,
                    "amount": float(amount) if amount is not None else 0.0,
                    "friend_names": friend_names,
                    "video_links": video_links,
                    "comment": comment
                }
                if op_id in daily_map and day_num in daily_map[op_id]:
                    daily_map[op_id][day_num].setdefault('bonuses', []).append(bonus_obj)

            technical_map_by_operator, technical_totals_by_operator = self._load_technical_issues_by_operator_day_tx(
                cursor=cursor,
                operator_ids=op_ids,
                start_date=start,
                end_date=end,
                group_id=group_id
            )
            offline_map_by_operator, offline_totals_by_operator = self._load_offline_activities_by_operator_day_tx(
                cursor=cursor,
                operator_ids=op_ids,
                start_date=start,
                end_date=end,
                group_id=group_id
            )
            training_totals_by_operator = self._load_training_hours_by_operator_tx(
                cursor=cursor,
                operator_ids=op_ids,
                start_date=start,
                end_date=end,
                group_id=group_id
            )
            chat_metrics_by_operator, chat_totals_by_operator = self._load_chat_manager_metrics_by_operator_day_tx(
                cursor=cursor,
                operator_ids=op_ids,
                start_date=start,
                end_date=end,
                group_id=group_id
            )

            # Сбор финального списка операторов
            operators = []
            for row in operator_rows:
                (op_id, op_name, rate, status, sup_id, direction_name, calculation_model_raw, norm_hours,
                regular_hours, total_break_time, total_talk_time,
                total_calls, total_efficiency_hours, calls_per_hour, fines) = row
                calculation_model_code = self._normalize_calculation_model_code(calculation_model_raw, direction_name)
                op_daily = daily_map.get(op_id, {})
                # transfer-aware: в group-aware режиме месячные агрегаты пересобираем из
                # group-filtered daily_map (work_hours хранит ОБЩИЙ итог оператора без
                # разбивки по группам). Формулы — как в _aggregate_month_from_daily_tx;
                # fines — из daily_fines (список fines[]).
                grp_regular = grp_break = grp_talk = grp_eff = grp_fines = 0.0
                grp_calls = 0
                if group_id is not None:
                    for _dnum, _dd in op_daily.items():
                        grp_regular += float(_dd.get("work_time") or 0.0)
                        grp_break += float(_dd.get("break_time") or 0.0)
                        grp_talk += float(_dd.get("talk_time") or 0.0)
                        grp_eff += float(_dd.get("efficiency") or 0.0)
                        grp_calls += int(_dd.get("calls") or 0)
                        for _f in (_dd.get("fines") or []):
                            grp_fines += float(_f.get("amount") or 0.0)
                training_hours = float(training_totals_by_operator.get(op_id, 0.0)) if isinstance(training_totals_by_operator, dict) else 0.0
                technical_issue_hours = float(technical_totals_by_operator.get(op_id, 0.0)) if isinstance(technical_totals_by_operator, dict) else 0.0
                offline_activity_hours = float(offline_totals_by_operator.get(op_id, 0.0)) if isinstance(offline_totals_by_operator, dict) else 0.0
                no_phone_hours = float(no_phone_totals_by_operator.get(op_id, 0.0))
                accounted_regular_hours = float(grp_regular if group_id is not None else (regular_hours or 0.0))
                accounted_hours = accounted_regular_hours + training_hours + technical_issue_hours + offline_activity_hours
                chat_metrics_by_day = chat_metrics_by_operator.get(op_id, {}) if isinstance(chat_metrics_by_operator, dict) else {}
                chat_metric_totals = chat_totals_by_operator.get(op_id, {}) if isinstance(chat_totals_by_operator, dict) else {}
                if calculation_model_code == CALCULATION_MODEL_CHAT_MANAGER:
                    _chat_chats = int(chat_metric_totals.get("chats_count") or 0)
                    total_calls = _chat_chats
                    regular_hours_for_rate = max(0.0, accounted_regular_hours)
                    calls_per_hour = (float(total_calls) / regular_hours_for_rate) if regular_hours_for_rate > 0 else 0.0
                    for day_key, metrics in (chat_metrics_by_day or {}).items():
                        entry = op_daily.setdefault(str(day_key), {
                            "work_time": 0.0,
                            "break_time": 0.0,
                            "talk_time": 0.0,
                            "calls": 0,
                            "efficiency": 0.0,
                            "fine_amount": 0.0,
                            "fine_reason": None,
                            "fine_comment": None,
                            "fines": [],
                            "bonuses": []
                        })
                        entry["chat_metrics"] = metrics
                        entry["calls"] = int(metrics.get("chats_count") or 0)

                operators.append({
                    "operator_id": op_id,
                    "name": op_name,
                    "direction": direction_name,
                    "calculation_model_code": calculation_model_code,
                    "calculationModelCode": calculation_model_code,
                    "supervisor_id": sup_id,
                    "rate": float(rate) if rate is not None else 0.0,
                    "status": status_as_of.get(op_id, status),
                    "norm_hours": float(norm_hours) if norm_hours is not None else 0.0,
                    "training_hours": round(float(training_hours), 2),
                    "no_phone_hours": round(float(no_phone_hours), 2),
                    "accounted_hours": round(float(accounted_hours), 2),
                    "worked_hours_used": round(float(accounted_hours), 2),
                    "daily": op_daily,
                    "group_segments": segments_by_operator.get(op_id, []),
                    "chat_metrics_by_day": chat_metrics_by_day,
                    "chat_metrics": chat_metric_totals,
                    "technical_issues_by_day": technical_map_by_operator.get(op_id, {}) if isinstance(technical_map_by_operator, dict) else {},
                    "technical_issue_hours": round(float(technical_issue_hours), 2),
                    "offline_activities_by_day": offline_map_by_operator.get(op_id, {}) if isinstance(offline_map_by_operator, dict) else {},
                    "offline_activity_hours": round(float(offline_activity_hours), 2),
                    "aggregates": ({
                        # group-aware: суммы из group-filtered daily_map (раздельно по группам)
                        "regular_hours": float(grp_regular),
                        "total_break_time": float(grp_break),
                        "total_talk_time": float(grp_talk),
                        "total_calls": int(total_calls if calculation_model_code == CALCULATION_MODEL_CHAT_MANAGER else grp_calls),
                        "total_efficiency_hours": float(grp_eff),
                        "calls_per_hour": (
                            (float(total_calls if calculation_model_code == CALCULATION_MODEL_CHAT_MANAGER else grp_calls) / grp_regular)
                            if grp_regular > 0 else 0.0
                        ),
                        "fines": float(grp_fines),
                        "chat_avg_score": chat_metric_totals.get("avg_score"),
                        "chat_avg_response_time_seconds": chat_metric_totals.get("avg_response_time_seconds"),
                        "chat_transfer_count": int(chat_metric_totals.get("transfer_chat_count") or 0),
                    } if group_id is not None else {
                        # legacy (по СВ / без группы): агрегаты из work_hours — поведение 1:1
                        "regular_hours": float(regular_hours),
                        "total_break_time": float(total_break_time),
                        "total_talk_time": float(total_talk_time),
                        "total_calls": int(total_calls),
                        "total_efficiency_hours": float(total_efficiency_hours),
                        "calls_per_hour": float(calls_per_hour),
                        "fines": float(fines),
                        "chat_avg_score": chat_metric_totals.get("avg_score"),
                        "chat_avg_response_time_seconds": chat_metric_totals.get("avg_response_time_seconds"),
                        "chat_transfer_count": int(chat_metric_totals.get("transfer_chat_count") or 0),
                    })
                })

        # Закрытый месяц (после 10-го числа следующего): накладываем ЗАМОРОЖЕННЫЕ агрегаты/мету
        # из снимка — числа стабильны и не «плывут» от пост-правок daily/смены формул. Композиция
        # и daily-календарь остаются (исторический след). Защищено try/except — фолбэк на live.
        if group_id is not None and operators and self._is_month_closed(month):
            try:
                with self._get_cursor() as _sc:
                    _sc.execute("""
                        SELECT operator_id, status, rate, norm_hours, regular_hours, total_break_time,
                               total_talk_time, total_calls, total_efficiency_hours, calls_per_hour, fines,
                               chat_avg_score, chat_avg_response_time_seconds, chat_transfer_count
                        FROM group_operator_month_snapshots
                        WHERE group_id = %s AND month = %s AND frozen_at IS NOT NULL
                    """, (int(group_id), month))
                    snap = {int(r[0]): r for r in _sc.fetchall() or []}
                for _op in operators:
                    r = snap.get(int(_op.get("operator_id")))
                    if not r:
                        continue
                    if r[1] is not None:
                        _op["status"] = r[1]
                    if r[2] is not None:
                        _op["rate"] = float(r[2])
                    if r[3] is not None:
                        _op["norm_hours"] = float(r[3])
                    _op["aggregates"] = {
                        "regular_hours": float(r[4] or 0.0),
                        "total_break_time": float(r[5] or 0.0),
                        "total_talk_time": float(r[6] or 0.0),
                        "total_calls": int(r[7] or 0),
                        "total_efficiency_hours": float(r[8] or 0.0),
                        "calls_per_hour": float(r[9] or 0.0),
                        "fines": float(r[10] or 0.0),
                        "chat_avg_score": r[11],
                        "chat_avg_response_time_seconds": r[12],
                        "chat_transfer_count": int(r[13] or 0),
                    }
                    _op["frozen"] = True
            except Exception as _ov_err:
                logging.error("snapshot overlay failed for %s g%s: %s", month, group_id, _ov_err, exc_info=True)

        return {"month": month, "days_in_month": days, "operators": operators}

    def get_daily_hours_for_all_month(self, month, department_id=None):
        """
        Возвращает все daily_hours и агрегаты work_hours для всех операторов за месяц YYYY-MM.
        Аналогично get_daily_hours_by_supervisor_month, но без фильтра по супервайзеру.
        """
        import calendar as _py_calendar
        from datetime import date as _date

        try:
            year, mon = map(int, month.split('-'))
            days = _py_calendar.monthrange(year, mon)[1]
            start = _date(year, mon, 1)
            end = _date(year, mon, days)
        except Exception as e:
            raise ValueError("Invalid month format, expected YYYY-MM") from e

        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT u.id, u.name,
                    COALESCE(
                        (SELECT wr.rate FROM work_hours wr
                         WHERE wr.operator_id = u.id AND wr.rate IS NOT NULL AND wr.month <= %s
                         ORDER BY wr.month DESC LIMIT 1),
                        u.rate
                    ) AS rate,
                    u.status, u.supervisor_id,
                    d.name as direction_name,
                    d.calculation_model_code,
                    COALESCE(w.norm_hours, 0) as norm_hours,
                    COALESCE(w.regular_hours, 0) as regular_hours,
                    COALESCE(w.total_break_time, 0) as total_break_time,
                    COALESCE(w.total_talk_time, 0) as total_talk_time,
                    COALESCE(w.total_calls, 0) as total_calls,
                    COALESCE(w.total_efficiency_hours, 0) as total_efficiency_hours,
                    COALESCE(w.calls_per_hour, 0) as calls_per_hour,
                    COALESCE(w.fines, 0) as fines,
                    u.department_id
                FROM users u
                LEFT JOIN work_hours w
                ON w.operator_id = u.id AND w.month = %s
                LEFT JOIN directions d ON u.direction_id = d.id
                -- Историческая видимость: берём не только текущих операторов, но и всех,
                -- кто был оператором В ЭТОМ МЕСЯЦЕ (есть daily_hours или членство в группе),
                -- даже если сейчас стал СВ/уволен. Иначе прошлый отчёт «теряет» людей.
                WHERE (
                    u.role = 'operator'
                    OR EXISTS (SELECT 1 FROM daily_hours dh WHERE dh.operator_id = u.id AND dh.day >= %s AND dh.day <= %s)
                    OR EXISTS (SELECT 1 FROM group_operator_memberships gom
                               WHERE gom.operator_id = u.id AND gom.start_date <= %s
                                 AND (gom.end_date IS NULL OR gom.end_date >= %s))
                )
                AND (%s::int IS NULL OR u.department_id = %s::int)
                ORDER BY u.name
            """, (month, month, start, end, end, start, department_id, department_id))
            operator_rows = cursor.fetchall()

            if not operator_rows:
                return {"month": month, "days_in_month": days, "operators": []}

            op_ids = [row[0] for row in operator_rows]

            cursor.execute("""
                SELECT d.operator_id, d.day, d.work_time, d.break_time, d.talk_time, d.calls, d.efficiency,
                    d.fine_amount, d.fine_reason, d.fine_comment,
                    COALESCE(d.no_phone_minutes, 0), COALESCE(d.no_phone_seconds, 0)
                FROM daily_hours d
                WHERE d.operator_id = ANY(%s)
                AND d.day >= %s AND d.day <= %s
                ORDER BY d.operator_id, d.day
            """, (op_ids, start, end))
            daily_rows = cursor.fetchall()

            daily_map = {}
            no_phone_totals_by_operator = {}
            for (op_id, day, work_time, break_time, talk_time, calls, eff,
                fine_amount, fine_reason, fine_comment, no_phone_minutes, no_phone_seconds) in daily_rows:
                day_num = str(int(day.day))
                no_phone_minutes = int(no_phone_minutes or 0)
                no_phone_seconds = int(no_phone_seconds or 0)
                no_phone_day_hours = float(no_phone_seconds or 0) / 3600.0
                no_phone_totals_by_operator[op_id] = no_phone_totals_by_operator.get(op_id, 0.0) + no_phone_day_hours
                d = {
                    "work_time": float(work_time) if work_time is not None else 0.0,
                    "break_time": float(break_time) if break_time is not None else 0.0,
                    "talk_time": float(talk_time) if talk_time is not None else 0.0,
                    "calls": int(calls) if calls is not None else 0,
                    "efficiency": float(eff) if eff is not None else 0.0,
                    "fine_amount": float(fine_amount) if fine_amount is not None else 0.0,
                    "fine_reason": fine_reason,
                    "fine_comment": fine_comment,
                    "no_phone_minutes": no_phone_minutes,
                    "no_phone_seconds": no_phone_seconds,
                    "no_phone_hours": round(float(no_phone_day_hours), 4),
                    "fines": [],
                    "bonuses": []
                }
                daily_map.setdefault(op_id, {})[day_num] = d

            cursor.execute("""
                SELECT df.operator_id, df.amount, df.reason, df.comment, df.day
                FROM daily_fines df
                WHERE df.operator_id = ANY(%s)
                AND df.day >= %s AND df.day <= %s
                ORDER BY df.operator_id, df.day, df.id
            """, (op_ids, start, end))
            fines_rows = cursor.fetchall()
            for op_id, amt, reason, comment, day_obj in fines_rows:
                day_num = str(int(day_obj.day))
                fine_obj = {"amount": float(amt) if amt is not None else 0.0, "reason": reason, "comment": comment}
                try:
                    if str(reason) == 'Опоздание':
                        fine_obj['minutes'] = int(round(float(amt) / 50)) if amt else 0
                except Exception:
                    pass
                if op_id in daily_map and day_num in daily_map[op_id]:
                    daily_map[op_id][day_num].setdefault('fines', []).append(fine_obj)

            cursor.execute("""
                SELECT db.operator_id, db.bonus_type, db.quantity, db.training_hours, db.amount, db.friend_names, db.video_links, db.comment, db.day
                FROM daily_bonuses db
                WHERE db.operator_id = ANY(%s)
                AND db.day >= %s AND db.day <= %s
                ORDER BY db.operator_id, db.day, db.id
            """, (op_ids, start, end))
            bonuses_rows = cursor.fetchall()
            for op_id, bonus_type, quantity, training_hours, amount, friend_names, video_links, comment, day_obj in bonuses_rows:
                day_num = str(int(day_obj.day))
                bonus_obj = {
                    "type": bonus_type,
                    "bonus_type": bonus_type,
                    "quantity": int(quantity) if quantity is not None else 1,
                    "training_hours": float(training_hours) if training_hours is not None else None,
                    "amount": float(amount) if amount is not None else 0.0,
                    "friend_names": friend_names,
                    "video_links": video_links,
                    "comment": comment
                }
                if op_id in daily_map and day_num in daily_map[op_id]:
                    daily_map[op_id][day_num].setdefault('bonuses', []).append(bonus_obj)

            technical_map_by_operator, technical_totals_by_operator = self._load_technical_issues_by_operator_day_tx(
                cursor=cursor,
                operator_ids=op_ids,
                start_date=start,
                end_date=end
            )
            offline_map_by_operator, offline_totals_by_operator = self._load_offline_activities_by_operator_day_tx(
                cursor=cursor,
                operator_ids=op_ids,
                start_date=start,
                end_date=end
            )
            training_totals_by_operator = self._load_training_hours_by_operator_tx(
                cursor=cursor,
                operator_ids=op_ids,
                start_date=start,
                end_date=end
            )
            chat_metrics_by_operator, chat_totals_by_operator = self._load_chat_manager_metrics_by_operator_day_tx(
                cursor=cursor,
                operator_ids=op_ids,
                start_date=start,
                end_date=end
            )

            operators = []
            for row in operator_rows:
                (op_id, op_name, rate, status, sup_id, direction_name, calculation_model_raw, norm_hours,
                regular_hours, total_break_time, total_talk_time,
                total_calls, total_efficiency_hours, calls_per_hour, fines, operator_department_id) = row
                calculation_model_code = self._normalize_calculation_model_code(calculation_model_raw, direction_name)
                op_daily = daily_map.get(op_id, {})
                training_hours = float(training_totals_by_operator.get(op_id, 0.0)) if isinstance(training_totals_by_operator, dict) else 0.0
                technical_issue_hours = float(technical_totals_by_operator.get(op_id, 0.0)) if isinstance(technical_totals_by_operator, dict) else 0.0
                offline_activity_hours = float(offline_totals_by_operator.get(op_id, 0.0)) if isinstance(offline_totals_by_operator, dict) else 0.0
                no_phone_hours = float(no_phone_totals_by_operator.get(op_id, 0.0))
                accounted_hours = float(regular_hours or 0.0) + training_hours + technical_issue_hours + offline_activity_hours
                chat_metrics_by_day = chat_metrics_by_operator.get(op_id, {}) if isinstance(chat_metrics_by_operator, dict) else {}
                chat_metric_totals = chat_totals_by_operator.get(op_id, {}) if isinstance(chat_totals_by_operator, dict) else {}
                if calculation_model_code == CALCULATION_MODEL_CHAT_MANAGER:
                    _chat_chats = int(chat_metric_totals.get("chats_count") or 0)
                    total_calls = _chat_chats
                    regular_hours_for_rate = max(0.0, float(regular_hours or 0.0))
                    calls_per_hour = (float(total_calls) / regular_hours_for_rate) if regular_hours_for_rate > 0 else 0.0
                    for day_key, metrics in (chat_metrics_by_day or {}).items():
                        entry = op_daily.setdefault(str(day_key), {
                            "work_time": 0.0,
                            "break_time": 0.0,
                            "talk_time": 0.0,
                            "calls": 0,
                            "efficiency": 0.0,
                            "fine_amount": 0.0,
                            "fine_reason": None,
                            "fine_comment": None,
                            "fines": [],
                            "bonuses": []
                        })
                        entry["chat_metrics"] = metrics
                        entry["calls"] = int(metrics.get("chats_count") or 0)

                operators.append({
                    "operator_id": op_id,
                    "name": op_name,
                    "direction": direction_name,
                    "department_id": operator_department_id,
                    "calculation_model_code": calculation_model_code,
                    "calculationModelCode": calculation_model_code,
                    "supervisor_id": sup_id,
                    "rate": float(rate) if rate is not None else 0.0,
                    "status": status,
                    "norm_hours": float(norm_hours) if norm_hours is not None else 0.0,
                    "training_hours": round(float(training_hours), 2),
                    "no_phone_hours": round(float(no_phone_hours), 2),
                    "accounted_hours": round(float(accounted_hours), 2),
                    "worked_hours_used": round(float(accounted_hours), 2),
                    "daily": op_daily,
                    "chat_metrics_by_day": chat_metrics_by_day,
                    "chat_metrics": chat_metric_totals,
                    "technical_issues_by_day": technical_map_by_operator.get(op_id, {}) if isinstance(technical_map_by_operator, dict) else {},
                    "technical_issue_hours": round(float(technical_issue_hours), 2),
                    "offline_activities_by_day": offline_map_by_operator.get(op_id, {}) if isinstance(offline_map_by_operator, dict) else {},
                    "offline_activity_hours": round(float(offline_activity_hours), 2),
                    "aggregates": {
                        "regular_hours": float(regular_hours),
                        "total_break_time": float(total_break_time),
                        "total_talk_time": float(total_talk_time),
                        "total_calls": int(total_calls),
                        "total_efficiency_hours": float(total_efficiency_hours),
                        "calls_per_hour": float(calls_per_hour),
                        "fines": float(fines),
                        "chat_avg_score": chat_metric_totals.get("avg_score"),
                        "chat_avg_response_time_seconds": chat_metric_totals.get("avg_response_time_seconds"),
                        "chat_transfer_count": int(chat_metric_totals.get("transfer_chat_count") or 0),
                    }
                })

        return {"month": month, "days_in_month": days, "operators": operators}

    def aggregate_month_from_daily(self, operator_id, month):
        """
        Публичный wrapper месячной агрегации daily_hours -> work_hours.
        """
        with self._get_cursor() as cursor:
            return self._aggregate_month_from_daily_tx(
                cursor=cursor,
                operator_id=int(operator_id),
                month=str(month)
            )

    def auto_fill_norm_hours(self, month):
        """
        Авто-подсчет `norm_hours` для всех операторов за указанный месяц (формат 'YYYY-MM'),
        где текущая `norm_hours` равна 0. Формула: рабочие дни * 8 * rate.

        Возвращает словарь: {"month": month, "work_days": int, "processed": int}
        processed — число строк, на которые сработал INSERT/UPDATE (оценочно).
        """
        try:
            year, mon = map(int, month.split('-'))
        except Exception as e:
            raise ValueError("Invalid month format, expected YYYY-MM") from e

        work_days = self._get_month_work_days(f"{year}-{mon:02d}")

        with self._get_cursor() as cursor:
            # Вставляем/обновляем norm_hours для всех операторов.
            # Для операторов без строки в work_hours будет INSERT, для существующих с norm_hours=0 — UPDATE.
            cursor.execute("""
                INSERT INTO work_hours (operator_id, month, norm_hours)
                SELECT u.id, %s as month, (%s::float * 8.0 * COALESCE(
                    (SELECT wr.rate FROM work_hours wr
                     WHERE wr.operator_id = u.id AND wr.rate IS NOT NULL AND wr.month <= %s
                     ORDER BY wr.month DESC LIMIT 1),
                    u.rate, 1.0))::float
                FROM users u
                WHERE u.role = 'operator'
                ON CONFLICT (operator_id, month) DO UPDATE
                  SET norm_hours = EXCLUDED.norm_hours
                  WHERE COALESCE(work_hours.norm_hours, 0) = 0
            """, (month, work_days, month))

            # rowcount может быть не точен при ON CONFLICT, но даёт оценку затронутых строк
            processed = cursor.rowcount if cursor.rowcount is not None else 0

        return {"month": month, "work_days": work_days, "processed": int(processed)}

    def save_directions(self, directions, scope_department_id=None):
        """Сохранить направления в таблицу directions, создавая новые версии при изменениях.

        Если задан scope_department_id — операция ограничена этим отделом:
        сравнение/деактивация берут только направления этого отдела, новые версии и
        новые направления получают этот department_id, направления других отделов
        не затрагиваются. Это нужно, чтобы глава отдела (или админ, редактирующий
        конкретный отдел) не «обнулял» направления других отделов.
        """
        scoped = scope_department_id is not None
        with self._get_cursor() as cursor:
            # 1. Получаем текущие активные направления (в рамках отдела, если задан scope)
            if scoped:
                cursor.execute("""
                    SELECT id, name, has_file_upload, criteria, version, calculation_model_code, department_id
                    FROM directions
                    WHERE is_active = TRUE AND department_id = %s
                """, (scope_department_id,))
            else:
                cursor.execute("""
                    SELECT id, name, has_file_upload, criteria, version, calculation_model_code, department_id
                    FROM directions
                    WHERE is_active = TRUE
                """)
            existing_directions = {
                row[1]: {
                    "id": row[0],
                    "has_file_upload": row[2],
                    "criteria": json.dumps(row[3] or [], ensure_ascii=False, sort_keys=True),
                    "version": row[4],
                    "calculation_model_code": normalize_calculation_model_code(row[5], row[1]),
                    "department_id": row[6]
                } for row in cursor.fetchall()
            }
            
            new_direction_names = {str(d.get('name') or '').strip() for d in directions if str(d.get('name') or '').strip()}
            directions_to_deactivate = []
            insert_values = []
            
            # 2. Подготовка данных для пакетной обработки
            for direction in directions:
                name = str(direction.get('name') or '').strip()
                if not name:
                    continue
                has_file_upload = bool(direction.get('hasFileUpload', True))
                criteria = json.dumps(direction.get('criteria') or [], ensure_ascii=False, sort_keys=True)
                calculation_model_code = normalize_calculation_model_code(
                    direction.get('calculationModelCode') or direction.get('calculation_model_code'),
                    name
                )
                
                if name in existing_directions:
                    existing = existing_directions[name]
                    if (existing['has_file_upload'] == has_file_upload and
                        existing['criteria'] == criteria and
                        existing['calculation_model_code'] == calculation_model_code):
                        continue  # Ничего не изменилось, пропускаем
                    
                    directions_to_deactivate.append(existing['id'])
                    insert_values.append((
                        name, has_file_upload, criteria, calculation_model_code,
                        existing['version'] + 1, existing['id'],
                        scope_department_id if scoped else existing.get('department_id')
                    ))
                else:
                    insert_values.append((
                        name, has_file_upload, criteria, calculation_model_code,
                        1, None,  # version=1, no previous version
                        scope_department_id  # NULL для глобального режима (без scope)
                    ))
            
            # 3. Пакетное деактивирование старых версий
            if directions_to_deactivate:
                cursor.execute("""
                    UPDATE directions
                    SET is_active = FALSE
                    WHERE id = ANY(%s)
                """, (directions_to_deactivate,))
            
            # 4. Пакетное добавление новых версий
            if insert_values:
                cursor.executemany("""
                    INSERT INTO directions (
                        name, has_file_upload, criteria, calculation_model_code,
                        version, previous_version_id, department_id
                    )
                    VALUES (%s, %s, %s, %s, %s, %s, %s)
                """, insert_values)

            # 5. Деактивируем направления, которых нет в новом списке (в рамках scope-отдела, если задан)
            if scoped:
                if new_direction_names:
                    cursor.execute("""
                        UPDATE directions
                        SET is_active = FALSE
                        WHERE is_active = TRUE AND department_id = %s AND name NOT IN %s
                    """, (scope_department_id, tuple(new_direction_names)))
                else:
                    cursor.execute("""
                        UPDATE directions
                        SET is_active = FALSE
                        WHERE is_active = TRUE AND department_id = %s
                    """, (scope_department_id,))
            elif new_direction_names:
                cursor.execute("""
                    UPDATE directions
                    SET is_active = FALSE
                    WHERE is_active = TRUE AND name NOT IN %s
                """, (tuple(new_direction_names),))
            else:
                cursor.execute("""
                    UPDATE directions
                    SET is_active = FALSE
                    WHERE is_active = TRUE
                """)
            
            # 6. Оптимизированное обновление direction_id в users
            cursor.execute("""
                -- Обновляем direction_id на последнюю активную версию в том же отделе
                UPDATE users u
                SET direction_id = latest.id
                FROM directions current
                JOIN (
                    SELECT name, department_id, id,
                        ROW_NUMBER() OVER (
                            PARTITION BY name, department_id
                            ORDER BY version DESC
                        ) as rn
                    FROM directions
                    WHERE is_active = TRUE
                ) latest ON current.name = latest.name
                    AND current.department_id IS NOT DISTINCT FROM latest.department_id
                    AND latest.rn = 1
                WHERE u.direction_id = current.id AND current.is_active = FALSE;
                
                -- Обнуляем direction_id где нет активных направлений
                UPDATE users
                SET direction_id = NULL
                WHERE direction_id IS NOT NULL
                AND direction_id NOT IN (
                    SELECT id FROM directions WHERE is_active = TRUE
                );
            """)

    def get_operator_credentials(self, operator_id, supervisor_id):
        """Получить логин и хеш пароля оператора с проверкой принадлежности супервайзеру"""
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT u.id, u.login 
                FROM users u
                WHERE u.id = %s AND u.role = 'operator' AND u.supervisor_id = %s
            """, (operator_id, supervisor_id))
            return cursor.fetchone()

    def migrate_daily_fines_from_daily_hours(self):
        """
        Migration helper: convert existing aggregated fine_amount/fine_reason/fine_comment
        from daily_hours into individual rows in daily_fines when no daily_fines exist for that day.
        This is idempotent: it will skip days that already have entries in daily_fines.
        """
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT id, operator_id, day, fine_amount, fine_reason, fine_comment
                FROM daily_hours
                WHERE COALESCE(fine_amount, 0) > 0
            """)
            rows = cursor.fetchall()
            for dh_id, op_id, day_obj, fine_amount, fine_reason, fine_comment in rows:
                # skip if fines already exist for this daily_hours
                cursor.execute("SELECT 1 FROM daily_fines WHERE daily_hours_id = %s LIMIT 1", (dh_id,))
                if cursor.fetchone():
                    continue
                # insert single aggregated fine as one row
                cursor.execute(
                    "INSERT INTO daily_fines (daily_hours_id, operator_id, day, amount, reason, comment) VALUES (%s, %s, %s, %s, %s, %s)",
                    (dh_id, op_id, day_obj, float(fine_amount or 0.0), fine_reason, fine_comment)
                )

    def update_user_password(self, user_id, new_password):
        password_hash = pbkdf2_sha256.hash(new_password)
        with self._get_cursor() as cursor:
            cursor.execute("""
                UPDATE users SET password_hash = %s
                WHERE id = %s
                RETURNING id
            """, (password_hash, user_id))
            return cursor.fetchone() is not None
    
    def update_operator_login(self, operator_id, supervisor_id, new_login):
        """Обновить логин оператора с проверкой принадлежности"""
        if supervisor_id:
            with self._get_cursor() as cursor:
                cursor.execute("""
                    UPDATE users SET login = %s
                    WHERE id = %s AND supervisor_id = %s
                    RETURNING id
                """, (new_login, operator_id, supervisor_id))
                return cursor.fetchone() is not None
        else:
            with self._get_cursor() as cursor:
                cursor.execute("""
                    UPDATE users SET login = %s
                    WHERE id = %s
                    RETURNING id
                """, (new_login, operator_id))
                return cursor.fetchone() is not None
    
    def update_operator_password(self, operator_id, supervisor_id, new_password):
        """Обновить пароль оператора с проверкой принадлежности"""
        password_hash = pbkdf2_sha256.hash(new_password)
        with self._get_cursor() as cursor:
            cursor.execute("""
                UPDATE users SET password_hash = %s
                WHERE id = %s AND role = 'operator' AND supervisor_id = %s
                RETURNING id
            """, (password_hash, operator_id, supervisor_id))
            return cursor.fetchone() is not None
            
    def get_user(self, **kwargs):
        from psycopg2 import sql
        conditions = []
        params = []
        for key, value in kwargs.items():
            if key == 'direction':
                conditions.append(sql.SQL("d.name = %s"))
                params.append(value)
            else:
                # Use sql.Identifier to safely quote the column name
                conditions.append(sql.SQL("u.{} = %s").format(sql.Identifier(key)))
                params.append(value)
        
        query = sql.SQL("""
            SELECT u.id, u.telegram_id, u.name, u.role, d.name, u.hire_date, u.supervisor_id, u.login, u.hours_table_url, u.scores_table_url, u.is_active, u.status, u.rate, u.gender, u.birth_date, u.avatar_bucket, u.avatar_blob_path, u.avatar_content_type, u.avatar_file_size, u.avatar_updated_at
            FROM users u
            LEFT JOIN directions d ON u.direction_id = d.id
            WHERE {}
        """).format(sql.SQL(' AND ').join(conditions))
        
        with self._get_cursor() as cursor:
            cursor.execute(query, params)
            return cursor.fetchone()

    def get_birthdays_for_date(self, day_value):
        """Return list of active users with birthdays matching the given date (month/day)."""
        day = None
        if isinstance(day_value, str):
            try:
                day = datetime.strptime(day_value, "%Y-%m-%d").date()
            except ValueError:
                raise ValueError("Invalid date format. Use YYYY-MM-DD")
        elif isinstance(day_value, datetime):
            day = day_value.date()
        else:
            day = day_value

        if not day:
            return []

        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT
                    u.id,
                    u.name,
                    u.role,
                    d.name AS direction,
                    u.status,
                    u.birth_date
                FROM users u
                LEFT JOIN directions d ON u.direction_id = d.id
                WHERE u.birth_date IS NOT NULL
                  AND EXTRACT(MONTH FROM u.birth_date) = %s
                  AND EXTRACT(DAY FROM u.birth_date) = %s
                  AND (u.status IS NULL OR u.status NOT IN ('fired', 'dismissal'))
            """, (day.month, day.day))
            rows = cursor.fetchall()

        return [
            {
                "id": row[0],
                "name": row[1],
                "role": row[2],
                "direction": row[3],
                "status": row[4],
                "birth_date": row[5].strftime('%Y-%m-%d') if row[5] else None
            }
            for row in rows
        ]

    def get_call_by_id(self, call_id):
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT id, operator_id, phone_number, audio_path
                FROM calls
                WHERE id = %s
            """, (call_id,))
            row = cursor.fetchone()
            if row:
                return {
                    "id": row[0],
                    "operator_id": row[1],
                    "phone_number": row[2],
                    "audio_path": row[3]
                }
            return None
        
    def update_user_table(self, user_id, hours_table_url=None, scores_table_url=None):
        with self._get_cursor() as cursor:
            cursor.execute("""
                UPDATE users 
                SET hours_table_url = COALESCE(%s, hours_table_url),
                    scores_table_url = COALESCE(%s, scores_table_url)
                WHERE id = %s
            """, (hours_table_url, scores_table_url, user_id))

    def add_call_evaluation(self,
                            evaluator_id,
                            operator_id,
                            phone_number,
                            score,
                            comment=None,
                            comment_visible_to_operator=True,
                            month=None,
                            audio_path=None,
                            is_draft=False,
                            scores=None,
                            criterion_comments=None,
                            direction_id=None,
                            is_correction=False,
                            previous_version_id=None,
                            appeal_date=None,
                            question_resolved=False,
                            resolved_first_contact=None,
                            external_id=None):   # <-- NEW optional param
        """
        Создаёт/обновляет запись в calls и, если возможно, помечает связанную запись в imported_calls как evaluated.
        """
        month = month or datetime.now().strftime('%Y-%m')
        question_resolved = bool(question_resolved)
        resolved_first_contact = bool(resolved_first_contact) if question_resolved else None

        # Подготовка JSON данных один раз
        scores_json = json.dumps(scores) if scores else None
        criterion_comments_json = json.dumps(criterion_comments) if criterion_comments else None

        with self._get_cursor() as cursor:
            # Проверка существования direction_id одним запросом
            if direction_id:
                cursor.execute("SELECT 1 FROM directions WHERE id = %s AND is_active = TRUE", (direction_id,))
                if not cursor.fetchone():
                    direction_id = None

            if is_correction and previous_version_id and not audio_path:
                cursor.execute("SELECT audio_path FROM calls WHERE id = %s", (previous_version_id,))
                result = cursor.fetchone()
                if result and result[0]:
                    audio_path = result[0]

            # Объединенная проверка черновика и существующей оценки
            cursor.execute("""
                WITH existing_data AS (
                    -- Проверка на существующий черновик
                    SELECT id, audio_path, FALSE AS is_existing_eval, created_at
                    FROM calls 
                    WHERE evaluator_id = %s 
                    AND operator_id = %s 
                    AND month = %s 
                    AND is_draft = TRUE
                    
                    UNION ALL
                    
                    -- Проверка на существующую оценку (не черновик)
                    SELECT id, NULL AS audio_path, TRUE AS is_existing_eval, created_at
                    FROM calls 
                    WHERE operator_id = %s 
                    AND month = %s 
                    AND phone_number = %s 
                    AND is_draft = FALSE
                )
                SELECT id, audio_path, is_existing_eval 
                FROM existing_data
                ORDER BY created_at DESC
                LIMIT 1
            """, (evaluator_id, operator_id, month, operator_id, month, phone_number))

            existing_record = cursor.fetchone()
            old_audio_path = None
            call_id = None

            if existing_record and not is_correction:
                call_id, old_audio_path, is_existing_eval = existing_record

                # Обновление существующей записи
                if is_draft:
                    # Для черновика обновляем все поля
                    cursor.execute("""
                        UPDATE calls
                        SET phone_number = %s,
                            score = %s,
                            comment = %s,
                            comment_visible_to_operator = %s,
                            question_resolved = %s,
                            resolved_first_contact = %s,
                            audio_path = COALESCE(%s, audio_path),
                            created_at = CURRENT_TIMESTAMP,
                            scores = %s,
                            criterion_comments = %s,
                            is_correction = %s,
                            direction_id = %s
                        WHERE id = %s
                        RETURNING id
                    """, (
                        phone_number, score, comment, bool(comment_visible_to_operator),
                        question_resolved, resolved_first_contact, audio_path,
                        scores_json, criterion_comments_json,
                        False,
                        direction_id,
                        call_id
                    ))
                    call_id = cursor.fetchone()[0]

                    # Удаляем старый аудиофайл если он был заменен
                    if old_audio_path and audio_path and old_audio_path != audio_path:
                        try:
                            bucket_name = os.getenv('GOOGLE_CLOUD_STORAGE_BUCKET')
                            client = get_gcs_client()
                            bucket = client.bucket(bucket_name)
                            blob = bucket.blob(old_audio_path.replace("my-app-audio-uploads/", ""))
                            blob.delete()
                        except Exception as e:
                            logging.error(f"Error removing old audio file: {str(e)}")

                    # Перед возвратом — пометить imported_calls (если найдено)
                    try:
                        if external_id:
                            cursor.execute("""
                                UPDATE imported_calls
                                SET status = 'evaluated',
                                    evaluated_at = CURRENT_TIMESTAMP AT TIME ZONE 'Asia/Almaty',
                                    evaluated_by = %s
                                WHERE external_id = %s AND month = %s AND status != 'evaluated'
                            """, (evaluator_id, external_id, month))
                        else:
                            # попытаться найти по телефону + дате (точное совпадение)
                            if phone_number and appeal_date:
                                phone_norm = _normalize_phone(phone_number)
                                cursor.execute("""
                                    UPDATE imported_calls
                                    SET status = 'evaluated',
                                        evaluated_at = CURRENT_TIMESTAMP AT TIME ZONE 'Asia/Almaty',
                                        evaluated_by = %s
                                    WHERE phone_normalized = %s AND month = %s AND datetime_raw = %s AND status != 'evaluated'
                                """, (evaluator_id, phone_norm, month, appeal_date))
                    except Exception as e:
                        logging.exception("Error marking imported_call as evaluated: %s", e)

                    return call_id

            # Создаем новую запись (для новой оценки, переоценки или если нет черновика)
            cursor.execute("""
                INSERT INTO calls (
                    evaluator_id, operator_id, month, phone_number, score, comment,
                    comment_visible_to_operator, question_resolved, resolved_first_contact,
                    audio_path, is_draft, is_correction, previous_version_id,
                    scores, criterion_comments, direction_id, appeal_date
                )
                VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
                RETURNING id
            """, (
                evaluator_id, operator_id, month, phone_number, score, comment,
                bool(comment_visible_to_operator), question_resolved, resolved_first_contact,
                audio_path, is_draft, is_correction, previous_version_id,
                scores_json, criterion_comments_json, direction_id, appeal_date
            ))
            call_id = cursor.fetchone()[0]

            # Удаляем старый аудиофайл, если он был заменен
            if old_audio_path and audio_path and old_audio_path != audio_path:
                try:
                    bucket_name = os.getenv('GOOGLE_CLOUD_STORAGE_BUCKET')
                    client = get_gcs_client()
                    bucket = client.bucket(bucket_name)
                    blob = bucket.blob(old_audio_path.replace("my-app-audio-uploads/", ""))
                    blob.delete()
                except Exception as e:
                    logging.error(f"Error removing old audio file: {str(e)}")

            # После успешного создания — помечаем imported_calls как evaluated (если можем сопоставить)
            try:
                if external_id:
                    cursor.execute("""
                        UPDATE imported_calls
                        SET status = 'evaluated',
                            evaluated_at = CURRENT_TIMESTAMP AT TIME ZONE 'Asia/Almaty',
                            evaluated_by = %s
                        WHERE external_id = %s AND month = %s AND status != 'evaluated'
                    """, (evaluator_id, external_id, month))
                else:
                    if phone_number and appeal_date:
                        phone_norm = _normalize_phone(phone_number)
                        cursor.execute("""
                            UPDATE imported_calls
                            SET status = 'evaluated',
                                evaluated_at = CURRENT_TIMESTAMP AT TIME ZONE 'Asia/Almaty',
                                evaluated_by = %s
                            WHERE phone_normalized = %s AND month = %s AND datetime_raw = %s AND status != 'evaluated'
                        """, (evaluator_id, phone_norm, month, appeal_date))
            except Exception as e:
                logging.exception("Error marking imported_call as evaluated: %s", e)

            return call_id
    
    def import_calls_from_distribution(self, payload: dict, importer_id: Optional[int] = None) -> dict:
        """
        Импортирует JSON payload в imported_calls.
        Возвращает отчёт: {'imported': n, 'updated': m, 'skipped': k, 'errors': [...], 'missing_operators': [...]}
        """
        month = payload.get('month')
        if not month:
            raise ValueError("Payload must include 'month' (YYYY-MM)")

        imported = 0
        updated = 0
        skipped = 0
        errors = []
        missing_operators = set()

        with self._get_cursor() as cur:
            for op in payload.get('distribution', []):
                op_name = op.get('operator')
                desired = op.get('desired')
                available = op.get('available')

                cur.execute("SELECT id FROM users WHERE name = %s LIMIT 1", (op_name,))
                r = cur.fetchone()
                operator_id = r[0] if r else None
                if not operator_id:
                    missing_operators.add(op_name)

                for c in op.get('calls', []):
                    external_id = c.get('id')
                    dt_raw_str = c.get('datetimeRaw')
                    parsed_dt = _parse_datetime_raw(dt_raw_str)
                    phone = c.get('phone')
                    phone_norm = _normalize_phone(phone)
                    duration = c.get('durationSec')

                    try:
                        cur.execute("""
                            INSERT INTO imported_calls
                            (external_id, operator_name, operator_id, month, datetime_raw,
                            phone_number, phone_normalized, duration_sec, desired, available, status, imported_at)
                            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,%s,'not_evaluated', CURRENT_TIMESTAMP AT TIME ZONE 'Asia/Almaty')
                            ON CONFLICT (external_id, month) DO UPDATE
                            SET operator_name = EXCLUDED.operator_name,
                                operator_id = COALESCE(EXCLUDED.operator_id, imported_calls.operator_id),
                                datetime_raw = COALESCE(EXCLUDED.datetime_raw, imported_calls.datetime_raw),
                                phone_number = COALESCE(EXCLUDED.phone_number, imported_calls.phone_number),
                                phone_normalized = COALESCE(EXCLUDED.phone_normalized, imported_calls.phone_normalized),
                                duration_sec = COALESCE(EXCLUDED.duration_sec, imported_calls.duration_sec),
                                desired = COALESCE(EXCLUDED.desired, imported_calls.desired),
                                available = COALESCE(EXCLUDED.available, imported_calls.available),
                                status = COALESCE(imported_calls.status, 'not_evaluated'),
                                imported_at = CURRENT_TIMESTAMP AT TIME ZONE 'Asia/Almaty'
                            """,
                            (external_id, op_name, operator_id, month, parsed_dt, phone, phone_norm, duration, desired, available)
                        )
                        # cur.rowcount может быть ненадёжен для ON CONFLICT; просто учитываем как imported/updated логически
                        imported += 1
                    except Exception as exc:
                        errors.append({"external_id": external_id, "error": str(exc)})
                        skipped += 1

        return {
            "imported": imported,
            "updated": updated,
            "skipped": skipped,
            "errors": errors,
            "missing_operators": list(missing_operators)
        }

    def list_imported_calls(self, month: str, status: Optional[str] = None, operator_name: Optional[str] = None, limit: int = 200):
        q = "SELECT id, external_id, operator_name, operator_id, datetime_raw, phone_number, phone_normalized, duration_sec, desired, available, status, evaluated_at, evaluated_by, notes FROM imported_calls WHERE month = %s"
        params = [month]
        if status:
            q += " AND status = %s"
            params.append(status)
        if operator_name:
            q += " AND operator_name = %s"
            params.append(operator_name)
        q += " ORDER BY datetime_raw NULLS LAST LIMIT %s"
        params.append(limit)
        with self._get_cursor() as cur:
            cur.execute(q, tuple(params))
            rows = cur.fetchall()
        keys = ["id","external_id","operator_name","operator_id","datetime_raw","phone_number","phone_normalized","duration_sec","desired","available","status","evaluated_at","evaluated_by","notes"]
        return [dict(zip(keys, r)) for r in rows]

    def mark_imported_call_skipped(self, imported_call_id: str, reason: Optional[str] = None):
        with self._get_cursor() as cur:
            cur.execute("UPDATE imported_calls SET status = 'skipped', notes = COALESCE(notes,'') || %s WHERE id = %s",
                        (f"\nskipped: {reason}" if reason else "\nskipped", imported_call_id))
            return cur.rowcount == 1

    def parse_calls_file(self, file, target_date: Optional[str] = None):
        try:
            filename = str(file.filename or "").lower()

            if filename.endswith(".csv"):
                try:
                    df = pd.read_csv(file, sep=None, engine="python")
                except Exception:
                    file.stream.seek(0)
                    df = pd.read_csv(file, sep=";")
                sheet_name = "CSV"
            elif filename.endswith((".xls", ".xlsx")):
                excel = pd.ExcelFile(file)
                sheet_name = excel.sheet_names[0]
                df = pd.read_excel(excel, sheet_name=sheet_name)
            else:
                return None, None, "Неверный формат файла. Поддерживаются только CSV, XLS, XLSX"

            if df is None or df.empty:
                return None, None, "Файл пустой или не содержит данных"

            df.columns = [str(col).strip() for col in df.columns]

            def _norm_header(value):
                txt = str(value or "").strip().lower()
                txt = txt.replace("ё", "е")
                txt = re.sub(r"\s+", " ", txt)
                return txt

            normalized_to_original = {_norm_header(col): col for col in df.columns}

            def _pick_column(candidates):
                # exact normalized match
                for cand in candidates:
                    found = normalized_to_original.get(_norm_header(cand))
                    if found:
                        return found
                # soft contains match
                candidate_norms = [_norm_header(c) for c in candidates]
                for col in df.columns:
                    col_norm = _norm_header(col)
                    for cand_norm in candidate_norms:
                        if cand_norm and (cand_norm in col_norm or col_norm in cand_norm):
                            return col
                return None

            name_col = _pick_column(["ФИО", "ФИО оператора", "Оператор", "Name"])
            date_col = _pick_column(["Дата", "Date", "День", "Дата звонка"])
            calls_col = _pick_column([
                "Кол-во поступивших",
                "Количество поступивших"
            ])

            if not name_col or not date_col or not calls_col:
                return None, None, (
                    "Ожидаются колонки: ФИО, Дата, Кол-во поступивших "
                    f"(найдены: {', '.join(map(str, df.columns))})"
                )

            target_date_obj = None
            if target_date:
                try:
                    target_date_obj = datetime.strptime(str(target_date), "%Y-%m-%d").date()
                except Exception:
                    return None, None, "Некорректный формат выбранной даты. Ожидается YYYY-MM-DD"

            def _parse_row_date(raw_value):
                if raw_value is None or (isinstance(raw_value, float) and pd.isna(raw_value)):
                    return None
                if isinstance(raw_value, pd.Timestamp):
                    return raw_value.date()
                if isinstance(raw_value, datetime):
                    return raw_value.date()
                if isinstance(raw_value, date):
                    return raw_value

                text = str(raw_value).strip()
                if not text or text.lower() == "nan":
                    return None

                for fmt in ("%Y-%m-%d", "%d.%m.%Y", "%d/%m/%Y", "%Y/%m/%d", "%d-%m-%Y"):
                    try:
                        return datetime.strptime(text, fmt).date()
                    except Exception:
                        pass

                parsed = pd.to_datetime(text, dayfirst=True, errors="coerce")
                if pd.isna(parsed):
                    return None
                if isinstance(parsed, pd.Timestamp):
                    return parsed.date()
                return None

            def _parse_calls(raw_value):
                if raw_value is None or (isinstance(raw_value, float) and pd.isna(raw_value)):
                    return 0
                if isinstance(raw_value, (int, float)) and not pd.isna(raw_value):
                    try:
                        return max(int(round(float(raw_value))), 0)
                    except Exception:
                        return 0
                text = str(raw_value).strip().replace(" ", "").replace("\xa0", "")
                if not text or text.lower() == "nan":
                    return 0
                text = text.replace(",", ".")
                try:
                    return max(int(round(float(text))), 0)
                except Exception:
                    digits = re.sub(r"[^\d\-]", "", text)
                    try:
                        return max(int(digits), 0)
                    except Exception:
                        return 0

            aggregated = {}
            skipped_other_date = 0

            for _, row in df.iterrows():
                name_val = row.get(name_col)
                name = str(name_val or "").strip()
                if not name or name.lower() == "nan":
                    continue

                row_date_obj = _parse_row_date(row.get(date_col))
                if not row_date_obj:
                    continue

                if target_date_obj and row_date_obj != target_date_obj:
                    skipped_other_date += 1
                    continue

                calls_value = _parse_calls(row.get(calls_col))
                date_str = row_date_obj.strftime("%Y-%m-%d")
                key = (name, date_str)
                if key not in aggregated:
                    aggregated[key] = {
                        "name": name,
                        "date": date_str,
                        "calls": int(calls_value),
                        "month": date_str[:7]
                    }
                else:
                    aggregated[key]["calls"] = int(aggregated[key]["calls"]) + int(calls_value)

            operators = sorted(
                aggregated.values(),
                key=lambda item: (item.get("date") or "", str(item.get("name") or "").lower())
            )

            if not operators:
                if target_date_obj and skipped_other_date > 0:
                    return None, None, (
                        f"В файле нет строк за выбранную дату {target_date_obj.strftime('%Y-%m-%d')}"
                    )
                return None, None, "Не удалось распознать строки с данными ФИО/Дата/Кол-во звонков"

            return sheet_name, operators, None

        except Exception as e:
            return None, None, str(e)


    def _get_month_end_date(self, month: Optional[str]) -> date:
        month_str = str(month or '').strip()
        try:
            year_str, month_part = month_str.split('-', 1)
            year_value = int(year_str)
            month_value = int(month_part)
            last_day = calendar.monthrange(year_value, month_value)[1]
            return date(year_value, month_value, last_day)
        except Exception:
            today = datetime.now().date()
            last_day = calendar.monthrange(today.year, today.month)[1]
            return date(today.year, today.month, last_day)

    def _get_month_date_range(self, month: Optional[str]) -> Tuple[date, date]:
        month_end_date = self._get_month_end_date(month)
        month_start_date = date(month_end_date.year, month_end_date.month, 1)
        if month_end_date.month == 12:
            next_month_start = date(month_end_date.year + 1, 1, 1)
        else:
            next_month_start = date(month_end_date.year, month_end_date.month + 1, 1)
        return month_start_date, next_month_start

    def _get_month_work_days(self, month: Optional[str]) -> int:
        month_start_date, next_month_start = self._get_month_date_range(month)
        work_days = 0
        current_date = month_start_date
        while current_date < next_month_start:
            if current_date.weekday() < 5:
                work_days += 1
            current_date += timedelta(days=1)
        return int(work_days)

    def _get_full_rate_norm_hours(self, month: Optional[str]) -> float:
        return float(self._get_month_work_days(month) * 8.0)

    def _load_training_hours_by_operator_tx(self, cursor, operator_ids, start_date, end_date, group_id=None):
        normalized_ids = []
        seen_ids = set()
        for raw_id in (operator_ids or []):
            try:
                op_id = int(raw_id)
            except (TypeError, ValueError):
                continue
            if op_id in seen_ids:
                continue
            seen_ids.add(op_id)
            normalized_ids.append(op_id)

        if not normalized_ids:
            return {}

        group_filter_sql = ""
        params = [normalized_ids, start_date, end_date]
        if group_id is not None:
            group_filter_sql = """
              AND EXISTS (
                  SELECT 1
                  FROM group_operator_memberships gom
                  WHERE gom.operator_id = t.operator_id
                    AND gom.group_id = %s
                    AND gom.start_date <= t.training_date
                    AND (gom.end_date IS NULL OR gom.end_date >= t.training_date)
              )
            """
            params.append(int(group_id))

        cursor.execute(f"""
            SELECT
                t.operator_id,
                COALESCE(SUM(
                    CASE
                        WHEN t.end_time <= t.start_time
                            THEN EXTRACT(EPOCH FROM (t.end_time + INTERVAL '24 hours' - t.start_time))
                        ELSE EXTRACT(EPOCH FROM (t.end_time - t.start_time))
                    END
                ), 0) / 3600.0 AS training_hours
            FROM trainings t
            WHERE t.operator_id = ANY(%s)
              AND t.count_in_hours = TRUE
              AND t.training_date >= %s
              AND t.training_date <= %s
              {group_filter_sql}
            GROUP BY t.operator_id
        """, params)

        totals = {int(op_id): float(hours or 0.0) for op_id, hours in cursor.fetchall()}
        _manual_phone_training_map, manual_phone_training_totals = self._load_phone_shift_manual_training_offline_intervals_by_operator_day_tx(
            cursor=cursor,
            operator_ids=normalized_ids,
            start_date=start_date,
            end_date=end_date,
            group_id=group_id,
            counted_only=True
        )
        for op_id in normalized_ids:
            totals[op_id] = max(
                0.0,
                float(totals.get(op_id, 0.0)) - float(manual_phone_training_totals.get(op_id, 0.0) or 0.0)
            )
        return totals

    def _get_tenure_months_for_reference(self, hire_date_value, reference_date: Optional[date]) -> Optional[int]:
        if not hire_date_value or not reference_date:
            return None

        if isinstance(hire_date_value, datetime):
            hire_date_obj = hire_date_value.date()
        elif isinstance(hire_date_value, date):
            hire_date_obj = hire_date_value
        elif isinstance(hire_date_value, str):
            hire_date_obj = None
            for date_format in ('%Y-%m-%d', '%d-%m-%Y'):
                try:
                    hire_date_obj = datetime.strptime(hire_date_value, date_format).date()
                    break
                except ValueError:
                    continue
            if hire_date_obj is None:
                return None
        else:
            return None

        months = (reference_date.year - hire_date_obj.year) * 12 + (reference_date.month - hire_date_obj.month)
        if reference_date.day < hire_date_obj.day:
            months -= 1
        return max(int(months), 0)

    def _get_base_call_target_by_tenure(self, tenure_months: Optional[int]) -> int:
        if tenure_months is None:
            return 20
        if tenure_months <= 2:
            return 20
        if tenure_months <= 5:
            return 10
        return 5

    def _fetch_operator_call_evaluation_target_source(self, cursor, operator_id: int, target_month: str):
        month_start_date, next_month_start = self._get_month_date_range(target_month)
        cursor.execute("""
            SELECT
                u.hire_date,
                COALESCE(wh.regular_hours, 0) AS regular_hours,
                COALESCE(wh.norm_hours, 0) AS norm_hours,
                COALESCE((
                    SELECT SUM(
                        CASE
                            WHEN t.end_time <= t.start_time
                                THEN EXTRACT(EPOCH FROM (t.end_time + INTERVAL '24 hours' - t.start_time))
                            ELSE EXTRACT(EPOCH FROM (t.end_time - t.start_time))
                        END
                    ) / 3600.0
                    FROM trainings t
                    WHERE t.operator_id = u.id
                      AND t.count_in_hours = TRUE
                      AND t.training_date >= %s
                      AND t.training_date < %s
                ), 0) AS training_hours,
                COALESCE((
                    SELECT SUM(
                        CASE
                            WHEN ti.end_time <= ti.start_time
                                THEN EXTRACT(EPOCH FROM (ti.end_time + INTERVAL '24 hours' - ti.start_time))
                            ELSE EXTRACT(EPOCH FROM (ti.end_time - ti.start_time))
                        END
                    ) / 3600.0
                    FROM operator_technical_issues ti
                    WHERE ti.operator_id = u.id
                      AND ti.issue_date >= %s
                      AND ti.issue_date < %s
                ), 0) AS technical_issue_hours,
                COALESCE((
                    SELECT SUM(
                        CASE
                            WHEN oa.end_time <= oa.start_time
                                THEN EXTRACT(EPOCH FROM (oa.end_time + INTERVAL '24 hours' - oa.start_time))
                            ELSE EXTRACT(EPOCH FROM (oa.end_time - oa.start_time))
                        END
                    ) / 3600.0
                    FROM operator_offline_activities oa
                    WHERE oa.operator_id = u.id
                      AND oa.activity_date >= %s
                      AND oa.activity_date < %s
                ), 0)
                + COALESCE((
                    SELECT SUM(
                        CASE
                            WHEN ws.end_time <= ws.start_time
                                THEN EXTRACT(EPOCH FROM (ws.end_time + INTERVAL '24 hours' - ws.start_time))
                            ELSE EXTRACT(EPOCH FROM (ws.end_time - ws.start_time))
                        END
                    ) / 3600.0
                    FROM work_shifts ws
                    WHERE ws.operator_id = u.id
                      AND COALESCE(ws.shift_type, 'regular') = 'office_practice'
                      AND ws.shift_date >= %s
                      AND ws.shift_date < %s
                ), 0) AS offline_activity_hours
            FROM users u
            LEFT JOIN work_hours wh
                ON wh.operator_id = u.id
               AND wh.month = %s
            WHERE u.id = %s
            LIMIT 1
        """, (
            month_start_date,
            next_month_start,
            month_start_date,
            next_month_start,
            month_start_date,
            next_month_start,
            month_start_date,
            next_month_start,
            target_month,
            operator_id
        ))
        row = cursor.fetchone()
        if not row:
            return {
                'hire_date_value': None,
                'regular_hours': 0.0,
                'operator_norm_hours': 0.0,
                'training_hours': 0.0,
                'technical_issue_hours': 0.0,
                'offline_activity_hours': 0.0,
            }

        manual_phone_training_map, _manual_phone_training_totals = self._load_phone_shift_manual_training_offline_intervals_by_operator_day_tx(
            cursor=cursor,
            operator_ids=[operator_id],
            start_date=month_start_date,
            end_date=next_month_start - timedelta(days=1)
        )
        _manual_phone_training_counted_map, manual_phone_training_counted_totals = self._load_phone_shift_manual_training_offline_intervals_by_operator_day_tx(
            cursor=cursor,
            operator_ids=[operator_id],
            start_date=month_start_date,
            end_date=next_month_start - timedelta(days=1),
            counted_only=True
        )
        status_phone_training_map, _status_phone_training_totals = self._load_phone_shift_training_offline_intervals_by_operator_day_tx(
            cursor=cursor,
            operator_ids=[operator_id],
            start_date=month_start_date,
            end_date=next_month_start - timedelta(days=1)
        )
        phone_training_totals = self._sum_phone_shift_offline_interval_maps(
            [operator_id],
            manual_phone_training_map,
            status_phone_training_map
        )
        return {
            'hire_date_value': row[0],
            'regular_hours': float(row[1] or 0.0),
            'operator_norm_hours': float(row[2] or 0.0),
            'training_hours': max(
                0.0,
                float(row[3] or 0.0) - float(manual_phone_training_counted_totals.get(int(operator_id), 0.0) or 0.0)
            ),
            'technical_issue_hours': float(row[4] or 0.0),
            'offline_activity_hours': float(row[5] or 0.0) + float(phone_training_totals.get(int(operator_id), 0.0) or 0.0),
        }

    def _build_operator_call_evaluation_target(
        self,
        operator_id: int,
        target_month: str,
        hire_date_value=None,
        regular_hours: float = 0.0,
        training_hours: float = 0.0,
        technical_issue_hours: float = 0.0,
        offline_activity_hours: float = 0.0,
        operator_norm_hours: float = 0.0
    ):
        month_end_date = self._get_month_end_date(target_month)
        regular_hours_value = float(regular_hours or 0.0)
        training_hours_value = float(training_hours or 0.0)
        technical_issue_hours_value = float(technical_issue_hours or 0.0)
        offline_activity_hours_value = float(offline_activity_hours or 0.0)
        accounted_hours_value = (
            regular_hours_value
            + training_hours_value
            + technical_issue_hours_value
            + offline_activity_hours_value
        )
        operator_norm_hours_value = float(operator_norm_hours or 0.0)
        work_days_value = int(self._get_month_work_days(target_month))
        full_rate_norm_hours_value = float(self._get_full_rate_norm_hours(target_month) or 0.0)

        tenure_months = self._get_tenure_months_for_reference(hire_date_value, month_end_date)
        base_call_target = self._get_base_call_target_by_tenure(tenure_months)
        worked_hours_ratio = (
            accounted_hours_value / full_rate_norm_hours_value
        ) if full_rate_norm_hours_value > 0 else 0.0
        required_calls_raw = float(worked_hours_ratio) * float(base_call_target)
        required_calls = int(math.ceil(required_calls_raw - 1e-9)) if required_calls_raw > 0 else 0

        if tenure_months is None:
            tenure_bucket = 'unknown'
        elif tenure_months <= 2:
            tenure_bucket = '0_2_months'
        elif tenure_months <= 5:
            tenure_bucket = '3_5_months'
        else:
            tenure_bucket = '6_plus_months'

        return {
            'operator_id': int(operator_id),
            'month': target_month,
            'reference_date': month_end_date.isoformat(),
            'tenure_months': tenure_months,
            'tenure_bucket': tenure_bucket,
            'base_call_target': int(base_call_target),
            'worked_hours_for_calls': round(float(regular_hours_value), 2),
            'training_hours': round(float(training_hours_value), 2),
            'technical_issue_hours': round(float(technical_issue_hours_value), 2),
            'offline_activity_hours': round(float(offline_activity_hours_value), 2),
            'accounted_hours': round(float(accounted_hours_value), 2),
            'worked_hours_used': round(float(accounted_hours_value), 2),
            'work_days': int(work_days_value),
            'operator_norm_hours': round(float(operator_norm_hours_value), 2),
            'full_rate_norm_hours': round(float(full_rate_norm_hours_value), 2),
            'norm_hours': round(float(full_rate_norm_hours_value), 2),
            'worked_hours_ratio': round(float(worked_hours_ratio), 4),
            'required_calls_raw': round(float(required_calls_raw), 2),
            'required_calls': int(required_calls),
        }

    def get_operator_call_evaluation_target(self, operator_id: int, month: Optional[str] = None):
        target_month = str(month or datetime.now().strftime('%Y-%m'))

        with self._get_cursor() as cursor:
            source = self._fetch_operator_call_evaluation_target_source(cursor, operator_id, target_month)

        return self._build_operator_call_evaluation_target(
            operator_id=operator_id,
            target_month=target_month,
            hire_date_value=source.get('hire_date_value'),
            regular_hours=source.get('regular_hours'),
            training_hours=source.get('training_hours'),
            technical_issue_hours=source.get('technical_issue_hours'),
            offline_activity_hours=source.get('offline_activity_hours'),
            operator_norm_hours=source.get('operator_norm_hours')
        )

    def get_operator_call_evaluation_targets_for_month(self, operator_ids, month: Optional[str] = None):
        target_month = str(month or datetime.now().strftime('%Y-%m'))

        normalized_ids = []
        seen_ids = set()
        for raw_id in (operator_ids or []):
            try:
                op_id = int(raw_id)
            except (TypeError, ValueError):
                continue
            if op_id in seen_ids:
                continue
            seen_ids.add(op_id)
            normalized_ids.append(op_id)

        if not normalized_ids:
            return {}

        result = {}
        with self._get_cursor() as cursor:
            for op_id in normalized_ids:
                source = self._fetch_operator_call_evaluation_target_source(cursor, op_id, target_month)
                result[op_id] = self._build_operator_call_evaluation_target(
                    operator_id=op_id,
                    target_month=target_month,
                    hire_date_value=source.get('hire_date_value'),
                    regular_hours=source.get('regular_hours'),
                    training_hours=source.get('training_hours'),
                    technical_issue_hours=source.get('technical_issue_hours'),
                    offline_activity_hours=source.get('offline_activity_hours'),
                    operator_norm_hours=source.get('operator_norm_hours')
                )

        return result

    def get_operator_stats(self, operator_id):
        """Получить статистику оператора (часы, оценки, звонки в час, тренинги)"""
        with self._get_cursor() as cursor:
            # Текущий месяц в формате YYYY-MM
            current_month = datetime.now().strftime('%Y-%m')
            # Модель — по группе оператора на конец текущего месяца (fallback — направление).
            _cm_y, _cm_m = map(int, current_month.split('-'))
            _cm_end = date(_cm_y, _cm_m, calendar.monthrange(_cm_y, _cm_m)[1])
            calculation_model_code = self._get_operator_calculation_model_tx(cursor, operator_id, as_of=_cm_end)

            # 1) Берём агрегаты из work_hours (regular_hours, total_calls, fines, norm_hours)
            cursor.execute("""
                SELECT 
                    COALESCE(wh.regular_hours, 0) AS regular_hours,
                    COALESCE(wh.fines, 0) AS fines,
                    COALESCE(wh.norm_hours, 0) AS norm_hours,
                    COALESCE(wh.total_calls, 0) AS total_calls
                FROM work_hours wh
                WHERE wh.operator_id = %s AND wh.month = %s
                LIMIT 1
            """, (operator_id, current_month))
            wh_row = cursor.fetchone()

            if wh_row:
                regular_hours, fines, norm_hours, total_calls = wh_row
                regular_hours = float(regular_hours or 0.0)
                fines = float(fines or 0.0)
                norm_hours = float(norm_hours or 0.0)
                total_calls = int(total_calls or 0)
            else:
                regular_hours = 0.0
                fines = 0.0
                norm_hours = 0.0
                total_calls = 0

            # 2) Рассчитываем training_hours прямо по таблице trainings (учитываем count_in_hours = TRUE)
            cursor.execute("""
                SELECT COALESCE(SUM(
                    CASE 
                    WHEN t.end_time <= t.start_time 
                        THEN EXTRACT(EPOCH FROM (t.end_time + INTERVAL '24 hours' - t.start_time))
                    ELSE EXTRACT(EPOCH FROM (t.end_time - t.start_time))
                    END
                ) / 3600.0, 0) AS training_hours_seconds
                FROM trainings t
                WHERE t.operator_id = %s
                AND TO_CHAR(t.training_date, 'YYYY-MM') = %s
                AND t.count_in_hours = TRUE
            """, (operator_id, current_month))
            tr_row = cursor.fetchone()
            training_hours = float(tr_row[0] or 0.0)
            month_start_date, next_month_start = self._get_month_date_range(current_month)
            _manual_phone_training_counted_map, manual_phone_training_counted_totals = self._load_phone_shift_manual_training_offline_intervals_by_operator_day_tx(
                cursor=cursor,
                operator_ids=[operator_id],
                start_date=month_start_date,
                end_date=next_month_start - timedelta(days=1),
                counted_only=True
            )
            training_hours = max(
                0.0,
                training_hours - float(manual_phone_training_counted_totals.get(int(operator_id), 0.0) or 0.0)
            )

            # 3) Рассчитываем техсбои за месяц (учитываются в часах выполнения нормы)
            cursor.execute("""
                SELECT COALESCE(SUM(
                    CASE
                    WHEN ti.end_time <= ti.start_time
                        THEN EXTRACT(EPOCH FROM (ti.end_time + INTERVAL '24 hours' - ti.start_time))
                    ELSE EXTRACT(EPOCH FROM (ti.end_time - ti.start_time))
                    END
                ) / 3600.0, 0) AS technical_issue_hours_seconds
                FROM operator_technical_issues ti
                WHERE ti.operator_id = %s
                AND TO_CHAR(ti.issue_date, 'YYYY-MM') = %s
            """, (operator_id, current_month))
            tech_row = cursor.fetchone()
            technical_issue_hours = float(tech_row[0] or 0.0)

            # 3.1) Рассчитываем офлайн-активность за месяц
            cursor.execute("""
                SELECT COALESCE(SUM(
                    CASE
                    WHEN oa.end_time <= oa.start_time
                        THEN EXTRACT(EPOCH FROM (oa.end_time + INTERVAL '24 hours' - oa.start_time))
                    ELSE EXTRACT(EPOCH FROM (oa.end_time - oa.start_time))
                    END
                ) / 3600.0, 0) AS offline_activity_hours_seconds
                FROM operator_offline_activities oa
                WHERE oa.operator_id = %s
                AND TO_CHAR(oa.activity_date, 'YYYY-MM') = %s
            """, (operator_id, current_month))
            offline_row = cursor.fetchone()
            offline_activity_hours = float(offline_row[0] or 0.0)

            cursor.execute("""
                SELECT COALESCE(SUM(
                    CASE
                    WHEN ws.end_time <= ws.start_time
                        THEN EXTRACT(EPOCH FROM (ws.end_time + INTERVAL '24 hours' - ws.start_time))
                    ELSE EXTRACT(EPOCH FROM (ws.end_time - ws.start_time))
                    END
                ) / 3600.0, 0) AS practice_shift_offline_hours
                FROM work_shifts ws
                WHERE ws.operator_id = %s
                AND COALESCE(ws.shift_type, 'regular') = 'office_practice'
                AND TO_CHAR(ws.shift_date, 'YYYY-MM') = %s
            """, (operator_id, current_month))
            practice_row = cursor.fetchone()
            offline_activity_hours += float(practice_row[0] or 0.0)
            manual_phone_training_map, _manual_phone_training_totals = self._load_phone_shift_manual_training_offline_intervals_by_operator_day_tx(
                cursor=cursor,
                operator_ids=[operator_id],
                start_date=month_start_date,
                end_date=next_month_start - timedelta(days=1)
            )
            status_phone_training_map, _status_phone_training_totals = self._load_phone_shift_training_offline_intervals_by_operator_day_tx(
                cursor=cursor,
                operator_ids=[operator_id],
                start_date=month_start_date,
                end_date=next_month_start - timedelta(days=1)
            )
            phone_training_totals = self._sum_phone_shift_offline_interval_maps(
                [operator_id],
                manual_phone_training_map,
                status_phone_training_map
            )
            offline_activity_hours += float(phone_training_totals.get(int(operator_id), 0.0) or 0.0)

            # 4) Количество оценённых звонков и средняя оценка (как раньше)
            cursor.execute("""
                SELECT 
                    (SELECT COUNT(*) FROM calls WHERE operator_id = %s AND month = %s AND is_draft = FALSE) AS call_count,
                    (SELECT AVG(score) FROM calls WHERE operator_id = %s AND month = %s AND is_draft = FALSE) AS avg_score
            """, (operator_id, current_month, operator_id, current_month))
            calls_row = cursor.fetchone()
            call_count = int(calls_row[0] or 0)
            avg_score = float(calls_row[1]) if calls_row[1] is not None else 0.0

            chat_avg_response_time_seconds = None
            chat_transfer_count = 0
            if calculation_model_code == CALCULATION_MODEL_CHAT_MANAGER:
                cursor.execute("""
                    SELECT
                        COALESCE(SUM(chats_count), 0),
                        (
                            COALESCE(SUM(score_sum) FILTER (WHERE score_count > 0 AND score_sum IS NOT NULL), 0)
                            + COALESCE(SUM(avg_score) FILTER (
                                WHERE NOT (COALESCE(score_count, 0) > 0 AND score_sum IS NOT NULL)
                                  AND avg_score IS NOT NULL
                            ), 0)
                        ) / NULLIF(
                            COALESCE(SUM(score_count) FILTER (WHERE score_count > 0 AND score_sum IS NOT NULL), 0)
                            + COALESCE(COUNT(avg_score) FILTER (
                                WHERE NOT (COALESCE(score_count, 0) > 0 AND score_sum IS NOT NULL)
                                  AND avg_score IS NOT NULL
                            ), 0),
                            0
                        ),
                        AVG(avg_response_time_seconds) FILTER (WHERE avg_response_time_seconds IS NOT NULL),
                        COALESCE(SUM(transfer_chat_count), 0)
                    FROM chat_manager_daily_metrics
                    WHERE operator_id = %s
                    AND TO_CHAR(day, 'YYYY-MM') = %s
                """, (operator_id, current_month))
                chat_row = cursor.fetchone() or (0, None, None, 0)
                total_calls = int(chat_row[0] or 0)
                call_count = total_calls
                avg_score = float(chat_row[1]) if chat_row[1] is not None else 0.0
                chat_avg_response_time_seconds = float(chat_row[2]) if chat_row[2] is not None else None
                chat_transfer_count = int(chat_row[3] or 0)

            # 5) calls_per_hour: total_calls / regular_hours (время в работе из статусов).
            effective_call_hours = max(0.0, float(regular_hours))
            if effective_call_hours > 0:
                calls_per_hour = float(total_calls) / float(effective_call_hours)
            else:
                calls_per_hour = 0.0

            # 6) percent_complete: считаем с учётом зачётных тренингов, техсбоев и офлайн-активности.
            accounted_hours = regular_hours + training_hours + technical_issue_hours + offline_activity_hours
            if norm_hours and norm_hours > 0:
                percent_complete = (accounted_hours / norm_hours) * 100.0
            else:
                percent_complete = 0.0

            return {
                'operator_id': operator_id,
                'month': current_month,
                'calculation_model_code': calculation_model_code,
                'calculationModelCode': calculation_model_code,
                'regular_hours': round(float(regular_hours), 2),
                'training_hours': round(float(training_hours), 2),
                'technical_issue_hours': round(float(technical_issue_hours), 2),
                'offline_activity_hours': round(float(offline_activity_hours), 2),
                'accounted_hours': round(float(accounted_hours), 2),
                'fines': round(float(fines), 2),
                'norm_hours': float(norm_hours),
                'percent_complete': round(percent_complete, 2),
                'call_count': int(call_count),
                'avg_score': round(float(avg_score), 2),
                'total_calls': int(total_calls),
                'calls_per_hour': round(float(calls_per_hour), 2),
                'chat_avg_score': round(float(avg_score), 2) if calculation_model_code == CALCULATION_MODEL_CHAT_MANAGER else None,
                'chat_avg_response_time_seconds': chat_avg_response_time_seconds,
                'chat_transfer_count': int(chat_transfer_count or 0)
            }


    def get_operators_by_supervisor(self, supervisor_id):
        with self._get_cursor() as cursor:
            cursor.execute("""
                SELECT
                    u.id,
                    u.name,
                    u.direction_id,
                    u.supervisor_id,
                    u.hire_date,
                    u.hours_table_url,
                    u.scores_table_url,
                    s.name as supervisor_name,
                    u.status,
                    u.rate,
                    u.gender,
                    u.birth_date,
                    u.avatar_bucket,
                    u.avatar_blob_path,
                    u.avatar_updated_at,
                    sp.status_code as status_period_status_code,
                    sp.start_date as status_period_start_date,
                    sp.end_date as status_period_end_date,
                    sp.dismissal_reason as status_period_dismissal_reason,
                    COALESCE(sp.is_blacklist, FALSE) as status_period_is_blacklist,
                    sp.comment as status_period_comment
                FROM users u
                LEFT JOIN directions d ON u.direction_id = d.id
                LEFT JOIN users s ON u.supervisor_id = s.id
                LEFT JOIN LATERAL (
                    SELECT
                        p.status_code,
                        p.start_date,
                        p.end_date,
                        p.dismissal_reason,
                        p.is_blacklist,
                        p.comment
                    FROM operator_schedule_status_periods p
                    WHERE p.operator_id = u.id
                      AND p.status_code = (
                          CASE
                              WHEN u.status = 'fired' THEN 'dismissal'
                              WHEN u.status = 'dismissal' THEN 'dismissal'
                              WHEN u.status = 'unpaid_leave' THEN 'bs'
                              ELSE u.status
                          END
                      )
                    ORDER BY
                        CASE
                            WHEN p.start_date <= CURRENT_DATE
                             AND COALESCE(p.end_date, DATE '9999-12-31') >= CURRENT_DATE
                            THEN 0
                            ELSE 1
                        END,
                        p.start_date DESC,
                        p.id DESC
                    LIMIT 1
                ) sp ON TRUE
                WHERE u.supervisor_id = %s AND u.role = 'operator'
            """, (supervisor_id,))
            return [
                {
                    'id': row[0],
                    'name': row[1],
                    'direction_id': row[2],
                    'supervisor_id': row[3],
                    'hire_date': row[4].strftime('%d-%m-%Y') if row[4] else None,
                    'hours_table_url': row[5],
                    'scores_table_url': row[6],
                    'supervisor_name': row[7],
                    'status': row[8],
                    'rate': row[9],
                    'gender': row[10],
                    'birth_date': row[11].strftime('%d-%m-%Y') if row[11] else None,
                    'avatar_bucket': row[12],
                    'avatar_blob_path': row[13],
                    'avatar_updated_at': row[14].isoformat() if row[14] else None,
                    'status_period_status_code': row[15],
                    'status_period_start_date': row[16].strftime('%Y-%m-%d') if row[16] else None,
                    'status_period_end_date': row[17].strftime('%Y-%m-%d') if row[17] else None,
                    'status_period_dismissal_reason': row[18] or '',
                    'status_period_is_blacklist': bool(row[19]) if row[19] is not None else False,
                    'status_period_comment': row[20] or ''
                } for row in cursor.fetchall()
            ]

